-- Poems batch 315
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('318f55ce-a737-4e9f-b574-82f5502e0710','次韵楊褒早春','蘇軾','宋','宋诗','song-poetry','','[]','窮巷淒涼苦未和，君家庭院得春多。',96,'全唐诗/poet.song.44000.json','["窮巷淒涼苦未和，君家庭院得春多。", "不辭瘦馬衝殘雪，來聽佳人唱踏莎。", "破恨徑須煩麴糵，增年誰復怨羲娥。", "良辰樂事古難並，白髮青衫我亦歌。", "細雨郊園聊種菜，冷官門戶可張羅。", "放朝三日君恩重，睡美不知身在何。"]'),
('8ad4c78c-f871-48b4-982f-2bc55d025ab6','次韵柳子玉見寄','蘇軾','宋','宋诗','song-poetry','','[]','薄雷輕雨曉晴初，陌上春泥未濺裾。',64,'全唐诗/poet.song.44000.json','["薄雷輕雨曉晴初，陌上春泥未濺裾。", "行樂及時雖有酒，出門無侶漫看書。", "遥知寒食催歸騎，定把鴟夷載後車。", "他日見邀須强起，不應辭病似相如。"]'),
('96e8c43f-6cf1-42be-bf82-d90164d3934f','送錢藻出守婺州得英字','蘇軾','宋','宋诗','song-poetry','','[]','老手便劇郡，高懷厭承明。',120,'全唐诗/poet.song.44000.json','["老手便劇郡，高懷厭承明。", "聊紆東陽綬，一濯滄浪纓。", "東陽佳山水，未到意已清。", "過家父老喜，出郭壺漿迎。", "子行得所願，愴悢居者情。", "吾君方急賢，日旰坐邇英。", "黄金招樂毅，白璧賜虞卿。", "子不少自貶，陳義空崢嶸。", "古稱爲郡樂，漸恐煩敲搒。", "臨分敢不盡，醉語醒還驚。"]'),
('4f47e0a2-1281-4a6a-88c3-344ea79f2109','送劉攽倅海陵','蘇軾','宋','宋诗','song-poetry','','[]','君不見阮嗣宗，臧否不挂口。',93,'全唐诗/poet.song.44000.json','["君不見阮嗣宗，臧否不挂口。", "莫誇舌在齒牙牢，是中惟可飲醇酒。", "讀書不用多，作詩不須工。", "海邊無事日日醉，夢魂不到蓬萊宮。", "秋風昨夜入庭樹，蒓絲未老君先去。", "君先去，幾時回。", "劉郎應白髮，桃花開不開。"]'),
('797e89dd-ab46-48ff-8863-1a910a0866e7','送曾子固倅越得燕字','蘇軾','宋','宋诗','song-poetry','','[]','醉翁門下士，雜遝難爲賢。',96,'全唐诗/poet.song.44000.json','["醉翁門下士，雜遝難爲賢。", "曾子獨超軼，孤芳陋羣妍。", "昔從南方來，與翁兩聯翩。", "翁今自憔悴，子去亦宜然。", "賈誼窮適楚，樂生老思燕。", "那因江鱠美，遽厭天庖羶。", "但苦世論隘，聒耳如蜩蟬。", "安得萬頃池，養此橫海鱣。"]'),
('0fc86d23-9d7f-4018-a89f-d11ac36881ed','綠筠亭','蘇軾','宋','宋诗','song-poetry','','[]','愛竹能延客，求詩剩掛牆。',48,'全唐诗/poet.song.44000.json','["愛竹能延客，求詩剩掛牆。", "風梢千纛亂，月影萬夫長。", "谷鳥驚棋響，山蜂識酒香。", "只應陶靖節，會取北窗凉。"]'),
('109be25f-dcac-4da9-82f7-50099e026dc2','送安惇秀才失解西歸','蘇軾','宋','宋诗','song-poetry','','[]','舊書不厭百回讀，熟讀深思子自知。',128,'全唐诗/poet.song.44000.json','["舊書不厭百回讀，熟讀深思子自知。", "他年名宦恐不免，今日棲遲那可追。", "我昔家居斷還往，著書不暇窺園葵。", "朅來東游慕人爵，棄去舊學從兒嬉。", "狂謀謬算百不遂，惟有霜鬢來如期。", "故山松柏皆手種，行且拱矣歸何時。", "萬事早知皆有命，十年浪走寧非癡。", "與君未可較得失，臨別惟有長嗟咨。"]'),
('130b35a1-541c-4d23-87e1-de81af8a2677','送呂希道知和州','蘇軾','宋','宋诗','song-poetry','','[]','去年送君守解梁，今年送君守歷陽。',128,'全唐诗/poet.song.44000.json','["去年送君守解梁，今年送君守歷陽。", "年年送人作太守，坐受塵土堆胸腸。", "君家聯翩三將相，富貴未已今方將。", "鳳雛驥子生有種，毛骨往往傳諸郎。", "觀君崛鬰負奇表，便合劍珮趨明光。", "胡爲小郡屢奔走，征馬未解風帆張。", "我生本是便江海，忍耻未去猶徬徨。", "無言贈君有長歎，美哉河水空洋洋。"]'),
('6cb49bf3-a821-4862-b011-703a4dea3de2','送文與可出守陵州','蘇軾','宋','宋诗','song-poetry','','[]','壁上墨君不解語，見之尚可消百憂。',96,'全唐诗/poet.song.44000.json','["壁上墨君不解語，見之尚可消百憂。", "而况我友似君者，素節凜凜欺霜秋。", "清詩健筆何足數，逍遥齊物追莊周。", "奪官遣去不自覺，曉梳脫髮誰能收。", "江邊亂山赤如赭，陵陽正在千山頭。", "君知遠別懷抱惡，時遣墨君解我愁。"]'),
('3c7b14bd-18cb-4377-b4ef-22ddb8a901c9','次韵王誨夜坐','蘇軾','宋','宋诗','song-poetry','','[]','愛君東閣能延客，顧我閑官不計員。',64,'全唐诗/poet.song.44000.json','["愛君東閣能延客，顧我閑官不計員。", "策杖頻過知未厭，卜居相近豈辭遷。", "莫將詩句驚摇落，漸喜樽罍省撲緣。", "待約月明池上宿，夜深同看水中天。"]'),
('bb0e1d3b-c2ef-4d41-a0ae-26a5607c146b','送蔡冠卿知饒州','蘇軾','宋','宋诗','song-poetry','','[]','吾觀蔡子與人遊，掀豗笑語無不可。',128,'全唐诗/poet.song.44000.json','["吾觀蔡子與人遊，掀豗笑語無不可。", "平生儻蕩不驚俗，臨事迂闊乃過我。", "橫前坑阱衆所畏，布路金珠誰不裹。", "爾來變化驚何速，昔號剛强今亦頗。", "憐君獨守廷尉法，晚歲却理鄱陽柂。", "莫嗟天驥逐羸牛，欲試良玉須猛火。", "世事徐觀真夢寐，人生不信長轗軻。", "知君决獄有陰功，他日老人酬魏顆。"]'),
('21739ccd-f1f3-41e4-ac5b-3badec3973e8','宋叔達家聽琵琶','蘇軾','宋','宋诗','song-poetry','','[]','數絃已品龍香撥，半面猶遮鳳尾槽。',64,'全唐诗/poet.song.44000.json','["數絃已品龍香撥，半面猶遮鳳尾槽。", "新曲從翻玉連鎖，舊聲終愛鬰輪袍。", "夢回只記歸舟字，賦罷雙垂紫錦絛。", "何異烏孫送公主，碧天無際雁行高。"]'),
('08663486-876e-4ddb-8459-b9a463b7e9d2','次韵子由初到陳州二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','道喪雖云久，吾猶及老成。',48,'全唐诗/poet.song.44000.json','["道喪雖云久，吾猶及老成。", "如今各衰晚，那更治刑名。", "懶惰便樗散，疏狂託聖明。", "阿奴須碌碌，門戶要全生。"]'),
('6586f4a0-30de-43fb-b8c4-342b8c5fd367','次韵子由初到陳州二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','舊隠三年別，杉松好在不。',48,'全唐诗/poet.song.44000.json','["舊隠三年別，杉松好在不。", "我今尚眷眷，此意恐悠悠。", "閉戶時尋夢，無人可說愁。", "還來送別處，雙淚寄南州。"]'),
('6f608e16-b628-49b2-9dab-0b707393c682','送劉道原歸覲南康','蘇軾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','晏嬰不滿六尺長，高節萬仞陵首陽。',224,'全唐诗/poet.song.44000.json','["晏嬰不滿六尺長，高節萬仞陵首陽。", "青衫白髮不自歎，富貴在天那得忙。", "十年閉戶樂幽獨，百金購書收散亡。", "朅來東觀弄丹墨，聊借舊史誅姦强。", "孔融不肯下曹操，汲黯本是輕張湯。", "雖無尺箠與寸刃，口吻排擊含風霜。", "自言靜中閱世俗，有似不飲觀酒狂。", "衣巾狼藉又屢舞，傍人大笑供千場。", "交朋翩翩去略盡，惟吾與子猶徬徨。", "世人共棄君獨厚，豈敢自愛恐子傷。", "朝來告別驚何速，歸意已逐征鴻翔。", "匡廬先生古君子，挂冠兩紀鬢未蒼。", "定將文度置膝上，喜動鄰里烹豬羊。", "君歸爲我道名姓，幅巾他日容登堂。"]'),
('efacd7ef-a4cc-4396-b5da-510a48737f1c','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其一','蘇軾','宋','宋诗','song-poetry','','[]','蛙鳴青草泊，蟬噪垂楊浦。',24,'全唐诗/poet.song.44000.json','["蛙鳴青草泊，蟬噪垂楊浦。", "吾行亦偶然，及此新過雨。"]'),
('6a0ac6a3-1812-4269-b569-2d13fe13bef5','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其二','蘇軾','宋','宋诗','song-poetry','','[]','鳥樂忘罝罦，魚樂忘鈎餌。',24,'全唐诗/poet.song.44000.json','["鳥樂忘罝罦，魚樂忘鈎餌。", "何必擇所安，滔滔天下是。"]'),
('feb0852f-5534-4b89-bbbd-1465b8481674','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其三','蘇軾','宋','宋诗','song-poetry','','[]','烟火動村落，晨光尚熹微。',24,'全唐诗/poet.song.44000.json','["烟火動村落，晨光尚熹微。", "田園處處好，淵明胡不歸。"]'),
('4bc6802c-26f2-4bbf-80b2-6514abf7d6d8','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其四','蘇軾','宋','宋诗','song-poetry','','[]','我行無疾徐，輕楫信溶漾。',24,'全唐诗/poet.song.44000.json','["我行無疾徐，輕楫信溶漾。", "船留村市鬧，閘發寒波漲。"]'),
('baab1a21-cf39-47e1-a715-8a625263964e','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其五','蘇軾','宋','宋诗','song-poetry','','[]','舟人苦炎熱，宿此喬木灣。',24,'全唐诗/poet.song.44000.json','["舟人苦炎熱，宿此喬木灣。", "清月未及上，黑雲如頹山。"]'),
('567b21ff-b98e-4599-a66c-e706ab71bda1','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其六','蘇軾','宋','宋诗','song-poetry','','[]','萬竅號地籟，衝風散天池。',24,'全唐诗/poet.song.44000.json','["萬竅號地籟，衝風散天池。", "喧豗瞬息間，還掛斗與箕。"]'),
('baa81c9e-bd26-43a6-ab09-a4eb28a6f4c6','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其七','蘇軾','宋','宋诗','song-poetry','','[]','潁水非漢水，亦作蒲萄綠。',24,'全唐诗/poet.song.44000.json','["潁水非漢水，亦作蒲萄綠。", "恨無襄陽兒，令唱銅鞮曲。"]'),
('9fd67d83-c68c-4233-80a6-69bac88ccf35','出都來陳所乘船上有題小詩八首不知何人有感於余心者聊爲和之  其八','蘇軾','宋','宋诗','song-poetry','','[]','我詩雖云拙，心平聲韵和。',24,'全唐诗/poet.song.44000.json','["我詩雖云拙，心平聲韵和。", "年來煩惱盡，古井無由波。"]'),
('33f565de-83c2-4a72-bca0-7ff8ffdeab29','次韵子由柳湖感物','蘇軾','宋','宋诗','song-poetry','','[]','憶昔子美在東屯，數間茅屋蒼山根。',176,'全唐诗/poet.song.44000.json','["憶昔子美在東屯，數間茅屋蒼山根。", "嘲吟草木調蠻獠，欲與猿鳥爭啾喧。", "子今憔悴衆所棄，驅馬獨出無往還。", "惟有柳湖萬株柳，清陰與子供朝昏。", "胡爲譏評不少借，生意凌挫難爲繁。", "柳雖無言不解慍，世俗乍見應憮然。", "嬌姿共愛春濯濯，豈問空腹修蛇蟠。", "朝看濃翠傲炎赫，夜愛疏影摇清圓。", "風翻雪陣春絮亂，蠹響啄木秋聲堅。", "四時盛衰各有態，摇落悽愴驚寒溫。", "南山孤松積雪底，抱凍不死誰復賢。"]'),
('2959d198-7081-481e-8537-ff49b4d5c9a5','次韵張安道讀杜詩','蘇軾','宋','宋诗','song-poetry','','[]','大雅初微缺，流風困暴豪。',240,'全唐诗/poet.song.44000.json','["大雅初微缺，流風困暴豪。", "張爲詞客賦，變作楚臣騷。", "展轉更崩壞，紛綸閱俊髦。", "地偏蕃怪産，源失亂狂濤。", "粉黛迷真色，魚蝦易豢牢。", "誰知杜陵傑，名與謫仙高。", "掃地收千軌，爭標看兩艘。", "詩人例窮苦，天意遣奔逃。", "塵暗人亡鹿，溟翻帝斬鰲。", "艱危思李牧，述作謝王褒。", "失意各千里，哀鳴聞九皋。", "騎鯨遁滄海，捋虎得綈袍。", "巨筆屠龍手，微官似馬曹。", "迂疏無事業，醉飽死遊遨。", "簡牘儀型在，兒童篆刻勞。", "今誰主文字，公合抱旌旄。", "開卷遥相憶，知音兩不遭。", "般斤思郢質，鯤化陋鯈濠。", "恨我無佳句，時蒙致白醪。", "殷勤理黄菊，未遣沒蓬蒿。"]'),
('fcdc7953-f19e-4f39-a452-8c2d47dbcd33','送張安道赴南都留臺','蘇軾','宋','宋诗','song-poetry','','[]','我公古仙伯，超然羨門姿。',144,'全唐诗/poet.song.44000.json','["我公古仙伯，超然羨門姿。", "偶懷濟物志，遂爲世所縻。", "黄龍遊帝郊，簫韶鳳來儀。", "終然反溟極，豈復安籠池。", "出入四十年，憂患未嘗辭。", "一言有歸意，闔府諫莫移。", "吾君信英睿，搜士及茅茨。", "無人長者側，何以安子思。", "歸來掃一室，虛白以自怡。", "游於物之初，世俗安得知。", "我亦世味薄，因循鬢生絲。", "出處良細事，從公當有時。"]'),
('46132848-2cad-4b16-b46e-c1e71d2ebbd4','傅堯俞濟源草堂','蘇軾','宋','宋诗','song-poetry','','[]','微官共有田園興，老罷方尋隠退廬。',64,'全唐诗/poet.song.44000.json','["微官共有田園興，老罷方尋隠退廬。", "栽種成陰十年事，倉黄求買百金無。", "先生卜築臨清濟，喬木如今似畫圖。", "鄰里亦知偏愛竹，春來相與護龍雛。"]'),
('547a00b8-6ae1-4579-82e7-78337aa6862a','陸龍圖詵挽詞','蘇軾','宋','宋诗','song-poetry','','[]','挺然直節庇峨岷，謀道從來不計身。',64,'全唐诗/poet.song.44000.json','["挺然直節庇峨岷，謀道從來不計身。", "屬纊家無十金産，過車巷哭六州民。", "塵埃輦寺三年別，樽俎岐陽一夢新。", "他日思賢見遺像，不論宿草更沾巾。"]'),
('27b0e856-7156-46b4-8eeb-bb09921b863a','胡完夫母周夫人挽詞','蘇軾','宋','宋诗','song-poetry','','[]','柏舟高節冠鄉鄰，絳帳清風聳搢紳。',64,'全唐诗/poet.song.44000.json','["柏舟高節冠鄉鄰，絳帳清風聳搢紳。", "豈似凡人但慈母，能令孝子作忠臣。", "當年織屨隨方進，晚節稱觴見伯仁。", "回首悲凉便陳迹，凱風吹盡棘成薪。"]'),
('5f3d9102-bc2b-4322-9f4d-50cb48221f3e','次韵柳子玉過陳絕糧二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','風雨蕭蕭夜晦迷，不須鳴叫强知時。',64,'全唐诗/poet.song.44000.json','["風雨蕭蕭夜晦迷，不須鳴叫强知時。", "多才久被天公怪，闕食惟應爨婦知。", "杜叟挽衣那及脛，顔公食粥敢言炊。", "詩人情味真嘗遍，試問於今底處虧。"]'),
('52e0a677-e934-48a6-a3eb-f263bde8b8bb','次韵柳子玉過陳絕糧二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','如我自觀猶可厭，非君誰復肯相尋。',64,'全唐诗/poet.song.44000.json','["如我自觀猶可厭，非君誰復肯相尋。", "圖書跌宕悲年老，燈火青熒語夜深。", "早歲便懷齊物志，微官敢有濟時心。", "南行千里成何事，一聽秋濤萬鼓音。"]'),
('9338746b-bf76-4e53-b30d-fe5933ca4a60','陪歐陽公燕西湖','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','謂公方壯鬚似雪，謂公已老光浮頰。',128,'全唐诗/poet.song.44000.json','["謂公方壯鬚似雪，謂公已老光浮頰。", "朅來湖上飲美酒，醉後劇談猶激烈。", "湖邊草木新著霜，芙蓉晚菊爭煌煌。", "插花起舞爲公壽，公言百歲如風狂。", "赤松共遊也不惡，誰能忍饑啖仙藥。", "已將壽夭付天公，彼徒辛苦吾差樂。", "城上烏棲暮靄生，銀缸畫燭照湖明。", "不辭歌詩勸公飲，坐無桓伊能撫箏。"]'),
('4c1ff821-6cde-48d7-ad37-0516c8276cf7','歐陽少師令賦所蓄石屏','蘇軾','宋','宋诗','song-poetry','','["\u5ce8\u7709\u5c71"]','何人遺公石屏風，上有水墨希微蹤。',147,'全唐诗/poet.song.44000.json','["何人遺公石屏風，上有水墨希微蹤。", "不畫長林與巨植，獨畫峨嵋山西雪嶺上萬歲不老之孤松。", "崖崩澗絕可望不可到，孤烟落日相溟濛。", "含風偃蹇得真態，刻畫始信天有工。", "我恐畢宏韋偃死葬虢山下，骨可朽爛心難窮。", "神機巧思無所發，化爲烟霏淪石中。", "古來畫師非俗士，摹寫物像略與詩人同。", "願公作詩慰不遇，無使二子含憤泣幽宮。"]'),
('7f8dc2b8-8249-46c8-9ad3-4c8583755ef0','潁州初別子由二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','征帆掛西風，別淚滴清潁。',120,'全唐诗/poet.song.44000.json','["征帆掛西風，別淚滴清潁。", "留連知無益，惜此須臾景。", "我生三度別，此別尤酸冷。", "念子似先君，木訥剛且靜。", "寡辭真吉人，介石乃機警。", "至今天下士，去莫如子猛。", "嗟我久病狂，意行無坎井。", "有如醉且墜，幸未傷輒醒。", "從今得閑暇，默坐消日永。", "作詩解子憂，持用日三省。"]'),
('a30187cb-7744-47db-bd5d-cb07ff7a0465','潁州初別子由二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','近別不改容，遠別涕霑胸。',120,'全唐诗/poet.song.44000.json','["近別不改容，遠別涕霑胸。", "咫尺不相見，實與千里同。", "人生無離別，誰知恩愛重。", "始我來宛丘，牽衣舞兒童。", "便知有此恨，留我過秋風。", "秋風亦已過，別恨終無窮。", "問我何年歸，我言歲在東。", "離合既循環，憂喜迭相攻。", "語此長太息，我生如飛蓬。", "多憂髮早白，不見六一翁。"]'),
('22cfb929-5bf1-4639-9949-ff847415e95b','十月二日將至渦口五里所遇風留宿','蘇軾','宋','宋诗','song-poetry','','[]','長淮久無風，放意弄清快。',96,'全唐诗/poet.song.44000.json','["長淮久無風，放意弄清快。", "今朝雪浪滿，始覺平野隘。", "兩山控吾前，吞吐久不嘬。", "孤舟繫桑本，終夜舞澎湃。", "舟人更傳呼，弱纜恃菅蒯。", "平生傲憂患，久矣恬百怪。", "鬼神欺吾窮，戲我聊一噫。", "瓶中尚有酒，信命誰能戒。"]'),
('1bd05b5f-fdea-4deb-8feb-e674c96a1c37','出潁口初見淮山是日至壽州','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u60c6\u6005", "\u5199\u666f", "\u611f\u6168"]','我行日夜向江海，楓葉蘆花秋興長。',64,'全唐诗/poet.song.44000.json','["我行日夜向江海，楓葉蘆花秋興長。", "長淮忽迷天遠近，青山久與船低昂。", "壽州已見白石塔，短棹未轉黄茅岡。", "波平風軟望不到，故人久立烟蒼茫。"]'),
('2c7ff7c5-dad4-41c7-83a6-470a08e900b9','壽州李定少卿出餞城東龍潭上','蘇軾','宋','宋诗','song-poetry','','[]','山鴉噪處古靈湫，亂沫浮涎繞客舟。',64,'全唐诗/poet.song.44000.json','["山鴉噪處古靈湫，亂沫浮涎繞客舟。", "未暇燃犀照奇鬼，欲將燒燕出潛虬。", "使君惜別催歌管，村巷驚呼聚玃猴。", "此地他年頌遺愛，觀魚并記老莊周。"]'),
('093ea919-f598-4785-962d-5f29e4d99413','濠州七絕 塗山','蘇軾','宋','宋诗','song-poetry','','[]','川鎖支祁水尚渾，地理汪罔骨應存。',32,'全唐诗/poet.song.44000.json','["川鎖支祁水尚渾，地理汪罔骨應存。", "樵蘇已入黄能廟，烏鵲猶朝禹會村。"]'),
('52a5fef5-017d-47d3-b503-c74a84fe9756','濠州七絕 彭祖廟','蘇軾','宋','宋诗','song-poetry','','[]','跨歷商周看盛衰，欲將齒髮鬬蛇龜。',32,'全唐诗/poet.song.44000.json','["跨歷商周看盛衰，欲將齒髮鬬蛇龜。", "空餐雲母連山盡，不見蟠桃著子時。"]'),
('48a7920f-5d07-4e2d-b742-30f6bd4a9ad7','濠州七絕 逍遥臺','蘇軾','宋','宋诗','song-poetry','','[]','常怪劉伶死便埋，豈伊忘死未忘骸。',32,'全唐诗/poet.song.44000.json','["常怪劉伶死便埋，豈伊忘死未忘骸。", "烏鳶奪得與螻蟻，誰信先生無此懷。"]'),
('e40ffdb7-e09d-4ee5-b872-86227cfa14a0','濠州七絕 觀魚臺','蘇軾','宋','宋诗','song-poetry','','[]','欲將同異較錙銖，肝膽猶能楚越如。',32,'全唐诗/poet.song.44000.json','["欲將同異較錙銖，肝膽猶能楚越如。", "若信萬殊歸一理，子今知我我知魚。"]'),
('05018148-5f6f-4802-bd5f-e59e0beb809a','濠州七絕 虞姬墓','蘇軾','宋','宋诗','song-poetry','','[]','帳下佳人拭淚痕，門前壯士氣如雲。',32,'全唐诗/poet.song.44000.json','["帳下佳人拭淚痕，門前壯士氣如雲。", "倉黄不負君王意，只有虞姬與鄭君。"]'),
('859577d9-faa4-4fc1-9e40-72576ca97506','濠州七絕 四望亭','蘇軾','宋','宋诗','song-poetry','','[]','頹垣破礎沒柴荆，故老猶言短李亭。',32,'全唐诗/poet.song.44000.json','["頹垣破礎沒柴荆，故老猶言短李亭。", "敢請使君重起廢，落霞孤鶩換新銘。"]'),
('6241da93-59c2-45bc-8705-5fe2b3527345','濠州七絕 浮山洞','蘇軾','宋','宋诗','song-poetry','','[]','人言洞府是鰲宮，升降隨波與海通。',32,'全唐诗/poet.song.44000.json','["人言洞府是鰲宮，升降隨波與海通。", "共坐船中那得見，乾坤浮水水浮空。"]'),
('5180098f-ee51-4026-a534-b9519430e97c','泗州僧伽塔','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5199\u666f"]','我昔南行舟繫汴，逆風三日沙吹面。',160,'全唐诗/poet.song.44000.json','["我昔南行舟繫汴，逆風三日沙吹面。", "舟人共勸禱靈塔，香火未收旂脚轉。", "回頭頃刻失長橋，却到龜山未朝飯。", "至人無心何厚薄，我自懷私欣所便。", "耕田欲雨刈欲晴，去得順風來者怨。", "若使人人禱輒遂，造物應須日千變。", "今我身世兩悠悠，去無所逐來無戀。", "得行固願留不惡，每到有求神亦倦。", "退之舊云三百尺，澄觀所營今已換。", "不嫌俗士污丹梯，一看雲山繞淮甸。"]'),
('2e762f54-085e-4adb-8bdb-2aa7ef4706e6','龜山','蘇軾','宋','宋诗','song-poetry','','[]','我生飄蕩去何求，再過龜山歲五周。',64,'全唐诗/poet.song.44000.json','["我生飄蕩去何求，再過龜山歲五周。", "身行萬里半天下，僧卧一庵初白頭。", "地隔中原勞北望，潮連滄海欲東游。", "元嘉舊事無人記，故壘摧頹今在不。"]'),
('786249b6-151d-4692-9f43-d17ddb60898b','發洪澤中途遇大風復還','蘇軾','宋','宋诗','song-poetry','','[]','風浪忽如此，吾行欲安歸。',120,'全唐诗/poet.song.44000.json','["風浪忽如此，吾行欲安歸。", "掛帆却西邁，此計未爲非。", "洪澤三十里，安流去如飛。", "居民見我還，勞問亦依依。", "携酒就船賣，此意厚莫違。", "醒來夜已半，岸木聲向微。", "明日淮陰市，白魚能許肥。", "我行無南北，適意乃所祈。", "何勞舞澎湃，終夜摇窗扉。", "妻孥莫憂色，更典篋中衣。"]'),
('c1e95022-7dd3-475e-958d-46b9d3602da9','十月十六日記所見','蘇軾','宋','宋诗','song-poetry','','[]','風高月暗雲水黄，淮陰夜發朝山陽。',160,'全唐诗/poet.song.44000.json','["風高月暗雲水黄，淮陰夜發朝山陽。", "山陽曉霧如細雨，炯炯初日寒無光。", "雲收霧卷已亭午，有風北來寒欲僵。", "忽驚飛雹穿戶牖，迅駛不復容遮防。", "市人顛沛百賈亂，疾雷一聲如頹牆。", "使君來呼晚置酒，坐定已復日照廊。", "怳疑所見皆夢寐，百種變怪旋消亡。", "共言蛟龍厭舊穴，魚鱉隨徙空陂塘。", "愚儒無知守章句，論說黑白推何祥。", "惟有主人言可用，天寒欲雪飲此觴。"]'),
('d9e838af-628d-43ab-bf58-f1069c150f6a','廣陵會三同舍各以其字爲韵仍邀同賦 劉貢父','蘇軾','宋','宋诗','song-poetry','','[]','去年送劉郎，醉語已驚衆。',120,'全唐诗/poet.song.44000.json','["去年送劉郎，醉語已驚衆。", "如今各飄泊，筆硯誰能弄。", "我命不在天，羿彀未必中。", "作詩聊遣意，老大慵譏諷。", "夫子少年時，雄辯輕子貢。", "爾來再傷弓，戢翼念前痛。", "廣陵三日飲，相對怳如夢。", "況逢賢主人，白酒潑春甕。", "竹西已揮手，灣口猶屢送。", "羨子去安閑，吾邦正喧鬨。"]'),
('61684d92-24cb-4403-b809-3cfb3c853dff','廣陵會三同舍各以其字爲韵仍邀同賦 孫巨源','蘇軾','宋','宋诗','song-poetry','','[]','三年客京輦，憔悴難具論。',120,'全唐诗/poet.song.44000.json','["三年客京輦，憔悴難具論。", "揮汗紅塵中，但隨馬蹄翻。", "人情貴往返，不報生禍根。", "坐令平生友，終歲不及門。", "南來實清曠，但恨無與言。", "不謂廣陵城，得逢劉與孫。", "異趣不兩立，譬如王孫猿。", "吾儕久相聚，恐見疑排拫。", "我褊類中散，子通真巨源。", "絕交固未敢，且復東南奔。"]'),
('2b7f45d4-cf89-4dc3-97a3-d7fd2ff46024','廣陵會三同舍各以其字爲韵仍邀同賦 劉莘老','蘇軾','宋','宋诗','song-poetry','','[]','江陵昔相遇，幕府稱上賓。',120,'全唐诗/poet.song.44000.json','["江陵昔相遇，幕府稱上賓。", "再見明光宮，峨冠挹搢紳。", "如今三見子，坎坷爲逐臣。", "朝遊雲霄間，欲分丞相茵。", "暮落江湖上，遂與屈子鄰。", "了不見慍喜，子豈真可人。", "邂逅成一歡，醉語出天真。", "士方在田里，自比渭與莘。", "出試乃大謬，芻狗難重陳。", "歲晚多霜露，歸耕當及辰。"]'),
('4830026b-31cf-4069-ac04-1a9b1b671202','遊金山寺','蘇軾','宋','宋诗','song-poetry','','[]','我家江水初發源，宦游直送江入海。',176,'全唐诗/poet.song.44000.json','["我家江水初發源，宦游直送江入海。", "聞道潮頭一丈高，天寒尚有沙痕在。", "中泠南畔石盤陀，古來出沒隨濤波。", "試登絕頂望鄉國，江南江北青山多。", "羈愁畏晚尋歸楫，山僧苦留看落日。", "微風萬頃靴文細，斷霞半空魚尾赤。", "是時江月初生魄，二更月落天深黑。", "江心似有炬火明，飛焰照山棲烏驚。", "悵然歸卧心莫識，非鬼非人竟何物。", "江山如此不歸山，江神見怪驚我頑。", "我謝江神豈得已，有田不歸如江水。"]'),
('ab221879-051f-4890-bc1e-44a965c73ba7','自金山放船至焦山','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u5c71\u6c34", "\u611f\u6168"]','金山樓觀何耽耽，撞鐘擊鼓聞淮南。',192,'全唐诗/poet.song.44000.json','["金山樓觀何耽耽，撞鐘擊鼓聞淮南。", "焦山何有有修竹，采薪汲水僧兩三。", "雲霾浪打人跡絕，時有沙戶祈春蠶。", "我來金山更留宿，而此不到心懷慚。", "同遊興盡决獨往，賦命窮薄輕江潭。", "清晨無風浪自湧，中流歌嘯倚半酣。", "老僧下山驚客至，迎笑喜作巴人談。", "自言久客忘鄉井，只有彌勒爲同龕。", "困眠得就紙帳暖，飽食未厭山蔬甘。", "山林饑餓古亦有，無田不退寧非貪。", "展禽雖未三見黜，叔夜自知七不堪。", "行當投劾謝簪組，爲我佳處留茅庵。"]'),
('0a4a7670-6e02-4d17-a132-807373d7a86c','甘露寺','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','江山豈不好，獨遊情易闌。',288,'全唐诗/poet.song.44000.json','["江山豈不好，獨遊情易闌。", "但有相携人，何必素所歡。", "我欲訪甘露，當途無閑官。", "二子舊不識，欣然肯聯鞍。", "古郡山爲城，層梯轉朱欄。", "樓臺斷崖上，地窄天水寬。", "一覽吞數州，山長江漫漫。", "却望大明寺，惟見煙中竿。", "狠石卧庭下，穹窿如伏羱。", "緬懷卧龍公，挾策事琱鑽。", "一談收猘子，再說走老瞞。", "名高有餘想，事往無留觀。", "蕭公古鐵鑊，相對空團團。", "陂陀受百斛，積雨生微瀾。", "泗水逸周鼎，渭城辭漢盤。", "山川失故態，怪此能獨完。", "僧繇六化人，霓衣掛冰紈。", "隠見十二疊，觀者疑夸謾。", "破板陸生畫，青猊戲盤跚。", "上有二天人，揮手如翔鸞。", "筆墨雖欲盡，典型垂不刊。", "赫赫贊皇公，英姿凜以寒。", "古柏手親種，挺然誰敢干。", "枝撐雲峰裂，根入石窟蟠。"]'),
('9f7ffeaf-66a1-49f3-b730-9d5cfed5ad89','初到杭州寄子由二絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','眼看時事力難勝，貪戀君恩退未能。',32,'全唐诗/poet.song.44000.json','["眼看時事力難勝，貪戀君恩退未能。", "遲鈍終須投劾去，使君何日換聾丞。"]'),
('62374e37-3c97-4c39-bad6-3d5fe4ac4733','初到杭州寄子由二絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','聖明寬大許全身，衰病摧頹自畏人。',32,'全唐诗/poet.song.44000.json','["聖明寬大許全身，衰病摧頹自畏人。", "莫上岡頭苦相望，吾方祭竈請比鄰。"]'),
('7ce51a8c-1560-4745-90c9-f14efdc7a4a1','次韵柳子玉二首 地爐','蘇軾','宋','宋诗','song-poetry','','[]','細聲蚯蚓發銀瓶，擁褐橫眠天未明。',64,'全唐诗/poet.song.44000.json','["細聲蚯蚓發銀瓶，擁褐橫眠天未明。", "衰鬢鑷殘敧雪領，壯心降盡倒風旌。", "自稱丹竈錙銖火，倦聽山城長短更。", "聞道床頭惟竹几，夫人應不解卿卿。"]'),
('2b4f4be7-a401-4edd-b329-12d5dd2d8664','次韵柳子玉二首 紙帳','蘇軾','宋','宋诗','song-poetry','','[]','亂文龜殻細相連，慣卧青綾恐未便。',64,'全唐诗/poet.song.44000.json','["亂文龜殻細相連，慣卧青綾恐未便。", "潔似僧巾白㲲布，暖於蠻帳紫茸氈。", "錦衾速卷持還客，破屋那愁仰見天。", "但恐嬌兒還惡睡，夜深踏裂不成眠。"]'),
('b54d9c6f-83ac-4538-bd1a-df6842b686fb','臘日遊孤山訪惠勤惠思二僧','蘇軾','宋','宋诗','song-poetry','','[]','天欲雪，雲滿湖，樓臺明滅山有無。',160,'全唐诗/poet.song.44000.json','["天欲雪，雲滿湖，樓臺明滅山有無。", "水清石出魚可數，林深無人鳥相呼。", "臘日不歸對妻孥，名尋道人實自娛。", "道人之居在何許，寶雲山前路盤紆。", "孤山孤絕誰肯廬，道人有道山不孤。", "紙窗竹屋深自暖，擁褐坐睡依團蒲。", "天寒路遠愁僕夫，整駕催歸及未晡。", "出山迴望雲木合，但見野鶻盤浮圖。", "茲遊淡薄歡有餘，到家恍如夢蘧蘧。", "作詩火急追亡逋，清景一失後難摹。"]'),
('1f63f196-a80e-4321-8160-50fd827dfd19','李杞寺丞見和前篇復用元韵答之','蘇軾','宋','宋诗','song-poetry','','[]','獸在藪，魚在湖，一入池檻歸期無。',160,'全唐诗/poet.song.44000.json','["獸在藪，魚在湖，一入池檻歸期無。", "誤隨弓旌落塵土，坐使鞭箠環呻呼。", "追胥連保罪及孥，百日愁歎一日娛。", "白雲舊有終老約，朱綬豈合山人紆。", "人生何者非蘧廬，故山鶴怨秋猿孤。", "何時自駕鹿車去，掃除白髮煩菖蒲。", "麻鞋短後隨獵夫，射弋狐兔供朝晡。", "陶潛自作五柳傳，潘閬畫入三峰圖。", "吾年凜凜今幾餘，知非不去慚衛蘧。", "歲荒無術歸亡逋，鵠則易畫虎難摹。"]'),
('adb8650a-63b6-475b-92b5-631f96b400aa','再和','蘇軾','宋','宋诗','song-poetry','','[]','東望海，西望湖，山平水遠細欲無。',160,'全唐诗/poet.song.44000.json','["東望海，西望湖，山平水遠細欲無。", "野人疏狂逐漁釣，刺史寬大容歌呼。", "君恩飽暖及爾孥，才者不閑拙者娛。", "穿巌度嶺脚力健，未厭山水相縈紆。", "三百六十古精廬，出遊無伴籃輿孤。", "作詩雖未造藩閾，破悶豈不賢摴蒱。", "君才敏贍兼百夫，朝作千篇日未晡。", "朅來湖上得佳句，從此不看營丘圖。", "知君篋櫝富有餘，莫惜錦繡償菅蘧。", "窮多鬬險誰先逋，賭取名畫不用摹。"]'),
('2599abb3-6bc3-4d75-9392-ea8ff7239a79','游靈隠寺得來詩復用前韵','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','君不見，錢塘湖，錢王壯觀今已無。',160,'全唐诗/poet.song.44000.json','["君不見，錢塘湖，錢王壯觀今已無。", "屋堆黄金斗量珠，運盡不勞折簡呼。", "四方宦游散其孥，宮闕留與閑人娛。", "盛衰哀樂兩須臾，何用多憂心鬰紆。", "溪山處處皆可廬，最愛靈隠飛來孤。", "喬松百尺蒼髯鬚，擾擾下笑柳與蒲。", "高堂會食羅千夫，撞鐘擊鼓喧朝晡。", "凝香方丈眠氍毹，絕勝絮被縫海圖。", "清風徐來驚睡餘，遂超羲皇傲几蘧。", "歸時棲鴉正畢逋，孤煙落日不可摹。"]'),
('7942d91b-496b-4af9-8b52-6e4162fb6bef','戲子由','蘇軾','宋','宋诗','song-poetry','','[]','宛丘先生長如丘，宛丘學舍小如舟。',240,'全唐诗/poet.song.44000.json','["宛丘先生長如丘，宛丘學舍小如舟。", "常時低頭誦經史，忽然欠伸屋打頭。", "斜風吹帷雨注面，先生不愧旁人羞。", "任從飽死笑方朔，肯爲雨立求秦優。", "眼前勃蹊何足道，處置六鑿須天游。", "讀書萬卷不讀律，致君堯舜知無術。", "勸農冠蓋鬧如雲，送老虀鹽甘似蜜。", "門前萬事不挂眼，頭雖長低氣不屈。", "餘杭別駕無功勞，畫堂五丈容旂旄。", "重樓跨空雨聲遠，屋多人少風騷騷。", "平生所慚今不恥，坐對疲氓更鞭箠。", "道逢陽虎呼與言，心知其非口諾唯。", "居高志下真何益，氣節消縮今無幾。", "文章小技安足程，先生別駕舊齊名。", "如今衰老俱無用，付與時人分重輕。"]'),
('ccfb1b96-ec12-4728-9889-63cadcd9b2c1','越州張中舍壽樂堂','蘇軾','宋','宋诗','song-poetry','','[]','青山偃蹇如高人，常時不肯入官府。',160,'全唐诗/poet.song.44000.json','["青山偃蹇如高人，常時不肯入官府。", "高人自與山有素，不待招邀滿庭戶。", "卧龍蟠屈半東州，萬室鱗鱗枕其股。", "背之不見與無同，狐裘反衣無乃魯。", "張君眼力覷天奧，能遣荆棘化堂宇。", "持頤宴坐不出門，收攬奇秀得十五。", "才多事少厭閑寂，卧看雲煙變風雨。", "筍如玉筯椹如簪，强飲且爲山作主。", "不憂兒輩知此樂，但恐造物怪多取。", "春濃睡足午窗明，想見新茶如潑乳。"]'),
('57d575fe-3223-4a37-bf70-3861e5fcb393','姚屯田挽詞','蘇軾','宋','宋诗','song-poetry','','[]','京口年來耆舊衰，高人淪喪路人悲。',64,'全唐诗/poet.song.44000.json','["京口年來耆舊衰，高人淪喪路人悲。", "空聞韋叟一經在，不見恬侯萬石時。", "貧病只知爲善樂，逍遥却恨棄官遲。", "七年一別真如夢，猶記蕭然瘦鶴姿。"]'),
('93ba3e87-9233-4b70-abb3-6fdab20bd085','送岑著作','蘇軾','宋','宋诗','song-poetry','','[]','懶者常似靜，靜豈懶者徒。',144,'全唐诗/poet.song.44000.json','["懶者常似靜，靜豈懶者徒。", "拙則近於直，而直豈拙歟。", "夫子靜且直，雍容時卷舒。", "嗟我復何爲，相得歡有餘。", "我本不違世，而世與我殊。", "拙於林間鳩，懶於冰底魚。", "人皆笑其狂，子獨憐其愚。", "直者有時信，靜者不終居。", "而我懶拙病，不受砭藥除。", "臨行怪酒薄，已與別淚俱。", "後會豈無時，遂恐出處疏。", "惟應故山夢，隨子到吾廬。"]'),
('4aed0f3c-2b97-4fbb-b085-57d4f7905eb3','雨中明慶賞牡丹','蘇軾','宋','宋诗','song-poetry','','[]','霏霏雨露作清妍，爍爍明燈照欲然。',32,'全唐诗/poet.song.44000.json','["霏霏雨露作清妍，爍爍明燈照欲然。", "明日春陰花未老，故應未忍著酥煎。"]'),
('c137f485-1331-458d-aad4-2efbd8dc3251','吉祥寺賞牡丹','蘇軾','宋','宋诗','song-poetry','','["\u4e50\u89c2", "\u6292\u60c5", "\u53d9\u4e8b", "\u8d4f\u82b1"]','人老簪花不自羞，花應羞上老人頭。',32,'全唐诗/poet.song.44000.json','["人老簪花不自羞，花應羞上老人頭。", "醉歸扶路人應笑，十里珠簾半上鉤。"]'),
('480e4335-8197-4cf2-b320-b235ec36f38b','吉祥寺僧求閣名','蘇軾','宋','宋诗','song-poetry','','[]','過眼榮枯電與風，久長那得似花紅。',32,'全唐诗/poet.song.44000.json','["過眼榮枯電與風，久長那得似花紅。", "上人宴坐觀空閣，觀色觀空色即空。"]'),
('76960472-5e10-469b-92e3-630ad6d46f9e','和劉道原見寄','蘇軾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','敢向清時怨不容，直嗟吾道與君東。',64,'全唐诗/poet.song.44000.json','["敢向清時怨不容，直嗟吾道與君東。", "坐談足使淮南懼，歸去方知冀北空。", "獨鶴不須驚夜旦，羣烏未可辨雌雄。", "廬山自古不到處，得與幽人子細窮。"]'),
('d9170480-db30-4f68-9d76-9e8aae964488','和劉道原詠史','蘇軾','宋','宋诗','song-poetry','','[]','仲尼憂世接輿狂，臧穀雖殊竟兩亡。',64,'全唐诗/poet.song.44000.json','["仲尼憂世接輿狂，臧穀雖殊竟兩亡。", "吳客漫陳豪士賦，桓侯初笑越人方。", "名高不朽終安用，日飲無何計亦良。", "獨掩陳編弔興廢，窗前山雨夜浪浪。"]'),
('f584aec9-fe4d-4c59-abe1-e888e88d4ed9','和劉道原寄張師民','蘇軾','宋','宋诗','song-poetry','','[]','仁義大捷徑，詩書一旅亭。',48,'全唐诗/poet.song.44000.json','["仁義大捷徑，詩書一旅亭。", "相夸綬若若，猶誦麥青青。", "腐鼠何勞嚇，高鴻本自冥。", "顛狂不用喚，酒盡漸須醒。"]'),
('cc43b330-6fcc-4484-a465-03f9d2f22a24','送張職方吉甫赴閩漕六和寺中作','蘇軾','宋','宋诗','song-poetry','','[]','羨君超然鸞鶴姿，江湖欲下還飛去。',64,'全唐诗/poet.song.44000.json','["羨君超然鸞鶴姿，江湖欲下還飛去。", "空使吳兒怨不留，青山漫漫七閩路。", "門前江水去掀天，寺後清池碧玉環。", "君如大江日千里，我如此水千山底。"]'),
('3a796ad1-8c78-44e1-b6f3-29548c06bd8d','和子由柳湖久涸忽有水開元寺山茶舊無花今歲盛開二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','太昊祠東鐵墓西，一樽曾與子同携。',64,'全唐诗/poet.song.44000.json','["太昊祠東鐵墓西，一樽曾與子同携。", "回瞻郡閣遥飛檻，北望檣竿半隠堤。", "飯豆羹藜思兩鵠，飲河噀水頼長霓。", "如今勝事無人共，花下壺盧鳥勸提。"]'),
('58ccfcda-486d-4b78-a8d3-d38cea676dea','和子由柳湖久涸忽有水開元寺山茶舊無花今歲盛開二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','長明燈下石欄干，長共松杉守歲寒。',64,'全唐诗/poet.song.44000.json','["長明燈下石欄干，長共松杉守歲寒。", "葉厚有稜犀甲健，花深少態鶴頭丹。", "久陪方丈曼陀雨，羞對先生苜蓿盤。", "雪裏盛開知有意，明年開後更誰看。"]'),
('ef209f13-c2f7-4c55-a496-57b273e0af7f','雨中遊天竺靈感觀音院','蘇軾','宋','宋诗','song-poetry','','[]','蠶欲老，麥半黄，前山後山雨浪浪。',32,'全唐诗/poet.song.44000.json','["蠶欲老，麥半黄，前山後山雨浪浪。", "農夫輟耒女廢筐，白衣仙人在高堂。"]'),
('cd743a22-1674-4698-a9ec-4a77222ff734','和蔡準郎中見邀遊西湖三首  其一','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','夏潦漲湖深更幽，西風落木芙蓉秋。',89,'全唐诗/poet.song.44000.json','["夏潦漲湖深更幽，西風落木芙蓉秋。", "飛雪闇天雲拂地，新蒲出水柳映洲。", "湖上四時看不足，惟有人生飄若浮。", "解顔一笑豈易得，主人有酒君應留。", "君不見錢塘游宦客，朝推囚，暮决獄，不因人喚何時休。"]'),
('cf6321d6-3f41-4351-8eee-5e863de5b5bb','和蔡準郎中見邀遊西湖三首  其二','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','城市不識江湖幽，如與蟪蛄語春秋。',89,'全唐诗/poet.song.44000.json','["城市不識江湖幽，如與蟪蛄語春秋。", "試令江湖處城市，却似麋鹿游汀洲。", "高人無心無不可，得坎且止乘流浮。", "公卿故舊留不得，遇所得意終年留。", "君不見拋官彭澤令，琴無絃，巾有酒，醉欲眠時遣客休。"]'),
('476f2dff-270a-4941-83c7-8b1e21362ae6','和蔡準郎中見邀遊西湖三首  其三','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','田間决水鳴幽幽，插秧未遍麥已秋。',89,'全唐诗/poet.song.44000.json','["田間决水鳴幽幽，插秧未遍麥已秋。", "相携燒筍苦竹寺，却下踏藕荷花洲。", "船頭斫鮮細縷縷，船尾炊玉香浮浮。", "臨風飽食得甘寢，肯使細故胸中留。", "君不見壯士憔悴時，饑謀食，渴謀飲，功名有時無罷休。"]'),
('9c905415-55a1-4f72-b9e4-20e76351de4b','六月二十七日望湖樓醉書五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','黑雲翻墨未遮山，白雨跳珠亂入船。',32,'全唐诗/poet.song.44000.json','["黑雲翻墨未遮山，白雨跳珠亂入船。", "卷地風來忽吹散，望湖樓下水如天。"]'),
('062adf8f-7dc0-438a-aa48-65f42ac9fdc8','六月二十七日望湖樓醉書五絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','放生魚鱉逐人來，無主荷花到處開。',32,'全唐诗/poet.song.44000.json','["放生魚鱉逐人來，無主荷花到處開。", "水枕能令山俯仰，風船解與月徘徊。"]'),
('f3e66d21-ae00-4423-be0d-3d3751268f05','六月二十七日望湖樓醉書五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','烏菱白芡不論錢，亂繫青菰裹綠盤。',32,'全唐诗/poet.song.44000.json','["烏菱白芡不論錢，亂繫青菰裹綠盤。", "忽憶嘗新會靈觀，滯留江海得加餐。"]'),
('75a81a42-cdf9-4e16-8783-1b754ca7550c','六月二十七日望湖樓醉書五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','獻花游女木蘭橈，細雨斜風溼翠翹。',32,'全唐诗/poet.song.44000.json','["獻花游女木蘭橈，細雨斜風溼翠翹。", "無限芳洲生杜若，吳兒不識楚辭招。"]'),
('b2dfb178-d5c9-4af7-9c5f-5f0a52eec3f4','六月二十七日望湖樓醉書五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','未成小隠聊中隠，可得長閑勝暫閑。',32,'全唐诗/poet.song.44000.json','["未成小隠聊中隠，可得長閑勝暫閑。", "我本無家更安往，故鄉無此好湖山。"]'),
('4dc4056c-67cb-4acd-bb50-f73f65f94f4a','七月一日出城舟中苦熱','蘇軾','宋','宋诗','song-poetry','','[]','凉飆呼不來，流汗方被體。',72,'全唐诗/poet.song.44000.json','["凉飆呼不來，流汗方被體。", "稀星乍明滅，暗水光瀰瀰。", "香風過蓮芡，驚枕裂魴鯉。", "欠伸宿酒餘，起坐濯清泚。", "火雲勢方壯，未受月露洗。", "身微欲安適，坐待東方啟。"]'),
('e5c32b5b-cba8-4014-8171-450009e1532b','宿餘杭法喜寺後綠野堂望吳興諸山懷孫莘老學士','蘇軾','宋','宋诗','song-poetry','','[]','徙倚秋原上，淒涼晚照中。',96,'全唐诗/poet.song.44000.json','["徙倚秋原上，淒涼晚照中。", "水流天不盡，人遠思何窮。", "問諜知秦過，看山識禹功。", "稻凉初吠蛤，柳老半書蟲。", "荷背風翻白，蓮腮雨退紅。", "追游慰遲暮，覓句效兒童。", "北望苕溪轉，遥憐震澤通。", "烹魚得尺素，好在紫髯翁。"]'),
('2061b808-272a-4d50-8b08-5a3eac0d44f2','宿臨安浄土寺','蘇軾','宋','宋诗','song-poetry','','[]','雞鳴發餘杭，到寺已亭午。',144,'全唐诗/poet.song.44000.json','["雞鳴發餘杭，到寺已亭午。", "參禪固未暇，飽食良先務。", "平生睡不足，急掃清風宇。", "閉門羣動息，香篆起烟縷。", "覺來烹石泉，紫筍發輕乳。", "晚凉沐浴罷，衰髮稀可數。", "浩歌出門去，暮色入村塢。", "微月半隠山，圓荷爭瀉露。", "相携石橋上，夜與故人語。", "明朝入山房，石鏡炯當路。", "昔照熊虎姿，今爲猿鳥顧。", "廢興何足弔，萬古一仰俯。"]'),
('cbaaf4b7-4c9f-4328-9974-073d7b226e56','自浄土寺步至功臣寺','蘇軾','宋','宋诗','song-poetry','','[]','落日岸葛巾，晚風吹羽扇。',168,'全唐诗/poet.song.44000.json','["落日岸葛巾，晚風吹羽扇。", "松間野步穩，竹外飛橋轉。", "神功鑿橫嶺，巌石得巨片。", "直渡千人溝，下有微流泫。", "岡巒蔚回合，金碧爛明絢。", "緬懷異姓王，負擔此鄉縣。", "長逢胯下辱，屢乞桑間飯。", "誰謂山石頑，識此希世彥。", "凜然英氣逼，屹起猶聳戰。", "他年萬騎歸，父老恣歡宴。", "錦繡被原野，金珠散貧賤。", "竇融既入朝，吳芮空記面。", "榮華坐銷歇，閱世如郵傳。", "惟有長明燈，依然照深殿。"]'),
('c5e03a17-c13b-48dc-90cb-af36320468fa','遊徑山','蘇軾','宋','宋诗','song-poetry','','[]','衆峰來自天目山，勢若駿馬奔平川。',224,'全唐诗/poet.song.44000.json','["衆峰來自天目山，勢若駿馬奔平川。", "中途勒破千里足，金鞭玉𩍐相迴旋。", "人言山住水亦住，下有萬古蛟龍淵。", "道人天眼識王氣，結茅宴坐荒山巔。", "精誠貫山石爲裂，天女下試顔如蓮。", "寒窗暖足來朴渥，夜鉢呪水降蜿蜒。", "雪眉老人朝叩門，願爲弟子長參禪。", "爾來廢興三百載，奔走吳會輸金錢。", "飛樓湧殿壓山破，朝鐘暮鼓驚龍眠。", "晴空仰見浮海蜃，落日下數投林鳶。", "有生共處覆載內，擾擾膏火同烹煎。", "近來愈覺世路隘，每到寬處差安便。", "嗟余老矣百事廢，却尋舊學心茫然。", "問龍乞水歸洗眼，欲看細字銷殘年。"]'),
('23f011ba-73b8-4f85-a78d-3a26fedffa23','自徑山回得呂察推詩用其韵招之宿湖上','蘇軾','宋','宋诗','song-poetry','','[]','多君貴公子，愛山如愛色。',108,'全唐诗/poet.song.44000.json','["多君貴公子，愛山如愛色。", "心隨葉舟去，夢繞千山碧。", "新詩到中路，令我喜折屐。", "古來軒冕徒，操舍兩悲慄。", "數朝辭簪笏，兩脚得暫赤。", "歸來不入府，却走湖上宅。", "寵辱吾久忘，寧畏官長詰。", "飄然便歸去，誰在子思側。", "君能從我遊，出郭及未黑。"]'),
('ea8fcd2c-27e8-4d6f-a370-cf1b56eb6442','宿望湖樓再和','蘇軾','宋','宋诗','song-poetry','','[]','新月如佳人，出海初弄色。',108,'全唐诗/poet.song.44000.json','["新月如佳人，出海初弄色。", "娟娟到湖上，瀲瀲摇空碧。", "夜凉人未寢，山靜聞響屐。", "騷人故多感，悲秋更憀慄。", "君胡不相就，朱墨紛黝赤。", "我行得所嗜，十日忘家宅。", "但恨無友生，詩病莫訶詰。", "君來試吟詠，定作鶴頭側。", "改罷心愈疑，滿紙蛟蛇黑。"]'),
('b7daee12-8427-4003-8e61-0eca739a141e','夜泛西湖五絕  其一','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','新月生魄迹未安，纔破五六漸盤桓。',32,'全唐诗/poet.song.44000.json','["新月生魄迹未安，纔破五六漸盤桓。", "今夜吐艷如半璧，游人得向三更看。"]'),
('7c3967f3-b5d4-4bcc-802b-868469f62d93','夜泛西湖五絕  其二','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','三更向闌月漸垂，欲落未落景特奇。',32,'全唐诗/poet.song.44000.json','["三更向闌月漸垂，欲落未落景特奇。", "明朝人事誰料得，看到蒼龍西沒時。"]'),
('990d7527-fa68-4baa-b093-cb086ecd3c90','夜泛西湖五絕  其三','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','蒼龍已沒牛斗橫，東方芒角昇長庚。',32,'全唐诗/poet.song.44000.json','["蒼龍已沒牛斗橫，東方芒角昇長庚。", "漁人收筒及未曉，船過惟有菰蒲聲。"]'),
('4059804f-1e11-44bb-918d-c843fc7683d9','夜泛西湖五絕  其四','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','菰蒲無邊水茫茫，荷花夜開風露香。',32,'全唐诗/poet.song.44000.json','["菰蒲無邊水茫茫，荷花夜開風露香。", "漸見燈明出遠寺，更待月黑看湖光。"]'),
('c3abcc87-3195-4ef6-a8a6-32a6ef0da191','夜泛西湖五絕  其五','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','湖光非鬼亦非仙，風恬浪靜光滿川。',32,'全唐诗/poet.song.44000.json','["湖光非鬼亦非仙，風恬浪靜光滿川。", "須臾兩兩入寺去，就視不見空茫然。"]'),
('b85f0417-792b-4012-b880-5e6772e4fd87','求焦千之惠山泉詩','蘇軾','宋','宋诗','song-poetry','','[]','茲山定空中，乳水滿其腹。',168,'全唐诗/poet.song.44000.json','["茲山定空中，乳水滿其腹。", "遇隙則發見，臭味實一族。", "淺深各有值，方圓隨所蓄。", "或爲雲洶湧，或作線斷續。", "或鳴空洞中，雜佩間琴筑。", "或流蒼石縫，宛轉龍鸞蹙。", "瓶罌走千里，真僞半相瀆。", "貴人高宴罷，醉眼亂紅綠。", "赤泥開方印，紫餠截圓玉。", "傾甌共歎賞，竊語笑僮僕。", "豈如泉上僧，盥灑自挹掬。", "故人憐我病，蒻籠寄新馥。", "欠伸北窗下，晝睡美方熟。", "精品厭凡泉，願子致一斛。"]'),
('3c0427e2-7b36-4b73-a848-0e5b7c310c4c','答任師中次韵','蘇軾','宋','宋诗','song-poetry','','[]','閑裏有深趣，常憂兒輩知。',48,'全唐诗/poet.song.44000.json','["閑裏有深趣，常憂兒輩知。", "已成歸蜀計，誰借買山貲。", "世事久已謝，故人猶見思。", "平生不飲酒，對子敢論詩。"]'),
('19cdefee-fbea-486b-9ea9-c4a572d766af','沈諫議召游湖不赴明日得雙蓮於北山下作一絕持獻沈既見和又別作一首因用其韵  其一','蘇軾','宋','宋诗','song-poetry','','[]','湖上棠陰手自栽，問公更得幾回來。',32,'全唐诗/poet.song.44000.json','["湖上棠陰手自栽，問公更得幾回來。", "水仙亦恐公歸去，故遣雙蓮一夜開。"]'),
('1e30e803-daf6-48fb-b278-4d82ab7dadd8','沈諫議召游湖不赴明日得雙蓮於北山下作一絕持獻沈既見和又別作一首因用其韵  其二','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','詔書行捧縷金箋，樂府應歌相府蓮。',32,'全唐诗/poet.song.44000.json','["詔書行捧縷金箋，樂府應歌相府蓮。", "莫忘今年花發處，西湖西畔北山前。"]'),
('7ef5f14a-3dba-4f01-bc7f-3fe0bb59fc46','和歐陽少師會老堂次韵','蘇軾','宋','宋诗','song-poetry','','[]','一時冠蓋盡嚴終，舊德年來豈易逢。',64,'全唐诗/poet.song.44000.json','["一時冠蓋盡嚴終，舊德年來豈易逢。", "聞道堂中延蓋叟，定應床下拜梁松。", "蠹魚自曬閑箱篋，科斗長收古鼎鐘。", "我欲棄官重問道，寸筳何以得舂容。"]'),
('e28b389a-c293-420a-9c11-4593a796883a','和歐陽少師寄趙少師次韵','蘇軾','宋','宋诗','song-poetry','','[]','朱門有遺啄，千里來燕雀。',104,'全唐诗/poet.song.44000.json','["朱門有遺啄，千里來燕雀。", "公家冷如冰，百呼無一諾。", "平生親友半遷逝，公雖不怪旁人愕。", "世事如今臘酒醲，交情自古春雲薄。", "二公凜凜和非同，疇昔心親豈貌從。", "白鬚相映松間鶴，清句更酬雪裏鴻。", "何日揚雄一廛足，却追范蠡五湖中。"]'),
('0870f639-ed8f-4c91-bfc3-149e743d95dd','監試呈諸試官','蘇軾','宋','宋诗','song-poetry','','[]','我本山中人，寒苦盜寸廩。',288,'全唐诗/poet.song.44000.json','["我本山中人，寒苦盜寸廩。", "文辭雖少作，勉强非天稟。", "既得旋廢忘，懶惰今十稔。", "麻衣如再著，墨水真可飲。", "每聞科詔下，白汗如流瀋。", "此邦東南會，多士敢題品。", "芻蕘盡蘭蓀，香不數葵荏。", "貧家見珠貝，眩晃自難審。", "緬懷嘉祐初，文格變已甚。", "千金碎全璧，百衲收寸錦。", "調和椒桂釅，咀嚼沙礫磣。", "廣眉成半額，學步歸踔踸。", "維時老宗伯，氣壓羣兒凜。", "蛟龍不世出，魚鮪初驚淰。", "至音久乃信，知味猶食椹。", "至今天下士，微管幾左衽。", "謂當千載後，石室祠高眹。", "爾來又一變，此學初誰諗。", "權衡破舊法，芻豢笑凡飪。", "高言追衛樂，篆刻鄙曹沈。", "先生周孔出，弟子淵騫寢。", "却顧老鈍軀，頑樸謝鎸鋟。", "諸君況才傑，容我懶且噤。", "聊欲廢書眠，秋濤舂午枕。"]'),
('cad04f02-0994-4960-9e75-fa0773ccfcf5','望海樓晚景五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','海上濤頭一線來，樓前指顧雪成堆。',32,'全唐诗/poet.song.44000.json','["海上濤頭一線來，樓前指顧雪成堆。", "從今潮上君須上，更看銀山二十回。"]'),
('4ae79906-5de8-487f-9507-97e26dd56df7','望海樓晚景五絕  其二','蘇軾','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u96e8"]','橫風吹雨入樓斜，壯觀應須好句誇。',32,'全唐诗/poet.song.44000.json','["橫風吹雨入樓斜，壯觀應須好句誇。", "雨過潮平江海碧，電光時掣紫金蛇。"]'),
('83961f9a-8001-48e3-aa41-dcd980002bda','望海樓晚景五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','青山斷處塔層層，隔岸人家喚欲譍。',32,'全唐诗/poet.song.44000.json','["青山斷處塔層層，隔岸人家喚欲譍。", "江上秋風晚來急，爲傳鐘鼓到西興。"]'),
('af94c148-f588-4b00-94c8-cd0ae725fdf6','望海樓晚景五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','樓下誰家燒夜香，玉笙哀怨弄初凉。',32,'全唐诗/poet.song.44000.json','["樓下誰家燒夜香，玉笙哀怨弄初凉。", "臨風有客吟秋扇，拜月無人見晚粧。"]'),
('a146aeca-0b77-4a3d-82e3-51f1a5f9e065','望海樓晚景五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','沙河燈火照山紅，歌鼓喧呼笑語中。',32,'全唐诗/poet.song.44000.json','["沙河燈火照山紅，歌鼓喧呼笑語中。", "爲問少年心在否，角巾敧側鬢如蓬。"]'),
('6454272c-6d05-406e-9a4c-163e6d7b35ea','試院煎茶','蘇軾','宋','宋诗','song-poetry','','[]','蟹眼已過魚眼生，颼颼欲作松風鳴。',146,'全唐诗/poet.song.44000.json','["蟹眼已過魚眼生，颼颼欲作松風鳴。", "蒙茸出磨細珠落，眩轉遶甌飛雪輕。", "銀瓶瀉湯誇第二，未識古人煎水意。", "君不見昔時李生好客手自煎，貴從活火發新泉。", "又不見今時潞公煎茶學西蜀，定州花瓷琢紅玉。", "我今貧病常苦饑，分無玉碗捧蛾眉。", "且學公家作茗飲，磚爐石銚行相隨。", "不用撐腸拄腹文字五千卷，但願一甌常及睡足日高時。"]'),
('58f42275-d719-49e6-867f-43556980dbb0','孫莘老求墨妙亭詩','蘇軾','宋','宋诗','song-poetry','','[]','蘭亭繭紙入昭陵，世間遺迹猶龍騰。',192,'全唐诗/poet.song.44000.json','["蘭亭繭紙入昭陵，世間遺迹猶龍騰。", "顔公變法出新意，細筋入骨如秋鷹。", "徐家父子亦秀絕，字外出力中藏稜。", "嶧山傳刻典刑在，千載筆法留陽冰。", "杜陵評書貴瘦硬，此論未公吾不憑。", "短長肥瘦各有態，玉環飛燕誰敢憎。", "吳興太守真好古，購買斷缺揮縑繒。", "龜趺入座螭隠壁，空齋晝靜聞登登。", "奇蹤散出走吳越，勝事傳說誇友朋。", "書來乞詩要自寫，爲把栗尾書溪藤。", "後來視今猶視昔，過眼百世如風燈。", "他年劉郎憶賀監，還道同時須服膺。"]'),
('697efc3a-777b-494b-89ac-9af49645b2eb','李公擇求黄鶴樓詩因記舊所聞於馮當世者','蘇軾','宋','宋诗','song-poetry','','[]','黄鶴樓前月滿川，抱關老卒饑不眠。',176,'全唐诗/poet.song.44000.json','["黄鶴樓前月滿川，抱關老卒饑不眠。", "夜聞三人笑語言，羽衣著屐響空山。", "非鬼非人意其仙，石扉三叩聲清圓。", "洞中鏗鈜落門關，縹緲入石如飛烟。", "鷄鳴月落風馭還，迎拜稽首願執鞭。", "汝非其人骨腥羶，黄金乞得重莫肩。", "持歸包裹敝席氈，夜穿茅屋光射天。", "里閭來觀已變遷，似石非石鉛非鉛。", "或取而有衆憤喧，訟歸有司今幾年。", "無功暴得喜欲顛，神人戲汝真可憐。", "願君爲考然不然，此語可信馮公傳。"]'),
('39105df6-81c3-4d0a-a0a2-e0cb5d1a573d','八月十日夜看月有懷子由并崔度賢良','蘇軾','宋','宋诗','song-poetry','','[]','宛丘先生自不飽，更笑老崔窮百巧。',96,'全唐诗/poet.song.44000.json','["宛丘先生自不飽，更笑老崔窮百巧。", "一更相過三更歸，古柏陰中看參昴。", "去年舉君苜蓿盤，夜傾閩酒赤如丹。", "今年還看去年月，露冷遥知范叔寒。", "典衣自種一頃豆，那知積雨生科斗。", "歸來四壁草蟲鳴，不如王江常飲酒。"]'),
('d24fa038-71b0-4f32-80f6-c4e7349adc98','催試官考較戲作','蘇軾','宋','宋诗','song-poetry','','[]','八月十五夜，月色隨處好。',120,'全唐诗/poet.song.44000.json','["八月十五夜，月色隨處好。", "不擇茅簷與市樓，況我官居似蓬島。", "鳳咮堂前野橘香，劍潭橋畔秋荷老。", "八月十八潮，壯觀天下無。", "鯤鵬水擊三千里，組練長驅十萬夫。", "紅旗青蓋互明滅，黑沙白浪相吞屠。", "人生會合古難必，此景此行那兩得。", "願君聞此添蠟燭，門外白袍如立鵠。"]'),
('4a32f03d-df8e-433a-a43b-32b921a54838','八月十七日復登望海樓自和前篇是日榜出余與試官兩人復留五首  其一','蘇軾','宋','宋诗','song-poetry','','[]','樓上烟雲怪不來，樓前飛紙落成堆。',32,'全唐诗/poet.song.44000.json','["樓上烟雲怪不來，樓前飛紙落成堆。", "非關文字須重看，却被江山未放回。"]'),
('ce8ce6d6-c8b8-45ce-8e6e-b20ba3d3e6f3','八月十七日復登望海樓自和前篇是日榜出余與試官兩人復留五首  其二','蘇軾','宋','宋诗','song-poetry','','[]','眼昏燭暗細行斜，考閱精强外已誇。',32,'全唐诗/poet.song.44000.json','["眼昏燭暗細行斜，考閱精强外已誇。", "明日失杯君莫怪，早知安足不成蛇。"]'),
('406c9161-c219-4a15-9fb0-76d35306626f','八月十七日復登望海樓自和前篇是日榜出余與試官兩人復留五首  其三','蘇軾','宋','宋诗','song-poetry','','[]','亂山遮曉擁千層，睡美初凉撼不譍。',32,'全唐诗/poet.song.44000.json','["亂山遮曉擁千層，睡美初凉撼不譍。", "昨夜酒行君屢歎，定知歸夢到吳興。"]'),
('5e8a653d-7870-4acd-bc58-4903c002dff6','八月十七日復登望海樓自和前篇是日榜出余與試官兩人復留五首  其四','蘇軾','宋','宋诗','song-poetry','','[]','天台桂子爲誰香，倦聽空階點夜凉。',32,'全唐诗/poet.song.44000.json','["天台桂子爲誰香，倦聽空階點夜凉。", "頼有明朝看潮在，萬人空巷鬥新粧。"]'),
('1d468dbb-a4a7-42b4-85ca-95e35d477e38','八月十七日復登望海樓自和前篇是日榜出余與試官兩人復留五首  其五','蘇軾','宋','宋诗','song-poetry','','[]','秋花不見眼花紅，身在孤舟兀兀中。',32,'全唐诗/poet.song.44000.json','["秋花不見眼花紅，身在孤舟兀兀中。", "細雨作寒知有意，未教金菊出蒿蓬。"]'),
('5041ec10-c35d-4751-a2cb-63a001e61d53','和沈立之留別二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','而今父老千行淚，一似當時去越時。',32,'全唐诗/poet.song.44000.json','["而今父老千行淚，一似當時去越時。", "不用鎸碑頌遺愛，丈人清德畏人知。"]'),
('43afb756-178d-4ac9-a054-4ca10781d87e','和沈立之留別二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','卧聞鐃鼓送歸艎，夢裏匆匆共一觴。',32,'全唐诗/poet.song.44000.json','["卧聞鐃鼓送歸艎，夢裏匆匆共一觴。", "試問別來愁幾許，春江萬斛若爲量。"]'),
('1f627c81-0a0c-4b0b-8e02-1998ec5761c4','和陳述古拒霜花','蘇軾','宋','宋诗','song-poetry','','[]','千林掃作一番黄，只有芙蓉獨自芳。',32,'全唐诗/poet.song.44000.json','["千林掃作一番黄，只有芙蓉獨自芳。", "喚作拒霜知未稱，細思却是最宜霜。"]'),
('23732bc9-81e5-40ed-9f35-122ac48ca471','梵天寺見僧守詮小詩清婉可愛次韵','蘇軾','宋','宋诗','song-poetry','','[]','但聞烟外鐘，不見烟中寺。',36,'全唐诗/poet.song.44000.json','["但聞烟外鐘，不見烟中寺。", "幽人行未已，草露濕芒屨。", "惟應山頭月，夜夜照來去。"]'),
('42b6f1d0-9c5d-41dc-8988-8647db1ce6cf','聽賢師琴','蘇軾','宋','宋诗','song-poetry','','[]','大弦春溫和且平，小弦廉折亮以清。',66,'全唐诗/poet.song.44000.json','["大弦春溫和且平，小弦廉折亮以清。", "平生未識宮與角，但聞牛鳴盎中雉登木。", "門前剝啄誰叩門，山僧未閑君勿嗔。", "歸家且覓千斛水，浄洗從前箏笛耳。"]'),
('23113ec5-0c87-4400-bda3-a5926d94d472','秋懷二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','苦熱念西風，常恐來無時。',108,'全唐诗/poet.song.44000.json','["苦熱念西風，常恐來無時。", "及茲遂凄凜，又作徂年悲。", "蟋蟀鳴我床，黄葉投我帷。", "窗前有棲鵩，夜嘯如狐狸。", "露冷梧葉脫，孤眠無安枝。", "熠燿亦有偶，高屋飛相追。", "定知無幾見，迫此清霜期。", "物化逝不留，我興爲嗟咨。", "便當勤秉燭，爲樂戒暮遲。"]'),
('87e26027-72d9-4294-be29-c48247d31b8c','秋懷二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','海風東南來，吹盡三日雨。',96,'全唐诗/poet.song.44000.json','["海風東南來，吹盡三日雨。", "空階有餘滴，似與幽人語。", "念我平生歡，寂寞守環堵。", "壺漿慰作勞，裹飯救寒苦。", "今年秋應熟，過從飽雞黍。", "嗟我獨何求，萬里涉江浦。", "居貧豈無食，自不安畎畝。", "念此坐達晨，殘燈翳復吐。"]'),
('bd845b64-3ce8-43cc-a2c4-f23717fb8569','哭歐陽公孤山僧惠思示小詩次韵','蘇軾','宋','宋诗','song-poetry','','[]','故人已爲土，衰鬢亦驚秋。',24,'全唐诗/poet.song.44000.json','["故人已爲土，衰鬢亦驚秋。", "猶喜孤山下，相逢說舊遊。"]'),
('d4ad613f-6251-4bcc-a3e2-6954061c19fe','次韵孔文仲推官見贈','蘇軾','宋','宋诗','song-poetry','','[]','我本麋鹿性，諒非伏轅姿。',288,'全唐诗/poet.song.44000.json','["我本麋鹿性，諒非伏轅姿。", "君如汗血馬，作駒已權奇。", "齊驅大道中，並带鑾鑣馳。", "聞聲自决驟，那復受縶維。", "謂君朝發燕，秣楚日未敧。", "云何中道止，連蹇馿騾隨。", "金鞍冒翠錦，玉勒垂青絲。", "旁觀信美矣，自揣良厭之。", "均爲人所勞，何必陋鹽輜。", "君看立仗馬，不敢鳴且窺。", "調習困鞭箠，僅存骨與皮。", "人生各有志，此論我久持。", "他人聞定笑，聊與吾子期。", "空齋卧積雨，病骨煩撐支。", "秋草上垣牆，霜葉鳴階墀。", "門前自無客，敢作揚雄麾。", "候吏報君來，弭節江之湄。", "一對高人談，稍忘俗吏卑。", "今朝枉詩句，粲如鳳來儀。", "上山絕梯磴，墮海迷津涯。", "憐我枯槁質，借潤生華滋。", "肯效世俗人，洗刮求瘢痍。", "賢明日登用，清廟歌緝熙。", "胡不學長卿，預作封禪詞。"]'),
('498309f3-c2c0-42bb-acc9-bcee5d6834f3','朱壽昌郎中少不知母所在刺血寫經求之五十年去歲得之蜀中以詩賀之','蘇軾','宋','宋诗','song-poetry','','[]','嗟君七歲知念母，憐君壯大心愈苦。',160,'全唐诗/poet.song.44000.json','["嗟君七歲知念母，憐君壯大心愈苦。", "羨君臨老得相逢，喜極無言淚如雨。", "不羨白衣作三公，不愛白日昇青天。", "愛君五十著綵服，兒啼却得償當年。", "烹龍爲炙玉爲酒，鶴髮初生千萬壽。", "金花詔書錦作囊，白藤肩輿簾蹙繡。", "感君離合我酸辛，此事今無古或聞。", "長陵朅來見大姊，仲孺豈意逢將軍。", "開皇苦桃空記面，建中天子終不見。", "西河郡守誰復譏，潁谷封人羞自薦。"]'),
('e28339db-719f-4206-a84c-ec029723f028','湯村開運鹽河雨中督役','蘇軾','宋','宋诗','song-poetry','','[]','居官不任事，蕭散羨長卿。',120,'全唐诗/poet.song.44000.json','["居官不任事，蕭散羨長卿。", "胡不歸去來，滯留愧淵明。", "鹽事星火急，誰能卹農耕。", "薨薨曉鼓動，萬指羅溝坑。", "天雨助官政，泫然淋衣纓。", "人如鴨與豬，投泥相濺驚。", "下馬荒堤上，四顧但湖泓。", "線路不容足，又與牛羊爭。", "歸田雖賤辱，豈失泥中行。", "寄語故山友，慎毋厭藜羹。"]'),
('085e5e7a-c74a-4fe8-a15a-7ce51e980ee6','是日宿水陸寺寄北山清順僧二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','草沒河堤雨暗村，寺藏修竹不知門。',64,'全唐诗/poet.song.44000.json','["草沒河堤雨暗村，寺藏修竹不知門。", "拾薪煮藥憐僧病，掃地焚香浄客魂。", "農事未休侵小雪，佛燈初上報黄昏。", "年來漸識幽居味，思與高人對榻論。"]'),
('c9e7759c-0c33-43ab-88c0-50eb37ae77d0','是日宿水陸寺寄北山清順僧二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','長嫌鐘鼓聒湖山，此境蕭條却自然。',64,'全唐诗/poet.song.44000.json','["長嫌鐘鼓聒湖山，此境蕭條却自然。", "乞食遶村真爲飽，無言對客本非禪。", "披榛覓路衝泥入，洗足關門聽雨眠。", "遥想後身窮賈島，夜寒應聳作詩肩。"]'),
('308d90ea-ea06-43d8-a424-e56acc1daa1a','鹽官部役戲呈同事兼寄述古','蘇軾','宋','宋诗','song-poetry','','[]','新月照水水欲冰，夜霜穿屋衣生稜。',96,'全唐诗/poet.song.44000.json','["新月照水水欲冰，夜霜穿屋衣生稜。", "野廬半與牛羊共，曉鼓却隨鴉鵲興。", "夜來履破裘穿縫，紅頰曲眉應入夢。", "千夫在野口如林，豈不懷歸畏嘲弄。", "我州賢將知人勞，已釀白酒買豚羔。", "耐寒努力歸不遠，兩脚凍硬須公軟。"]'),
('e265ed30-b07c-4b8a-bf69-7e6389cd85af','鹽官絕句四首 南寺千佛閣','蘇軾','宋','宋诗','song-poetry','','[]','古邑居民半海濤，師來構築便能高。',32,'全唐诗/poet.song.44000.json','["古邑居民半海濤，師來構築便能高。", "千金用盡身無事，坐看香烟繞白毫。"]'),
('8661c356-3f0e-4f4c-8554-7b85b0773227','鹽官絕句四首 北寺悟空禪師塔','蘇軾','宋','宋诗','song-poetry','','[]','已將世界等微塵，空裏浮花夢裏身。',32,'全唐诗/poet.song.44000.json','["已將世界等微塵，空裏浮花夢裏身。", "豈爲龍顔更分別，只應天眼識天人。"]'),
('0060dc75-3ed4-43aa-8c73-7fc9ce55c93a','鹽官絕句四首 塔前古檜','蘇軾','宋','宋诗','song-poetry','','[]','當年雙檜是雙童，相對無言老更恭。',32,'全唐诗/poet.song.44000.json','["當年雙檜是雙童，相對無言老更恭。", "庭雪到腰埋不死，如今化作兩蒼龍。"]'),
('9f7c63af-91f0-41c7-adc4-411c339f2706','鹽官絕句四首 僧爽白雞','蘇軾','宋','宋诗','song-poetry','','[]','斷尾雄雞本畏烹，年來聽法伴修行。',32,'全唐诗/poet.song.44000.json','["斷尾雄雞本畏烹，年來聽法伴修行。", "還須却置蓮花漏，老怯風霜恐不鳴。"]'),
('6e181d6c-dcb0-44e4-aa5b-eec029e0c03f','六和寺沖師閘山溪爲水軒','蘇軾','宋','宋诗','song-poetry','','[]','欲放清溪自在流，忍教冰雪落沙洲。',32,'全唐诗/poet.song.44000.json','["欲放清溪自在流，忍教冰雪落沙洲。", "出山定被江潮涴，能爲山僧更少留。"]'),
('074fde35-2e7c-4797-8109-f4adfdb0e69d','冬至日獨遊吉祥寺','蘇軾','宋','宋诗','song-poetry','','[]','井底微陽回未回，蕭蕭寒雨濕枯荄。',32,'全唐诗/poet.song.44000.json','["井底微陽回未回，蕭蕭寒雨濕枯荄。", "何人更似蘇夫子，不是花時肯獨來。"]'),
('238cfc7a-e41a-45b9-ac52-f2d524ea2821','後十餘日復至','蘇軾','宋','宋诗','song-poetry','','[]','東君意淺著寒梅，千朵深紅未暇裁。',32,'全唐诗/poet.song.44000.json','["東君意淺著寒梅，千朵深紅未暇裁。", "安得道人殷七七，不論時節遣花開。"]'),
('f5e7fc9b-c4c3-43b2-a58c-92b65fbfd0f7','戲贈','蘇軾','宋','宋诗','song-poetry','','[]','惆悵沙河十里春，一番花老一番新。',32,'全唐诗/poet.song.44000.json','["惆悵沙河十里春，一番花老一番新。", "小樓依舊斜陽裏，不見樓中垂手人。"]'),
('cb566aa6-9987-4d18-a13e-bd484a0612ca','和人求筆迹','蘇軾','宋','宋诗','song-poetry','','[]','麥光鋪几浄無瑕，入夜青燈照眼花。',32,'全唐诗/poet.song.44000.json','["麥光鋪几浄無瑕，入夜青燈照眼花。", "從此剡藤真可弔，半紆春蚓綰秋蛇。"]'),
('37922c0b-2906-4e61-b1a9-5bfb1c9edce3','將之湖州戲贈莘老','蘇軾','宋','宋诗','song-poetry','','[]','餘杭自是山水窟，仄聞吳興更清絕。',96,'全唐诗/poet.song.44000.json','["餘杭自是山水窟，仄聞吳興更清絕。", "湖中橘林新著霜，溪上苕花正浮雪。", "顧渚茶芽白於齒，梅溪木瓜紅勝頰。", "吳兒膾縷薄欲飛，未去先說饞涎垂。", "亦知謝公到郡久，應怪杜牧尋春遲。", "鬢絲只可對禪榻，湖亭不用張水嬉。"]'),
('70dafb8d-c9a5-413a-a293-eba3ac7532ac','送張軒民寺丞赴省試','蘇軾','宋','宋诗','song-poetry','','[]','龍飛甲子盡豪英，嘗喜吾猶及老成。',64,'全唐诗/poet.song.44000.json','["龍飛甲子盡豪英，嘗喜吾猶及老成。", "人競春蘭笑秋菊，天教明月伴長庚。", "傳家各自聞詩禮，與子相逢亦弟兄。", "洗眼上林看躍馬，賀詩先到古宣城。"]'),
('faf46c22-c209-4d34-aa2b-6e9d07993829','再用前韵寄莘老','蘇軾','宋','宋诗','song-poetry','','[]','君不見夷甫開三窟，不如長康號癡絕。',97,'全唐诗/poet.song.44000.json','["君不見夷甫開三窟，不如長康號癡絕。", "癡人自得終天年，智士死智罪莫雪。", "困窮誰要卿料理，舉頭看山笏拄頰。", "野鳬翅重自不飛，黄鶴何事兩翼垂。", "泥中相從豈得久，今我不往行恐遲。", "江夏無雙應未去，恨無文字相娛嬉。"]'),
('eeacf07d-e804-48b5-a0b0-51931d7acf00','畫魚歌','蘇軾','宋','宋诗','song-poetry','','[]','天寒水落魚在泥，短鈎畫水如耕犁。',96,'全唐诗/poet.song.44000.json','["天寒水落魚在泥，短鈎畫水如耕犁。", "渚蒲披折藻荇亂，此意豈復遺鰍鯢。", "偶然信手皆虛擊，本不辭勞幾萬一。", "一魚中刃百魚驚，蝦蟹奔忙誤跳擲。", "漁人養魚如養雛，插竿冠笠驚鵜鶘。", "豈知白梃鬧如雨，攪水覓魚嗟已疏。"]'),
('3a7b92cd-7fb2-4aed-8543-a077048ac728','鴉種麥行','蘇軾','宋','宋诗','song-poetry','','[]','霜林老鴉閑無用，畦東拾麥畦西種。',100,'全唐诗/poet.song.44000.json','["霜林老鴉閑無用，畦東拾麥畦西種。", "畦西種得青猗猗，畦東已作牛尾稀。", "明年麥熟芒攢槊，農夫未食鴉先啄。", "徐行俯仰若自矜，鼓翅跳踉上牛角。", "憶昔舜耕歷山鳥爲耘，如今老鴉種麥更辛勤。", "農夫羅拜鴉飛起，勸農使者來行水。"]'),
('e915b732-391d-4fe5-8f0d-ad0e162e47b7','和致仕張郎中春晝','蘇軾','宋','宋诗','song-poetry','','[]','投紱歸來萬事輕，消磨未盡只風情。',128,'全唐诗/poet.song.44000.json','["投紱歸來萬事輕，消磨未盡只風情。", "舊因蒓菜求長假，新爲楊枝作短行。", "不禱自安緣壽骨，深藏難沒是詩名。", "淺斟杯酒紅生頰，細琢歌詞穩稱聲。", "蝸殻卜居心自放，蠅頭寫字眼能明。", "盛衰閱過君應笑，寵辱年來我亦平。", "跪履數從圯下老，逸書閑問濟南生。", "東風屈指無多日，只恐先春鶗鴂鳴。"]'),
('91f52074-04da-4fb0-bdeb-1df220ab5d66','和邵同年戲贈賈收秀才三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','傾蓋相歡一笑中，從來未省馬牛風。',64,'全唐诗/poet.song.44000.json','["傾蓋相歡一笑中，從來未省馬牛風。", "卜鄰尚可容三徑，投社終當作兩翁。", "古意已將蘭緝佩，招詞閑詠桂生叢。", "此身自斷天休問，白髮年來漸不公。"]'),
('63aa65dd-d2fa-40d6-aee3-9788c09bcedd','和邵同年戲贈賈收秀才三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','朝見新荑出舊槎，騷人孤憤苦思家。',64,'全唐诗/poet.song.44000.json','["朝見新荑出舊槎，騷人孤憤苦思家。", "五噫處士大窮約，三賦先生多誕誇。", "帳外鶴鳴匳有鏡，筒中錢盡案無鮭。", "玉川何日朝金闕，白晝關門守夜叉。"]'),
('68084497-b153-4ab2-ab5d-75f59bc6e980','和邵同年戲贈賈收秀才三首  其三','蘇軾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','生涯到處似檣烏，科第無心摘頷鬚。',64,'全唐诗/poet.song.44000.json','["生涯到處似檣烏，科第無心摘頷鬚。", "黄帽刺船忘歲月，白衣擔酒慰鰥孤。", "狙公欺病來分栗，水伯知饞爲出鱸。", "莫向洞庭歌此曲，烟波渺渺正愁予。"]'),
('d5f25475-df61-4f01-a174-08db940550f4','吳中田婦歎','蘇軾','宋','宋诗','song-poetry','','[]','今年粳稻熟苦遲，庶見霜風來幾時。',128,'全唐诗/poet.song.44000.json','["今年粳稻熟苦遲，庶見霜風來幾時。", "霜風來時雨如瀉，杷頭出菌鐮生衣。", "眼枯淚盡雨不盡，忍見黄穗卧青泥。", "茅苫一月隴上宿，天晴穫稻隨車歸。", "汗流肩頳載入市，價賤乞與如糠粞。", "賣牛納稅拆屋炊，慮淺不及明年饑。", "官今要錢不要米，西北萬里招羌兒。", "龔黄滿朝人更苦，不如却作河伯婦。"]'),
('ed2d1108-af42-4cfd-a6e4-a155de401cf6','遊道場山何山','蘇軾','宋','宋诗','song-poetry','','[]','道場山頂何山麓，上徹雲峰下幽谷。',160,'全唐诗/poet.song.44000.json','["道場山頂何山麓，上徹雲峰下幽谷。", "我從山水窟中來，尚愛此山看不足。", "陂湖行盡白漫漫，青山忽作龍蛇盤。", "山高無風松自響，誤認石齒號驚湍。", "山僧不放山泉出，屋底清池照瑶席。", "階前合抱香入雲，月裏仙人親手植。", "出山回望翠雲鬟，碧瓦朱欄縹緲間。", "白水田頭問行路，小溪深處是何山。", "高人讀書夜達旦，至今山鶴鳴夜半。", "我今廢學不歸山，山中對酒空三歎。"]'),
('90045df9-201c-4db2-8590-ae0a1959fe2b','莘老葺天慶觀小園有亭北向道士山宗說乞名與詩','蘇軾','宋','宋诗','song-poetry','','[]','春風欲動北風微，歸雁亭邊送雁歸。',64,'全唐诗/poet.song.44000.json','["春風欲動北風微，歸雁亭邊送雁歸。", "蜀客南遊家最遠，吳山寒盡雪先晞。", "扁舟去後花絮亂，五馬來時賓從非。", "惟有道人應不忘，抱琴無語立斜暉。"]'),
('9fff3ef6-5cef-4448-b551-583c9fc6109d','贈孫莘老七絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','嗟予與子久離羣，耳冷心灰百不聞。',32,'全唐诗/poet.song.44000.json','["嗟予與子久離羣，耳冷心灰百不聞。", "若對青山談世事，當須舉白便浮君。"]'),
('e1ceedb0-aa9d-4b85-a815-174e45e7d767','贈孫莘老七絕  其二','蘇軾','宋','宋诗','song-poetry','','["\u592a\u6e56"]','天目山前綠浸裾，碧瀾堂上看銜艫。',32,'全唐诗/poet.song.44000.json','["天目山前綠浸裾，碧瀾堂上看銜艫。", "作隄捍水非吾事，閑送苕溪入太湖。"]'),
('6e95101f-f1ff-4450-8ae8-c9cc76bb5708','贈孫莘老七絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','夜來雨洗碧巑岏，浪湧雲屯遶郭寒。',32,'全唐诗/poet.song.44000.json','["夜來雨洗碧巑岏，浪湧雲屯遶郭寒。", "聞有弁山何處是，爲君四面意求看。"]'),
('be63ecea-66cf-4891-b458-d0da9ab0a0b3','贈孫莘老七絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','夜橋燈火照溪明，欲放扁舟取次行。',32,'全唐诗/poet.song.44000.json','["夜橋燈火照溪明，欲放扁舟取次行。", "暫借官奴遣吹笛，明朝新月到三更。"]'),
('cc8c07bb-4b94-48ec-bada-7aab71019f23','贈孫莘老七絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','三年京國厭藜蒿，長羨淮魚壓楚糟。',32,'全唐诗/poet.song.44000.json','["三年京國厭藜蒿，長羨淮魚壓楚糟。", "今日駱駝橋下泊，恣看修網出銀刀。"]'),
('ed2fc6f1-dd7a-44ca-9ac4-20687fc674ef','贈孫莘老七絕  其六','蘇軾','宋','宋诗','song-poetry','','[]','烏程霜稻襲人香，釀作春風霅水光。',32,'全唐诗/poet.song.44000.json','["烏程霜稻襲人香，釀作春風霅水光。", "時復中之徐邈聖，無多酌我次公狂。"]'),
('a6d06e95-7cb6-4874-89c3-a07fd9d1a861','贈孫莘老七絕  其七','蘇軾','宋','宋诗','song-poetry','','[]','去年臘日訪孤山，曾借僧窗半日閑。',32,'全唐诗/poet.song.44000.json','["去年臘日訪孤山，曾借僧窗半日閑。", "不爲思歸對妻子，道人有約徑須還。"]'),
('902f776a-4338-4a1b-b9a8-1702fe593e5d','至秀州贈錢端公安道並寄其弟惠山老','蘇軾','宋','宋诗','song-poetry','','[]','鴛鴦湖邊月如水，孤舟夜榜鴛鴦起。',160,'全唐诗/poet.song.44000.json','["鴛鴦湖邊月如水，孤舟夜榜鴛鴦起。", "平明繫纜石橋亭，慚愧冒寒髯御史。", "結交最晚情獨厚，論心無數今有幾。", "寂寞抱關歎蕭生，耆老執戟哀揚子。", "怪君顔采却秀發，無乃遷謫反便美。", "天公欲困無奈何，世人共抑真疏矣。", "毘陵高山錫爲骨，陸子遺味泉冰齒。", "賢哉仲氏早拂衣，占斷此山長洗耳。", "山頭望湖光潑眼，山下濯足波生指。", "倘容逸少問金堂，記與嵇康留石髓。"]'),
('9a710617-375e-4e14-8103-ac63759b9ae5','秀州報本禪院鄉僧文長老方丈','蘇軾','宋','宋诗','song-poetry','','[]','萬里家山一夢中，吳音漸已變兒童。',64,'全唐诗/poet.song.44000.json','["萬里家山一夢中，吳音漸已變兒童。", "每逢蜀叟談終日，便覺峨眉翠掃空。", "師已忘言真有道，我除搜句百無功。", "明年採藥天台去，更欲題詩滿浙東。"]'),
('a29a4f1f-2ba5-48ed-8830-566708a43681','王復秀才所居雙檜二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','吳王池館遍重城，閑草幽花不記名。',32,'全唐诗/poet.song.44000.json','["吳王池館遍重城，閑草幽花不記名。", "青蓋一歸無覓處，只留雙檜待昇平。"]'),
('c6b14a96-7d3b-4e79-8cf8-e5596f7ce03a','王復秀才所居雙檜二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','凜然相對敢相欺，直幹凌空未要奇。',32,'全唐诗/poet.song.44000.json','["凜然相對敢相欺，直幹凌空未要奇。", "根到九泉無曲處，世間惟有蟄龍知。"]'),
('82d5ad60-a922-4f03-9961-181e8e9fd3d3','元日次韵張先子野見和七夕寄莘老之作','蘇軾','宋','宋诗','song-poetry','','[]','得句牛女夕，轉頭參尾中。',96,'全唐诗/poet.song.44000.json','["得句牛女夕，轉頭參尾中。", "青春先入睡，白髮不遺窮。", "酒社我爲敵，詩壇子有功。", "縮頭先夏鱉，實腹鄙秋蟲。", "莫唱裙垂綠，無人臉斷紅。", "舊交懷賀老，新進謝終童。", "袍鶻雙雙瑞，腰犀一一通。", "小蠻知在否，試問囁嚅翁。"]'),
('cefccdcf-28d7-40dc-83a1-ce7366e3ef38','正月九日有美堂飲醉歸徑睡五鼓方醒不復能眠起閱文書得鮮于子駿所寄雜興作古意一首答之','蘇軾','宋','宋诗','song-poetry','','[]','衆人事紛擾，志士獨悄悄。',120,'全唐诗/poet.song.44000.json','["衆人事紛擾，志士獨悄悄。", "何意琵琶弦，常遭腰鼓鬧。", "三杯忘萬慮，醒後還皎皎。", "有如轆轤索，已脫重縈繞。", "家人自約飭，始慕陳婦孝。", "可憐原巨先，放蕩今誰弔。", "平生嗜羊炙，識味肯輕飽。", "烹蛇啖蛙蛤，頗訝能稍稍。", "憂來自不寐，起視天漢渺。", "闌干玉繩低，耿耿太白曉。"]'),
('ce6e2a49-de6c-48c8-954a-80898f5dae0e','次韵答章傳道見贈','蘇軾','宋','宋诗','song-poetry','','[]','並生天地宇，同閱古今宙。',264,'全唐诗/poet.song.44000.json','["並生天地宇，同閱古今宙。", "視下則有高，無前孰爲後。", "達人千鈞弩，一弛難再彀。", "下士沐猴冠，已繫猶跳驟。", "欲將駒過隙，坐待石穿溜。", "君看漢唐主，宮殿悲麥秀。", "而況彼區區，何異壹醉富。", "鶢鶋非所養，俯仰眩金奏。", "髑髏有餘樂，不博南面后。", "嗟我昔少年，守道貧非疚。", "自從出求仕，役物恐見囿。", "馬融既依梁，班固亦事竇。", "效矉豈不欲，頑質謝鎸鏤。", "仄聞長者言，婞直非養壽。", "唾面慎勿拭，出胯當俯就。", "居然成懶廢，敢復齒豪右。", "子如照海珠，網目疏見漏。", "宏材乏近用，巧舞困短袖。", "坐令傾國容，臨老見邂逅。", "吾衰信久矣，書絕十年舊。", "門前可羅雀，感子煩屢叩。", "願言歌緇衣，子粲還予授。"]'),
('69f57bd5-43c4-4094-9179-047e580d2fad','法惠寺橫翠閣','蘇軾','宋','宋诗','song-poetry','','[]','朝見吳山橫，暮見吳山縱。',128,'全唐诗/poet.song.44000.json','["朝見吳山橫，暮見吳山縱。", "吳山故多態，轉折爲君容。", "幽人起朱閣，空洞更無物。", "惟有千步岡，東西作簾額。", "春來故國歸無期，人言秋悲春更悲。", "已泛平湖思濯錦，更看橫翠憶峨眉。", "雕欄能得幾時好，不獨憑欄人易老。", "百年興廢更堪哀，懸知草莽化池臺。", "遊人尋我舊遊處，但覓吳山橫處來。"]'),
('f844429f-b741-4a4d-9cfd-4030bead63df','祥符寺九曲觀燈','蘇軾','宋','宋诗','song-poetry','','[]','紗籠擎燭迎門入，銀葉燒香見客邀。',64,'全唐诗/poet.song.44000.json','["紗籠擎燭迎門入，銀葉燒香見客邀。", "金鼎轉丹光吐夜，寶珠穿蟻鬧連朝。", "波翻焰裏元相激，魚舞湯中不畏焦。", "明日酒醒空想像，清吟半逐夢魂銷。"]'),
('f2604611-c2a9-49ff-af25-0aed844b4f0e','上元過祥符僧可久房蕭然無燈火','蘇軾','宋','宋诗','song-poetry','','[]','門前歌舞鬥分朋，一室清風冷欲冰。',32,'全唐诗/poet.song.44000.json','["門前歌舞鬥分朋，一室清風冷欲冰。", "不把琉璃閑照佛，始知無盡本無燈。"]'),
('be69b9db-3297-4605-a50f-7f6e907d0fa8','正月二十一日病後述古邀往城外尋春','蘇軾','宋','宋诗','song-poetry','','[]','屋上山禽苦喚人，檻前冰沼忽生鱗。',64,'全唐诗/poet.song.44000.json','["屋上山禽苦喚人，檻前冰沼忽生鱗。", "老來厭伴紅裙醉，病起空驚白髮新。", "卧聽使君鳴鼓角，試呼稚子整冠巾。", "曲欄幽榭終寒窘，一看郊原浩蕩春。"]'),
('f94ebe50-227d-4f9e-a88c-7f1b4504eefa','有以官法酒見餉者因用前韵求述古爲移厨飲湖上','蘇軾','宋','宋诗','song-poetry','','[]','喜逢門外白衣人，欲膾湖中赤玉鱗。',64,'全唐诗/poet.song.44000.json','["喜逢門外白衣人，欲膾湖中赤玉鱗。", "遊舫已粧吳榜穩，舞衫初試越羅新。", "欲將漁釣追黄帽，未要靴刀抹絳巾。", "芳意十分强半在，爲君先踏水邊春。"]'),
('610e5dea-c92e-4045-93d4-e617c90aab27','飲湖上初晴後雨二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','朝曦迎客艷重岡，晚雨留人入醉鄉。',32,'全唐诗/poet.song.44000.json','["朝曦迎客艷重岡，晚雨留人入醉鄉。", "此意自佳君不會，一杯當屬水仙王。"]'),
('84ac0afb-51fb-499a-91d6-f71e5c6ea1cf','飲湖上初晴後雨二首  其二','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56", "\u5199\u96e8", "\u5c71\u6c34", "\u5199\u666f", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u5b8b\u8bd7"]','水光瀲灧晴方好，山色空濛雨亦奇。',32,'全唐诗/poet.song.44000.json','["水光瀲灧晴方好，山色空濛雨亦奇。", "若把西湖比西子，淡粧濃抹總相宜。"]'),
('951e8b9d-c761-4902-a641-c560d0391fc0','往富陽新城李節推先行三日留風水洞見待','蘇軾','宋','宋诗','song-poetry','','[]','春山磔磔鳴春禽，此間不可無我吟。',128,'全唐诗/poet.song.44000.json','["春山磔磔鳴春禽，此間不可無我吟。", "路長漫漫傍江浦，此間不可無君語。", "金鯽池邊不見君，追君直過定山村。", "路人皆言君未遠，騎馬少年清且婉。", "風巌水穴舊聞名，只隔山溪夜不行。", "溪橋曉溜浮梅萼，知君繫馬巌花落。", "出城三日尚逶遲，妻孥怪駡歸何時。", "世上小兒誇疾走，如君相待今安有。"]'),
('e689ce4e-9241-4814-a8a1-877f16f27bc6','風水洞二首和李節推  其一','蘇軾','宋','宋诗','song-poetry','','[]','風轉鳴空穴，泉幽瀉石門。',48,'全唐诗/poet.song.44000.json','["風轉鳴空穴，泉幽瀉石門。", "虛心聞地籟，妄意覓桃源。", "過客詩難好，居僧語不繁。", "歸瓶得冰雪，清冷慰文園。"]'),
('b63abe8f-703b-461f-93fe-a4c18f856e48','風水洞二首和李節推  其二','蘇軾','宋','宋诗','song-poetry','','[]','山前乳水隔塵凡，山上仙風舞檜杉。',64,'全唐诗/poet.song.44000.json','["山前乳水隔塵凡，山上仙風舞檜杉。", "細細龍鱗生亂石，團團羊角轉空巌。", "馮夷窟宅非梁棟，御寇車輿謝轡銜。", "世事漸艱吾欲去，永隨二子脫譏讒。"]'),
('118158de-f7a5-491a-9991-acd90220fbbe','獨遊富陽普照寺','蘇軾','宋','宋诗','song-poetry','','[]','富春真古邑，此寺亦唐餘。',48,'全唐诗/poet.song.44000.json','["富春真古邑，此寺亦唐餘。", "鶴老依喬木，龍歸護賜書。", "連筒春水遠，出谷晚鐘疏。", "欲繼江潮韵，何人爲起予。"]'),
('b07d63ba-3ca0-4a77-aa0f-6a85fae2d7fa','自普照游二庵','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','長松吟風晚雨細，東庵半掩西庵閉。',96,'全唐诗/poet.song.44000.json','["長松吟風晚雨細，東庵半掩西庵閉。", "山行盡日不逢人，裛裛野梅香入袂。", "居僧笑我戀清景，自厭山深出無計。", "我雖愛山亦自笑，獨往神傷後難繼。", "不如西湖飲美酒，紅杏碧桃香覆髻。", "作詩寄謝採薇翁，本不避人那避世。"]'),
('2fb62d22-8d9e-452b-a0a6-8e514b49e345','富陽妙庭觀董雙成故宅發地得丹鼎覆以銅盤承以琉璃盆盆既破碎丹亦爲人爭奪持去今獨盤鼎在耳二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','人去山空鶴不歸，丹亡鼎在世徒悲。',32,'全唐诗/poet.song.44000.json','["人去山空鶴不歸，丹亡鼎在世徒悲。", "可憐九轉功成後，却把飛昇乞內芝。"]'),
('dbc21f50-a79d-4b24-ad17-dca9f8b0dfda','富陽妙庭觀董雙成故宅發地得丹鼎覆以銅盤承以琉璃盆盆既破碎丹亦爲人爭奪持去今獨盤鼎在耳二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','琉璃擊碎走金丹，無復神光發舊壇。',32,'全唐诗/poet.song.44000.json','["琉璃擊碎走金丹，無復神光發舊壇。", "時有世人來舐鼎，欲隨雞犬事劉安。"]'),
('f709b795-0cc0-4f5a-a033-fcd93b5d5d3c','新城道中二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','東風知我欲山行，吹斷檐間積雨聲。',64,'全唐诗/poet.song.44000.json','["東風知我欲山行，吹斷檐間積雨聲。", "嶺上晴雲披絮帽，樹頭初日挂銅鉦。", "野桃含笑竹籬短，溪柳自摇沙水清。", "西崦人家應最樂，煮芹燒筍餉春耕。"]'),
('37e48246-f139-4288-8a11-83066e8585c1','新城道中二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','身世悠悠我此行，溪邊委轡聽溪聲。',64,'全唐诗/poet.song.44000.json','["身世悠悠我此行，溪邊委轡聽溪聲。", "散材畏見搜林斧，疲馬思聞卷旆鉦。", "細雨足時茶戶喜，亂山深處長官清。", "人間岐路知多少，試向桑田問耦耕。"]'),
('61b3324a-d593-4be0-9ca9-54cbbcde7a2d','山村五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','竹籬茅屋趁溪斜，春入山村處處花。',32,'全唐诗/poet.song.44000.json','["竹籬茅屋趁溪斜，春入山村處處花。", "無象太平還有象，孤烟起處是人家。"]'),
('7ed0399d-21b1-459f-b244-456a0f0c3466','山村五絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','烟雨濛濛雞犬聲，有生何處不安生。',32,'全唐诗/poet.song.44000.json','["烟雨濛濛雞犬聲，有生何處不安生。", "但令黄犢無人佩，布穀何勞也勸耕。"]'),
('5640498d-f2d9-43e2-ba5b-0c36db7826bc','山村五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','老翁七十自腰鎌，慚愧春山筍蕨甜。',32,'全唐诗/poet.song.44000.json','["老翁七十自腰鎌，慚愧春山筍蕨甜。", "豈是聞韶解忘味，邇來三月食無鹽。"]'),
('1db82968-6331-4543-802a-b650d8646439','山村五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','杖藜裹飯去匆匆，過眼青錢轉手空。',32,'全唐诗/poet.song.44000.json','["杖藜裹飯去匆匆，過眼青錢轉手空。", "贏得兒童語音好，一年强半在城中。"]'),
('f67ffc82-346a-4615-beb5-d526404dac68','山村五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','竊祿忘歸我自羞，豐年底事汝憂愁。',32,'全唐诗/poet.song.44000.json','["竊祿忘歸我自羞，豐年底事汝憂愁。", "不須更待飛鳶墮，方念平生馬少游。"]'),
('d04ed969-3820-4751-a724-d4256f6e7aca','癸丑春分後雪','蘇軾','宋','宋诗','song-poetry','','[]','雪入春分省見稀，半開桃李不勝威。',64,'全唐诗/poet.song.44000.json','["雪入春分省見稀，半開桃李不勝威。", "應慚落地梅花識，却作漫天柳絮飛。", "不分東君專節物，故將新巧發陰機。", "從今造物尤難料，更暖須留御臘衣。"]'),
('0da3c3a9-0b4a-4ad7-9d40-665872ec090f','湖上夜歸','蘇軾','宋','宋诗','song-poetry','','[]','我飲不盡器，半酣味尤長。',120,'全唐诗/poet.song.44000.json','["我飲不盡器，半酣味尤長。", "籃輿湖上歸，春風灑面凉。", "行到孤山西，夜色已蒼蒼。", "清吟雜夢寐，得句旋已忘。", "尚記梨花村，依依聞暗香。", "入城定何時，賓客半在亡。", "睡眼忽驚矍，繁燈鬧河塘。", "市人拍手笑，狀如失林麞。", "始悟山野姿，異趣難自强。", "人生安爲樂，吾策殊未良。"]'),
('e379bba2-d774-42e9-9e64-67c80cf0a735','同曾元恕游龍山呂穆仲不至','蘇軾','宋','宋诗','song-poetry','','[]','青春不覺老朱顔，强半銷磨簿領間。',64,'全唐诗/poet.song.44000.json','["青春不覺老朱顔，强半銷磨簿領間。", "愁客倦吟花似酒，佳人休唱日銜山。", "共知寒食明朝過，且赴僧窗半日閑。", "命駕呂安邀不至，浴沂曾點暮方還。"]'),
('1bd053f1-b0d2-44d5-a321-1e2b15e51e22','寒食未明至湖上太守未來兩縣令先在','蘇軾','宋','宋诗','song-poetry','','["\u538c\u5026", "\u6292\u60c5", "\u8bb0\u6e38", "\u5199\u666f"]','城頭月落尚啼烏，烏榜紅舷早滿湖。',64,'全唐诗/poet.song.44000.json','["城頭月落尚啼烏，烏榜紅舷早滿湖。", "鼓吹未容迎五馬，水雲先已颺雙鳬。", "映山黄帽螭頭舫，夾道青烟鵲尾爐。", "老病逢春只思睡，獨求僧榻寄須臾。"]'),
('60470bc2-f3a5-408b-96ee-455147b849dd','次韵孫莘老見贈時莘老移廬州因以別之','蘇軾','宋','宋诗','song-poetry','','[]','鑪錘一手賦形殊，造化無心敢望渠。',64,'全唐诗/poet.song.44000.json','["鑪錘一手賦形殊，造化無心敢望渠。", "我本疏頑固當爾，子猶淪落況其餘。", "龔黄側畔難言政，羅趙前頭且眩書。", "惟有陽關一杯酒，殷勤重唱贈離居。"]'),
('3016a969-3c1c-43f9-98d1-19af782af7c2','贈別','蘇軾','宋','宋诗','song-poetry','','[]','青鳥銜巾久欲飛，黄鶑別主更悲啼。',32,'全唐诗/poet.song.44000.json','["青鳥銜巾久欲飛，黄鶑別主更悲啼。", "殷勤莫忘分携處，湖水東邊鳳嶺西。"]'),
('6276561d-75ea-46c0-9915-40f5bda6c813','次韵代留別','蘇軾','宋','宋诗','song-poetry','','[]','絳蠟燒殘玉斝飛，離歌唱徹萬行啼。',32,'全唐诗/poet.song.44000.json','["絳蠟燒殘玉斝飛，離歌唱徹萬行啼。", "他年一舸鴟夷去，應記儂家舊住西。"]'),
('b1a206ac-42e8-42a4-80bd-1c4586e398e6','月兔茶','蘇軾','宋','宋诗','song-poetry','','[]','環非環，玦非玦，中有迷離玉兔兒。',63,'全唐诗/poet.song.44000.json','["環非環，玦非玦，中有迷離玉兔兒。", "一似佳人裙上月，月圓還缺缺還圓，此月一缺圓何年。", "君不見鬥茶公子不忍鬥小團，上有雙銜綬带雙飛鸞。"]'),
('90cbbd04-d695-4f75-a023-9cb4d0f3b6dd','薄命佳人','蘇軾','宋','宋诗','song-poetry','','[]','雙頰凝酥髮抹漆，眼光入簾珠的皪。',64,'全唐诗/poet.song.44000.json','["雙頰凝酥髮抹漆，眼光入簾珠的皪。", "故將白練作仙衣，不許紅膏污天質。", "吳音嬌軟带兒癡，無限閑愁總未知。", "自古佳人多命薄，閉門春盡楊花落。"]'),
('0ef31bee-e1cd-49da-8acd-0f6ce7839d2d','吉祥寺花將落而述古不至','蘇軾','宋','宋诗','song-poetry','','[]','今歲東風巧剪裁，含情只待使君來。',32,'全唐诗/poet.song.44000.json','["今歲東風巧剪裁，含情只待使君來。", "對花無信花應恨，直恐明年便不開。"]'),
('cde7b9aa-dbab-458b-bbc9-26c345f03fc0','述古聞之明日即至坐上復用前韵同賦','蘇軾','宋','宋诗','song-poetry','','[]','仙衣不用剪刀裁，國色初酣卯酒來。',32,'全唐诗/poet.song.44000.json','["仙衣不用剪刀裁，國色初酣卯酒來。", "太守問花花有語，爲君零落爲君開。"]'),
('be6aef95-c08a-44cc-8d69-7b5dfdd7cf7c','李鈐轄坐上分題戴花','蘇軾','宋','宋诗','song-poetry','','[]','二八佳人細馬馱，十千美酒渭城歌。',64,'全唐诗/poet.song.44000.json','["二八佳人細馬馱，十千美酒渭城歌。", "簾前柳絮驚春晚，頭上花枝奈老何。", "露濕醉巾香掩冉，月明歸路影婆娑。", "綠珠吹笛何時見，欲把斜紅插皂羅。"]'),
('c2291fa9-e92a-427c-9d3f-e95dcd081f4e','於潛令刁同年野翁亭','蘇軾','宋','宋诗','song-poetry','','[]','山翁不出山，溪翁長在溪。',112,'全唐诗/poet.song.44000.json','["山翁不出山，溪翁長在溪。", "不如野翁來往溪山間，上友麋鹿下鳧鷖。", "問翁何所樂，三年不去煩推擠。", "翁言此間亦有樂，非絲非竹非蛾眉。", "山人醉後鐵冠落，溪女笑時銀櫛低。", "我來觀政問風謠，皆云吠犬足生氂。", "但恐此翁一旦捨此去，長使山人索寞溪女啼。"]'),
('f66e3bd2-62e3-4c68-b2bb-c5086c415d09','於潛僧綠筠軒','蘇軾','宋','宋诗','song-poetry','','[]','可使食無肉，不可使居無竹。',65,'全唐诗/poet.song.44000.json','["可使食無肉，不可使居無竹。", "無肉令人瘦，無竹令人俗。", "人瘦尚可肥，俗士不可醫。", "旁人笑此言，似高還似癡。", "若對此君仍大嚼，世間那有揚州鶴。"]'),
('944e2c2f-b706-41ad-aff5-04a29a33a166','於潛女','蘇軾','宋','宋诗','song-poetry','','[]','青裙縞袂於潛女，兩足如霜不穿屨。',83,'全唐诗/poet.song.44000.json','["青裙縞袂於潛女，兩足如霜不穿屨。", "{舟奢}沙鬢髮絲穿柠，蓬沓障前走風雨。", "老濞宮粧傳父祖，至今遺民悲故主。", "苕溪楊柳初飛絮，照溪畫眉渡溪去。", "逢郎樵歸相媚嫵，不信姬姜有齊魯。"]'),
('6324ffd9-a8eb-4186-ae6e-86f0e5793c38','自昌化雙溪館下步尋溪源至治平寺二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','亂山滴翠衣裘重，雙澗響空窗戶摇。',64,'全唐诗/poet.song.44000.json','["亂山滴翠衣裘重，雙澗響空窗戶摇。", "飽食不嫌溪筍瘦，穿林閑覓野芎苗。", "却愁縣令知游寺，尚喜漁人爭渡橋。", "正似醴泉山下路，桑枝刺眼麥齊腰。"]'),
('638f8221-8679-4794-ade4-30e2555dcf56','自昌化雙溪館下步尋溪源至治平寺二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','每見田園輒自招，倦飛不擬控扶摇。',64,'全唐诗/poet.song.44000.json','["每見田園輒自招，倦飛不擬控扶摇。", "共疑楊惲非鋤豆，誰信劉章解立苗。", "老去尚貪彭澤米，夢歸時到錦江橋。", "宦游莫作無家客，舉族長懸似細腰。"]'),
('b580fd7e-0e8d-4cd6-8033-170a38168947','與臨安令宗人同年劇飲','蘇軾','宋','宋诗','song-poetry','','[]','我雖不解飲，把盞歡意足。',76,'全唐诗/poet.song.44000.json','["我雖不解飲，把盞歡意足。", "試呼白髮感秋人，令唱黄雞催曉曲。", "與君登科如隔晨，敝袍霜葉空殘綠。", "如今莫問老與少，兒子森森如立竹。", "黄雞催曉不須愁，老盡世人非我獨。"]'),
('e778fd03-7146-4e75-87a9-9a603c41bd4e','寶山晝睡','蘇軾','宋','宋诗','song-poetry','','[]','七尺頑軀走世塵，十圍便腹貯天真。',32,'全唐诗/poet.song.44000.json','["七尺頑軀走世塵，十圍便腹貯天真。", "此中空洞渾無物，何止容君數百人。"]'),
('8e826c18-01f0-4bc3-9662-f0e32f2b99c2','僧清順新作垂雲亭','蘇軾','宋','宋诗','song-poetry','','[]','江山雖有餘，亭榭苦難穩。',168,'全唐诗/poet.song.44000.json','["江山雖有餘，亭榭苦難穩。", "登臨不得要，萬象各偃蹇。", "惜哉垂雲軒，此地得何晚。", "天公爭向背，詩眼巧增損。", "路窮朱欄出，山破石壁很。", "海門浸坤軸，湖尾抱雲巘。", "葱葱城郭麗，淡淡烟村遠。", "紛紛鳥鵲去，一一漁樵返。", "雄觀快新獲，微景收昔遁。", "道人真古人，嘯詠慕嵇阮。", "空齋卧蒲褐，芒屨每自捆。", "天憐詩人窮，乞與供詩本。", "我詩久不作，荒澀旋鋤墾。", "從君覓佳句，咀嚼廢朝飯。"]'),
('1cf59392-c3f2-4afb-8347-47a2a20aef74','五月十日與呂仲甫周邠僧惠勤惠思清順可久惟肅義詮同泛湖游北山','蘇軾','宋','宋诗','song-poetry','','[]','三吳雨連月，湖水日夜添。',96,'全唐诗/poet.song.44000.json','["三吳雨連月，湖水日夜添。", "尋僧去無路，瀲瀲水拍檐。", "駕言徂北山，得與幽人兼。", "清風洗昏翳，晚景分穠纖。", "縹緲朱樓人，斜陽半疏簾。", "臨風一揮手，悵焉起遐瞻。", "世人騖朝市，獨向溪山廉。", "此樂得有命，輕傳神所殲。"]'),
('2f5bfe26-3243-4c3a-88ab-b5e3b2a66159','會客有美堂周邠長官與數僧同泛湖往北山湖中聞堂上歌笑聲以詩見寄因和二首時周有服  其一','蘇軾','宋','宋诗','song-poetry','','[]','靄靄君詩似嶺雲，從來不許醉紅裙。',64,'全唐诗/poet.song.44000.json','["靄靄君詩似嶺雲，從來不許醉紅裙。", "不知野屐穿山翠，惟見輕橈破浪紋。", "頗憶呼盧袁彥道，難邀駡座灌將軍。", "晚風落日元無主，不惜清凉與子分。"]'),
('c510e5c9-668f-402c-9691-32101f839ceb','會客有美堂周邠長官與數僧同泛湖往北山湖中聞堂上歌笑聲以詩見寄因和二首時周有服  其二','蘇軾','宋','宋诗','song-poetry','','[]','載酒無人過子雲，掩關晝卧客書裙。',64,'全唐诗/poet.song.44000.json','["載酒無人過子雲，掩關晝卧客書裙。", "歌喉不共聽珠貫，醉面何因作纈紋。", "僧侶且陪香火社，詩壇欲斂鸛鵝軍。", "憑君遍遶湖邊寺，漲綠晴來已十分。"]'),
('feae085e-e3b2-44c6-8c2d-9cb1192344c4','席上代人贈別三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','悽音怨亂不成歌，縱使重來奈老何。',32,'全唐诗/poet.song.44000.json','["悽音怨亂不成歌，縱使重來奈老何。", "淚眼無窮似梅雨，一番勻了一番多。"]'),
('4a21de24-5600-4d1e-956e-021d2b62136c','席上代人贈別三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','天上麒麟豈混塵，籠中翡翠不由身。',32,'全唐诗/poet.song.44000.json','["天上麒麟豈混塵，籠中翡翠不由身。", "那知昨夜香閨裏，更有偷啼暗別人。"]'),
('42463fbb-19a9-4d3b-b688-2c5e6a10a254','席上代人贈別三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','蓮子劈開須見臆，楸枰著盡更無期。',32,'全唐诗/poet.song.44000.json','["蓮子劈開須見臆，楸枰著盡更無期。", "破衫却有重逢處，一飯何曾忘却時。"]'),
('c67eb6b1-4e3e-4393-95fd-01bf79c2049d','唐道人言天目山上俯視雷雨每大雷電但聞雲中如嬰兒聲殊不聞雷震也','蘇軾','宋','宋诗','song-poetry','','[]','已外浮名更外身，區區雷電若爲神。',32,'全唐诗/poet.song.44000.json','["已外浮名更外身，區區雷電若爲神。", "山頭只作嬰兒看，無限人間失箸人。"]'),
('03ddd545-b00d-4511-a041-87b441be26f9','追和子由去歲試舉人洛下所寄九首 暴雨初晴樓上晚景 其一','蘇軾','宋','宋诗','song-poetry','','[]','秋後風光雨後山，滿城流水碧潺潺。',32,'全唐诗/poet.song.44000.json','["秋後風光雨後山，滿城流水碧潺潺。", "烟雲好處無多子，及取昏鴉未到間。"]'),
('83001f8c-b389-4767-8538-94cea7c3bfb0','追和子由去歲試舉人洛下所寄九首 暴雨初晴樓上晚景 其二','蘇軾','宋','宋诗','song-poetry','','[]','洛邑從來天地中，嵩高蒼翠北邙紅。',32,'全唐诗/poet.song.44000.json','["洛邑從來天地中，嵩高蒼翠北邙紅。", "風流耆舊消磨盡，只有青山對病翁。"]'),
('9058f848-9822-4644-accb-aefce4bece3a','追和子由去歲試舉人洛下所寄九首 暴雨初晴樓上晚景 其三','蘇軾','宋','宋诗','song-poetry','','[]','白汗翻漿午景前，雨餘風物便蕭然。',32,'全唐诗/poet.song.44000.json','["白汗翻漿午景前，雨餘風物便蕭然。", "應傾半熟鵝黄酒，照見新晴水碧天。"]'),
('b5200feb-1cc9-4c7a-9638-f1d4d03a1b41','追和子由去歲試舉人洛下所寄九首 暴雨初晴樓上晚景 其四','蘇軾','宋','宋诗','song-poetry','','[]','疾雷破屋雨翻河，一掃清風未覺多。',32,'全唐诗/poet.song.44000.json','["疾雷破屋雨翻河，一掃清風未覺多。", "應似畫師吳道子，高堂巨壁寫降魔。"]'),
('f5c73049-dbe3-4528-8c10-9b5b53c4842e','追和子由去歲試舉人洛下所寄九首 暴雨初晴樓上晚景 其五','蘇軾','宋','宋诗','song-poetry','','[]','客路三年不見山，上樓相對夢魂間。',32,'全唐诗/poet.song.44000.json','["客路三年不見山，上樓相對夢魂間。", "明朝却踏紅塵去，羞向清伊照病顔。"]'),
('23d3ff09-fc5d-4ad6-905c-1622a7b640f8','追和子由去歲試舉人洛下所寄九首 過廣愛寺見三學演師觀楊惠之塑寶山朱瑶畫文殊普賢 其一','蘇軾','宋','宋诗','song-poetry','','[]','寓世身如夢，安閑日似年。',48,'全唐诗/poet.song.44000.json','["寓世身如夢，安閑日似年。", "敗蒲翻覆卧，破裓再三連。", "勸客眠風竹，長齋飲石泉。", "回頭萬事錯，自笑覺師賢。"]'),
('b2e3819e-6455-450a-bd76-2c161155a0e9','追和子由去歲試舉人洛下所寄九首 過廣愛寺見三學演師觀楊惠之塑寶山朱瑶畫文殊普賢 其二','蘇軾','宋','宋诗','song-poetry','','[]','妙迹苦難尋，茲山見幾層。',48,'全唐诗/poet.song.44000.json','["妙迹苦難尋，茲山見幾層。", "亂峰螺髻出，絕澗陣雲崩。", "措意元同畫，觀空欲問僧。", "莫教林下意，終老歎何曾。"]'),
('126658d6-57c6-4812-90d9-234d4a63dc32','追和子由去歲試舉人洛下所寄九首 過廣愛寺見三學演師觀楊惠之塑寶山朱瑶畫文殊普賢 其三','蘇軾','宋','宋诗','song-poetry','','[]','朱瑶唐晚輩，得法尚雄深。',48,'全唐诗/poet.song.44000.json','["朱瑶唐晚輩，得法尚雄深。", "滿寺空遺跡，何人識苦心。", "長廊敧雨脚，破壁撼鐘音。", "成壞無窮事，他年復弔今。"]'),
('86c9cfb5-569b-4434-a3c8-6402be671204','追和子由去歲試舉人洛下所寄九首 韓子華石淙莊','蘇軾','宋','宋诗','song-poetry','','[]','絳侯百萬兵，尚畏書牘背。',168,'全唐诗/poet.song.44000.json','["絳侯百萬兵，尚畏書牘背。", "功名意不已，數與危機會。", "我公抱絕識，凜凜鎮橫潰。", "欲收伊呂迹，遠與巢由對。", "誓言雖未從，久已斷諸內。", "區區爲懷祖，頗覺羲之隘。", "此身隨造物，一葉舞澎湃。", "田園不早定，歸宿終安在。", "彼美石淙莊，每到百事廢。", "泉流知人意，屈折作濤瀨。", "寒光洗肝膈，清響跨竽籟。", "我舊門前客，放言不自外。", "園中亦何有，薈蔚可勝計。", "請公試回首，歲晚餘蒼檜。"]'),
('9a8d20ae-8c78-4935-8f4b-88818edc0825','贈上天竺辯才師','蘇軾','宋','宋诗','song-poetry','','[]','南北一山門，上下兩天竺。',120,'全唐诗/poet.song.44000.json','["南北一山門，上下兩天竺。", "中有老法師，瘦長如鸛鵠。", "不知修何行，碧眼照山谷。", "見之自清凉，洗盡煩惱毒。", "坐令一都會，男女禮白足。", "我有長頭兒，角頰峙犀玉。", "四歲不知行，抱負煩背腹。", "師來爲摩頂，起走趁奔鹿。", "乃知戒律中，妙用謝羈束。", "何必言法華，佯狂啖魚肉。"]'),
('4b73879f-fa09-4885-918a-8f14e31a7032','立秋日禱雨宿靈隠寺同周徐二令','蘇軾','宋','宋诗','song-poetry','','[]','百重堆案掣身閑，一葉秋聲對榻眠。',64,'全唐诗/poet.song.44000.json','["百重堆案掣身閑，一葉秋聲對榻眠。", "床下雪霜侵戶月，枕中琴筑落階泉。", "崎嶇世味嘗應遍，寂寞山棲老漸便。", "惟有憫農心尚在，起占雲漢更茫然。"]'),
('0cb46bc7-1d1b-4350-9379-b29b6b3a60dd','病中獨遊浄慈謁本長老周長官以詩見寄仍邀遊靈隠因次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','卧聞禪老入南山，浄掃清風五百間。',64,'全唐诗/poet.song.44000.json','["卧聞禪老入南山，浄掃清風五百間。", "我與世疏宜獨往，君緣詩好不容攀。", "自知樂事年年減，難得高人日日閑。", "欲問雲公覓心地，要知何處是無還。"]'),
('19f4928a-af88-41dc-abda-6b47a4a6b34e','病中遊祖塔院','蘇軾','宋','宋诗','song-poetry','','[]','紫李黄瓜村路香，烏紗白葛道衣凉。',64,'全唐诗/poet.song.44000.json','["紫李黄瓜村路香，烏紗白葛道衣凉。", "閉門野寺松陰轉，敧枕風軒客夢長。", "因病得閑殊不惡，安心是藥更無方。", "道人不惜階前水，借與匏樽自在嘗。"]'),
('4ff35d30-fd27-4cb7-8f96-f6c0aa80a4d3','虎跑泉','蘇軾','宋','宋诗','song-poetry','','[]','亭亭石塔東峰上，此老初來百神仰。',64,'全唐诗/poet.song.44000.json','["亭亭石塔東峰上，此老初來百神仰。", "虎移泉眼趁行脚，龍作浪花供撫掌。", "至今遊人盥濯罷，卧聽空階環玦響。", "故知此老如此泉，莫作人間去來想。"]'),
('0108c90d-cc60-4c97-8a9d-b6387b34bd38','佛日山榮長老方丈五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','陶令思歸久未成，遠公不出但聞名。',32,'全唐诗/poet.song.44000.json','["陶令思歸久未成，遠公不出但聞名。", "山中只有蒼髯叟，數里蕭蕭管送迎。"]'),
('d1e9ede4-72ea-48a6-9ad3-259ba777312f','佛日山榮長老方丈五絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','千株玉槊攙雲立，一穗珠旒落鏡寒。',32,'全唐诗/poet.song.44000.json','["千株玉槊攙雲立，一穗珠旒落鏡寒。", "何處霜眉碧眼客，結爲三友冷相看。"]'),
('5ea6a75f-6944-4797-bd78-d981cbc4e3ef','佛日山榮長老方丈五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','東麓雲根露角牙，細泉幽咽走金沙。',32,'全唐诗/poet.song.44000.json','["東麓雲根露角牙，細泉幽咽走金沙。", "不堪土肉埋山骨，未放蒼龍浴渥洼。"]'),
('bfe2b58f-38a3-476d-86b3-d263947d4413','佛日山榮長老方丈五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','食罷茶甌未要深，清風一榻抵千金。',32,'全唐诗/poet.song.44000.json','["食罷茶甌未要深，清風一榻抵千金。", "腹摇鼻息庭花落，還盡平生未足心。"]'),
('f20df2c2-eba6-4a43-9ff7-b1885dc80bd7','佛日山榮長老方丈五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','日射回廊午枕明，水沉銷盡碧烟橫。',32,'全唐诗/poet.song.44000.json','["日射回廊午枕明，水沉銷盡碧烟橫。", "山人睡覺無人見，只有飛蚊繞鬢鳴。"]'),
('dd5235fe-cde3-422d-9e8e-102a1895539e','弔天竺海月辯師三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','欲尋遺跡强沾裳，本自無生可得亡。',32,'全唐诗/poet.song.44000.json','["欲尋遺跡强沾裳，本自無生可得亡。", "今夜生公講堂月，滿庭依舊冷如霜。"]'),
('8607ae82-eeea-404f-be23-0569508b6574','弔天竺海月辯師三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','生死猶如臂屈伸，情鍾我輩一酸辛。',32,'全唐诗/poet.song.44000.json','["生死猶如臂屈伸，情鍾我輩一酸辛。", "樂天不是蓬萊客，憑仗西方作主人。"]'),
('551a2fec-1453-4cb3-bfb4-4743dcb6d494','弔天竺海月辯師三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','欲訪浮雲起滅因，無緣却見夢中身。',32,'全唐诗/poet.song.44000.json','["欲訪浮雲起滅因，無緣却見夢中身。", "安心好住王文度，此理何須更問人。"]'),
('83840da8-fcd0-4e31-b32d-101ae3586aa7','孤山二詠 柏堂','蘇軾','宋','宋诗','song-poetry','','[]','道人手種幾生前，鶴骨龍筋尚宛然。',64,'全唐诗/poet.song.44000.json','["道人手種幾生前，鶴骨龍筋尚宛然。", "雙幹一先神物化，九朝三見太平年。", "忽驚華構依巌出，乞與佳名到處傳。", "此柏未枯君記取，灰心聊伴小乘禪。"]'),
('0969132f-6214-4731-bfd1-3c6fe32c84dc','孤山二詠 竹閣','蘇軾','宋','宋诗','song-poetry','','[]','海山兜率兩茫然，古寺無人竹滿軒。',64,'全唐诗/poet.song.44000.json','["海山兜率兩茫然，古寺無人竹滿軒。", "白鶴不留歸後語，蒼龍猶是種時孫。", "兩叢恰似蕭郎筆，十畝空懷渭上村。", "欲把新詩問遺像，病維摩詰更無言。"]'),
('dff43259-3011-420f-aa55-96f8a3edb002','與述古自有美堂乘月夜歸','蘇軾','宋','宋诗','song-poetry','','[]','娟娟雲月稍侵軒，瀲瀲星河半隠山。',64,'全唐诗/poet.song.44000.json','["娟娟雲月稍侵軒，瀲瀲星河半隠山。", "魚鑰未收清夜永，鳳簫猶在翠微間。", "淒風瑟縮經絃柱，香霧淒迷著髻鬟。", "共喜使君能鼓樂，萬人爭看火城還。"]'),
('0a51cad5-338c-485c-91ad-bd8611418faa','有美堂暴雨','蘇軾','宋','宋诗','song-poetry','','["\u5199\u96e8", "\u8d5e\u7f8e", "\u96e8"]','遊人脚底一聲雷，滿座頑雲撥不開。',64,'全唐诗/poet.song.44000.json','["遊人脚底一聲雷，滿座頑雲撥不開。", "天外黑風吹海立，浙東飛雨過江來。", "十分瀲灧金樽凸，千杖敲鏗羯鼓催。", "喚起謫仙泉灑面，倒傾鮫室瀉瓊瑰。"]'),
('2d61dd4b-ec97-434b-bf52-36f0958f8889','八月十五日看潮五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','定知玉兔十分圓，已作霜風九月寒。',32,'全唐诗/poet.song.44000.json','["定知玉兔十分圓，已作霜風九月寒。", "寄語重門休上鑰，夜潮留向月中看。"]'),
('7e04f5aa-c40f-425f-82c5-070173c721d3','八月十五日看潮五絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','萬人鼓譟懾吳儂，猶是浮江老阿童。',32,'全唐诗/poet.song.44000.json','["萬人鼓譟懾吳儂，猶是浮江老阿童。", "欲識潮頭高幾許，越山渾在浪花中。"]'),
('178cbe5e-ac45-4053-825d-9b36bdb95fcd','八月十五日看潮五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','江邊身世兩悠悠，久與滄波共白頭。',32,'全唐诗/poet.song.44000.json','["江邊身世兩悠悠，久與滄波共白頭。", "造物亦知人易老，故教江水向西流。"]'),
('4edd9eb1-d798-4b8e-aeaa-6bf3e4cc9352','八月十五日看潮五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','吳兒生長狎濤淵，冒利輕生不自憐。',32,'全唐诗/poet.song.44000.json','["吳兒生長狎濤淵，冒利輕生不自憐。", "東海若知明主意，應教斥鹵變桑田。"]'),
('b5a45ab5-1ae1-40e2-afa7-bb4be854d41b','八月十五日看潮五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','江神河伯兩醯雞，海若東來氣吐霓。',32,'全唐诗/poet.song.44000.json','["江神河伯兩醯雞，海若東來氣吐霓。", "安得夫差水犀手，三千强弩射潮低。"]'),
('2e63e363-74fb-4ae3-a6e3-da22ba452ced','東陽水樂亭','蘇軾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','君不學白公引涇東注渭，五斗黄泥一鍾水。',152,'全唐诗/poet.song.44000.json','["君不學白公引涇東注渭，五斗黄泥一鍾水。", "又不學哥舒橫行西海頭，歸來羯鼓打凉州。", "但向空山石壁下，愛此有聲無用之清流。", "流泉無絃石無竅，强名水樂人人笑。", "慣見山僧已厭聽，多情海月空留照。", "洞庭不復來軒轅，至今魚龍舞鈞天。", "聞道磬襄東入海，遺聲恐在海山間。", "鏘然澗谷含宮徵，節奏未成君獨喜。", "不須寫入薰風絃，縱有此聲無此耳。"]'),
('2bb5aa83-f9f0-45ca-8694-763260df8899','與周長官李秀才遊徑山二君先以詩見寄次其韵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','少年飲紅裙，酒盡推不去。',96,'全唐诗/poet.song.44000.json','["少年飲紅裙，酒盡推不去。", "呼來徑山下，試與洗塵霧。", "癡馬惜障泥，臨流不肯渡。", "獨有汝南君，從我無朝暮。", "肯將紅塵脚，暫著白雲屨。", "嗟我與世人，何異笑百步。", "功名一破甑，棄置何用顧。", "更憑陶靖節，往問征夫路。"]'),
('b2c32f0d-b127-4a41-b6b2-9a364562bfc5','與周長官李秀才遊徑山二君先以詩見寄次其韵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','龍亦戀故居，百年尚來去。',96,'全唐诗/poet.song.44000.json','["龍亦戀故居，百年尚來去。", "至今雨雹夜，殿闇風纏霧。", "而我棄鄉國，大江忘北渡。", "便欲此山前，築室安遲暮。", "又恐太幽獨，歲晚霜入屨。", "同遊得李生，仄足隨蹇步。", "孔明不自愛，臨老起三顧。", "吾歸便却掃，誰踏門前路。"]'),
('878a1672-228d-4d44-ba5d-23da8ccb6a16','臨安三絕 將軍樹','蘇軾','宋','宋诗','song-poetry','','[]','阿堅澤畔菰蒲節，玄德牆頭羽葆桑。',32,'全唐诗/poet.song.44000.json','["阿堅澤畔菰蒲節，玄德牆頭羽葆桑。", "不會世間閑草木，與人何事管興亡。"]'),
('8df1b73b-63fa-45f4-81eb-3f29ddb9e60b','臨安三絕 錦溪','蘇軾','宋','宋诗','song-poetry','','[]','楚人休笑沐猴冠，越俗徒誇翁子賢。',32,'全唐诗/poet.song.44000.json','["楚人休笑沐猴冠，越俗徒誇翁子賢。", "五百年間異人出，盡將錦繡裹山川。"]'),
('e552714b-54c5-47ec-8d48-e42c13d7ee68','臨安三絕 石鏡','蘇軾','宋','宋诗','song-poetry','','[]','山雞舞破半巌雲，菱葉開殘野水春。',32,'全唐诗/poet.song.44000.json','["山雞舞破半巌雲，菱葉開殘野水春。", "應笑武都山下土，枉教明月殉佳人。"]'),
('921028a0-a3e7-4752-9537-77e8762426d9','登玲瓏山','蘇軾','宋','宋诗','song-poetry','','[]','何年僵立兩蒼龍，瘦脊盤盤尚倚空。',64,'全唐诗/poet.song.44000.json','["何年僵立兩蒼龍，瘦脊盤盤尚倚空。", "翠浪舞翻紅罷亞，白雲穿破碧玲瓏。", "三休亭上工延月，九折巌前巧貯風。", "脚力盡時山更好，莫將有限趁無窮。"]'),
('f8cdc692-0b0c-4896-bc08-758e0929ebd3','宿九仙山','蘇軾','宋','宋诗','song-poetry','','[]','風流王謝古仙真，一去空山五百春。',64,'全唐诗/poet.song.44000.json','["風流王謝古仙真，一去空山五百春。", "玉室金堂餘漢士，桃花流水失秦人。", "困眠一榻香凝帳，夢遶千巌冷逼身。", "夜半老僧呼客起，雲峰缺處湧冰輪。"]'),
('dc72058d-a702-4082-b77d-37b53d6b3771','陌上花三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','陌上花開蝴蝶飛，江山猶是昔人非。',32,'全唐诗/poet.song.44000.json','["陌上花開蝴蝶飛，江山猶是昔人非。", "遺民幾度垂垂老，遊女長歌緩緩歸。"]'),
('9d3441aa-f4bf-4ffe-8541-190d96f4ef11','陌上花三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','陌上山花無數開，路人爭看翠軿來。',32,'全唐诗/poet.song.44000.json','["陌上山花無數開，路人爭看翠軿來。", "若爲留得堂堂去，且更從教緩緩回。"]'),
('415b5905-a9e4-4e0e-9d03-94260e7e37e2','陌上花三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','生前富貴草頭露，身後風流陌上花。',32,'全唐诗/poet.song.44000.json','["生前富貴草頭露，身後風流陌上花。", "已作遲遲君去魯，猶教緩緩妾還家。"]'),
('ce67b430-5aaf-498f-89be-ec0f7a287fa2','遊東西巌','蘇軾','宋','宋诗','song-poetry','','[]','謝公含雅量，世運屬艱難。',144,'全唐诗/poet.song.44000.json','["謝公含雅量，世運屬艱難。", "況復情所鍾，感概萃中年。", "正頼絲與竹，陶寫有餘歡。", "嘗恐兒輩覺，坐令高趣闌。", "獨携縹緲人，來上東西山。", "放懷事物外，徙倚弄雲泉。", "一旦功業成，管蔡復流言。", "慷慨桓野王，哀歌和清彈。", "挽鬚起流涕，始知使君賢。", "意長日月促，卧病已辛酸。", "慟哭西州門，往駕那復還。", "空餘行樂處，古木昏蒼煙。"]'),
('f9f95556-0bbf-4196-a962-fd73516afea7','宿海會寺','蘇軾','宋','宋诗','song-poetry','','[]','籃輿三日山中行，山中信美少曠平。',128,'全唐诗/poet.song.44000.json','["籃輿三日山中行，山中信美少曠平。", "下投黄泉上青冥，線路每與猿狖爭。", "重樓束縛遭澗坑，兩股酸哀饑腸鳴。", "北渡飛橋踏彭鏗，繚垣百步如古城。", "大鐘橫撞千指迎，高堂延客夜不扃。", "杉槽漆斛江河傾，本來無垢洗更輕。", "倒牀鼻息四鄰驚，紞如五鼓天未明。", "木魚呼粥亮且清，不聞人聲聞履聲。"]'),
('8b849390-2982-494b-9b13-bdbbcbcad207','徑山道中次韵答周長官兼贈蘇寺丞','蘇軾','宋','宋诗','song-poetry','','[]','年來戰紛華，漸覺夫子勝。',288,'全唐诗/poet.song.44000.json','["年來戰紛華，漸覺夫子勝。", "欲求五畝宅，灑掃樂清浄。", "學道恨日淺，問禪慚聽瑩。", "聊爲山水行，遂此麋鹿性。", "獨遊吾未果，覓伴誰復聽。", "吾宗古遺直，窮達付前定。", "餔糟醉方熟，灑面呼不醒。", "奈何效燕蝠，屢欲爭晨暝。", "不如從我遊，高論發犀柄。", "溪南渡橫木，山寺稱小徑。", "幽尋自茲始，歸路微月映。", "南望功臣山，雲外盤飛磴。", "三更渡錦水，再宿留石鏡。", "緬懷周與李，能作洛生詠。", "明朝三子至，詩律嚴號令。", "籃輿置紙筆，得句輕千乘。", "玲瓏苦奇秀，名實巧相稱。", "九仙更幽絕，笑語千山應。", "空巌側破甕，飛溜灑浮磬。", "山前見虎迹，候吏鐃鼓競。", "我生本艱奇，塵土滿釜甑。", "山禽與野獸，知我久蹭蹬。", "笑謂候吏還，遇虎我有命。", "徑山雖云遠，行李稍可併。"]'),
('7ff46773-8303-4a87-88b5-eb7b17d4b5e1','汪覃秀才久留山中以詩見寄次其韵','蘇軾','宋','宋诗','song-poetry','','[]','季子應嗔不下機，棄家來伴碧雲師。',64,'全唐诗/poet.song.44000.json','["季子應嗔不下機，棄家來伴碧雲師。", "中秋冷坐無因醉，半月長齋未肯辭。", "擲簡摇毫無忤色，投名入社有新詩。", "飛騰桂籍他年事，莫忘山中採藥時。"]'),
('53bdd191-47cf-46be-8dca-81333edd6179','再遊徑山','蘇軾','宋','宋诗','song-poetry','','[]','老人登山汗如濯，倒床困卧呼不覺。',224,'全唐诗/poet.song.44000.json','["老人登山汗如濯，倒床困卧呼不覺。", "覺來五鼓日三竿，始信孤雲天一握。", "平生未省出艱險，兩足慣曾行犖确。", "含暉亭上望東溟，淩霄峰頭挹南岳。", "共愛絲杉翠絲亂，誰見玉芝紅玉琢。", "白雲何事自來往，明月長圓無晦朔。", "冢上雞鳴猶憶欽，山前鳳舞遠徵璞。", "雪窗馴兔元不死，煙嶺孤猿苦難捉。", "從來白足傲生死，不怕黄巾把刀槊。", "榻上雙痕凜然在，劍頭一鷄何須角。", "嗟我昏頑晚聞道，與世齟齬空多學。", "靈水先除眼界花，清詩爲洗心源濁。", "騷人未要逃競病，禪老但喜聞剝啄。", "此生更得幾回來，從今有暇無辭數。"]'),
('e0d991b8-3b11-4f8c-8a1e-3a2c9029fcc3','洞霄宮','蘇軾','宋','宋诗','song-poetry','','[]','上帝高居愍世頑，故留瓊館在凡間。',64,'全唐诗/poet.song.44000.json','["上帝高居愍世頑，故留瓊館在凡間。", "青山九鎖不易到，作者七人相對閑。", "庭下流泉翠蛟舞，洞中飛鼠白鴉翻。", "長松怪石宜霜鬢，不用金丹苦駐顔。"]'),
('54c1a98b-a160-462e-8a31-ed58ba00ff4c','初自徑山歸述古召飲介亭以病先起','蘇軾','宋','宋诗','song-poetry','','[]','西風初作十分凉，喜見新橙透甲香。',64,'全唐诗/poet.song.44000.json','["西風初作十分凉，喜見新橙透甲香。", "遲暮賞心驚節物，登臨病眼怯秋光。", "慣眠處士雲庵裏，倦醉佳人錦瑟傍。", "猶有夢回清興在，卧聞歸路樂聲長。"]'),
('39a5c3a8-73b5-4126-a1d1-1ea1a451e966','明日重九亦以病不赴述古會再用前韵','蘇軾','宋','宋诗','song-poetry','','[]','月入秋幃病枕凉，霜飛夜簟故衾香。',64,'全唐诗/poet.song.44000.json','["月入秋幃病枕凉，霜飛夜簟故衾香。", "可憐吹帽狂司馬，空對親舂老孟光。", "不作雍容傾坐上，翻成骯髒倚門傍。", "人間此會論今古，細看茱萸感歎長。"]'),
('01111af6-fd6b-43a7-934b-b299b49c4688','九日尋臻闍黎遂泛小舟至勤師院二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','白髮長嫌歲月侵，病眸兼怕酒杯深。',64,'全唐诗/poet.song.44000.json','["白髮長嫌歲月侵，病眸兼怕酒杯深。", "南屏老宿閑相過，東閣郎君懶重尋。", "試碾露芽烹白雪，休拈霜蕊嚼黄金。", "扁舟又截平湖去，欲訪孤山支道林。"]'),
('e488e87a-8cdb-41e8-a291-b0177440ab6a','九日尋臻闍黎遂泛小舟至勤師院二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','湖上青山翠作堆，葱葱鬰鬰氣佳哉。',64,'全唐诗/poet.song.44000.json','["湖上青山翠作堆，葱葱鬰鬰氣佳哉。", "笙歌叢裏抽身出，雲水光中洗眼來。", "白足赤髭迎我笑，拒霜黄菊爲誰開。", "明年桑苧煎茶處，憶著衰翁首重回。"]'),
('4489a9b1-73d9-4ecc-89b7-707d14917ba4','九日舟中望見有美堂上魯少卿飲以詩戲之二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','指點雲間數點紅，笙歌正擁紫髯翁。',32,'全唐诗/poet.song.44000.json','["指點雲間數點紅，笙歌正擁紫髯翁。", "誰知愛酒龍山客，却在漁舟一葉中。"]'),
('ecca23b3-219d-4477-bbca-343b1e807dcc','九日舟中望見有美堂上魯少卿飲以詩戲之二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','西閣珠簾卷落暉，水沉煙斷珮聲微。',32,'全唐诗/poet.song.44000.json','["西閣珠簾卷落暉，水沉煙斷珮聲微。", "遥知通德淒涼甚，擁髻無言怨未歸。"]'),
('4eb04d66-6a5f-4b5f-995a-a01ca550e02f','遊諸佛舍一日飲釅茶七盞戲書勤師壁','蘇軾','宋','宋诗','song-poetry','','[]','示病維摩元不病，在家靈運已忘家。',32,'全唐诗/poet.song.44000.json','["示病維摩元不病，在家靈運已忘家。", "何須魏帝一丸藥，且盡盧仝七碗茶。"]'),
('e0fc4d33-9642-4161-927a-aca74ceaa9f7','九日湖上尋周李二君不見君亦見尋於湖上以詩見寄明日乃次其韵','蘇軾','宋','宋诗','song-poetry','','[]','湖上野芙蓉，含思愁脈脈。',120,'全唐诗/poet.song.44000.json','["湖上野芙蓉，含思愁脈脈。", "娟然如靜女，不肯傍阡陌。", "詩人杳未來，霜艷冷難宅。", "君行逐鷗鷺，出處浩莫測。", "葦問聞拏音，雲表已飛屐。", "使我終日尋，逢花不忍摘。", "人生如朝露，要作百年客。", "喟彼終歲勞，幸茲一日澤。", "願言竟不遂，人事多乖隔。", "悟此知有命，沉憂傷魂魄。"]'),
('f317416d-021a-4f0d-af8e-f7dc1059ee25','送杭州杜戚陳三掾罷官歸鄉','蘇軾','宋','宋诗','song-poetry','','[]','秋風摵摵鳴枯蓼，船閣荒村夜悄悄。',128,'全唐诗/poet.song.44000.json','["秋風摵摵鳴枯蓼，船閣荒村夜悄悄。", "正當逐客斷腸時，君獨歌呼醉連曉。", "老夫平生齊得喪，尚戀微官失輕矯。", "君今憔悴歸無食，五斗未可秋毫小。", "君言失意能幾時，月啖蝦蟆行復皎。", "殺人無驗中不快，此恨終身恐難了。", "徇時所得無幾何，隨手已遭憂患繞。", "期君正似種宿麥，忍饑待食明年麨。"]'),
('c838d8ef-3eff-491d-bce1-0ac041226660','元翰少卿寵惠谷簾水一器龍團二枚仍以新詩爲貺歎味不已次韵奉和','蘇軾','宋','宋诗','song-poetry','','[]','巌垂匹練千絲落，雷起雙龍萬物春。',32,'全唐诗/poet.song.44000.json','["巌垂匹練千絲落，雷起雙龍萬物春。", "此水此茶俱第一，共成三絕鑑中人。"]'),
('d66e0701-274a-47fa-b18d-160cd4cae6df','次韵周長官壽星院同餞魯少卿','蘇軾','宋','宋诗','song-poetry','','[]','琉璃百頃水仙家，風靜湖平響釣車。',64,'全唐诗/poet.song.44000.json','["琉璃百頃水仙家，風靜湖平響釣車。", "寂歷疏松敧晚照，伶俜寒蝶抱秋花。", "困眠不覺依蒲褐，歸路相將踏桂華。", "更著綸巾披鶴氅，他年應作畫圖誇。"]'),
('a557ea5e-f0f4-413a-afa7-32f264154151','次韵述古過周長官夜飲','蘇軾','宋','宋诗','song-poetry','','[]','二更鐃鼓動諸鄰，百首新詩間八珍。',64,'全唐诗/poet.song.44000.json','["二更鐃鼓動諸鄰，百首新詩間八珍。", "已遣亂蛙成兩部，更邀明月作三人。", "雲煙湖寺家家境，燈火沙河夜夜春。", "曷不勸公勤秉燭，老來光景似奔輪。"]'),
('1fe42e52-a504-4e23-9427-b38e6a064665','述古以詩見責屢不赴會復次前韵','蘇軾','宋','宋诗','song-poetry','','[]','我生孤僻本無鄰，老病年來益自珍。',64,'全唐诗/poet.song.44000.json','["我生孤僻本無鄰，老病年來益自珍。", "肯對紅裙辭白酒，但愁新進笑陳人。", "北山怨鶴休驚夜，南畝巾車欲及春。", "多謝清時屢推轂，狶膏那解轉方輪。"]'),
('3f0708de-4622-4c22-b00a-bf5cad07e530','胡穆秀才遺古銅器似鼎而小上有兩柱可以覆而不蹶以爲鼎則不足疑其飲器也胡有詩答之','蘇軾','宋','宋诗','song-poetry','','[]','隻耳獸齧環，長唇鵝擘喙。',88,'全唐诗/poet.song.44000.json','["隻耳獸齧環，長唇鵝擘喙。", "三趾下銳春蒲短，兩柱高張秋菌細。", "君看翻覆俯仰間，覆成三角翻兩髻。", "古書雖滿腹，苟有用我亦隨世。", "嗟君一見呼作鼎，纔注升合已漂逝。", "不如學鴟夷，盡日盛酒真良計。"]'),
('8fbc1b8b-bd5f-4a0b-b3ce-f31fbf4b8327','賀陳述古弟章生子','蘇軾','宋','宋诗','song-poetry','','[]','鬰葱佳氣夜充閭，始見徐卿第二雛。',64,'全唐诗/poet.song.44000.json','["鬰葱佳氣夜充閭，始見徐卿第二雛。", "甚欲去爲湯餠客，惟愁錯寫弄麞書。", "參軍新婦賢相敵，阿大中郎喜有餘。", "我亦從來識英物，試教啼看定何如。"]'),
('61085e05-138b-466d-bea0-028a96de3bb4','贈治易僧智周','蘇軾','宋','宋诗','song-poetry','','[]','寒窗孤坐凍生瓶，尚把遺編照露螢。',64,'全唐诗/poet.song.44000.json','["寒窗孤坐凍生瓶，尚把遺編照露螢。", "閣束九師新得妙，夢吞三畫舊通靈。", "斷弦挂壁知音喪，揮麈空山亂石聽。", "齋罷何須更臨水，胸中自有洗心經。"]'),
('9436c3b1-b935-44b3-b659-1824528ac929','張子野年八十五尚聞買妾述古令作詩','蘇軾','宋','宋诗','song-poetry','','[]','錦里先生自笑狂，莫欺九尺鬢眉蒼。',64,'全唐诗/poet.song.44000.json','["錦里先生自笑狂，莫欺九尺鬢眉蒼。", "詩人老去鶑鶑在，公子歸來燕燕忙。", "柱下相君猶有齒，江南刺史已無腸。", "平生謬作安昌客，略遣彭宣到後堂。"]'),
('74c28ec2-deda-439d-b3ac-d2f043c54f65','書雙竹湛師房二首  其一','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','我本西湖一釣舟，意嫌高屋冷颼颼。',32,'全唐诗/poet.song.44000.json','["我本西湖一釣舟，意嫌高屋冷颼颼。", "羨師此室纔方丈，一炷清香盡日留。"]'),
('9aa36a27-a1ef-4bf2-a790-eb0949b8bfd5','書雙竹湛師房二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','暮鼓朝鐘自擊撞，閉門孤枕對殘缸。',32,'全唐诗/poet.song.44000.json','["暮鼓朝鐘自擊撞，閉門孤枕對殘缸。", "白灰旋撥通紅火，卧聽蕭蕭雨打窗。"]'),
('885ae34e-13b5-4f81-8511-51f22b1cba7a','寶山新開徑','蘇軾','宋','宋诗','song-poetry','','[]','藤梢橘刺元無路，竹杖椶鞋不用扶。',64,'全唐诗/poet.song.44000.json','["藤梢橘刺元無路，竹杖椶鞋不用扶。", "風自遠來聞笑語，水分流處見江湖。", "回觀佛國青螺髻，踏遍仙人碧玉壺。", "野客歸時山月上，棠梨葉戰暝禽呼。"]'),
('9b42368c-5533-488a-942b-9636589801cb','和述古冬日牡丹四首  其一','蘇軾','宋','宋诗','song-poetry','','[]','一朵妖紅翠欲流，春光回照雪霜羞。',32,'全唐诗/poet.song.44000.json','["一朵妖紅翠欲流，春光回照雪霜羞。", "化工只欲呈新巧，不放閑花得少休。"]'),
('ca2b0fa2-c4b5-4793-92ce-f1745ef85d25','和述古冬日牡丹四首  其二','蘇軾','宋','宋诗','song-poetry','','[]','花開時節雨連風，却向霜餘染爛紅。',32,'全唐诗/poet.song.44000.json','["花開時節雨連風，却向霜餘染爛紅。", "漏洩春光私一物，此心未信出天工。"]'),
('9b4aa5d9-d53d-4180-9544-2fb58e5b0818','和述古冬日牡丹四首  其三','蘇軾','宋','宋诗','song-poetry','','[]','當時只道鶴林仙，解遣秋光發杜鵑。',32,'全唐诗/poet.song.44000.json','["當時只道鶴林仙，解遣秋光發杜鵑。", "誰信詩能回造化，直教霜枿放春妍。"]'),
('e8005659-f1b9-4af9-b519-7c0b75f68303','和述古冬日牡丹四首  其四','蘇軾','宋','宋诗','song-poetry','','[]','不分清霜入小園，故將詩律變寒暄。',32,'全唐诗/poet.song.44000.json','["不分清霜入小園，故將詩律變寒暄。", "使君欲見藍關詠，更倩韓郎爲染根。"]'),
('c55be576-62b8-4ebb-b391-2c35d9c7b159','和柳子玉喜雪次韵仍呈述古','蘇軾','宋','宋诗','song-poetry','','[]','詩翁愛酒常如渴，瓶盡欲沽囊已竭。',112,'全唐诗/poet.song.44000.json','["詩翁愛酒常如渴，瓶盡欲沽囊已竭。", "燈青火冷不成眠，一夜撚鬚吟喜雪。", "詩成就我覓歡處，我窮正與君彷彿。", "曷不走投陳孟公，有酒醉君仍飽德。", "瓊瑶欲盡天應惜，更遣清光續殘月。", "安得佳人擢素手，笑捧玉碗兩奇絕。", "艷歌一曲回陽春，坐使高堂生暖熱。"]'),
('ac2a0b81-200f-426e-bba8-657dfeee2349','觀子玉郎中草聖','蘇軾','宋','宋诗','song-poetry','','[]','柳侯運筆如電閃，子雲寒悴羊欣儉。',32,'全唐诗/poet.song.44000.json','["柳侯運筆如電閃，子雲寒悴羊欣儉。", "百斛明珠便可扛，此書非我誰能雙。"]'),
('21eb578a-aafa-4d33-9888-d826c5f372c7','李頎秀才善畫山以兩軸見寄仍有詩次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','平生自是箇中人，欲向漁舟便寫真。',64,'全唐诗/poet.song.44000.json','["平生自是箇中人，欲向漁舟便寫真。", "詩句對君難出手，雲泉勸我早抽身。", "年來白髮驚秋速，長恐青山與世新。", "從此北歸休悵望，囊中收得武陵春。"]'),
('88e280b9-959d-4b85-a25b-251bcf935c74','雪後至臨平與柳子玉同至僧舍見陳尉烈','蘇軾','宋','宋诗','song-poetry','','[]','落帆古戍下，積雪高如丘。',96,'全唐诗/poet.song.44000.json','["落帆古戍下，積雪高如丘。", "强邀詩老出，疏髯散颼飀。", "僧房有宿火，手足漸和柔。", "靜士素寡言，相對自忘憂。", "銅爐擢烟穗，石鼎浮霜漚。", "征夫念前路，急鼓催行舟。", "我行雖有程，坐穩且復留。", "大哉天地間，此生得浮遊。"]'),
('7e2b9c35-a8a6-4160-862e-f07bbee0cbee','夜至永樂文長老院文時卧病退院','蘇軾','宋','宋诗','song-poetry','','[]','夜聞巴叟卧荒村，來打三更月下門。',64,'全唐诗/poet.song.44000.json','["夜聞巴叟卧荒村，來打三更月下門。", "往事過年如昨日，此身未死得重論。", "老非懷土情相得，病不開堂道益尊。", "惟有孤棲舊時鶴，舉頭見客似長言。"]'),
('ca80195e-f914-4bc8-905d-38c8a9a4d32a','和錢安道寄惠建茶','蘇軾','宋','宋诗','song-poetry','','[]','我官於南今幾時，嘗盡溪茶與山茗。',256,'全唐诗/poet.song.44000.json','["我官於南今幾時，嘗盡溪茶與山茗。", "胸中似記故人面，口不能言心自省。", "爲君細說我未暇，試評其略差可聽。", "建溪所産雖不同，一一天與君子性。", "森然可愛不可慢，骨清肉膩和且正。", "雪花雨脚何足道，啜過始知真味永。", "縱復苦硬終可錄，汲黯少戇寬饒猛。", "草茶無頼空有名，高者妖邪次頑懭。", "體輕雖復强浮沉，性滯偏工嘔酸冷。", "其間絕品豈不佳，張禹縱賢非骨鯁。", "葵花玉𩊓不易致，道路幽險隔雲嶺。", "誰知使者來自西，開緘磊落收百餠。", "嗅香嚼味本非別，透紙自覺光炯炯。", "粃糠團鳳友小龍，奴隸日注臣雙井。", "收藏愛惜待佳客，不敢包裹鑽權倖。", "此詩有味君勿傳，空使時人怒生癭。"]'),
('bd9d7cc8-3aba-457a-bcac-784911499ab9','錢安道席上令歌者道服','蘇軾','宋','宋诗','song-poetry','','[]','烏府先生鐵作肝，霜風捲地不知寒。',64,'全唐诗/poet.song.44000.json','["烏府先生鐵作肝，霜風捲地不知寒。", "猶嫌白髮年前少，故點紅燈雪裏看。", "他日卜鄰先有約，待君投劾我休官。", "如今且作華陽服，醉唱儂家七返丹。"]'),
('eef2a0c5-25c3-407a-9528-01bfa922d9b1','惠山謁錢道人烹小龍團登絕頂望太湖','蘇軾','宋','宋诗','song-poetry','','["\u592a\u6e56"]','踏遍江南南岸山，逢山未免更流連。',64,'全唐诗/poet.song.44000.json','["踏遍江南南岸山，逢山未免更流連。", "獨携天上小團月，來試人間第二泉。", "石路縈回九龍脊，水光翻動五湖天。", "孫登無語空歸去，半嶺松聲萬壑傳。"]'),
('14e3ccfb-1e86-4609-883a-ddaa81c88ab7','除夜野宿常州城外二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','行歌野哭兩堪悲，遠火低星漸向微。',64,'全唐诗/poet.song.44000.json','["行歌野哭兩堪悲，遠火低星漸向微。", "病眼不眠非守歲，鄉音無伴苦思歸。", "重衾脚冷知霜重，新沐頭輕感髮稀。", "多謝殘燈不嫌客，孤舟一夜許相依。"]'),
('7c46a74e-8f6c-4e85-9142-dc6ac161d1dd','除夜野宿常州城外二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','南來三見歲云徂，直恐終身走道途。',64,'全唐诗/poet.song.44000.json','["南來三見歲云徂，直恐終身走道途。", "老去怕看新曆日，退歸擬學舊桃符。", "烟花已作青春意，霜雪偏尋病客鬚。", "但把窮愁博長健，不辭最後飲屠蘇。"]'),
('6f6931f8-fcf5-4428-936e-f9876b1f5654','元日過丹陽明日立春寄魯元翰','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','堆盤紅縷細茵陳，巧與椒花兩鬬新。',64,'全唐诗/poet.song.44000.json','["堆盤紅縷細茵陳，巧與椒花兩鬬新。", "竹馬異時寧信老，土牛明日莫辭春。", "西湖弄水猶應早，北寺觀燈欲及辰。", "白髮蒼顔誰肯記，曉來頻嚏爲何人。"]'),
('d2f02f70-ba62-4eaf-ba6b-ff1836ab00fe','古纏頭曲','蘇軾','宋','宋诗','song-poetry','','[]','鵾弦鐵撥世無有，樂府舊工惟尚叟。',160,'全唐诗/poet.song.44000.json','["鵾弦鐵撥世無有，樂府舊工惟尚叟。", "一生喙硬眼無人，坐此困窮今白首。", "翠鬟女子年十七，指法已似呼韓婦。", "輕帆渡海風掣回，滿面塵沙和淚垢。", "青衫不逢湓浦客，紅袖漫插曹綱手。", "爾來一見哀駘佗，便著臂韝躬井臼。", "我慚貧病百不足，强對黄花飲白酒。", "轉關濩索動有神，雷輥空堂戰窗牖。", "四弦一抹擁袂立，再拜十分爲我壽。", "世人只解錦纏頭，與汝作詩傳不朽。"]'),
('87da270b-7274-4ace-98f3-8c3590241284','刁同年草堂','蘇軾','宋','宋诗','song-poetry','','[]','不用長竿矯繡衣，南園北第兩參差。',64,'全唐诗/poet.song.44000.json','["不用長竿矯繡衣，南園北第兩參差。", "青山有約長當戶，流水無情自入池。", "歲久酴醾渾欲合，春來楊柳不勝垂。", "主人不用匆匆去，正是紅梅著子時。"]'),
('da41136b-959f-4340-ba9e-f6401721af5c','刁景純賞瑞香花憶先朝侍宴次韵','蘇軾','宋','宋诗','song-poetry','','[]','上苑夭桃自作行，劉郎去後幾回芳。',64,'全唐诗/poet.song.44000.json','["上苑夭桃自作行，劉郎去後幾回芳。", "厭從年少追新賞，閑對宮花識舊香。", "欲贈佳人非泛洧，好紉幽佩弔沉湘。", "鶴林神女無消息，爲問何年返帝鄉。"]'),
('356c91fd-6bd0-4189-8c53-d39d1f480da0','同柳子玉遊鶴林招隠醉歸呈景純','蘇軾','宋','宋诗','song-poetry','','[]','花時臘酒照人光，歸路春風灑面凉。',64,'全唐诗/poet.song.44000.json','["花時臘酒照人光，歸路春風灑面凉。", "劉氏宅邊霜竹老，戴公山下野桃香。", "巌頭匹練兼天浄，泉底真珠濺客忙。", "安得道人携笛去，一聲吹裂翠崖岡。"]'),
('e9d42cef-2124-4115-9931-7fb41bb2bff5','景純見和復次韵贈之二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','解組歸來道益光，坐看百物自炎凉。',64,'全唐诗/poet.song.44000.json','["解組歸來道益光，坐看百物自炎凉。", "捲簾堂上檀槽鬧，送客林間樺燭香。", "淺量已愁當酒怯，非才猶覺和詩忙。", "何人貪佩黄金印，千柱耽耽瑣北岡。"]'),
('e9fef570-12e1-4376-82fb-7f32bc525179','景純見和復次韵贈之二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','人間膏火正爭光，每到藏春得暫凉。',64,'全唐诗/poet.song.44000.json','["人間膏火正爭光，每到藏春得暫凉。", "多事始知田舍好，凶年偏覺野蔬香。", "溪山勝畫徒能說，來往如梭爲底忙。", "老去此身無處著，爲翁栽插萬松岡。"]'),
('990e39fc-4777-4fc5-95ae-19f948d6beb5','柳子玉亦見和因以送之兼寄其兄子璋道人','蘇軾','宋','宋诗','song-poetry','','[]','不羨腰金照地光，暫時假面弄西凉。',64,'全唐诗/poet.song.44000.json','["不羨腰金照地光，暫時假面弄西凉。", "晴窗嚥日肝腸暖，古殿朝真屨袖香。", "說靜故知猶有動，無閑底處更求忙。", "先生官罷乘風去，何用區區賦陟岡。"]'),
('5c8c95fc-d335-4f10-8628-08c9bc47f283','子玉家宴用前韵見寄復答之','蘇軾','宋','宋诗','song-poetry','','[]','自酌金樽勸孟光，更教長笛奏伊凉。',64,'全唐诗/poet.song.44000.json','["自酌金樽勸孟光，更教長笛奏伊凉。", "牽衣男女遶太白，扇枕郎君煩阿香。", "詩病逢春轉深痼，愁魔得酒暫奔忙。", "醒時情味吾能說，日在西南白草岡。"]'),
('3131d645-e7b0-42c0-8b4a-01d253046efb','景純復以二篇一言其亡兄與伯父同年之契一言今者唱酬之意仍次其韵  其一','蘇軾','宋','宋诗','song-poetry','','[]','靈壽扶來似孔光，感時懷舊一悲凉。',64,'全唐诗/poet.song.44000.json','["靈壽扶來似孔光，感時懷舊一悲凉。", "蟾枝不獨同攀桂，雞舌還應共賜香。", "等是浮休無得喪，粗分憂樂有閑忙。", "年來世事如波浪，鬰鬰誰知柏在岡。"]'),
('b28d7bac-3f92-40ed-89ff-4361df31733f','景純復以二篇一言其亡兄與伯父同年之契一言今者唱酬之意仍次其韵  其二','蘇軾','宋','宋诗','song-poetry','','[]','屢把鉛刀齒步光，更遭華衮照厖凉。',64,'全唐诗/poet.song.44000.json','["屢把鉛刀齒步光，更遭華衮照厖凉。", "蘇門山上莫長嘯，薝蔔林中無別香。", "燭燼已殘終夜刻，槐花還似昔年忙。", "背城借一吾何敢，慎莫樽前替戾岡。"]'),
('3ee865d7-de7b-4af1-86c9-cb4064c5df57','柳氏二外甥求筆跡二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','退筆如山未足珍，讀書萬卷始通神。',32,'全唐诗/poet.song.44000.json','["退筆如山未足珍，讀書萬卷始通神。", "君家自有元和脚，莫厭家雞更問人。"]'),
('2e1c498f-fcf6-4c4c-ba3e-551ec6a50068','柳氏二外甥求筆跡二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','一紙行書兩絕詩，遂良鬚鬢已成絲。',32,'全唐诗/poet.song.44000.json','["一紙行書兩絕詩，遂良鬚鬢已成絲。", "何當火急傳家法，欲見誠懸筆諫時。"]'),
('93a17c44-7ff4-43a0-854b-1bbd9d0e0623','成都進士杜暹伯升出家名法通往來吳中','蘇軾','宋','宋诗','song-poetry','','[]','欲識當年杜伯升，飄然雲水一孤僧。',32,'全唐诗/poet.song.44000.json','["欲識當年杜伯升，飄然雲水一孤僧。", "若教俯首隨韁鎖，料得如今似我能。"]'),
('4901ed30-1e37-4723-9d66-17c998aca2a0','子玉以詩見邀同刁丈遊金山','蘇軾','宋','宋诗','song-poetry','','[]','君年甲子未相逢，難向人前說老翁。',32,'全唐诗/poet.song.44000.json','["君年甲子未相逢，難向人前說老翁。", "更有方瞳八十一，奮衣矍鑠走山中。"]'),
('905b37a7-2b64-42ed-a719-f3051a08acba','金山寺與柳子玉飲大醉卧寶覺禪榻夜分方醒書其壁','蘇軾','宋','宋诗','song-poetry','','[]','惡酒如惡人，相攻劇刀箭。',72,'全唐诗/poet.song.44000.json','["惡酒如惡人，相攻劇刀箭。", "頹然一榻上，勝之以不戰。", "詩翁氣雄拔，禪老語清軟。", "我醉都不知，但覺紅綠眩。", "醒時江月墮，摵摵風響變。", "惟有一龕燈，二豪俱不見。"]'),
('706e235c-a234-4116-b946-f12830d6524f','送柳子玉赴靈仙','蘇軾','宋','宋诗','song-poetry','','[]','世事方艱便猛迴，此心未老已先灰。',32,'全唐诗/poet.song.44000.json','["世事方艱便猛迴，此心未老已先灰。", "何時夢入真君殿，也學傳呼觀主來。"]'),
('daf49c42-6bab-4bc9-b2c5-257fee775478','監洞霄宮俞康直郎中所居四詠 退圃','蘇軾','宋','宋诗','song-poetry','','[]','百丈休牽上瀨船，一鈎歸釣縮頭鯿。',32,'全唐诗/poet.song.44000.json','["百丈休牽上瀨船，一鈎歸釣縮頭鯿。", "園中草木春無數，只有黄楊厄閏年。"]'),
('2b9d4c24-9676-4902-a02d-c3895bb4f1be','監洞霄宮俞康直郎中所居四詠 逸堂','蘇軾','宋','宋诗','song-poetry','','[]','新第誰來作並鄰，舊官寧復憶星辰。',32,'全唐诗/poet.song.44000.json','["新第誰來作並鄰，舊官寧復憶星辰。", "請君置酒吾當賀，知向江湖拜散人。"]'),
('da1fe2d1-ee2d-483a-895b-0eb03016f177','監洞霄宮俞康直郎中所居四詠 遯軒','蘇軾','宋','宋诗','song-poetry','','[]','冠蓋相望起隠淪，先生那得老江村。',32,'全唐诗/poet.song.44000.json','["冠蓋相望起隠淪，先生那得老江村。", "古來真遯何曾遯，笑殺喻垣與閉門。"]'),
('b1fc66cb-c0a2-40cb-afdf-a6e9071e1b91','監洞霄宮俞康直郎中所居四詠 遠樓','蘇軾','宋','宋诗','song-poetry','','[]','西山烟雨捲疏簾，北戶星河落短檐。',32,'全唐诗/poet.song.44000.json','["西山烟雨捲疏簾，北戶星河落短檐。", "不獨江天解空闊，地偏心遠似陶潛。"]'),
('9301a001-72ad-48c2-8428-a3c71439e257','遊鶴林招隠二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','郊原雨初霽，春物有餘妍。',48,'全唐诗/poet.song.44000.json','["郊原雨初霽，春物有餘妍。", "古寺滿修竹，深林聞杜鵑。", "睡餘柳花墮，目眩山櫻然。", "西窗有病客，危坐看香烟。"]'),
('5428694a-9ab4-4873-bda2-db6eee8f1f17','遊鶴林招隠二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','行歌白雲嶺，坐詠修竹林。',48,'全唐诗/poet.song.44000.json','["行歌白雲嶺，坐詠修竹林。", "風輕花自落，日薄山半陰。", "澗草誰復識，聞香杳難尋。", "時見城市人，幽居惜未深。"]'),
('ab0f28dc-3582-4426-aac3-d9a62656d5a4','書普慈長老壁','蘇軾','宋','宋诗','song-poetry','','[]','普慈寺後千竿竹，醉裏曾看碧玉椽。',64,'全唐诗/poet.song.44000.json','["普慈寺後千竿竹，醉裏曾看碧玉椽。", "倦客再遊行老矣，高僧一笑故依然。", "久參白足知禪味，苦厭黄公聒晝眠。", "惟有兩株紅百葉，晚來猶得向人妍。"]'),
('9a5a1181-2b46-4ba1-9a61-e20d7731e1f7','刁景純席上和謝生二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','悞入仙人碧玉壺，一歡那復問親疏。',64,'全唐诗/poet.song.44000.json','["悞入仙人碧玉壺，一歡那復問親疏。", "杯盤狼藉吾何敢，車騎雍容子甚都。", "此夜新聲聞北里，他年故事記南徐。", "欲窮風月三千界，願化天人百億軀。"]'),
('3d4af07b-6e2e-401a-9b74-d22f2c0d62c7','刁景純席上和謝生二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','縱飲誰能問挈壺，不知門外曉星疏。',64,'全唐诗/poet.song.44000.json','["縱飲誰能問挈壺，不知門外曉星疏。", "綺羅勝事齊三閣，賓主談鋒敵兩都。", "榻畔烟花嘗歎杜，海中童丱尚追徐。", "無多酌我君須聽，醉後粗狂膽滿軀。"]'),
('8aefbdb7-4c0a-4bed-af41-6a9b0137d238','和蘇州太守王規父侍太夫人觀燈之什余時以劉道原見訪滯留京口不及赴此會二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','不覺朱轓輾後塵，爭看繡幰錦纏輪。',64,'全唐诗/poet.song.44000.json','["不覺朱轓輾後塵，爭看繡幰錦纏輪。", "洛濱侍從三人貴，京兆平反一笑春。", "但逐東山携妓女，那知後閣走窮賓。", "滯留不見榮華事，空作賡詩第七人。"]'),
('0c8886cb-0436-4db1-90a2-036200bb0e43','和蘇州太守王規父侍太夫人觀燈之什余時以劉道原見訪滯留京口不及赴此會二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','翻翻緹騎走香塵，激激飛濤射火輪。',64,'全唐诗/poet.song.44000.json','["翻翻緹騎走香塵，激激飛濤射火輪。", "美酒留連三夜月，豐年傾倒五州春。", "安排詩律追强對，蹭蹬歸期爲惡賓。", "墮珥遺簪想無限，華胥猶見夢回人。"]'),
('85f1bc27-877f-47a8-963e-c887710a694b','書焦山綸長老壁','蘇軾','宋','宋诗','song-poetry','','[]','法師住焦山，而實未嘗住。',120,'全唐诗/poet.song.44000.json','["法師住焦山，而實未嘗住。", "我來輒問法，法師了無語。", "法師非無語，不知所答故。", "君看頭與足，本自安冠屨。", "譬如長鬣人，不以長爲苦。", "一旦或人問，每睡安所措。", "歸來被上下，一夜無著處。", "展轉遂達晨，意欲盡鑷去。", "此言雖鄙淺，故自有深趣。", "持此問法師，法師一笑許。"]'),
('af4f4b96-b907-46ea-990b-b32c92c59a09','留別金山寶覺圓通二長老','蘇軾','宋','宋诗','song-poetry','','[]','沐罷巾冠快晚凉，睡餘齒頰带茶香。',64,'全唐诗/poet.song.44000.json','["沐罷巾冠快晚凉，睡餘齒頰带茶香。", "艤舟北岸何時渡，晞髮東軒未肯忙。", "康濟此身殊有道，醫治外物本無方。", "風流二老長還往，顧我歸期尚渺茫。"]'),
('3221e64e-965d-4de3-acf5-edcef73f88c6','常潤道中有懷錢塘寄述古五首  其一','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','從來直道不辜身，得向西湖兩過春。',64,'全唐诗/poet.song.44000.json','["從來直道不辜身，得向西湖兩過春。", "沂上已成曾點服，泮宮初采魯侯芹。", "休驚歲歲年年貌，且對朝朝暮暮人。", "細雨晴時一百六，畫船鼉鼓莫違民。"]'),
('7c6b6ca9-4166-4cf1-b314-c81f6dda35cb','常潤道中有懷錢塘寄述古五首  其二','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','草長江南鶑亂飛，年來事事與心違。',64,'全唐诗/poet.song.44000.json','["草長江南鶑亂飛，年來事事與心違。", "花開後院還空落，燕入華堂怪未歸。", "世上功名何日是，樽前點檢幾人非。", "去年柳絮飛時節，記得金籠放雪衣。"]'),
('c92b1ba6-ec76-4283-ab1f-0e19be9bfb94','常潤道中有懷錢塘寄述古五首  其三','蘇軾','宋','宋诗','song-poetry','','[]','浮玉山頭日日風，湧金門外已春融。',64,'全唐诗/poet.song.44000.json','["浮玉山頭日日風，湧金門外已春融。", "二年魚鳥渾相識，三月鶑花付與公。", "剩看新翻眉倒暈，未應泣別臉消紅。", "何人織得相思字，寄與江邊北向鴻。"]'),
('fc651149-0bc2-40ec-b919-e123eed18441','常潤道中有懷錢塘寄述古五首  其四','蘇軾','宋','宋诗','song-poetry','','[]','國艷夭嬈酒半酣，去年同賞寄僧簷。',64,'全唐诗/poet.song.44000.json','["國艷夭嬈酒半酣，去年同賞寄僧簷。", "但知撲撲晴香軟，誰見森森曉態嚴。", "穀雨共驚無幾日，蜜蜂未許輒先甜。", "應須火急回征棹，一片辭枝可得黏。"]'),
('7f4abbd3-971b-4d7b-8569-2c8f999ce5a3','常潤道中有懷錢塘寄述古五首  其五','蘇軾','宋','宋诗','song-poetry','','[]','惠泉山下土如濡，陽羨溪頭米勝珠。',64,'全唐诗/poet.song.44000.json','["惠泉山下土如濡，陽羨溪頭米勝珠。", "賣劍買牛吾欲老，殺雞爲黍子來無。", "地偏不信容高蓋，俗儉真堪著腐儒。", "莫怪江南苦留滯，經營身計一生迂。"]'),
('ea980825-9c30-43bf-9136-fa97b8258205','常州太平寺觀牡丹','蘇軾','宋','宋诗','song-poetry','','[]','武林千葉照觀空，別後湖山幾信風。',32,'全唐诗/poet.song.44000.json','["武林千葉照觀空，別後湖山幾信風。", "自笑眼花紅綠眩，還將白首對鞓紅。"]'),
('28e16cff-60c4-43fa-b3d7-d1af656ada57','遊太平寺浄土院觀牡丹中有淡黄一朵特奇爲作小詩','蘇軾','宋','宋诗','song-poetry','','[]','醉中眼纈自斕斑，天雨曼陀照玉盤。',32,'全唐诗/poet.song.44000.json','["醉中眼纈自斕斑，天雨曼陀照玉盤。", "一朵淡黄微拂掠，鞓紅魏紫不須看。"]'),
('8681e896-19eb-4a67-b3a2-460eb42375ed','杭州牡丹開時僕猶在常潤周令作詩見寄次其韵復次一首送赴闕  其一','蘇軾','宋','宋诗','song-poetry','','[]','羞歸應爲負花期，已見成陰結子時。',64,'全唐诗/poet.song.44000.json','["羞歸應爲負花期，已見成陰結子時。", "與物寡情憐我老，遣春無恨頼君詩。", "玉臺不見朝酣酒，金縷猶歌空折枝。", "從此年年定相見，欲師老圃問樊遲。"]'),
('974d795f-513d-40b5-bc5a-cac19fa9283c','杭州牡丹開時僕猶在常潤周令作詩見寄次其韵復次一首送赴闕  其二','蘇軾','宋','宋诗','song-poetry','','[]','莫負黄花九日期，人生窮達可無時。',64,'全唐诗/poet.song.44000.json','["莫負黄花九日期，人生窮達可無時。", "十年且就三都賦，萬戶終輕千首詩。", "天靜傷鴻猶戢翼，月明驚鵲未安枝。", "君看六月河無水，萬斛龍驤到自遲。"]'),
('e8ec3129-3496-413e-bdf7-44455c6f4ebb','無錫道中賦水車','蘇軾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','翻翻聯聯銜尾鴉，犖犖确确蛻骨蛇。',64,'全唐诗/poet.song.44000.json','["翻翻聯聯銜尾鴉，犖犖确确蛻骨蛇。", "分疇翠浪走雲陣，刺水綠鍼抽稻芽。", "洞庭五月欲飛沙，鼉鳴窟中如打衙。", "天公不見老翁泣，喚取阿香推雷車。"]'),
('7e3d3da8-a221-453a-bdf8-30bd3c0f38e3','虎丘寺','蘇軾','宋','宋诗','song-poetry','','[]','入門無平田，石路細穿嶺。',168,'全唐诗/poet.song.44000.json','["入門無平田，石路細穿嶺。", "陰風生澗壑，古木翳潭井。", "湛盧誰復見，秋水光耿耿。", "鐵花繡巌壁，殺氣噤蛙黽。", "幽幽生公堂，左右立頑礦。", "當年或未信，異類服精猛。", "胡爲百歲後，仙鬼互馳騁。", "窈然留清詩，讀者爲悲哽。", "東軒有佳致，雲水麗千頃。", "熙熙覽生物，春意破凄冷。", "我來屬無事，暖日相與永。", "喜鵲翻初旦，愁鳶蹲落景。", "坐見漁樵還，新月溪上影。", "悟彼良自咍，歸田行可請。"]'),
('321bf24d-5f06-44d4-9133-9ac6de905b9d','劉孝叔會虎丘時王規父齋素祈雨不至二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','白簡威猶凜，青山興已濃。',48,'全唐诗/poet.song.44000.json','["白簡威猶凜，青山興已濃。", "鶴閑雲作氅，駝卧草埋峰。", "跪屨若可教，卜鄰應見容。", "因公問回老，何處定相逢。"]'),
('71bde201-8e97-4423-8fbb-a3b2314ed171','劉孝叔會虎丘時王規父齋素祈雨不至二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','太常齋未解，不肯對纖穠。',48,'全唐诗/poet.song.44000.json','["太常齋未解，不肯對纖穠。", "只遣三千履，來遊十二峰。", "林空答清唱，潭浄寫衰容。", "歸去瑶臺路，還應月下逢。"]'),
('ecb28b4b-0e6f-4c88-8234-be12860efb2c','蘇州閭丘江君二家雨中飲酒二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','小圃陰陰遍灑塵，方塘瀲瀲欲生紋。',64,'全唐诗/poet.song.44000.json','["小圃陰陰遍灑塵，方塘瀲瀲欲生紋。", "已煩仙袂來行雨，莫遣歌聲便駐雲。", "肯對綺羅辭白酒，試將文字惱紅裙。", "今宵記取醒時節，點滴空階獨自聞。"]'),
('b149e32e-edde-42fb-9c12-a1d11eb9ad9f','蘇州閭丘江君二家雨中飲酒二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','五紀歸來鬢未霜，十眉環列坐生光。',64,'全唐诗/poet.song.44000.json','["五紀歸來鬢未霜，十眉環列坐生光。", "喚船渡口迎秋女，駐馬橋邊問泰娘。", "曾把四弦娛白傅，敢將百草鬥吳王。", "從今却笑風流守，畫戟空凝宴寢香。"]'),
('83b8fc79-9fba-45b3-9215-89f722a4ecb1','次韵沈長官三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','家山何在兩忘歸，杯酒相逢慎勿違。',32,'全唐诗/poet.song.44000.json','["家山何在兩忘歸，杯酒相逢慎勿違。", "不獨飯山嘲我瘦，也應糠覈怪君肥。"]'),
('4de09b7e-b8af-4be0-ad09-ea3d71b71849','次韵沈長官三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','男婚已畢女將歸，累盡身輕志莫違。',32,'全唐诗/poet.song.44000.json','["男婚已畢女將歸，累盡身輕志莫違。", "聞道山中食無肉，玉池清水自生肥。"]'),
('aa6d5319-502c-4a2e-9c48-5e5bc0c594e9','次韵沈長官三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','造物知吾久念歸，似憐衰病不相違。',32,'全唐诗/poet.song.44000.json','["造物知吾久念歸，似憐衰病不相違。", "風來震澤帆初飽，雨入松江水漸肥。"]'),
('73a1f2df-2582-420b-98a4-fe1cb1a57185','戲書吳江三賢畫像三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','誰將射御教吳兒，長笑申公爲夏姬。',32,'全唐诗/poet.song.44000.json','["誰將射御教吳兒，長笑申公爲夏姬。", "却遣姑蘇有麋鹿，更憐夫子得西施。"]'),
('8e0b405a-75b7-439e-95bc-58f0d3034ce4','戲書吳江三賢畫像三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','浮世功勞食與眠，季鷹真得水中仙。',32,'全唐诗/poet.song.44000.json','["浮世功勞食與眠，季鷹真得水中仙。", "不須更說知機早，直爲鱸魚也自賢。"]'),
('879305bc-cd90-4fdc-806d-49b362c86663','戲書吳江三賢畫像三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','千首文章二頃田，囊中未有一錢看。',32,'全唐诗/poet.song.44000.json','["千首文章二頃田，囊中未有一錢看。", "却因養得能言鴨，驚破王孫金彈丸。"]'),
('a79ea7a9-241e-4e03-8716-e707a67b25d9','過永樂文長老已卒','蘇軾','宋','宋诗','song-poetry','','[]','初驚鶴瘦不可識，旋覺雲歸無處尋。',64,'全唐诗/poet.song.44000.json','["初驚鶴瘦不可識，旋覺雲歸無處尋。", "三過門間老病死，一彈指頃去來今。", "存亡慣見渾無淚，鄉井難忘尚有心。", "欲向錢塘訪圓澤，葛洪川畔待秋深。"]'),
('c2317168-add6-4eff-99da-052b4186e19e','安平泉','蘇軾','宋','宋诗','song-poetry','','[]','策杖徐徐步此山，撥雲尋徑興飄然。',64,'全唐诗/poet.song.44000.json','["策杖徐徐步此山，撥雲尋徑興飄然。", "鑿開海眼知何代，種出菱花不計年。", "烹茗僧誇甌泛雪，煉丹人化骨成仙。", "當年陸羽空收拾，遺却安平一片泉。"]'),
('734681e3-e45b-4072-8222-0573e2f4a6f3','贈張刁二老','蘇軾','宋','宋诗','song-poetry','','[]','兩邦山水未淒涼，二老風流總健强。',64,'全唐诗/poet.song.44000.json','["兩邦山水未淒涼，二老風流總健强。", "共成一百七十歲，各飲三萬六千觴。", "藏春塢裏鶑花鬧，仁壽橋邊日月長。", "惟有詩人被磨折，金釵零落不成行。"]'),
('00f18cf7-9ef3-4eb0-8838-9e86cd5f2135','去年秋偶遊寶山上方入一小院闃然無人有一僧隠几低頭讀書與之語漠然不甚對問其鄰之僧曰此雲闍黎也不出十五年矣今年六月自常潤還復至其室則死葬數月矣作詩題其壁','蘇軾','宋','宋诗','song-poetry','','[]','雲師來寶山，一住十五秋。',96,'全唐诗/poet.song.44000.json','["雲師來寶山，一住十五秋。", "讀書常閉戶，客至不舉頭。", "去年造其室，清坐忘百憂。", "我初無言說，師亦無對酬。", "今來復扣門，空房但颼飀。", "云已滅無餘，薪盡火不留。", "却疑此室中，嘗有斯人不。", "所遇孰非夢，事過吾何求。"]'),
('ee3781ce-1b66-407f-82df-2aaa81adb883','聽僧昭素琴','蘇軾','宋','宋诗','song-poetry','','[]','至和無攫醳，至平無按抑。',48,'全唐诗/poet.song.44000.json','["至和無攫醳，至平無按抑。", "不知微妙聲，究竟從何出。", "散我不平氣，洗我不和心。", "此心知有在，尚復此微吟。"]'),
('78bd3c7a-7063-496a-ba99-234b45a2aff5','僧惠勤初罷僧職','蘇軾','宋','宋诗','song-poetry','','[]','軒軒青田鶴，鬰鬰在樊籠。',96,'全唐诗/poet.song.44000.json','["軒軒青田鶴，鬰鬰在樊籠。", "既爲物所縻，遂與吾輩同。", "今來始謝去，萬事一笑空。", "新詩如洗出，不受外垢蒙。", "清風入齒牙，出語如風松。", "霜髭茁病骨，饑坐聽午鐘。", "非詩能窮人，窮者詩乃工。", "此語信不妄，吾聞諸醉翁。"]'),
('752d8791-9c04-4c5d-a08b-715e2f0928a6','遊靈隠高峰塔','蘇軾','宋','宋诗','song-poetry','','[]','言遊高峰塔，蓐食治野裝。',144,'全唐诗/poet.song.44000.json','["言遊高峰塔，蓐食治野裝。", "火雲秋未衰，及此初旦凉。", "霧霏巌谷暗，日出草木香。", "嘉我同來人，久便雲水鄉。", "相勸小舉足，前路高且長。", "古松攀龍蛇，怪石坐牛羊。", "漸聞鐘磬音，飛鳥皆下翔。", "入門空有無，雲海浩茫茫。", "惟見聾道人，老病時絕糧。", "問年笑不答，但指穴藜床。", "心知不復來，欲歸更彷徨。", "贈別留匹布，今歲天早霜。"]'),
('32480746-c9f8-4a69-8131-b39bd5739739','八月十七日天竺山送桂花分贈元素','蘇軾','宋','宋诗','song-poetry','','[]','月缺霜濃細蕊乾，此花元屬玉堂仙。',64,'全唐诗/poet.song.44000.json','["月缺霜濃細蕊乾，此花元屬玉堂仙。", "鷲峰子落驚前夜，蟾窟枝空記昔年。", "破裓山僧憐耿介，練裙溪女鬥清妍。", "願公採擷紉幽佩，莫遣孤芳老澗邊。"]'),
('82270860-5d85-4cf1-b567-af123195f70c','海會寺清心堂','蘇軾','宋','宋诗','song-poetry','','[]','南郭子綦初喪我，西來達摩尚求心。',64,'全唐诗/poet.song.44000.json','["南郭子綦初喪我，西來達摩尚求心。", "此堂不說有清濁，遊客自觀隨淺深。", "兩歲頻爲山水役，一溪長照雪霜侵。", "紛紛無補竟何事，慚愧高人閉戶吟。"]'),
('8d704d49-93b5-4f8c-be34-155296844013','捕蝗至浮雲嶺山行疲苶有懷子由弟二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','西來烟障塞空虛，灑徧秋田雨不如。',64,'全唐诗/poet.song.44000.json','["西來烟障塞空虛，灑徧秋田雨不如。", "新法清平那有此，老身窮苦自招渠。", "無人可訴烏銜肉，憶弟難憑犬附書。", "自笑迂疏皆此類，區區猶欲理蝗餘。"]'),
('454cb215-a7b3-4f05-a965-709b5fa35ed3','捕蝗至浮雲嶺山行疲苶有懷子由弟二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','霜風漸欲作重陽，熠熠溪邊野菊黄。',64,'全唐诗/poet.song.44000.json','["霜風漸欲作重陽，熠熠溪邊野菊黄。", "久廢山行疲犖确，尚能村醉舞淋浪。", "獨眠林下夢魂好，回首人間憂患長。", "殺馬毀車從此逝，子來何處問行藏。"]'),
('fc6667e9-bba8-421c-b566-06b0dfe5c9c7','青牛嶺高絕處有小寺人迹罕到','蘇軾','宋','宋诗','song-poetry','','[]','暮歸走馬沙河塘，爐烟裊裊十里香。',68,'全唐诗/poet.song.44000.json','["暮歸走馬沙河塘，爐烟裊裊十里香。", "朝行曳杖青牛嶺，寒泉咽咽千山靜。", "君勿笑老僧，耳聾喚不聞，百年俱是可憐人。", "明朝且復城中去，白雲却在題詩處。"]'),
('977866d1-a48c-4612-a7d8-607fe840bb9b','新城陳氏園次晁補之韵','蘇軾','宋','宋诗','song-poetry','','[]','荒凉廢圃秋，寂歷幽花晚。',48,'全唐诗/poet.song.44000.json','["荒凉廢圃秋，寂歷幽花晚。", "山城已窮僻，況與城相遠。", "我來亦何事，徙倚望雲巘。", "不見苦吟人，清樽爲誰滿。"]'),
('35ff9f8f-9b5e-4563-b79a-e68c47f464ec','梅聖俞詩中有毛長官者今於潛令國華也聖俞沒十五年而君猶爲令捕蝗至其邑作詩戲之','蘇軾','宋','宋诗','song-poetry','','[]','詩翁憔悴老一官，厭見苜蓿堆青盤。',128,'全唐诗/poet.song.44000.json','["詩翁憔悴老一官，厭見苜蓿堆青盤。", "歸來羞澀對妻子，自比鮎魚緣竹竿。", "今君滯留生二毛，飽聽衙鼓眠黄紬。", "更將嘲笑調朋友，人道獼猴騎土牛。", "願君恰似高常侍，暫爲小邑仍刺史。", "不願君爲孟浩然，却遭明主放還山。", "宦遊逢此歲年惡，飛蝗來時半天黑。", "羨君封境稻如雲，蝗自識人人不識。"]'),
('9f6184ef-8097-480f-b0de-faefbe3e2a3b','與毛令方尉遊西菩寺二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','推擠不去已三年，魚鳥依然笑我頑。',64,'全唐诗/poet.song.44000.json','["推擠不去已三年，魚鳥依然笑我頑。", "人未放歸江北路，天教看盡浙西山。", "尚書清節衣冠後，處士風流水石間。", "一笑相逢那易得，數詩狂語不須刪。"]'),
('8e2d7d3f-ffde-4d7d-a163-2fea3c2a8c01','與毛令方尉遊西菩寺二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','路轉山腰足未移，水清石瘦便能奇。',64,'全唐诗/poet.song.44000.json','["路轉山腰足未移，水清石瘦便能奇。", "白雲自占東西嶺，明月誰分上下池。", "黑黍黄粱初熟候，朱柑綠橘半甜時。", "人生此樂須天付，莫遣兒曹取次知。"]'),
('f8bc6a00-aa54-4ed4-80dd-6073e4c0fbdb','李行中醉眠亭三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','已向閑中作地仙，更於酒裏得天全。',32,'全唐诗/poet.song.44000.json','["已向閑中作地仙，更於酒裏得天全。", "從教世路風波惡，賀監偏工水底眠。"]'),
('b14f35ec-e1e8-48c4-819d-0898b0b763b3','李行中醉眠亭三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','君且歸休我欲眠，人言此語出天然。',32,'全唐诗/poet.song.44000.json','["君且歸休我欲眠，人言此語出天然。", "醉中對客眠何害，須信陶潛未若賢。"]'),
('69cb136a-eea6-427d-9ced-abe2954f82f3','李行中醉眠亭三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','孝先風味也堪憐，肯爲周公晝日眠。',32,'全唐诗/poet.song.44000.json','["孝先風味也堪憐，肯爲周公晝日眠。", "枕麴先生猶笑汝，枉將空腹貯遺編。"]'),
('7dc2cadc-5810-4182-9bc3-f6f9e5546f84','贈寫真何充秀才','蘇軾','宋','宋诗','song-poetry','','[]','君不見潞州別駕眼如電，左手挂弓橫撚箭。',118,'全唐诗/poet.song.44000.json','["君不見潞州別駕眼如電，左手挂弓橫撚箭。", "又不見雪中騎馿孟浩然，皺眉吟詩肩聳山。", "饑寒富貴兩安在，空有遺像留人間。", "此身常擬同外物，浮雲變化無蹤跡。", "問君何苦寫我真，君言好之聊自適。", "黄冠野服山家容，意欲置我山巌中。", "勳名將相今何限，往寫褒公與鄂公。"]'),
('dd4b207d-2a56-461b-972f-3ad11b723aeb','回先生過湖州東林沈氏飲醉以石榴皮書其家東老庵之壁云西鄰已富憂不足東老雖貧樂有餘白酒釀來因好客黄金散盡爲收書西蜀和仲聞而次其韵三首東老沈氏之老自謂也湖人因以名之其子偕作詩有可觀者  其一','蘇軾','宋','宋诗','song-poetry','','[]','世俗何知貧是病，神仙可學道之餘。',32,'全唐诗/poet.song.44000.json','["世俗何知貧是病，神仙可學道之餘。", "但知白酒留佳客，不問黄公覓素書。"]'),
('43fe1294-ff86-42ab-b6c6-2d7f0f9e0d39','回先生過湖州東林沈氏飲醉以石榴皮書其家東老庵之壁云西鄰已富憂不足東老雖貧樂有餘白酒釀來因好客黄金散盡爲收書西蜀和仲聞而次其韵三首東老沈氏之老自謂也湖人因以名之其子偕作詩有可觀者  其二','蘇軾','宋','宋诗','song-poetry','','[]','符離道士晨興際，華岳先生尸解餘。',32,'全唐诗/poet.song.44000.json','["符離道士晨興際，華岳先生尸解餘。", "忽見黄庭丹篆句，猶傳青紙小朱書。"]'),
('e954124b-4dfb-4a56-8108-04314a392b69','回先生過湖州東林沈氏飲醉以石榴皮書其家東老庵之壁云西鄰已富憂不足東老雖貧樂有餘白酒釀來因好客黄金散盡爲收書西蜀和仲聞而次其韵三首東老沈氏之老自謂也湖人因以名之其子偕作詩有可觀者  其三','蘇軾','宋','宋诗','song-poetry','','[]','淒涼雨露三年後，仿佛塵埃數字餘。',32,'全唐诗/poet.song.44000.json','["淒涼雨露三年後，仿佛塵埃數字餘。", "至用榴皮緣底事，中書君豈不中書。"]'),
('4091656f-a2d0-4179-8f34-893306a1e4fd','單同年求德興俞氏聚遠樓詩三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','雲山烟水苦難親，野草幽花各自春。',32,'全唐诗/poet.song.44000.json','["雲山烟水苦難親，野草幽花各自春。", "頼有高樓能聚遠，一時收拾與閑人。"]'),
('d8688fd4-3a1f-4c22-92d3-55897accd2eb','單同年求德興俞氏聚遠樓詩三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','無限青山散不收，雲奔浪卷入簾鉤。',32,'全唐诗/poet.song.44000.json','["無限青山散不收，雲奔浪卷入簾鉤。", "直將眼力爲疆界，何啻人間萬戶侯。"]'),
('1fb35ada-5569-4696-b7c0-853cd008954e','單同年求德興俞氏聚遠樓詩三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','聞說樓居似地仙，不知門外有塵寰。',32,'全唐诗/poet.song.44000.json','["聞說樓居似地仙，不知門外有塵寰。", "幽人隠几寂無語，心在飛鴻滅沒間。"]'),
('046af7a6-6082-4eca-832e-12efcff9aa13','潤州甘露寺彈箏','蘇軾','宋','宋诗','song-poetry','','[]','多景樓上彈神曲，欲斷哀弦再三促。',64,'全唐诗/poet.song.44000.json','["多景樓上彈神曲，欲斷哀弦再三促。", "江妃出聽霧雨愁，白浪翻空動浮玉。", "喚取吾家雙鳳槽，遣作三峽孤猿號。", "與君合奏芳春調，啄木飛來霜樹杪。"]'),
('3cc64eef-99bf-4c19-94aa-b9e0aab79e6d','平山堂次王居卿祠部韵','蘇軾','宋','宋诗','song-poetry','','[]','高會日陪山簡醉，狂言屢發次公醒。',64,'全唐诗/poet.song.44000.json','["高會日陪山簡醉，狂言屢發次公醒。", "酒如人面天然白，山向吾曹分外青。", "江上飛雲來北固，檻前修竹憶南屏。", "六朝興廢餘丘壠，空使奸雄笑寧馨。"]'),
('658a5b7f-15cc-4b30-81e9-0c8b79f60598','次韵陳海州書懷','蘇軾','宋','宋诗','song-poetry','','[]','鬰鬰蒼梧海上山，蓬萊方丈有無間。',64,'全唐诗/poet.song.44000.json','["鬰鬰蒼梧海上山，蓬萊方丈有無間。", "舊聞草木皆仙藥，欲棄妻孥守市闤。", "雅志未成空自歎，故人相對若爲顔。", "酒醒却憶兒童事，長恨雙鳬去莫攀。"]'),
('1306605b-c73b-42de-a43f-731a526c1499','次韵陳海州乘槎亭','蘇軾','宋','宋诗','song-poetry','','[]','人事無涯生有涯，逝將歸釣漢江槎。',64,'全唐诗/poet.song.44000.json','["人事無涯生有涯，逝將歸釣漢江槎。", "乘桴我欲從安石，遁世誰能識子嗟。", "日上紅波浮翠巘，潮來白浪卷青沙。", "清談美景雙奇絕，不覺歸鞍带月華。"]'),
('7302fc44-ad8f-4e20-95b5-63b831c7b312','次韵孫職方蒼梧山','蘇軾','宋','宋诗','song-poetry','','[]','蒼梧奇事豈虛傳，荒怪還須問子年。',64,'全唐诗/poet.song.44000.json','["蒼梧奇事豈虛傳，荒怪還須問子年。", "遠託鰲頭轉滄海，來依鵬背負青天。", "或云靈境歸賢者，又恐神功亦偶然。", "聞道新春恣遊覽，羨君平地作飛仙。"]'),
('a091aa46-6d3c-40a3-8956-d70d28d5316a','次韵孫巨源寄漣水李盛二著作并以見寄五絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','南岳諸劉豈易逢，相望無復馬牛風。',32,'全唐诗/poet.song.44000.json','["南岳諸劉豈易逢，相望無復馬牛風。", "山公雖見無多子，社燕何由戀塞鴻。"]'),
('a0257a04-6c38-44f2-a58c-29b4ba7ef9b4','次韵孫巨源寄漣水李盛二著作并以見寄五絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','高才晚歲終難進，勇退當年正急流。',32,'全唐诗/poet.song.44000.json','["高才晚歲終難進，勇退當年正急流。", "不獨二疏爲可慕，他時當有景孫樓。"]'),
('e29a672f-7e59-4f13-ac93-53cfc17c6448','次韵孫巨源寄漣水李盛二著作并以見寄五絕  其三','蘇軾','宋','宋诗','song-poetry','','[]','漱石先生難可意，齧氈校尉久無朋。',32,'全唐诗/poet.song.44000.json','["漱石先生難可意，齧氈校尉久無朋。", "應知客路愁無奈，故遣吟詩調李陵。"]'),
('67961397-4c71-46a5-842b-9e4a9690921c','次韵孫巨源寄漣水李盛二著作并以見寄五絕  其四','蘇軾','宋','宋诗','song-poetry','','[]','雲雨休排神女車，忠州老病畏人誇。',32,'全唐诗/poet.song.44000.json','["雲雨休排神女車，忠州老病畏人誇。", "詩豪正值安仁在，空看河陽滿縣花。"]'),
('0f81c90a-a978-4f50-a472-14f5d4c7499c','次韵孫巨源寄漣水李盛二著作并以見寄五絕  其五','蘇軾','宋','宋诗','song-poetry','','[]','膠西未到吾能說，桑柘禾麻不見春。',32,'全唐诗/poet.song.44000.json','["膠西未到吾能說，桑柘禾麻不見春。", "不羨京塵騎馬客，羨他淮月弄舟人。"]'),
('405ec34f-31a7-405e-a844-4c1717633eea','王莽','蘇軾','宋','宋诗','song-poetry','','[]','漢家殊未識經綸，入手功名事事新。',32,'全唐诗/poet.song.44000.json','["漢家殊未識經綸，入手功名事事新。", "百尺穿成連夜井，千金購得解飛人。"]'),
('d65a3fca-007c-4940-b5e3-bdf7ae58f6bb','董卓','蘇軾','宋','宋诗','song-poetry','','[]','公業平時勸用儒，諸公何事起相圖。',32,'全唐诗/poet.song.44000.json','["公業平時勸用儒，諸公何事起相圖。", "只言天下無健者，豈信車中有布乎。"]'),
('33a5b987-f9f6-43c8-9ea7-87208ac886ca','虎兒','蘇軾','宋','宋诗','song-poetry','','[]','舊聞老蚌生明珠，未省老兔生於菟。',96,'全唐诗/poet.song.44000.json','["舊聞老蚌生明珠，未省老兔生於菟。", "老兔自謂月中物，不騎快馬騎蟾蜍。", "蟾蜍爬沙不肯行，坐令青衫垂白鬚。", "於菟駿猛不類渠，指揮黄熊駕黑貙。", "丹砂紫麝不用塗，眼光百步走妖狐。", "妖狐莫誇智有餘，不勞摇牙咀爾徒。"]'),
('e924430c-6b58-426d-9696-261228ece12d','鐵溝行贈喬太博','蘇軾','宋','宋诗','song-poetry','','[]','城東坡隴何所似，風吹海濤低復起。',160,'全唐诗/poet.song.44000.json','["城東坡隴何所似，風吹海濤低復起。", "城中病守無所爲，走馬來尋鐵溝水。", "鐵溝水淺不容輈，恰似當年韓與侯。", "有魚無魚何足道，駕言聊復寫我憂。", "孤村野店亦何有，欲發狂言須斗酒。", "山頭落日側金盆，倒著接䍦搔白首。", "忽憶從軍年少時，輕裘細馬百不知。", "臂弓腰箭南山下，追逐長楊射獵兒。", "老去同君兩憔悴，犯夜醉歸人不避。", "明年定起故將軍，未肯先誅霸陵尉。"]'),
('f1b8b7b5-5db0-473a-92a0-2019fb95234d','雪後書北臺壁二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','黄昏猶作雨纖纖，夜靜無風勢轉嚴。',64,'全唐诗/poet.song.44000.json','["黄昏猶作雨纖纖，夜靜無風勢轉嚴。", "但覺衾裯如潑水，不知庭院已堆鹽。", "五更曉色來書幌，半夜寒聲落畫檐。", "試埽北臺看馬耳，未隨埋沒有雙尖。"]'),
('339c6d68-5534-4c50-a55a-deb28aab0cb4','雪後書北臺壁二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','城頭初日始翻鴉，陌上晴泥已沒車。',64,'全唐诗/poet.song.44000.json','["城頭初日始翻鴉，陌上晴泥已沒車。", "凍合玉樓寒起粟，光摇銀海眩生花。", "遺蝗入地應千尺，宿麥連雲有幾家。", "老病自嗟詩力退，空吟冰柱憶劉叉。"]'),
('fbbe641e-4f34-476a-b7a1-94e03fae69b6','謝人見和前篇二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','已分酒杯欺淺懦，敢將詩律鬥深嚴。',64,'全唐诗/poet.song.44000.json','["已分酒杯欺淺懦，敢將詩律鬥深嚴。", "漁蓑句好應須畫，柳絮才高不道鹽。", "敗履尚存東郭足，飛花又舞謫仙檐。", "書生事業真堪笑，忍凍孤吟筆退尖。"]'),
('98014cfd-62a1-400e-834c-5f5eb74b6b0b','謝人見和前篇二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','九陌凄風戰齒牙，銀杯逐馬带隨車。',64,'全唐诗/poet.song.44000.json','["九陌凄風戰齒牙，銀杯逐馬带隨車。", "也知不作堅牢玉，無奈能開頃刻花。", "得酒强歡愁底事，閉門高卧定誰家。", "臺前日暖君須愛，冰下寒魚漸可叉。"]'),
('6f37535f-cc10-4bbb-ab07-2074880042ed','除夜病中贈段屯田','蘇軾','宋','宋诗','song-poetry','','[]','龍鍾三十九，勞生已强半。',192,'全唐诗/poet.song.44000.json','["龍鍾三十九，勞生已强半。", "歲暮日斜時，還爲昔人歎。", "今年一線在，那復堪把玩。", "欲起强持酒，故交雲雨散。", "惟有病相尋，空齋爲老伴。", "蕭條燈火冷，寒夜何時旦。", "倦僕觸屏風，饑鼯嗅空案。", "數朝閉閣卧，霜髮秋蓬亂。", "傳聞使者來，策杖就梳盥。", "書來苦安慰，不怪造請緩。", "大夫忠烈後，高義金石貫。", "要當擊權豪，未肯覷衰懦。", "此生何所似，暗盡灰中炭。", "歸田計已决，此邦聊假館。", "三徑粗成資，一枝有餘暖。", "願君更信宿，庶奉一笑粲。"]'),
('fe4b62df-77b8-49d6-bce4-6a6933b4f035','喬太博見和復次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','百年三萬日，老病常居半。',192,'全唐诗/poet.song.44000.json','["百年三萬日，老病常居半。", "其間互憂樂，歌笑雜悲歎。", "顛倒不自知，直爲神所玩。", "須臾便堪笑，萬事風雨散。", "自從識此理，久謝少年伴。", "逝將遊無何，豈暇讀城旦。", "非才更多病，二事可并案。", "愧煩賢使者，弭節整紛亂。", "喬侯瑚璉質，清廟嘗薦盥。", "奮髯百吏走，坐變齊俗緩。", "未遭甘鷁退，並進恥魚貫。", "每聞議論餘，凜凜激貪懦。", "莫邪當自躍，豈復煩爐炭。", "便慶朝秣越，未暮刷燕館。", "胡爲守故丘，眷戀桑榆暖。", "爲君叩牛角，一詠南山粲。"]'),
('10f38556-e317-4e9b-b1e0-1b13879fc9e6','二公再和亦再答之','蘇軾','宋','宋诗','song-poetry','','[]','寒雞知將晨，饑鶴知夜半。',192,'全唐诗/poet.song.44000.json','["寒雞知將晨，饑鶴知夜半。", "亦如老病客，遇節嘗感歎。", "光陰等敲石，過眼不容玩。", "親友如摶沙，放手還復散。", "羈孤每自笑，寂寞誰肯伴。", "元達號神君，高論森月旦。", "紀明本賢將，汩沒事堆案。", "欣然肯相顧，夜閣燈火亂。", "盤空愧不飽，酒薄僅堪盥。", "雍容許著帽，不怪安石緩。", "雖無窈窕人，清唱弄珠貫。", "幸有縱橫舌，說劍起慵懦。", "二豪沉下位，暗火埋濕炭。", "豈似草玄人，默默老儒館。", "行看富貴逼，炙手借餘暖。", "應念苦思歸，登樓賦王粲。"]'),
('980a6d49-43dd-4ec1-a5d2-bd32328b450c','蘇州姚氏三瑞堂','蘇軾','宋','宋诗','song-poetry','','[]','君不見董召南，隠居行義孝且慈。',97,'全唐诗/poet.song.44000.json','["君不見董召南，隠居行義孝且慈。", "天公亦恐無人知，故令雞狗相哺兒，又令韓老爲作詩。", "爾來三百年，名與淮水東南馳。", "此人世不乏，此事亦時有。", "楓橋三瑞皆目見，天意宛在虞鰥後。", "惟有此詩非昔人，君更往求無價手。"]'),
('cc91e110-cb38-49d4-a9f4-c72186a65b18','莫笑銀杯小答喬太博','蘇軾','宋','宋诗','song-poetry','','[]','陶潛一縣令，獨飲仍獨醒。',96,'全唐诗/poet.song.44000.json','["陶潛一縣令，獨飲仍獨醒。", "猶將公田二頃五十畝，種秫作酒不種秔。", "我今號爲二千石，歲釀百石何以醉賓客。", "請君莫笑銀杯小，爾來歲旱東海窄。", "會當拂衣歸故丘，作書貸粟監河侯。", "萬斛船中著美酒，與君一生長拍浮。"]'),
('cd997b00-75ab-49af-a00a-ec92ca69112f','送段屯田分得于字','蘇軾','宋','宋诗','song-poetry','','[]','勸農使者古大夫，不惜春衫踐泥塗。',112,'全唐诗/poet.song.44000.json','["勸農使者古大夫，不惜春衫踐泥塗。", "王事靡盬君甚劬，奉常客卿虬兩鬚。", "東武縣令天馬駒，泮宮先生非俗儒。", "相與野飲四子俱，樂哉此樂城中無。", "溪邊策杖自携壺，腰笏不煩何易于。", "膠西病守老且迂，空齋愁坐紛墨朱。", "四十豈不知頭顱，畏人不出何其愚。"]'),
('cfef127f-3cf9-4a65-b8ed-f9144d27d323','和段屯田荆林館','蘇軾','宋','宋诗','song-poetry','','[]','南山有佳色，無人空自奇。',48,'全唐诗/poet.song.44000.json','["南山有佳色，無人空自奇。", "清詩爲題品，草木變芬菲。", "謝女得秀句，留待中郎歸。", "便當勤鞭策，僕倦馬亦饑。"]'),
('7f0c486e-314d-4e3c-9bcf-f353598150cd','出城送客不及步至溪上二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','送客客已去，尋花花未開。',48,'全唐诗/poet.song.44000.json','["送客客已去，尋花花未開。", "未能城裏去，且復水邊來。", "父老借問我，使君安在哉。", "今年好風雪，會見麥千堆。"]'),
('03f129e3-e308-4858-90dd-8cc7c2b99b52','出城送客不及步至溪上二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','春來六十日，笑口幾回開。',48,'全唐诗/poet.song.44000.json','["春來六十日，笑口幾回開。", "會作堂堂去，何妨得得來。", "倦遊行老矣，舊隠賦歸哉。", "東望峨眉小，盧山翠作堆。"]'),
('696d0acd-7261-4733-8ea3-c2ce13094c5d','游盧山次韵章傳道','蘇軾','宋','宋诗','song-poetry','','[]','塵容已似服轅駒，野性猶同縱壑魚。',64,'全唐诗/poet.song.44000.json','["塵容已似服轅駒，野性猶同縱壑魚。", "出入巌巒千仞表，較量筋力十年初。", "雖無窈窕驅前馬，還有鴟夷挂後車。", "莫笑吟詩淡生活，當令阿買爲君書。"]'),
('50444a80-0ace-4fdd-a07d-0b82df394083','盧山五詠 盧敖洞','蘇軾','宋','宋诗','song-poetry','','[]','上界足官府，飛昇亦何益。',24,'全唐诗/poet.song.44000.json','["上界足官府，飛昇亦何益。", "還在此山中，相逢不相識。"]'),
('0925eb37-b7ba-4199-bc4e-a3e9c9a598cc','盧山五詠 飲酒臺','蘇軾','宋','宋诗','song-poetry','','[]','博士雅好飲，空山誰與娛。',24,'全唐诗/poet.song.44000.json','["博士雅好飲，空山誰與娛。", "莫向驪山去，君王不喜儒。"]'),
('5c2573db-ecdd-4ce1-bba2-6e280c54935b','盧山五詠 聖燈巌','蘇軾','宋','宋诗','song-poetry','','[]','石室有金丹，山神不知秘。',24,'全唐诗/poet.song.44000.json','["石室有金丹，山神不知秘。", "何必吐光芒，夜半驚童稚。"]'),
('62d1d994-bc0e-44a1-af51-42cc50b39eff','盧山五詠 三泉','蘇軾','宋','宋诗','song-poetry','','[]','皎皎巌下泉，無人還自潔。',24,'全唐诗/poet.song.44000.json','["皎皎巌下泉，無人還自潔。", "不用比三星，清光同一月。"]'),
('510f8b76-8b05-4e78-ae15-c9413c6c9e61','盧山五詠 障日峰','蘇軾','宋','宋诗','song-poetry','','[]','長安自不遠，蜀客苦思歸。',24,'全唐诗/poet.song.44000.json','["長安自不遠，蜀客苦思歸。", "莫教名障日，喚作小峨眉。"]'),
('9ad123a1-910f-4a21-a1d1-792c928b7f05','次韵章傳道喜雨','蘇軾','宋','宋诗','song-poetry','','[]','去年夏旱秋不雨，海畔居民飲鹹苦。',320,'全唐诗/poet.song.44000.json','["去年夏旱秋不雨，海畔居民飲鹹苦。", "今年春暖欲生蝝，地上戢戢多於土。", "預憂一旦開兩翅，口吻如風那肯吐。", "前時渡江入吳越，布陣橫空如項羽。", "農夫拱手但垂泣，人力區區固難禦。", "撲緣鬉毛困牛馬，啖齧衣服穿房戶。", "坐觀不救亦何心，秉畀炎火傳自古。", "荷鋤散掘誰敢後，得米濟饑還小補。", "常山山神信英烈，撝駕雷公訶電母。", "應憐郡守老且愚，欲把瘡痍手摩撫。", "山中歸時風色變，中路已覺商羊舞。", "夜窗騷騷鬧松竹，朝畦泫泫流膏乳。", "從來蝗旱必相資，此事吾聞老農語。", "庶將積潤掃遺孽，收拾豐歲還明主。", "縣前已窖八千斛，率以一升完一畝。", "更看蠶婦過初眠，未用賀客來旁午。", "先生筆力吾所畏，蹴踏鮑謝跨徐庾。", "偶然談笑得佳篇，便恐流傳成樂府。", "陋邦一雨何足道，吾君盛德九州普。", "中和樂職幾時作，試向諸生選何武。"]'),
('e30cb597-46d7-4549-bad7-6d682573dd00','謝郡人田賀二生獻花','蘇軾','宋','宋诗','song-poetry','','[]','城裏田員外，城西賀秀才。',96,'全唐诗/poet.song.44000.json','["城裏田員外，城西賀秀才。", "不愁家四壁，自有錦千堆。", "珍重尤奇品，艱難最後開。", "芳心困落日，薄艷戰輕雷。", "老守尤多病，壯懷先已灰。", "殷勤此粲者，攀折爲誰哉。", "玉腕揎紅袖，金樽瀉白醅。", "何當鑷霜鬢，强插滿頭回。"]'),
('44fbfe1b-dce8-4e29-8c67-7f7a3d03c959','惜花','蘇軾','宋','宋诗','song-poetry','','[]','吉祥寺中錦千堆，前年賞花真盛哉，道人勸我清明來。',136,'全唐诗/poet.song.44000.json','["吉祥寺中錦千堆，前年賞花真盛哉，道人勸我清明來。", "腰鼓百面如春雷，打徹凉州花自開。", "沙河塘上插花回，醉倒不覺吳兒咍。", "豈知如今雙鬢摧，城西古寺沒蒿萊。", "有僧閉門手自栽，千枝萬葉巧剪裁。", "就中一叢何所似，馬瑙盤盛金縷杯。", "而我食菜方清齋，對花不飲花應猜。", "夜來雨雹如李梅，紅殘綠暗吁可哀。"]'),
('4ab4b883-e803-4239-b370-6b7f02bf3904','和頓教授見寄用除夜韵','蘇軾','宋','宋诗','song-poetry','','[]','我笑陶淵明，種秫二頃半。',192,'全唐诗/poet.song.44000.json','["我笑陶淵明，種秫二頃半。", "婦言既不用，還有責子歎。", "無弦則無琴，何必勞撫玩。", "我笑劉伯倫，醉髮蓬茅散。", "二豪苦不納，獨以鍤自伴。", "既死何用埋，此身同夜旦。", "孰云二子賢，自結兩重案。", "笑人還自笑，出口談治亂。", "一生溷塵垢，晚以道自盥。", "無成空得懶，坐此百事緩。", "仄聞頓夫子，講道出新貫。", "豈無一尺書，恐不記庸懦。", "陋邦貧且病，數米銖稱炭。", "慚愧章先生，十日坐空館。", "袖中出子詩，貪讀酒屢暖。", "狂言各須慎，勿使輸薪粲。"]'),
('a3a25ae2-d665-4d41-b087-2a6c24c4bdcb','和子由四首 韓太祝送游太山','蘇軾','宋','宋诗','song-poetry','','[]','偶作郊原十日游，未應回首厭籠囚。',64,'全唐诗/poet.song.44000.json','["偶作郊原十日游，未應回首厭籠囚。", "但教塵土驅馳足，終把雲山爛漫酬。", "聞道逢春思濯錦，更須到處覓菟裘。", "恨君不上東封頂，夜看金輪出九幽。"]'),
('1a09ba8d-4ed6-4129-b3ea-1678df229e0c','和子由四首 送春','蘇軾','宋','宋诗','song-poetry','','[]','夢裏青春可得追，欲將詩句絆餘暉。',64,'全唐诗/poet.song.44000.json','["夢裏青春可得追，欲將詩句絆餘暉。", "酒闌病客惟思睡，蜜熟黄蜂亦懶飛。", "芍藥櫻桃俱掃地，鬢絲禪榻兩忘機。", "憑君借取法界觀，一洗人間萬事非。"]'),
('584c7c4f-2a3b-4783-ac84-04dd33e7f3f0','和子由四首 首夏官舍即事','蘇軾','宋','宋诗','song-poetry','','[]','安石榴花開最遲，絳裙深樹出幽菲。',64,'全唐诗/poet.song.44000.json','["安石榴花開最遲，絳裙深樹出幽菲。", "吾廬想見無限好，客子倦遊胡不歸。", "坐上一樽雖得滿，古來四事巧相違。", "令人却憶湖邊寺，垂柳陰陰晝掩扉。"]'),
('f98b336f-c0fa-4b5e-99d7-cee2e458a917','和子由四首 送李供備席上和李詩','蘇軾','宋','宋诗','song-poetry','','[]','家聲赫奕蓋并凉，也解微吟錦瑟傍。',64,'全唐诗/poet.song.44000.json','["家聲赫奕蓋并凉，也解微吟錦瑟傍。", "擘水取魚湖起浪，引杯看劍坐生光。", "風流別後人人憶，才器歸來種種長。", "不用更貪窮事業，風騷分付與沉湘。"]'),
('df7d5f1d-9f2b-47f4-ad99-3cd215f8edea','西齋','蘇軾','宋','宋诗','song-poetry','','[]','西齋深且明，中有六尺床。',120,'全唐诗/poet.song.44000.json','["西齋深且明，中有六尺床。", "病夫朝睡足，危坐覺日長。", "昏昏既非醉，踽踽亦非狂。", "褰衣竹風下，穆然中微凉。", "起行西園中，草木含幽香。", "榴花開一枝，桑棗沃以光。", "鳴鳩得美蔭，困立忘飛翔。", "黄鳥亦自喜，新音變圓吭。", "杖藜觀物化，亦以觀我生。", "萬物各得時，我生日皇皇。"]'),
('0856511c-d1f2-436c-9074-f1d548df479a','小兒','蘇軾','宋','宋诗','song-poetry','','[]','小兒不識愁，起坐牽我衣。',60,'全唐诗/poet.song.44000.json','["小兒不識愁，起坐牽我衣。", "我欲嗔小兒，老妻勸兒癡。", "兒癡君更甚，不樂愁何爲。", "還坐愧此言，洗盞當我前。", "大勝劉伶婦，區區爲酒錢。"]'),
('407f5982-b24f-4559-b2ca-4161c7bcd82d','寄劉孝叔','蘇軾','宋','宋诗','song-poetry','','[]','君王有意誅驕虜，椎破銅山鑄銅虎。',352,'全唐诗/poet.song.44000.json','["君王有意誅驕虜，椎破銅山鑄銅虎。", "聯翩三十七將軍，走馬西來各開府。", "南山伐木作車軸，東海取鼉漫戰鼓。", "汗流奔走誰敢後，恐乏軍興污資斧。", "保甲連村團未遍，方田訟牒紛如雨。", "爾來手實降新書，抉剔根株窮脈縷。", "詔書惻怛信深厚，吏能淺薄空勞苦。", "平生學問只流俗，衆裏笙竽誰比數。", "忽令獨奏鳳將雛，倉卒欲吹那得譜。", "況復連年苦饑饉，剝齧草木啖泥土。", "今年雨雪頗應時，又報蝗蟲生翅股。", "憂來洗盞欲强醉，寂寞虛齋卧空甒。", "公厨十日不生煙，更望紅裙踏筵舞。", "故人屢寄山中信，只有當歸無別語。", "方將雀鼠偷太倉，未肯衣冠挂神武。", "吳興丈人真得道，平日立朝非小補。", "自從四方冠蓋鬧，歸作二浙湖山主。", "高蹤已自雜漁釣，大隠何曾棄簪組。", "去年相從殊未足，問道已許談其粗。", "逝將棄官往卒業，俗緣未盡那得睹。", "公家只在霅溪上，上有白雲如白羽。", "應憐進退苦皇皇，更把安心教初祖。"]'),
('fcb923c9-6607-4dec-87e3-234c9eeea7db','孔長源挽詞二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','少年才氣冠當時，晚節孤風益自奇。',64,'全唐诗/poet.song.44000.json','["少年才氣冠當時，晚節孤風益自奇。", "君勝宜爲夫子後，林宗不愧蔡邕碑。", "南荒尚記誅元惡，東越誰能事細兒。", "耆舊如今幾人在，爲君無憾爲時悲。"]'),
('bd1af2a1-7955-448d-bf2c-c4dafc0b91e4','孔長源挽詞二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','小堰門頭柳繫船，吳山堂上月侵筵。',64,'全唐诗/poet.song.44000.json','["小堰門頭柳繫船，吳山堂上月侵筵。", "潮聲半夜千巌響，詩句明朝萬口傳。", "豈意日斜庚子後，忽驚歲在巳辰年。", "佳城一閉無窮事，南望題詩淚灑箋。"]'),
('c826c45f-2f82-404c-8a47-3eaa10db7f4e','寄呂穆仲寺丞','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','孤山寺下水侵門，每到先看醉墨痕。',64,'全唐诗/poet.song.44000.json','["孤山寺下水侵門，每到先看醉墨痕。", "楚相未亡談笑是，中郎不見典刑存。", "君先去踏塵埃陌，我亦來尋桑棗村。", "回首西湖真一夢，灰心霜鬢更休論。"]'),
('5f035dcb-5ed2-4c3b-a5a9-5ed8927cdc82','余主簿母挽詞','蘇軾','宋','宋诗','song-poetry','','[]','閨庭蘭玉照鄉閭，自昔雖貧樂有餘。',64,'全唐诗/poet.song.44000.json','["閨庭蘭玉照鄉閭，自昔雖貧樂有餘。", "豈獨家人在中饋，却因麟趾識關雎。", "雲軿忽已歸仙府，喬木依然擁舊盧。", "忍把還鄉千斛淚，一時灑向老萊裾。"]'),
('13424c07-a148-4757-b22e-57f54d949216','答陳述古二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','漫說山東第二州，棗林桑泊負春游。',32,'全唐诗/poet.song.44000.json','["漫說山東第二州，棗林桑泊負春游。", "城西亦有紅千葉，人老簪花却自羞。"]'),
('482ec294-287f-4dfd-8be1-d67ea8436e2a','答陳述古二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','小桃破萼未勝春，羅綺叢中第一人。',32,'全唐诗/poet.song.44000.json','["小桃破萼未勝春，羅綺叢中第一人。", "聞道使君歸去後，舞衫歌扇總成塵。"]'),
('c5430791-9896-4f55-bb80-f0c87689f476','張安道樂全堂','蘇軾','宋','宋诗','song-poetry','','[]','列子御風殊不惡，猶被莊生譏數數。',128,'全唐诗/poet.song.44000.json','["列子御風殊不惡，猶被莊生譏數數。", "步兵飲酒中散琴，於此得全非至樂。", "樂全居士全於天，維摩丈室空翛然。", "平生痛飲今不飲，無琴不獨琴無弦。", "我公天與英雄表，龍章鳳姿照魚鳥。", "但令端委坐廟堂，北狄西戎談笑了。", "如今老去苦思歸，小字親書寄我詩。", "試問樂全全底事，無全何處更相虧。"]'),
('61854af9-2f02-4a1b-90c9-13335642fbc2','張文裕挽詞','蘇軾','宋','宋诗','song-poetry','','[]','高才本出朝廷右，能事方推德業餘。',64,'全唐诗/poet.song.44000.json','["高才本出朝廷右，能事方推德業餘。", "每見便聞曹植句，至今傳寶魏華書。", "濟南名士新彫喪，劍外生祠已潔除。", "欲寄西風兩行淚，依然喬木鄭公廬。"]'),
('744f5649-7079-431c-917d-77f675b39c7a','懷西湖寄晁美叔同年','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖天下景，游者無愚賢。',168,'全唐诗/poet.song.44000.json','["西湖天下景，游者無愚賢。", "淺深隨所得，誰能識其全。", "嗟我本狂直，早爲世所捐。", "獨專山水樂，付與寧非天。", "三百六十寺，幽尋遂窮年。", "所至得其妙，心知口難傳。", "至今清夜夢，耳目餘芳鮮。", "君持使者節，風采爍雲煙。", "清流與碧巘，安肯爲君妍。", "胡不屏騎從，暫借僧榻眠。", "讀我壁間詩，清凉洗煩煎。", "策杖無道路，直造意所便。", "應逢古漁父，葦間自延緣。", "問道若有得，買魚勿論錢。"]'),
('59a120d8-99ff-4e1e-be2b-0f70017ff92f','次韵劉貢父李公擇見寄二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','白髮相望兩故人，眼看時事幾番新。',64,'全唐诗/poet.song.44000.json','["白髮相望兩故人，眼看時事幾番新。", "曲無和者應思郢，論少卑之且借秦。", "歲惡詩人無好語，夜長鰥守向誰親。", "少思多睡無如我，鼻息雷鳴撼四鄰。"]'),
('0040dab0-c3aa-451f-b7f5-bd31d9144b70','次韵劉貢父李公擇見寄二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','何人勸我此間來，絃管生衣甑有埃。',64,'全唐诗/poet.song.44000.json','["何人勸我此間來，絃管生衣甑有埃。", "綠蟻沾唇無百斛，蝗蟲撲面已三回。", "磨刀入谷追窮寇，灑涕循城拾棄孩。", "爲郡鮮歡君莫歎，猶勝塵土走章臺。"]'),
('b6244449-fe7c-46b9-9f03-e43effac31cd','祭常山回小獵','蘇軾','宋','宋诗','song-poetry','','[]','青蓋前頭點皂旗，黄茅岡下出長圍。',64,'全唐诗/poet.song.44000.json','["青蓋前頭點皂旗，黄茅岡下出長圍。", "弄風驕馬跑空立，趁兔蒼鷹掠地飛。", "回望白雲生翠巘，歸來紅葉滿征衣。", "聖明若用西凉簿，白羽猶能效一揮。"]'),
('efc5a899-c69b-4724-bbcd-e9ea2e4f07d2','和梅戶曹會獵鐵溝','蘇軾','宋','宋诗','song-poetry','','[]','山西從古說三明，誰信儒冠也捍城。',64,'全唐诗/poet.song.44000.json','["山西從古說三明，誰信儒冠也捍城。", "竿上鯨鯢猶未掩，草中狐兔不須驚。", "東州趙傁飲無敵，南國梅仙詩有聲。", "向不如皋閑射雉，歸來何以得卿卿。"]'),
('3bfdd635-5846-4196-96e3-604ddb7092e6','劉貢父見余歌詞數首以詩見戲聊次其韵','蘇軾','宋','宋诗','song-poetry','','[]','十載飄然未可期，那堪重作看花詩。',64,'全唐诗/poet.song.44000.json','["十載飄然未可期，那堪重作看花詩。", "門前惡語誰傳去，醉後狂歌自不知。", "刺舌君今猶未戒，灸眉吾亦更何辭。", "相從痛飲無餘事，正是春容最好時。"]'),
('b84b7516-61b1-4659-9085-98679a8c6d73','和章七出守湖州二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','方丈仙人出淼茫，高情猶愛水雲鄉。',64,'全唐诗/poet.song.44000.json','["方丈仙人出淼茫，高情猶愛水雲鄉。", "功名誰使連三捷，身世何緣得兩忘。", "早歲歸休心共在，他年相見話偏長。", "只因未報君恩重，清夢時時到玉堂。"]'),
('baa55973-4536-4012-9230-530e5f4166b4','和章七出守湖州二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','絳闕雲臺總有名，應須極貴又長生。',64,'全唐诗/poet.song.44000.json','["絳闕雲臺總有名，應須極貴又長生。", "鼎中龍虎黄金賤，松下龜蛇綠骨輕。", "霅水未渾纓可濯，弁峰初見眼應明。", "兩卮春酒真堪羨，獨占人間分外榮。"]'),
('2476c886-6956-48e6-9858-2c5140dd25b1','和張子野見寄三絕句 過舊遊','蘇軾','宋','宋诗','song-poetry','','[]','前生我已到杭州，到處長如到舊遊。',32,'全唐诗/poet.song.44000.json','["前生我已到杭州，到處長如到舊遊。", "更欲洞霄爲隠吏，一庵閑地且相留。"]'),
('a9a2850b-f80c-4312-963e-dbb992a9ac71','和張子野見寄三絕句 見題壁','蘇軾','宋','宋诗','song-poetry','','[]','狂吟跌宕無風雅，醉墨淋漓不整齊。',32,'全唐诗/poet.song.44000.json','["狂吟跌宕無風雅，醉墨淋漓不整齊。", "應爲詩人一回顧，山僧未忍掃黄泥。"]'),
('2b785758-0f5a-444c-8510-9fadf90f0905','和張子野見寄三絕句 竹閣見憶','蘇軾','宋','宋诗','song-poetry','','[]','柏堂南畔竹如雲，此閣何人是主人。',32,'全唐诗/poet.song.44000.json','["柏堂南畔竹如雲，此閣何人是主人。", "但遣先生披鶴氅，不須更畫樂天真。"]'),
('70003b47-2ca1-4dd8-b211-b9a38c74d27d','送趙寺丞寄陳海州','蘇軾','宋','宋诗','song-poetry','','[]','景疏樓上喚蛾眉，君到應先誦此詩。',32,'全唐诗/poet.song.44000.json','["景疏樓上喚蛾眉，君到應先誦此詩。", "若見孟公投轄飲，莫忘衝雪送君時。"]'),
('e4f32375-7c00-415f-8b36-5832c8856568','和蔣夔寄茶','蘇軾','宋','宋诗','song-poetry','','[]','我生百事常隨緣，四方水陸無不便。',256,'全唐诗/poet.song.44000.json','["我生百事常隨緣，四方水陸無不便。", "扁舟渡江適吳越，三年飲食窮芳鮮。", "金虀玉膾飯炊雪，海螯江柱初脫泉。", "臨風飽食甘寢罷，一甌花乳浮輕圓。", "自從捨舟入東武，沃野便到桑麻川。", "剪毛胡羊大如馬，誰記鹿角腥盤筵。", "厨中蒸粟堆飯甕，大杓更取酸生涎。", "柘羅銅碾棄不用，脂麻白土須盆研。", "故人猶作舊眼看，謂我好尚如當年。", "沙溪北苑强分別，水脚一綫爭誰先。", "清詩兩幅寄千里，紫金百餠費萬錢。", "吟哦烹噍兩奇絕，只恐偷乞煩封纏。", "老妻稚子不知愛，一半已入薑鹽煎。", "人生所遇無不可，南北嗜好知誰賢。", "死生禍福久不擇，更論甘苦爭蚩妍。", "知君窮旅不自釋，因詩寄謝聊相鎸。"]'),
('683bf39b-7bb6-41dd-b315-eb892ca9c38b','光祿庵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','文章恨不見文園，禮樂方將訪石泉。',32,'全唐诗/poet.song.44000.json','["文章恨不見文園，禮樂方將訪石泉。", "何事庵中著光祿，枉教閑處筆如椽。"]'),
('ec10f67f-c629-47f3-bf50-e8c86bcd4d70','光祿庵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','城中太守的何人，林下先生非我身。',32,'全唐诗/poet.song.44000.json','["城中太守的何人，林下先生非我身。", "若向庵中覓光祿，雪中履迹鏡中真。"]'),
('638a6b87-ac2f-4108-9b4e-f7c54d7108a3','立春日病中邀安國仍請率禹功同來僕雖不能飲當請成伯主會某當杖策倚几於其間觀諸公醉笑以撥滯悶也二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','孤燈照影夜漫漫，拈得花枝不忍看。',64,'全唐诗/poet.song.44000.json','["孤燈照影夜漫漫，拈得花枝不忍看。", "白髮敧簪羞彩勝，黄耆煮粥薦春盤。", "東方烹狗陽初動，南陌爭牛卧作團。", "老子從來興不淺，向隅誰有滿堂歡。"]'),
('285f5027-d5e6-4af4-aa37-3103597e9ca4','立春日病中邀安國仍請率禹功同來僕雖不能飲當請成伯主會某當杖策倚几於其間觀諸公醉笑以撥滯悶也二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','齋居卧病禁烟前，辜負名花已一年。',64,'全唐诗/poet.song.44000.json','["齋居卧病禁烟前，辜負名花已一年。", "此日使君不强喜，早春風物爲誰妍。", "青衫公子家千里，白髮先生杖百錢。", "曷不相將來問病，已教呼取散花天。"]'),
('a876ce9f-617e-4f6c-8175-9508a5ebd86c','答李邦直','蘇軾','宋','宋诗','song-poetry','','[]','美人如春風，著物物未知。',192,'全唐诗/poet.song.44000.json','["美人如春風，著物物未知。", "羈愁似冰雪，見子先流凘。", "子從徐方來，吏民舉熙熙。", "扶病出見之，驚我一何衰。", "知我久慵倦，起我以新詩。", "詩詞如醇酒，盎然熏四支。", "徑飲不覺醉，欲和先昏疲。", "西齋有蠻帳，風雨夜紛披。", "放懷語不擇，撫掌笑脫頤。", "別來今幾何，春物已含姿。", "柳色日夜暗，子來竟何時。", "徐方雖云樂，東山禁游嬉。", "又無狂太守，何以解憂思。", "聞子有賢婦，華堂詠螽斯。", "曷不倒囊橐，賣劍買蛾眉。", "不用教絲竹，唱我新歌詞。"]'),
('272e688b-9888-4238-8953-94e7b7a9ff72','和文與可洋川園池三十首 湖橋','蘇軾','宋','宋诗','song-poetry','','[]','朱欄畫柱照湖明，白葛烏紗曳履行。',32,'全唐诗/poet.song.44000.json','["朱欄畫柱照湖明，白葛烏紗曳履行。", "橋下龜魚晚無數，識君拄杖過橋聲。"]'),
('a3c558e6-b7f2-40b6-bd98-26b2351a9c42','和文與可洋川園池三十首 橫湖','蘇軾','宋','宋诗','song-poetry','','[]','貪看翠蓋擁紅粧，不覺湖邊一夜霜。',32,'全唐诗/poet.song.44000.json','["貪看翠蓋擁紅粧，不覺湖邊一夜霜。", "卷却天機雲錦段，從教匹練寫秋光。"]'),
('4fc5b2ee-2efa-4e70-8dbb-b6e75746f056','和文與可洋川園池三十首 書軒','蘇軾','宋','宋诗','song-poetry','','[]','雨昏石硯寒雲色，風動牙籤亂葉聲。',32,'全唐诗/poet.song.44000.json','["雨昏石硯寒雲色，風動牙籤亂葉聲。", "庭下已生書带草，使君疑是鄭康成。"]'),
('f9cae631-5d64-41c7-b049-0854c13ae7cc','和文與可洋川園池三十首 冰池','蘇軾','宋','宋诗','song-poetry','','[]','不嫌冰雪繞池看，誰似詩人巧耐寒。',32,'全唐诗/poet.song.44000.json','["不嫌冰雪繞池看，誰似詩人巧耐寒。", "記取羲之洗硯處，碧琉璃下黑蛟蟠。"]'),
('0de5ab38-3690-4d54-8bc2-8ccffe6af6a4','和文與可洋川園池三十首 竹塢','蘇軾','宋','宋诗','song-poetry','','[]','晚節先生道轉孤，歲寒惟有竹相娛。',32,'全唐诗/poet.song.44000.json','["晚節先生道轉孤，歲寒惟有竹相娛。", "粗才杜牧真堪笑，喚作軍中十萬夫。"]'),
('65214576-a2b9-4f76-894d-d1bb8d03ffb0','和文與可洋川園池三十首 荻蒲','蘇軾','宋','宋诗','song-poetry','','[]','雨折霜乾不耐秋，白花黄葉使人愁。',32,'全唐诗/poet.song.44000.json','["雨折霜乾不耐秋，白花黄葉使人愁。", "月明小艇湖邊宿，便是江南鸚鵡洲。"]'),
('c3c3e5e0-91e7-4822-8f88-b67f6d2f9b4c','和文與可洋川園池三十首 蓼嶼','蘇軾','宋','宋诗','song-poetry','','[]','秋歸南浦蟪蛄鳴，霜落橫湖沙水清。',32,'全唐诗/poet.song.44000.json','["秋歸南浦蟪蛄鳴，霜落橫湖沙水清。", "卧雨幽花無限思，抱叢寒蝶不勝情。"]'),
('5fa0b78a-c112-40c3-a010-d18df047a628','和文與可洋川園池三十首 望雲樓','蘇軾','宋','宋诗','song-poetry','','[]','陰晴朝暮幾回新，已向虛空付此身。',32,'全唐诗/poet.song.44000.json','["陰晴朝暮幾回新，已向虛空付此身。", "出本無心歸亦好，白雲還似望雲人。"]'),
('9ed8cbef-b687-402c-8b73-4600b3c3166c','和文與可洋川園池三十首 天漢臺','蘇軾','宋','宋诗','song-poetry','','[]','漾水東流舊見經，銀潢左界上通靈。',32,'全唐诗/poet.song.44000.json','["漾水東流舊見經，銀潢左界上通靈。", "此臺試向天文覓，閣道中間第幾星。"]'),
('65d2263a-f39f-4366-9595-6c84f5d55e2f','和文與可洋川園池三十首 待月臺','蘇軾','宋','宋诗','song-poetry','','[]','月與高人本有期，挂簷低戶映蛾眉。',32,'全唐诗/poet.song.44000.json','["月與高人本有期，挂簷低戶映蛾眉。", "只從昨夜十分滿，漸覺冰輪出海遲。"]'),
('8142c203-d8d7-4b14-aeaa-1c2cf0808907','和文與可洋川園池三十首 二樂榭','蘇軾','宋','宋诗','song-poetry','','[]','此間真趣豈容談，二樂并君已是三。',32,'全唐诗/poet.song.44000.json','["此間真趣豈容談，二樂并君已是三。", "仁智更煩訶妄見，坐令魯叟作瞿曇。"]'),
('0a4d5ec3-4354-4e9a-ac43-c60558c266e6','和文與可洋川園池三十首 灙泉亭','蘇軾','宋','宋诗','song-poetry','','[]','聞道池亭勝兩川，應須爛醉答雲烟。',32,'全唐诗/poet.song.44000.json','["聞道池亭勝兩川，應須爛醉答雲烟。", "勸君多揀長腰米，消破亭中萬斛泉。"]'),
('e6b0411a-db3a-402d-9fa4-f2b1fe0051b0','和文與可洋川園池三十首 吏隠亭','蘇軾','宋','宋诗','song-poetry','','[]','縱橫憂患滿人間，頗怪先生日日閑。',32,'全唐诗/poet.song.44000.json','["縱橫憂患滿人間，頗怪先生日日閑。", "昨夜清風眠北牖，朝來爽氣在西山。"]'),
('977fd656-042f-4179-8918-2d95fe4b5d5a','和文與可洋川園池三十首 霜筠亭','蘇軾','宋','宋诗','song-poetry','','[]','解籜新篁不自持，嬋娟已有歲寒姿。',32,'全唐诗/poet.song.44000.json','["解籜新篁不自持，嬋娟已有歲寒姿。", "要看凜凜霜前意，須待秋風粉落時。"]'),
('38942c8a-5be0-4fef-95cb-5a5322e551fe','和文與可洋川園池三十首 無言亭','蘇軾','宋','宋诗','song-poetry','','[]','殷勤稽首維摩詰，敢問如何是法門。',32,'全唐诗/poet.song.44000.json','["殷勤稽首維摩詰，敢問如何是法門。", "彈指未終千偈了，向人還道本無言。"]'),
('411f55e4-be8d-4d50-821c-c6d25da8fdea','和文與可洋川園池三十首 露香亭','蘇軾','宋','宋诗','song-poetry','','[]','亭下佳人錦繡衣，滿身瓔珞綴明璣。',32,'全唐诗/poet.song.44000.json','["亭下佳人錦繡衣，滿身瓔珞綴明璣。", "晚香消歇無尋處，花已飄零露已晞。"]'),
('bec13b29-8cd0-4869-ac9c-cb91e728fe74','和文與可洋川園池三十首 涵虛亭','蘇軾','宋','宋诗','song-poetry','','[]','水軒花榭兩爭妍，秋月春風各自偏。',32,'全唐诗/poet.song.44000.json','["水軒花榭兩爭妍，秋月春風各自偏。", "惟有此亭無一物，坐觀萬景得天全。"]'),
('25c92c98-af31-44c7-9c6f-2498f3f86588','和文與可洋川園池三十首 溪光亭','蘇軾','宋','宋诗','song-poetry','','[]','决去湖波尚有情，却隨初日動檐楹。',32,'全唐诗/poet.song.44000.json','["决去湖波尚有情，却隨初日動檐楹。", "溪光自古無人畫，憑仗新詩與寫成。"]'),
('38440c79-6d5d-44ca-ba72-f350a3ce0265','和文與可洋川園池三十首 過溪亭','蘇軾','宋','宋诗','song-poetry','','[]','身輕步穩去忘歸，四柱亭前野彴微。',32,'全唐诗/poet.song.44000.json','["身輕步穩去忘歸，四柱亭前野彴微。", "忽悟過溪還一笑，水禽驚落翠毛衣。"]'),
('ace41f00-9eb1-4737-9aef-c341d4afbed5','和文與可洋川園池三十首 披錦亭','蘇軾','宋','宋诗','song-poetry','','[]','烟紅露綠曉風香，燕舞鶑啼春日長。',32,'全唐诗/poet.song.44000.json','["烟紅露綠曉風香，燕舞鶑啼春日長。", "誰道使君貧且老，繡屏錦帳咽笙簧。"]'),
('683077de-fedc-48db-a563-f128be157455','和文與可洋川園池三十首 禊亭','蘇軾','宋','宋诗','song-poetry','','[]','曲池流水細鱗鱗，高會傳觴似洛濱。',32,'全唐诗/poet.song.44000.json','["曲池流水細鱗鱗，高會傳觴似洛濱。", "紅粉翠蛾應不要，畫船來往勝於人。"]'),
('4718804c-5c1d-4e3f-8fc3-c2af06dd8f93','和文與可洋川園池三十首 菡萏亭','蘇軾','宋','宋诗','song-poetry','','[]','日日移床趁下風，清香不斷思何窮。',32,'全唐诗/poet.song.44000.json','["日日移床趁下風，清香不斷思何窮。", "若爲化作龜千歲，巢向田田亂葉中。"]'),
('0d3b1da2-bfdf-4002-a335-eafab393872c','和文與可洋川園池三十首 荼蘼洞','蘇軾','宋','宋诗','song-poetry','','[]','長憶故山寒食夜，野荼蘼發暗香來。',32,'全唐诗/poet.song.44000.json','["長憶故山寒食夜，野荼蘼發暗香來。", "分無素手簪羅髻，且折霜蕤浸玉醅。"]'),
('387961a1-c808-44e6-9d1f-05d1d73a5d0c','和文與可洋川園池三十首 篔簹谷','蘇軾','宋','宋诗','song-poetry','','[]','漢川修竹賤如蓬，斤斧何曾赦籜龍。',32,'全唐诗/poet.song.44000.json','["漢川修竹賤如蓬，斤斧何曾赦籜龍。", "料得清貧饞太守，渭川千畝在胸中。"]'),
('58101a44-62aa-4c2f-87db-15ee8f86473e','和文與可洋川園池三十首 寒蘆港','蘇軾','宋','宋诗','song-poetry','','[]','溶溶晴港漾春暉，蘆筍生時柳絮飛。',32,'全唐诗/poet.song.44000.json','["溶溶晴港漾春暉，蘆筍生時柳絮飛。", "還有江南風物否，桃花流水鮆魚肥。"]'),
('141281d7-50fe-4584-b073-fc9ebeae2319','和文與可洋川園池三十首 野人廬','蘇軾','宋','宋诗','song-poetry','','[]','少年辛苦事犁鋤，剛厭青山遶故居。',32,'全唐诗/poet.song.44000.json','["少年辛苦事犁鋤，剛厭青山遶故居。", "老覺華堂無意味，却須時到野人廬。"]'),
('733f008d-ef26-45c1-908e-5f330665c9df','和文與可洋川園池三十首 此君庵','蘇軾','宋','宋诗','song-poetry','','[]','寄語庵前抱節君，與君到處合相親。',32,'全唐诗/poet.song.44000.json','["寄語庵前抱節君，與君到處合相親。", "寫真雖是文夫子，我亦真堂作記人。"]'),
('bd1d4490-0ba2-40fe-8833-e776a92eda1a','和文與可洋川園池三十首 金橙徑','蘇軾','宋','宋诗','song-poetry','','[]','金橙縱復里人知，不見鱸魚價自低。',32,'全唐诗/poet.song.44000.json','["金橙縱復里人知，不見鱸魚價自低。", "須是松江烟雨裏，小船燒薤擣香虀。"]'),
('bd0b8c2e-ccf8-4c20-8a80-afbe0de9d8d6','和文與可洋川園池三十首 南園','蘇軾','宋','宋诗','song-poetry','','[]','不種夭桃與綠楊，使君應欲候農桑。',32,'全唐诗/poet.song.44000.json','["不種夭桃與綠楊，使君應欲候農桑。", "春畦雨過羅紈膩，夏壠風來餠餌香。"]'),
('bc8d3ece-c389-4a28-b56d-f4adeb0d9888','和文與可洋川園池三十首 北園','蘇軾','宋','宋诗','song-poetry','','[]','漢水巴山樂有餘，一麾從此首歸途。',32,'全唐诗/poet.song.44000.json','["漢水巴山樂有餘，一麾從此首歸途。", "北園草木憑君問，許我他年作主無。"]'),
('608df132-c9fb-41cb-8b8e-0e7d799bceef','寄題刁景純藏春塢','蘇軾','宋','宋诗','song-poetry','','[]','白首歸來種萬松，待看千尺舞霜風。',64,'全唐诗/poet.song.44000.json','["白首歸來種萬松，待看千尺舞霜風。", "年拋造物陶甄外，春在先生杖屨中。", "楊柳長齊低戶暗，櫻桃爛熟滴階紅。", "何時却與徐元直，共訪襄陽龐德公。"]'),
('dc651b1e-e226-46f4-b3a7-61d90f4b4489','玉盤盂  其一','蘇軾','宋','宋诗','song-poetry','','[]','雜花狼藉占春餘，芍藥開時掃地無。',64,'全唐诗/poet.song.44000.json','["雜花狼藉占春餘，芍藥開時掃地無。", "兩寺粧成寶瓔珞，一枝爭看玉盤盂。", "佳名會作新翻曲，絕品難逢舊畫圖。", "從此定知年穀熟，姑山親見雪肌膚。"]'),
('2521729f-096d-4795-9dbe-1679c94e55da','玉盤盂  其二','蘇軾','宋','宋诗','song-poetry','','[]','花不能言意可知，令君痛飲更無疑。',64,'全唐诗/poet.song.44000.json','["花不能言意可知，令君痛飲更無疑。", "但持白酒勸嘉客，直待瓊舟覆玉彝。", "負郭相君初擇地，看羊屬國首吟詩。", "吾家豈與花相厚，更問殘芳有幾枝。"]'),
('79c19972-d046-499a-82fe-abc9661f191b','和潞公超然臺次韵','蘇軾','宋','宋诗','song-poetry','','[]','我公厭富貴，常苦勳業尋。',96,'全唐诗/poet.song.44000.json','["我公厭富貴，常苦勳業尋。", "相期赤松子，永望白雲岑。", "清風出談笑，萬竅爲號吟。", "吟成超然詩，洗我蓬之心。", "嗟我本何人，麋鹿强冠襟。", "身微空志大，交淺屢言深。", "囑公如得謝，呼我幸寄音。", "但恐酒錢盡，煩公揮橐金。"]'),
('81bc3a88-0b82-4487-9821-d56a9edddf1f','聞喬太博換左藏知欽州以詩招飲','蘇軾','宋','宋诗','song-poetry','','[]','今年果起故將軍，幽夢清詩信有神。',64,'全唐诗/poet.song.44000.json','["今年果起故將軍，幽夢清詩信有神。", "馬革裹屍真細事，虎頭食肉更何人。", "陣雲冷壓黄茅瘴，羽扇斜揮白葛巾。", "痛飲從今有幾日，西軒月色夜來新。"]'),
('a08ba486-c621-4dda-9a5b-ab618a2cc669','喬將行烹鵝鹿出刀劍以飲客以詩戲之','蘇軾','宋','宋诗','song-poetry','','[]','破匣哀鳴出素虬，倦看鶂鶂聽呦呦。',64,'全唐诗/poet.song.44000.json','["破匣哀鳴出素虬，倦看鶂鶂聽呦呦。", "明朝只恐兼烹鶴，此去還須却佩牛。", "便可先呼報恩子，不妨仍带醉鄉侯。", "他年萬騎歸應好，奈有移文在故丘。"]'),
('ca8bd40e-a803-4efd-8fba-b550931e9aaa','奉和成伯兼戲禹功','蘇軾','宋','宋诗','song-poetry','','[]','金錢石竹道傍秋，翠黛紅裙馬上謳。',32,'全唐诗/poet.song.44000.json','["金錢石竹道傍秋，翠黛紅裙馬上謳。", "無限小兒齊拍手，山公又作習池遊。"]'),
('908b7866-b590-4157-a181-52bf7aac1d05','寄黎眉州','蘇軾','宋','宋诗','song-poetry','','[]','膠西高處望西川，應在孤雲落照邊。',64,'全唐诗/poet.song.44000.json','["膠西高處望西川，應在孤雲落照邊。", "瓦屋寒堆春後雪，峨眉翠掃雨餘天。", "治經方笑春秋學，好士今無六一賢。", "且待淵明賦歸去，共將詩酒趁流年。"]'),
('d7e3665c-1625-4c76-a159-f88a8fc3dac8','和趙郎中捕蝗見寄次韵','蘇軾','宋','宋诗','song-poetry','','[]','麥穗人許長，穀苗牛可沒。',144,'全唐诗/poet.song.44000.json','["麥穗人許長，穀苗牛可沒。", "天公獨何意，忍使蝗蟲發。", "驅攘著令典，農事安可忽。", "我僕既胼胝，我馬亦款矻。", "飛騰漸云少，筋力亦已竭。", "苟無百篇詩，何以醒睡兀。", "初如疏畎澮，漸若决澥渤。", "往來供十吏，腕脫不容歇。", "平生輕妄庸，熟視笑魏勃。", "愛君有逸氣，詩壇專斬伐。", "民病何時休，吏職不可越。", "慎毋及世事，向空書咄咄。"]'),
('8b536cc0-bf5c-45a2-a840-9adb5d12d7d4','登常山絕頂廣麗亭','蘇軾','宋','宋诗','song-poetry','','[]','西望穆陵關，東望琅邪臺。',120,'全唐诗/poet.song.44000.json','["西望穆陵關，東望琅邪臺。", "南望九仙山，北望空飛埃。", "相將叫虞舜，遂欲歸蓬萊。", "嗟我二三子，狂飲亦荒哉。", "紅裙欲仙去，長笛有餘哀。", "清歌入雲霄，妙舞纖腰回。", "自從有此山，白石封蒼苔。", "何嘗有此樂，將去復徘徊。", "人生如朝露，白髮日夜催。", "棄置當何言，萬劫終飛灰。"]'),
('4dfd271c-3a7c-418c-8449-b7878b2d5519','薄薄酒二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','薄薄酒，勝茶湯，粗粗布，勝無裳，醜妻惡妾勝空房。',108,'全唐诗/poet.song.44000.json','["薄薄酒，勝茶湯，粗粗布，勝無裳，醜妻惡妾勝空房。", "五更待漏靴滿霜，不如三伏日高睡足北窗凉。", "珠襦玉柙萬人相送歸北邙，不如懸鶉百結獨坐負朝陽。", "生前富貴，死後文章，百年瞬息萬世忙。", "夷齊盜跖俱亡羊，不如眼前一醉是非憂樂兩都忘。"]'),
('370d1dfa-9ce2-4c67-83df-e1f9a8b12095','薄薄酒二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','薄薄酒，飲兩鍾，粗粗布，著兩重。',120,'全唐诗/poet.song.44000.json','["薄薄酒，飲兩鍾，粗粗布，著兩重。", "美惡雖異醉暖同，醜妻惡妾壽乃公。", "隠居求志義之從，本不計較東華塵土北窗風。", "百年雖長要有終，富死未必輸生窮。", "但恐珠玉留君容，千載不朽遭樊崇。", "文章自足欺盲聾，誰使一朝富貴面發紅。", "達人自達酒何功，世間是非憂樂本來空。"]'),
('36b6c96e-647d-4c9a-bedf-da9f5cca92ea','同年王中甫挽詞','蘇軾','宋','宋诗','song-poetry','','[]','先帝親收十五人，四方爭看擊鵬鵾。',64,'全唐诗/poet.song.44000.json','["先帝親收十五人，四方爭看擊鵬鵾。", "如君事業真堪用，顧我衰遲不足論。", "出處升沉十年後，死生契闊幾人存。", "他時京口尋遺跡，宿草猶應有淚痕。"]'),
('8604cc4e-6970-485f-b9d2-210afbbc077a','七月五日二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','避謗詩尋醫，畏病酒入務。',72,'全唐诗/poet.song.44000.json','["避謗詩尋醫，畏病酒入務。", "蕭條北窗下，長日誰與度。", "今年苦炎熱，草木困薰煮。", "況我早衰人，幽居氣如縷。", "秋來有佳興，秫稻已含露。", "還復此微吟，往和糟牀注。"]'),
('ea5d42b1-c0b9-4dcf-ae9a-460e3d4903d6','七月五日二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','何處覓新秋，蕭然北臺上。',72,'全唐诗/poet.song.44000.json','["何處覓新秋，蕭然北臺上。", "秋來未云幾，風日已清亮。", "雲間聳孤翠，林表浮遠漲。", "新棗漸堪剝，晚瓜猶可餉。", "西風送落日，萬竅含悽愴。", "念當急行樂，白髮不汝放。"]'),
('0d2ee5ec-6351-49bd-ad76-a7c8b8c2642c','趙郎中見和戲復答之','蘇軾','宋','宋诗','song-poetry','','[]','趙子吟詩如潑水，一揮三百六十字。',96,'全唐诗/poet.song.44000.json','["趙子吟詩如潑水，一揮三百六十字。", "奈何效我欲尋醫，恰似西施藏白地。", "趙子飲酒如淋灰，一年十萬八千杯。", "若不令君早入務，飲竭東海生黄埃。", "我衰臨政多繆錯，羨君精采如秋鶚。", "頗哀老子令日飲，爲君坐嘯主畫諾。"]'),
('a1655999-bf66-4bb4-9af0-67154dd7021a','和魯人孔周翰題詩二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','壞壁題詩已五年，故人風物兩依然。',32,'全唐诗/poet.song.44000.json','["壞壁題詩已五年，故人風物兩依然。", "定知來歲中秋月，又照先生枕麴眠。"]'),
('a0257c89-8805-44e2-b39e-e455c1721b7d','和魯人孔周翰題詩二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','更邀明月說明年，記取孤吟孟浩然。',32,'全唐诗/poet.song.44000.json','["更邀明月說明年，記取孤吟孟浩然。", "此去宦遊如傳舍，揀枝驚鵲幾時眠。"]'),
('cdf8a0a5-075b-4aa5-8a24-d4af18c6b1cb','送碧香酒與趙明叔教授','蘇軾','宋','宋诗','song-poetry','','[]','聞君有婦賢且廉，勸君慎勿爲楚相。',96,'全唐诗/poet.song.44000.json','["聞君有婦賢且廉，勸君慎勿爲楚相。", "不羨紫駝分御食，自遣赤脚沽村釀。", "嗟君老狂不知愧，更吟醜婦惡嘲謗。", "諸生聞語定失笑，冬暖號寒卧無帳。", "碧香近出帝子家，鵝兒破殻酥流盎。", "不學劉伶獨自飲，一壺往助齊眉餉。"]'),
('c0bba73e-4dc3-4d99-b12b-7eb9487b1610','趙既見和復次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','長安小吏天所放，日夜歌呼和丞相。',96,'全唐诗/poet.song.44000.json','["長安小吏天所放，日夜歌呼和丞相。", "豈知後世有阿瞞，北海樽前捉私釀。", "先生未出禁酒國，詩語孤高常近謗。", "幾回無酒欲沽君，却畏有司書簿帳。", "酸寒可笑分一斗，日飲無何足袁盎。", "更將險語壓衰翁，只恐自是臺無餉。"]'),
('19b32ea5-43b5-4379-a078-c444fae6e263','趙郎中往莒縣逾月而歸復以一壺遺之仍用前韵','蘇軾','宋','宋诗','song-poetry','','[]','東鄰主人游不歸，悲歌夜夜聞舂相。',96,'全唐诗/poet.song.44000.json','["東鄰主人游不歸，悲歌夜夜聞舂相。", "門前人鬧馬嘶急，一家喜氣如春釀。", "王事何曾怨獨賢，室人豈忍交謫謗。", "大兒踉蹡越門限，小兒咿啞語繡帳。", "定教舞袖掣伊凉，更想夜庖鳴甕盎。", "題詩送酒君勿誚，免使退之嘲一餉。"]'),
('55be6fa3-a8c4-4469-8d62-c5382992be70','蘇潛聖挽詞','蘇軾','宋','宋诗','song-poetry','','[]','妙齡馳譽百夫雄，晚節忘懷大隠中。',64,'全唐诗/poet.song.44000.json','["妙齡馳譽百夫雄，晚節忘懷大隠中。", "悃愊無華真漢吏，文章爾雅稱吾宗。", "趨時肯負平生志，有子還應不死同。", "惟我閑思十年事，數行老淚寄西風。"]'),
('915466ca-3dd4-4f6c-b73a-714268a455ea','和晁同年九日見寄','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','仰看鸞鵠刺天飛，富貴功名老不思。',64,'全唐诗/poet.song.44000.json','["仰看鸞鵠刺天飛，富貴功名老不思。", "病馬已無千里志，騷人長負一秋悲。", "古來重九皆如此，別後西湖付與誰。", "遣子窮愁天有意，吳中山水要清詩。"]'),
('540cd7fa-d99b-4364-a0df-3ba7689cc1f9','送喬施州','蘇軾','宋','宋诗','song-poetry','','[]','恨無負郭田二頃，空有載行書五車。',64,'全唐诗/poet.song.44000.json','["恨無負郭田二頃，空有載行書五車。", "江上青山橫絕壁，雲間細路躡飛蛇。", "雞號黑暗通蠻貨，蜂鬧黄連採蜜花。", "共怪河南門下客，不應萬里向長沙。"]'),
('6dab844d-addd-4e17-90bc-6eff68858248','次韵周邠寄雁蕩山圖二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','指點先憑采藥翁，丹青化出大槐宮。',64,'全唐诗/poet.song.44000.json','["指點先憑采藥翁，丹青化出大槐宮。", "眼明小閣浮烟翠，齒冷新詩嚼雪風。", "二華行看雄陝右，九仙今已壓京東。", "此生的有尋山分，已覺溫台落手中。"]'),
('790d6d52-f123-4793-9dfc-7031536b4b32','次韵周邠寄雁蕩山圖二首  其二','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','西湖三載與君同，馬入塵埃鶴入籠。',64,'全唐诗/poet.song.44000.json','["西湖三載與君同，馬入塵埃鶴入籠。", "東海獨來看出日，石橋先去踏長虹。", "遥知別後添華髮，時向樽前說病翁。", "所恨蜀山君未見，他年携手醉郫筒。"]'),
('ba77985b-5dc1-4263-ba4d-38934455dd9b','雪夜獨宿柏仙庵','蘇軾','宋','宋诗','song-poetry','','[]','晚雨纖纖變玉霙，小庵高卧有餘清。',64,'全唐诗/poet.song.44000.json','["晚雨纖纖變玉霙，小庵高卧有餘清。", "夢驚忽有穿窗片，夜靜惟聞瀉竹聲。", "稍壓冬溫聊得健，未濡秋旱若爲耕。", "天公用意真難會，又作春風爛漫晴。"]'),
('ee5e7c61-a0a1-4eaa-84a5-df92a3d7aaad','和孔郎中荆林馬上見寄','蘇軾','宋','宋诗','song-poetry','','[]','秋禾不滿眼，宿麥種亦稀。',108,'全唐诗/poet.song.44000.json','["秋禾不滿眼，宿麥種亦稀。", "永愧此邦人，芒刺在膚肌。", "平生五千卷，一字不救饑。", "方將怨無襦，忽復歌緇衣。", "堂堂孔北海，直氣凜羣兒。", "朱輪未及郊，清風已先馳。", "何以累君子，十萬貧與羸。", "滔滔滿四方，我行竟安之。", "何時劍關路，春山聞子規。"]'),
('437cbbe5-f567-400a-9039-961ea5f9734a','別東武流杯','蘇軾','宋','宋诗','song-poetry','','[]','莫笑官居如傳舍，故應人世等浮雲。',32,'全唐诗/poet.song.44000.json','["莫笑官居如傳舍，故應人世等浮雲。", "百年父老知誰在，惟有雙松識使君。"]'),
('49f5d419-7f6d-4925-a1fe-48426156ac5c','留別雩泉','蘇軾','宋','宋诗','song-poetry','','[]','舉酒屬雩泉，白髮日夜新。',48,'全唐诗/poet.song.44000.json','["舉酒屬雩泉，白髮日夜新。", "何時泉中天，復照泉上人。", "二年飲泉水，魚鳥亦相親。", "還將弄泉手，遮日向西秦。"]'),
('b581ff91-7157-4094-91e5-9a36601ba2d3','留別釋迦院牡丹呈趙倅','蘇軾','宋','宋诗','song-poetry','','[]','春風小院初來時，壁間惟見使君詩。',64,'全唐诗/poet.song.44000.json','["春風小院初來時，壁間惟見使君詩。", "應問使君何處去，憑花說與春風知。", "年年歲歲何窮已，花似今年人老矣。", "去年崔護若重來，前度劉郎在千里。"]'),
('e5b2440e-2339-463d-bb63-247de138e8ec','董儲郎中嘗知眉州與先人遊過安丘訪其故居見其子希甫留詩屋壁','蘇軾','宋','宋诗','song-poetry','','[]','白髮郎潛舊使君，至今人道最能文。',64,'全唐诗/poet.song.44000.json','["白髮郎潛舊使君，至今人道最能文。", "隻雞敢忘橋公語，下馬來尋董相墳。", "冬月負薪雖得免，鄰人吹笛不堪聞。", "死生契闊君休問，灑淚西南向白雲。"]'),
('07bef840-1c13-4bb1-a994-3431c79ac7d4','除夜大雪留濰州元日早晴遂行中途雪復作','蘇軾','宋','宋诗','song-poetry','','[]','除夜雪相留，元日晴相送。',120,'全唐诗/poet.song.44000.json','["除夜雪相留，元日晴相送。", "東風吹宿酒，瘦馬兀殘夢。", "葱曨曉光開，旋轉餘花弄。", "下馬成野酌，佳哉誰與共。", "須臾晚雲合，亂灑無缺空。", "鵝毛垂馬騣，自怪騎白鳳。", "三年東方旱，逃戶連敧棟。", "老農釋耒歎，淚入饑腸痛。", "春雪雖云晚，春麥猶可種。", "敢怨行役勞，助爾歌飯甕。"]'),
('1adc9353-3128-4008-80a7-ed311cdd205d','大雪青州道上有懷東武園亭寄交代孔周翰','蘇軾','宋','宋诗','song-poetry','','[]','超然臺上雪，城郭山川兩奇絕。',146,'全唐诗/poet.song.44000.json','["超然臺上雪，城郭山川兩奇絕。", "海風吹碎碧琉璃，時見三山白銀闕。", "蓋公堂前雪，綠窗朱戶相明滅。", "堂中美人雪爭妍，粲然一笑玉齒頰。", "就中山堂雪更奇，青松怪石亂瓊絲。", "惟有使君游不歸，五更馬上愁斂眉。", "君不是淮西李侍中，夜入蔡州縛取吳元濟。", "又不是襄陽孟浩然，長安道上騎馿吟雪詩。", "何當閉門飲美酒，無人毀譽河東守。"]'),
('70d9d8f4-9f84-4a25-b987-cd030416c3fe','至濟南李公擇以詩相迎次其韵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','敝裘羸馬古河濱，野闊天低糝玉塵。',64,'全唐诗/poet.song.44000.json','["敝裘羸馬古河濱，野闊天低糝玉塵。", "自笑餐氈典屬國，來看換酒謫仙人。", "宦遊到處身如寄，農事何時手自親。", "剩作新詩與君和，莫因風雨廢鳴晨。"]'),
('fbb9b5f6-f7ba-4b26-9f77-0a96c3e078a0','至濟南李公擇以詩相迎次其韵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','夜擁笙歌霅水濱，回頭樂事總成塵。',64,'全唐诗/poet.song.44000.json','["夜擁笙歌霅水濱，回頭樂事總成塵。", "今年送汝作太守，到處逢君是主人。", "聚散細思都是夢，身名漸覺兩非親。", "相從繼燭何須問，蝙蝠飛時日正晨。"]'),
('e9ff2599-3594-4410-9f00-e8d7bd1e574b','和孔君亮郎中見贈','蘇軾','宋','宋诗','song-poetry','','[]','偶對先生盡一樽，醉看萬物洶崩奔。',64,'全唐诗/poet.song.44000.json','["偶對先生盡一樽，醉看萬物洶崩奔。", "優游共我聊卒歲，骯髒如君合倚門。", "只恐掉頭難久住，應須傾蓋便深論。", "固知嚴勝風流在，又見長身十世孫。"]'),
('22c25726-5dbf-4d50-b880-d11f1bae25fa','送范景仁游洛中','蘇軾','宋','宋诗','song-poetry','','[]','小人真闇事，閑退豈公難。',144,'全唐诗/poet.song.44000.json','["小人真闇事，閑退豈公難。", "道大吾何病，言深聽者寒。", "憂時雖早白，駐世有還丹。", "得酒相逢樂，無心所遇安。", "去年行萬里，蜀路走千盤。", "投老身彌健，登山意未闌。", "西游爲櫻筍，東道盡鵷鸞。", "杖屨携兒去，園亭借客看。", "折花斑竹寺，弄水石樓灘。", "鬻馬衰憐白，驚雷怯笑韓。", "蘚書標洞府，松蓋偃天壇。", "試與劉夫子，重尋靖長官。"]'),
('2ef1bfce-b6fa-41e4-9ac1-a503b877525a','次韵景仁留別','蘇軾','宋','宋诗','song-poetry','','[]','公老我亦衰，相見恨不數。',96,'全唐诗/poet.song.44000.json','["公老我亦衰，相見恨不數。", "臨行一杯酒，此意重山岳。", "歌詞白紵清，琴弄黄鍾濁。", "詩新眇難和，飲少僅可學。", "欲參兵部選，有力誰如犖。", "且作東諸侯，山城雄鼓角。", "南游許過我，不憚千里邈。", "會當聞公來，倒屣髮一握。"]'),
('bea7ce8f-ae59-41b6-861c-f85a518bbde6','書韓幹牧馬圖','蘇軾','宋','宋诗','song-poetry','','[]','南山之下，汧渭之間，想見開元天寶年。',202,'全唐诗/poet.song.44000.json','["南山之下，汧渭之間，想見開元天寶年。", "八坊分屯隘秦川，四十萬匹如雲烟。", "騅駓駰駱驪騮騵，白魚赤兔騂皇䮧。", "龍顱鳳頸獰且妍，奇姿逸德隠駑頑。", "碧眼胡兒手足鮮，歲時剪刷供帝閑。", "柘袍臨池侍三千，紅粧照日光流淵。", "樓下玉螭吐清寒，往來蹙踏生飛湍。", "衆工舐筆和朱鉛，先生曹霸弟子韓。", "廐馬多肉尻脽圓，肉中畫骨誇尤難，金羈玉勒繡羅鞍。", "鞭箠刻烙傷天全，不如此圖近自然。", "平沙細草荒芊綿，驚鴻脫兔爭後先。", "王良挾策飛上天，何必俯首服短轅。"]'),
('ae3bc5c8-aee8-4ab6-9e7a-1906d67b1ddd','京師哭任遵聖','蘇軾','宋','宋诗','song-poetry','','[]','十年不還鄉，兒女日夜長。',216,'全唐诗/poet.song.44000.json','["十年不還鄉，兒女日夜長。", "豈惟催老大，漸復成彫喪。", "每聞耆舊亡，涕泣聲輒放。", "老任況奇逸，先子推輩行。", "文章少得譽，詩語尤清壯。", "吏能復所長，談笑萬夫上。", "自喜作劇縣，偏工破豪黨。", "奮髯走猾吏，嚼齒對姦將。", "哀哉命不偶，每以才得謗。", "竟使落窮山，青衫就黄壤。", "宦游久不樂，江海永相望。", "退耕本就君，時節相勞餉。", "此懷今不遂，歸見纍纍葬。", "望哭國西門，落日銜千嶂。", "平生惟一子，抱負珠在掌。", "見之齠齔中，已有食牛量。", "他年如入洛，生死一相訪。", "惟有王濬沖，心知中散狀。"]'),
('681b3748-074c-484e-bef1-cb339557c5ec','送魯元翰少卿知衛州','蘇軾','宋','宋诗','song-poetry','','[]','冗士無處著，寄身范公園。',240,'全唐诗/poet.song.44000.json','["冗士無處著，寄身范公園。", "桃李忽成陰，薺麥秀已繁。", "閉門春晝永，惟有黄蜂喧。", "誰人肯携酒，共醉榆柳村。", "髯卿獨何者，一月三到門。", "我不往拜之，髯來意彌敦。", "堂堂元老後，亹亹仁人言。", "憶在錢塘歲，情好均弟昆。", "時於冰雪中，笑語作春溫。", "欲飲徑相覓，夜開叢竹軒。", "搜尋到篋笥，鮓醢無復存。", "每愧烟火中，玉腕親炮燔。", "別來今幾何，相對如夢魂。", "告我當北渡，新詩侑清樽。", "坡陀太行麓，洶湧黄河翻。", "仕宦非不遇，王畿西北垣。", "斯民如魚耳，見網則驚奔。", "皎皎千丈清，不如尺水渾。", "刑政雖首務，念當養其源。", "一聞襦袴音，盜賊安足論。"]'),
('94c212f4-6be9-4b5f-9ff2-6b35c09c69d9','次韵子由送蔣夔赴代州學官','蘇軾','宋','宋诗','song-poetry','','[]','功利爭先變法初，典型獨守老成餘。',64,'全唐诗/poet.song.44000.json','["功利爭先變法初，典型獨守老成餘。", "窮人未信詩能爾，倚市懸知繡不如。", "代北諸生漸狂簡，牀頭雜說爲爬梳。", "歸來問雁吾何敢，疾世王符解著書。"]'),
('da94475a-47bb-4a0b-afe4-266f7eec8310','宿州次韵劉涇','蘇軾','宋','宋诗','song-poetry','','[]','我欲歸休瑟漸希，舞雩何日著春衣。',64,'全唐诗/poet.song.44000.json','["我欲歸休瑟漸希，舞雩何日著春衣。", "多情白髮三千丈，無用蒼皮四十圍。", "晚覺文章真小技，早知富貴有危機。", "爲君垂涕君知否，千古華亭鶴自飛。"]'),
('4f3d666c-1cd7-4cb8-9abc-7771a13cab28','徐州送交代仲達少卿','蘇軾','宋','宋诗','song-poetry','','[]','此身無用且東來，頼有江山慰不才。',64,'全唐诗/poet.song.44000.json','["此身無用且東來，頼有江山慰不才。", "舊尹未嫌衰廢久，清樽猶許再三開。", "滿城遺愛知誰繼，極目扁舟挽不回。", "歸去青雲還記否，交遊勝絕古城隈。"]'),
('a62421d7-54ba-4e7e-afde-caa0daa2645c','和孔密州五絕 見邸家園留題','蘇軾','宋','宋诗','song-poetry','','[]','大旆傳聞載酒過，小詩未忍著磚磨。',32,'全唐诗/poet.song.44000.json','["大旆傳聞載酒過，小詩未忍著磚磨。", "陽關三疊君須秘，除却膠西不解歌。"]'),
('1cb0dbff-e12e-46f6-86a2-9d6b808f8fea','和孔密州五絕 春步西園見寄','蘇軾','宋','宋诗','song-poetry','','[]','歲歲開園成故事，年年行樂不辜春。',32,'全唐诗/poet.song.44000.json','["歲歲開園成故事，年年行樂不辜春。", "今年太守尤難繼，慈愛聰明惠利人。"]'),
('89b825d7-5843-465c-9b40-51a182f35d9f','和孔密州五絕 東欄梨花','蘇軾','宋','宋诗','song-poetry','','[]','梨花淡白柳深青，柳絮飛時花滿城。',32,'全唐诗/poet.song.44000.json','["梨花淡白柳深青，柳絮飛時花滿城。", "惆悵東欄二株雪，人生看得幾清明。"]'),
('4f9af534-da47-4810-ac3f-6c839c05a9ba','和孔密州五絕 和流杯石上草書小詩','蘇軾','宋','宋诗','song-poetry','','[]','蜂腰鶴膝嘲希逸，春蚓秋蛇病子雲。',32,'全唐诗/poet.song.44000.json','["蜂腰鶴膝嘲希逸，春蚓秋蛇病子雲。", "醉裏自書醒自笑，如今二絕更逢君。"]'),
('11328e24-0509-4725-888b-882696dc0004','和孔密州五絕 堂後白牡丹','蘇軾','宋','宋诗','song-poetry','','[]','城西千葉豈不好，笑舞春風醉臉丹。',32,'全唐诗/poet.song.44000.json','["城西千葉豈不好，笑舞春風醉臉丹。", "何似後堂冰玉潔，遊蜂非意不相干。"]'),
('92c2d2cc-dc2c-463a-b858-e087cfcd639e','和趙郎中見戲二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','燕子人亡三百秋，捲簾那復似揚州。',32,'全唐诗/poet.song.44000.json','["燕子人亡三百秋，捲簾那復似揚州。", "西行未必能勝此，空唱崔徽上白樓。"]'),
('776ff83a-ab39-43e1-8143-15194a3f4bf8','和趙郎中見戲二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','我擊藤床君唱歌，明年六十奈君何。',32,'全唐诗/poet.song.44000.json','["我擊藤床君唱歌，明年六十奈君何。", "醉顛只要裝風景，莫向人前自洗磨。"]'),
('951928ce-7d15-4650-95d3-b124067a4d9c','司馬君實獨樂園','蘇軾','宋','宋诗','song-poetry','','[]','青山在屋上，流水在屋下。',156,'全唐诗/poet.song.44000.json','["青山在屋上，流水在屋下。", "中有五畝園，花竹秀而野。", "花香襲杖屨，竹色侵杯斝。", "樽酒樂餘春，棋局消長夏。", "洛陽古多士，風俗猶爾雅。", "先生卧不出，冠蓋傾洛社。", "雖云與衆樂，中有獨樂者。", "才全德不形，所貴知我寡。", "先生獨何事，四海望陶冶。", "兒童誦君實，走卒知司馬。", "持此欲安歸，造物不我捨。", "名聲逐吾輩，此病天所赭。", "撫掌笑先生，年來效瘖啞。"]'),
('cef32474-067b-4c54-901e-e6470b803bab','和李邦直沂山祈雨有應','蘇軾','宋','宋诗','song-poetry','','[]','高田生黄埃，下田生蒼耳。',154,'全唐诗/poet.song.44000.json','["高田生黄埃，下田生蒼耳。", "蒼耳亦已無，更問麥有幾。", "蛟龍睡足亦解慚，二麥枯時雨如洗。", "不知雨從何處來，但聞呂梁百步聲如雷。", "試上城南望城北，際天菽粟青成堆。", "饑火燒腸作牛吼，不知待得秋成否。", "半年不雨坐龍慵，共怨天公不怨龍。", "今朝一雨聊自贖，龍神社鬼各言功。", "無功日盜太倉穀，嗟我與龍同此責。", "勸農使者不汝容，因君作詩先自劾。"]'),
('9d6677a1-8a24-4331-b085-6cb162f045e0','次韵子由與顔長道同遊百步洪相地築亭種柳','蘇軾','宋','宋诗','song-poetry','','[]','平明坐衙不暖席，歸來閉閣閑終日。',128,'全唐诗/poet.song.44000.json','["平明坐衙不暖席，歸來閉閣閑終日。", "卧聞客至倒屣迎，兩眼蒙籠餘睡色。", "城東泗水步可到，路轉河洪翻雪白。", "安得青絲絡駿馬，蹙踏飛波柳陰下。", "奮身三丈兩蹄間，振鬣長鳴聲自乾。", "少年狂興久已謝，但憶嘉陵繞劍關。", "劍關大道車方軌，君自不去歸何難。", "山中故人應大笑，築室種柳何時還。"]'),
('9d7fdb38-c8f5-44e8-92a4-9de6efdd8074','與梁先舒煥泛舟得臨釀字二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','彭城古戰國，孤客倦登臨。',48,'全唐诗/poet.song.44000.json','["彭城古戰國，孤客倦登臨。", "汴泗交流處，清潭百丈深。", "故人輕千里，繭足來相尋。", "何以娛嘉客，潭水洗君心。"]'),
('747e7368-f4fd-4369-8c85-a8174ccc2d96','與梁先舒煥泛舟得臨釀字二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','老守厭簿書，先生罷函丈。',48,'全唐诗/poet.song.44000.json','["老守厭簿書，先生罷函丈。", "風流魏晉間，談笑羲皇上。", "河洪忽已過，水色綠可釀。", "君無輕此樂，此樂清且放。"]'),
('ca928f27-a015-47d0-892d-6c9f7e98e7e3','次韵李邦直感舊','蘇軾','宋','宋诗','song-poetry','','[]','騶騎傳呼出跨坊，簿書填委入充堂。',64,'全唐诗/poet.song.44000.json','["騶騎傳呼出跨坊，簿書填委入充堂。", "誰教按部如何武，只許清尊對孟光。", "婉娩有時來入夢，溫柔何日聽還鄉。", "酸寒病守尤堪笑，千步空餘僕射場。"]'),
('3821c343-d134-4874-965d-b3c73921e1e2','次韵答邦直子由五首  其一','蘇軾','宋','宋诗','song-poetry','','[]','簿書顛倒夢魂間，知我疏慵肯見原。',64,'全唐诗/poet.song.44000.json','["簿書顛倒夢魂間，知我疏慵肯見原。", "閑作閉門僧舍冷，卧聞吹枕海濤喧。", "忘懷杯酒逢人共，引睡文書信手翻。", "欲吐狂言喙三尺，怕君嗔我却須吞。"]'),
('b0bb67a5-f26e-4d50-b423-134e7ab309b0','次韵答邦直子由五首  其二','蘇軾','宋','宋诗','song-poetry','','[]','城南短李好交遊，箕踞狂歌不自由。',64,'全唐诗/poet.song.44000.json','["城南短李好交遊，箕踞狂歌不自由。", "尊主庇民君有道，樂天知命我無憂。", "醉呼妙舞留連夜，閑作清詩斷送秋。", "瀟灑使君殊不俗，樽前容我攬須不。"]'),
('97cd1a06-589a-487f-bb90-2ef5900bc299','次韵答邦直子由五首  其三','蘇軾','宋','宋诗','song-poetry','','[]','老弟東來殊寂寞，故人留飲慰酸寒。',64,'全唐诗/poet.song.44000.json','["老弟東來殊寂寞，故人留飲慰酸寒。", "草荒城角開新徑，雨入河洪失舊灘。", "車馬追陪迹未掃，唱酬往復字應漫。", "此詩更欲憑君改，待與江南子布看。"]'),
('df73cace-8a78-4cf9-9030-1a5b6d50da41','次韵答邦直子由五首  其四','蘇軾','宋','宋诗','song-poetry','','[]','君雖爲我此遲留，別後淒涼我已憂。',64,'全唐诗/poet.song.44000.json','["君雖爲我此遲留，別後淒涼我已憂。", "不見便同千里遠，退歸終作十年游。", "恨無揚子一區宅，懶卧元龍百尺樓。", "聞道鵷鸞滿臺閣，網羅應不到沙鷗。"]'),
('c391b912-4172-4f29-b619-8a9a80b8fe1b','次韵答邦直子由五首  其五','蘇軾','宋','宋诗','song-poetry','','[]','五斗塵勞尚足留，閉關却欲治幽憂。',64,'全唐诗/poet.song.44000.json','["五斗塵勞尚足留，閉關却欲治幽憂。", "羞爲毛遂囊中穎，未許朱雲地下遊。", "無事會須成好飲，思歸時欲賦登樓。", "羨君幕府如僧舍，日向城南看浴鷗。"]'),
('b9dad7c5-3d79-4287-86e7-c32b13ddc662','送顔復兼寄王鞏','蘇軾','宋','宋诗','song-poetry','','[]','彭城官居冷如水，誰從我遊顔氏子。',192,'全唐诗/poet.song.44000.json','["彭城官居冷如水，誰從我遊顔氏子。", "我衰且病君亦窮，衰窮相守正其理。", "胡爲一朝捨我去，輕衫觸熱行千里。", "問君無乃求之與，答我不然聊爾耳。", "京師萬事日日新，故人如故今有幾。", "君知牛行相君宅，扣門但覓王居士。", "清詩草聖俱入妙，別後寄我書連紙。", "苦恨相思不相見，約我重陽嗅霜蕊。", "君歸可喚與俱來，未應指目妨進擬。", "太一老仙閑不出，踵門問道今時矣。", "因行過我路幾何，願君推挽加鞭箠。", "吾儕一醉豈易得，買羊釀酒從今始。"]'),
('0c321d77-a973-4659-9db1-e539960bd3ac','蝎虎','蘇軾','宋','宋诗','song-poetry','','[]','黄鷄啄蝎如啄黍，窗間守宮稱蝎虎。',96,'全唐诗/poet.song.44000.json','["黄鷄啄蝎如啄黍，窗間守宮稱蝎虎。", "闇中繳尾伺飛蟲，巧捷功夫在腰膂。", "跂跂脈脈善緣壁，陋質從來誰比數。", "今年歲旱號蜥蜴，狂走兒童鬧歌舞。", "能銜渠水作冰雹，便向蛟龍覓雲雨。", "守宮努力搏蒼蠅，明年歲旱當求汝。"]'),
('15de4028-2033-4dee-af69-d7e01b77085a','子由將赴南都與余會宿於逍遥堂作兩絕句讀之殆不可爲懷因和其詩以自解余觀子由自少曠達天資近道又得至人養生長年之訣而余亦竊聞其一二以爲今者宦游相別之日淺而異時退休相從之日長既以自解且以慰子由云  其一','蘇軾','宋','宋诗','song-poetry','','[]','別期漸近不堪聞，風雨蕭蕭已斷魂。',32,'全唐诗/poet.song.44000.json','["別期漸近不堪聞，風雨蕭蕭已斷魂。", "猶勝相逢不相識，形容變盡語音存。"]'),
('b5774023-e2d8-4abd-837d-f32534cbe7c5','子由將赴南都與余會宿於逍遥堂作兩絕句讀之殆不可爲懷因和其詩以自解余觀子由自少曠達天資近道又得至人養生長年之訣而余亦竊聞其一二以爲今者宦游相別之日淺而異時退休相從之日長既以自解且以慰子由云  其二','蘇軾','宋','宋诗','song-poetry','','[]','但令朱雀長金花，此別還同一轉車。',32,'全唐诗/poet.song.44000.json','["但令朱雀長金花，此別還同一轉車。", "五百年間誰復在，會看銅狄兩咨嗟。"]'),
('744a8935-6211-4614-b325-c8f3a4af4bed','留題石經院三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','葱蒨門前路，行穿翠密中。',24,'全唐诗/poet.song.44000.json','["葱蒨門前路，行穿翠密中。", "却來堂上看，巌谷意無窮。"]'),
('540fe053-3535-4306-b16b-a2535989e3c3','留題石經院三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','夭矯庭中檜，枯枝鵲踏消。',24,'全唐诗/poet.song.44000.json','["夭矯庭中檜，枯枝鵲踏消。", "瘦皮纏鶴骨，高頂轉龍腰。"]'),
('a0407f4c-5521-4241-8cf2-2f3ba0f2da98','留題石經院三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','窈窕山頭井，潛通伏澗清。',24,'全唐诗/poet.song.44000.json','["窈窕山頭井，潛通伏澗清。", "欲知深幾許，聽放轆轤聲。"]'),
('3f39fb69-81d9-46ab-b16b-68a85bbae807','過雲龍山人張天驥','蘇軾','宋','宋诗','song-poetry','','[]','郊原雨初足，風日清且好。',192,'全唐诗/poet.song.44000.json','["郊原雨初足，風日清且好。", "病守亦欣然，肩輿白門道。", "荒田咽蛩蚓，村巷懸梨棗。", "下有幽人居，閉門空雀噪。", "西風高正厲，落葉紛可掃。", "孤童卧斜日，病馬放秋草。", "墟里通有無，垣牆任摧倒。", "君家本冠蓋，絲竹鬧鄰保。", "脫身聲利中，道德自濯澡。", "躬耕抱羸疾，奉養百歲老。", "詩書膏吻頰，菽水媚翁媼。", "饑寒天隨子，杞菊自擷芼。", "慈孝董邵南，雞狗相乳抱。", "吾生如寄耳，歸計失不早。", "故山豈敢忘，但恐迫華皓。", "從君好種秫，斗酒時自勞。"]'),
('8ffbbc42-d591-483b-8505-2d9ce26aa12c','贈王仲素寺丞','蘇軾','宋','宋诗','song-poetry','','[]','養氣如養兒，棄官如棄泥。',192,'全唐诗/poet.song.44000.json','["養氣如養兒，棄官如棄泥。", "人皆笑子拙，事定竟誰迷。", "歸耕獨患貧，問子何所齎。", "尺宅足自庇，寸田有餘畦。", "明珠照短褐，陋室生虹霓。", "雖無孔方兄，顧有法喜妻。", "彈琴一長嘯，不答阮與嵇。", "曹南劉夫子，名與子政齊。", "家有鴻寶書，不鑄金褭蹄。", "促膝問道要，遂蒙分刀圭。", "不忍獨不死，尺書肯見梯。", "我生本强鄙，少以氣自擠。", "孤舟倒江河，赤手攬象犀。", "年來稍自笑，留氣下暖臍。", "苦恨聞道晚，意象颯已淒。", "空見孫思邈，區區賦病梨。"]'),
('91ce8779-dc19-49f6-96bc-b80a5e3608cd','陽關詞三首 贈張繼愿','蘇軾','宋','宋诗','song-poetry','','[]','受降城下紫髯郎，戲馬臺前古戰場。',32,'全唐诗/poet.song.44000.json','["受降城下紫髯郎，戲馬臺前古戰場。", "恨君不取契丹首，金甲牙旗歸故鄉。"]'),
('e0e24fd4-ddd4-473f-a55d-8bebdbf7325e','陽關詞三首 答李公擇','蘇軾','宋','宋诗','song-poetry','','[]','濟南春好雪初晴，行到龍山馬足輕。',32,'全唐诗/poet.song.44000.json','["濟南春好雪初晴，行到龍山馬足輕。", "使君莫忘霅溪女，時作陽關腸斷聲。"]'),
('16986fb6-d025-4ce1-83ff-10e036967042','陽關詞三首 中秋月','蘇軾','宋','宋诗','song-poetry','','["\u5b8b\u8bcd\u7cbe\u9009", "\u4e2d\u79cb\u8282", "\u79bb\u522b", "\u6708\u4eae", "\u4e2d\u79cb"]','暮雲收盡溢清寒，銀漢無聲轉玉盤。',32,'全唐诗/poet.song.44000.json','["暮雲收盡溢清寒，銀漢無聲轉玉盤。", "此生此夜不長好，明月明年何處看。"]'),
('dd8b329e-5058-4961-b442-90eccf33f389','和孔周翰二絕 再觀邸園留題','蘇軾','宋','宋诗','song-poetry','','[]','小園香霧曉蒙籠，醉守狂詞未必工。',32,'全唐诗/poet.song.44000.json','["小園香霧曉蒙籠，醉守狂詞未必工。", "魯叟錄詩應有取，曲收彤管邶鄘風。"]'),
('b811d989-8dbe-47cd-9540-c9e73090544b','和孔周翰二絕 觀靜觀堂效韋蘇州詩','蘇軾','宋','宋诗','song-poetry','','[]','弱羽巢林在一枝，幽人蝸舍兩相宜。',32,'全唐诗/poet.song.44000.json','["弱羽巢林在一枝，幽人蝸舍兩相宜。", "樂天長短三千首，却愛韋郎五字詩。"]'),
('ee6fc3da-fe10-49a8-9cea-c1d535e390f4','答任師中家漢公','蘇軾','宋','宋诗','song-poetry','','[]','先君昔未仕，杜門皇祐初。',288,'全唐诗/poet.song.44000.json','["先君昔未仕，杜門皇祐初。", "道德無貧賤，風采照鄉閭。", "何嘗疏小人，小人自闊疏。", "出門無所詣，老史在郊墟。", "門前萬竿竹，堂上四庫書。", "高樹紅消梨，小池白芙蕖。", "常呼赤脚婢，雨中擷園蔬。", "矯矯任夫子，罷官還舊廬。", "是時里中兒，始識長者車。", "烹雞酌白酒，相對歡有餘。", "有如龐德公，往還葛與徐。", "妻子走堂下，主人竟誰歟。", "我時年尚幼，作賦慕相如。", "侍立看君談，精悍實起予。", "歲月曾幾何，耆老逝不居。", "史侯最先沒，孤墳拱桑樗。", "我亦涉萬里，清血滿襟袪。", "漂流二十年，始悟萬緣虛。", "獨喜任夫子，老佩刺史魚。", "威行烏白蠻，解辮請冠裾。", "方當入奏事，清廟陳璠璵。", "胡爲厭軒冕，歸意不少紓。", "上蔡有良田，黄沙走清渠。", "罷亞百頃稻，雍容十年儲。"]'),
('ee970fd2-1f50-4a06-b25d-5af29cbe4b85','初別子由','蘇軾','宋','宋诗','song-poetry','','[]','我少知子由，天資和而清。',240,'全唐诗/poet.song.44000.json','["我少知子由，天資和而清。", "好學老益堅，表裏漸融明。", "豈獨爲吾弟，要是賢友生。", "不見六七年，微言誰與賡。", "常恐坦率性，放縱不自程。", "會合亦何事，無言對空枰。", "使人之意消，不善無由萌。", "森然有六女，包裹布與荆。", "無憂頼賢婦，藜藿等大烹。", "使子得行意，青衫陋公卿。", "明日無晨炊，倒床作雷鳴。", "秋眠我東閣，夜聽風雨聲。", "懸知不久別，妙理難細評。", "昨日忽出門，孤舟轉西城。", "歸來北堂上，古屋空崢嶸。", "退食悞相從，入門中自驚。", "南都信繁會，人事水火爭。", "念當閉閣坐，頹然寄聾盲。", "妻子亦細事，文章固虛名。", "會須掃白髮，不復用黄精。"]'),
('9e62e9bb-b371-4f92-b4a7-963e16d4e1c6','次韵呂梁仲屯田','蘇軾','宋','宋诗','song-poetry','','[]','雨葉風花日夜稀，一杯相屬竟何時。',64,'全唐诗/poet.song.44000.json','["雨葉風花日夜稀，一杯相屬竟何時。", "空虛豈敢酬瓊玉，枯朽猶能出菌芝。", "門外呂梁從迅急，胸中雲夢自逶遲。", "待君筆力追靈運，莫負南臺九日期。"]'),
('e12a3c1e-c31a-495f-ad22-1394208093d1','王鞏屢約重九見訪既而不至以詩送將官梁交且見寄次韵答之交頗文雅不類武人家有侍者甚惠麗','蘇軾','宋','宋诗','song-poetry','','[]','知君月下見傾城，破恨懸知酒有兵。',64,'全唐诗/poet.song.44000.json','["知君月下見傾城，破恨懸知酒有兵。", "老守亡何惟日飲，將軍競病自詩鳴。", "花枝不共秋敧帽，筆陣空來夜斫營。", "愛惜微官將底用，他年只好寫銘旌。"]'),
('85008bea-0152-42f8-bfd5-34a9daab5264','九日邀仲屯田爲大水所隔以詩見寄次其韵','蘇軾','宋','宋诗','song-poetry','','[]','無復龍山對孟嘉，西來河伯意雄夸。',64,'全唐诗/poet.song.44000.json','["無復龍山對孟嘉，西來河伯意雄夸。", "霜風可使吹黄帽，樽酒那能泛浪花。", "漫遣鯉魚傳尺素，却將燕石報瓊華。", "何時得見悲秋老，醉裏題詩字半斜。"]'),
('431e9fb2-8e17-4a91-8c59-f31a4d1906a6','臺頭寺雨中送李邦直赴史館分韵得憶字人字兼寄孫巨源二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','霜林日夜西風急，老送君歸百憂集。',64,'全唐诗/poet.song.44000.json','["霜林日夜西風急，老送君歸百憂集。", "清歌窈眇入行雲，雲爲不行天爲泣。", "紅葉黄花秋正亂，白魚紫蟹君須憶。", "憑君說向髯將軍，衰病相逢應不識。"]'),
('3a4ee778-3182-4072-bbdf-2d2a8dbe2228','臺頭寺雨中送李邦直赴史館分韵得憶字人字兼寄孫巨源二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','珥筆西歸近紫宸，太平典冊不緣麟。',64,'全唐诗/poet.song.44000.json','["珥筆西歸近紫宸，太平典冊不緣麟。", "付君此事寧論晉，載我當時舊過秦。", "門外想無千斛米，墓中知有百年人。", "看君兩眼明如鏡，休把春秋坐素臣。"]'),
('5f0be7b7-3a1d-4d93-aa3c-f557ab4de61e','代書答梁先','蘇軾','宋','宋诗','song-poetry','','[]','此身與世真悠悠，蒼顔華髮誰汝留。',224,'全唐诗/poet.song.44000.json','["此身與世真悠悠，蒼顔華髮誰汝留。", "强名太守古徐州，忘歸不如楚沐猴。", "魯人豈獨不知丘，蹸藉夫子無罪尤。", "異哉梁子清而修，不遠千里從我遊。", "瞭然正色懸雙眸，世之所馳子獨不。", "一經通明傳節侯，小楷精絕規摹歐。", "我衰廢學懶且媮，畏見問事賈長頭。", "別來紅葉黄花秋，夜夢見之起坐愁。", "遺我駁石盆與甌，黑質白章聲琳球。", "謂言山石生澗溝，追琢尚可王公羞。", "感子佳意能無酬，反將木瓜報珍投。", "學如富賈在博收，仰取俯拾無遺籌。", "道大如天不可求，修其可見致其幽。", "願子篤實慎勿浮，發憤忘食樂忘憂。"]'),
('7169d8d7-3929-4cbd-9102-c26164c76565','送楊奉禮','蘇軾','宋','宋诗','song-poetry','','[]','譜牒推關右，風流出靖恭。',48,'全唐诗/poet.song.44000.json','["譜牒推關右，風流出靖恭。", "時情任險陂，家法故雍容。", "南去河千頃，餘惟酒一鍾。", "更誰哀老子，令得放疏慵。"]'),
('f2f171db-00f9-4516-9b77-804f19b33443','河復','蘇軾','宋','宋诗','song-poetry','','[]','君不見西漢元光元封間，河决瓠子二十年。',131,'全唐诗/poet.song.44000.json','["君不見西漢元光元封間，河决瓠子二十年。", "鉅野東傾淮泗滿，楚人恣食黄河鱣。", "萬里沙回封禪罷，初遣越巫沉白馬。", "河公未許人力窮，薪芻萬計隨流下。", "吾君盛德如唐堯，百神受職河神驕。", "帝遣風師下約束，北流夜起澶州橋。", "東風吹凍收微淥，神功不用淇園竹。", "楚人種麥滿河淤，仰看浮槎棲古木。"]'),
('3acdad7f-2e1f-4647-bed4-2a6366597988','登望谼亭','蘇軾','宋','宋诗','song-poetry','','[]','河漲西來失舊谼，孤城渾在水光中。',32,'全唐诗/poet.song.44000.json','["河漲西來失舊谼，孤城渾在水光中。", "忽然歸壑無尋處，千里禾麻一半空。"]'),
('d4ed62d0-9f4a-4c2a-b9b4-4dcd5b19a0b5','韓幹馬十四匹','蘇軾','宋','宋诗','song-poetry','','[]','二馬并驅攢八蹄，二馬宛頸騣尾齊。',128,'全唐诗/poet.song.44000.json','["二馬并驅攢八蹄，二馬宛頸騣尾齊。", "一馬任前雙舉後，一馬却避長鳴嘶。", "老髯奚官騎且顧，前身作馬通馬語。", "後有八匹飲且行，微流赴吻若有聲。", "前者既濟出林鶴，後者欲涉鶴俯啄。", "最後一匹馬中龍，不嘶不動尾摇風。", "韓生畫馬真是馬，蘇子作詩如見畫。", "世無伯樂亦無韓，此詩此畫誰當看。"]'),
('41352edf-db67-4dae-9fa7-a8d8e9177203','有言郡東北荆山下可以溝畎積水因與吳正字王戶曹同往相視以地多亂石不果還遊聖女山山有石室如墓而無棺槨或云宋司馬桓魋墓二子有詩次其韵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','側手區區豈易遮，奔流一瞬卷千家。',64,'全唐诗/poet.song.44000.json','["側手區區豈易遮，奔流一瞬卷千家。", "共疑智伯初圍趙，猶有張湯欲漕斜。", "已坐迂疏來此地，分將勞苦送生涯。", "使君下策真堪笑，隠隠驚雷響踏車。"]'),
('b18110cb-304c-45a0-9901-2140761a6e9f','有言郡東北荆山下可以溝畎積水因與吳正字王戶曹同往相視以地多亂石不果還遊聖女山山有石室如墓而無棺槨或云宋司馬桓魋墓二子有詩次其韵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','茫茫清泗遶孤岑，歸路相將得暫臨。',64,'全唐诗/poet.song.44000.json','["茫茫清泗遶孤岑，歸路相將得暫臨。", "試著芒鞋穿犖确，更然松炬照幽深。", "縱令司馬能鑱石，奈有中郎解摸金。", "强寫蒼崖留歲月，他年誰識此時心。"]'),
('ef2cd63f-11ad-4f3a-904f-211715407a17','贈寫御容妙善師','蘇軾','宋','宋诗','song-poetry','','[]','憶昔射策干先皇，珠簾翠幄分兩廂。',224,'全唐诗/poet.song.44000.json','["憶昔射策干先皇，珠簾翠幄分兩廂。", "紫衣中使下傳詔，跪奉冉冉聞天香。", "仰觀眩晃目生暈，但見曉色開扶桑。", "迎陽晚出步就坐，絳紗玉斧光照廊。", "野人不識日月角，彷彿尚記重瞳光。", "三年歸來真一夢，橋山松檜淒風霜。", "天容玉色誰敢畫，老師古寺晝閉房。", "夢中神授心有得，覺來信手筆已忘。", "幅巾常服儼不動，孤臣入門涕自滂。", "元老侑坐鬚眉古，虎臣立侍冠劍長。", "平生慣寫龍鳳質，肯顧草間猿與麞。", "都人踏破鐵門限，黄金白璧空堆床。", "爾來摹寫亦到我，謂是先帝白髮郎。", "不須覽鏡坐自了，明年乞身歸故鄉。"]'),
('becb3cca-6a41-4da2-abc1-6825c699057f','哭刁景純','蘇軾','宋','宋诗','song-poetry','','[]','讀書想前輩，每恨生不早。',216,'全唐诗/poet.song.44000.json','["讀書想前輩，每恨生不早。", "紛紛少年場，猶得見此老。", "此老如松柏，不受霜雪槁。", "直從毫末中，自養到合抱。", "宏才乏近用，千歲自枯倒。", "文章餘正始，風節貫華皓。", "平生爲人爾，自爲薄如縞。", "是非雖難齊，反覆看愈好。", "前年旅吳越，把酒慶壽考。", "扣門無晨夜，百過迹未掃。", "但知從德公，未省厭丘嫂。", "別時公八十，後會知難保。", "昨日故人書，連年喪翁媼。", "傷心范橋水，漾漾舞寒藻。", "華堂不見人，瘦馬空戀皁。", "我欲江東去，匏樽酌行潦。", "鏡湖無賀監，慟哭稽山道。", "忍見萬松岡，荒池沒秋草。"]'),
('95ad93fc-64e1-4f96-9dd0-1b3ba290f37f','答呂梁仲屯田','蘇軾','宋','宋诗','song-poetry','','[]','亂山合沓圍彭門，官居獨在懸水村。',288,'全唐诗/poet.song.44000.json','["亂山合沓圍彭門，官居獨在懸水村。", "居民蕭條雜麋鹿，小市冷落無雞豚。", "黄河西來初不覺，但訝清泗奔流渾。", "夜聞沙岸鳴甕盎，曉看雪浪浮鵬鯤。", "呂梁自古喉吻地，萬頃一抹何由吞。", "坐觀入市卷閭井，吏民走盡餘王尊。", "計窮路斷欲安適，吟詩破屋愁鳶蹲。", "歲寒霜重水歸壑，但見屋瓦留沙痕。", "入城相對如夢寐，我亦僅免爲魚黿。", "旋呼歌舞雜詼笑，不惜飲釂空瓶盆。", "念君官舍冰雪冷，新詩美酒聊相溫。", "人生如寄何不樂，任使絳蠟燒黄昏。", "宜房未築淮泗滿，故道堙滅瘡痍存。", "明年勞苦應更甚，我當畚鍤先黥髠。", "付君萬指伐頑石，千鎚雷動蒼山根。", "高城如鐵洪口快，談笑却掃看崩奔。", "農夫掉臂免狼顧，秋穀布野如雲屯。", "還須更置軟脚酒，爲君擊鼓行金樽。"]'),
('9127ced8-5500-46de-afc0-9d4c719bade8','答孔周翰求書與詩','蘇軾','宋','宋诗','song-poetry','','[]','身閑曷不長閉口，天寒正好深藏手。',96,'全唐诗/poet.song.44000.json','["身閑曷不長閉口，天寒正好深藏手。", "吟詩寫字有底忙，未脫多生宿塵垢。", "不蒙譏訶子厚疾，反更刻畫無鹽醜。", "征西自有家雞肥，太白應驚飯山瘦。", "與君相從知幾日，東風待得花開否。", "撥棄萬事勿復談，百觚之後那辭酒。"]'),
('c074b629-dcba-4e06-bd65-aab25ed0e1e7','顔樂亭詩','蘇軾','宋','宋诗','song-poetry','','[]','天生烝民，爲之鼻口。',100,'全唐诗/poet.song.44000.json','["天生烝民，爲之鼻口。", "美者可嚼，芬者可嗅。", "美必有惡，芬必有臭。", "我無天游，六鑿交鬥。", "騖而不返，跬步商受。", "偉哉先師，安此微陋。", "孟賁股栗，虎豹却走。", "眇然其身，中亦何有。", "我求至樂，千載無偶。", "執瓢從之，忽焉在後。"]'),
('0ed9a46f-9599-4a66-a016-34dfca5bf490','送李公恕赴闕','蘇軾','宋','宋诗','song-poetry','','[]','君才有如切玉刀，見之凜凜寒生毛。',192,'全唐诗/poet.song.44000.json','["君才有如切玉刀，見之凜凜寒生毛。", "願隨壯士斬蛟蜃，不願腰間纏錦絳。", "用違其才志不展，坐與胥史同疲勞。", "忽然眉上有黄氣，吾君漸欲收英髦。", "立談左右皆動色，一語徑破千言牢。", "我頃分符在東武，脫略萬事惟嬉遨。", "盡壞屏障通內外，仍呼騎曹爲馬曹。", "君爲使者見不問，反更對飲持雙螯。", "酒酣箕坐語驚衆，雜以嘲諷窮詩騷。", "世上小兒多忌諱，獨能容我真賢豪。", "爲我買田臨汶水，逝將歸去誅蓬蒿。", "安能終老塵土下，俯仰隨人如桔槹。"]'),
('807aa142-89a7-417f-9219-4872eff73405','張寺丞益齋','蘇軾','宋','宋诗','song-poetry','','[]','張子作齋舍，而以益爲名。',168,'全唐诗/poet.song.44000.json','["張子作齋舍，而以益爲名。", "吾聞諸夫子，求益非速成。", "譬如遠遊客，日夜事征行。", "今年適燕薊，明年走蠻荆。", "東觀盡滄海，西涉渭與涇。", "歸來閉戶坐，八方在軒庭。", "又如學醫人，識病由飽更。", "風雨晦明淫，跛躄瘖聾盲。", "虛實在其脈，靜躁在其情。", "榮枯在其色，壽夭在其形。", "苟能閱千人，望見知死生。", "爲學務日益，此言當自程。", "爲道貴日損，此理在既盈。", "願言書此詩，以爲益齋銘。"]'),
('63ba7749-b57a-44c4-9556-0a9ee50ba5a6','春菜','蘇軾','宋','宋诗','song-poetry','','[]','蔓菁宿根已生葉，韭芽戴土拳如蕨。',128,'全唐诗/poet.song.44000.json','["蔓菁宿根已生葉，韭芽戴土拳如蕨。", "爛蒸香薺白魚肥，碎點青蒿凉餠滑。", "宿酒初消春睡起，細履幽畦掇芳辣。", "茵陳甘菊不負渠，鱠縷堆盤纖手抹。", "北方苦寒今未已，雪底波稜如鐵甲。", "豈如吾蜀富冬蔬，霜葉露芽寒更茁。", "久拋松菊猶細事，苦筍江豚那忍說。", "明年投劾徑須歸，莫待齒摇并髮脫。"]'),
('1d173550-7228-49c7-8126-f4910dc1887a','送鄭戶曹','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','遊遍錢塘湖上山，歸來文字带芳鮮。',64,'全唐诗/poet.song.44000.json','["遊遍錢塘湖上山，歸來文字带芳鮮。", "羸童瘦馬從吾飲，陋巷何人似子賢。", "公業有田常乏食，廣文好客竟無氈。", "東歸不趁花時節，開盡春風誰與妍。"]'),
('b3798633-e569-4566-b2bf-cb429267e1d7','虔州八境圖八首  其一','蘇軾','宋','宋诗','song-poetry','','[]','坐看奔湍遶石樓，使君高會百無憂。',32,'全唐诗/poet.song.44000.json','["坐看奔湍遶石樓，使君高會百無憂。", "三犀竊鄙秦太守，八詠聊同沈隠侯。"]'),
('fd100d5d-838f-4485-8ca2-f187f5d09009','虔州八境圖八首  其二','蘇軾','宋','宋诗','song-poetry','','[]','濤頭寂寞打城還，章貢臺前暮靄寒。',32,'全唐诗/poet.song.44000.json','["濤頭寂寞打城還，章貢臺前暮靄寒。", "倦客登臨無限思，孤雲落日是長安。"]'),
('1f4f9aa6-635a-4d23-83d3-5386394d003f','虔州八境圖八首  其三','蘇軾','宋','宋诗','song-poetry','','[]','白鵲樓前翠作堆，縈雲嶺路若爲開。',32,'全唐诗/poet.song.44000.json','["白鵲樓前翠作堆，縈雲嶺路若爲開。", "故人應在千山外，不寄梅花遠信來。"]'),
('6670dbcd-2f50-4c38-8f05-ca98b883cee7','虔州八境圖八首  其四','蘇軾','宋','宋诗','song-poetry','','[]','朱樓深處日微明，皂蓋歸時酒半醒。',32,'全唐诗/poet.song.44000.json','["朱樓深處日微明，皂蓋歸時酒半醒。", "薄暮漁樵人去盡，碧溪青嶂遶螺亭。"]'),
('c55f564c-8ada-4a38-92ec-d517014142c1','虔州八境圖八首  其五','蘇軾','宋','宋诗','song-poetry','','[]','使君那暇日參禪，一望叢林一悵然。',32,'全唐诗/poet.song.44000.json','["使君那暇日參禪，一望叢林一悵然。", "成佛莫教靈運後，著鞭從使祖生先。"]'),
('2505dded-cf04-4a89-b835-d45fb638f3e3','虔州八境圖八首  其六','蘇軾','宋','宋诗','song-poetry','','[]','却從塵外望塵中，無限樓臺烟雨濛。',32,'全唐诗/poet.song.44000.json','["却從塵外望塵中，無限樓臺烟雨濛。", "山水照人迷向背，只尋孤塔認西東。"]'),
('d0a08881-6414-4c86-8d7d-52293d3de92f','虔州八境圖八首  其七','蘇軾','宋','宋诗','song-poetry','','[]','雲烟縹緲鬰孤臺，積翠浮空雨半開。',32,'全唐诗/poet.song.44000.json','["雲烟縹緲鬰孤臺，積翠浮空雨半開。", "想見之罘觀海市，絳宮明滅是蓬萊。"]'),
('96dfa707-bde1-4f20-bf58-10242be5bced','虔州八境圖八首  其八','蘇軾','宋','宋诗','song-poetry','','[]','回峰亂嶂鬰參差，雲外高人世得知。',32,'全唐诗/poet.song.44000.json','["回峰亂嶂鬰參差，雲外高人世得知。", "誰向空山弄明月，山中木客解吟詩。"]'),
('b4faf30e-9949-4c18-9a7c-340a7ea129e1','讀孟郊詩二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','夜讀孟郊詩，細字如牛毛。',120,'全唐诗/poet.song.44000.json','["夜讀孟郊詩，細字如牛毛。", "寒燈照昏花，佳處時一遭。", "孤芳擢荒穢，苦語餘詩騷。", "水清石鑿鑿，湍激不受篙。", "初如食小魚，所得不償勞。", "又似煮彭𧑅，竟日持空螯。", "要當鬬僧清，未足當韓豪。", "人生如朝露，日夜火消膏。", "何苦將兩耳，聽此寒蟲號。", "不如且置之，飲我玉色醪。"]'),
('51198d9d-47b4-4910-a004-3b5babc509a9','讀孟郊詩二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','我憎孟郊詩，復作孟郊語。',120,'全唐诗/poet.song.44000.json','["我憎孟郊詩，復作孟郊語。", "饑腸自鳴喚，空壁轉饑鼠。", "詩從肺腑出，出輒愁肺腑。", "有如黄河魚，出膏以自煮。", "尚愛銅斗歌，鄙俚頗近古。", "桃弓射鴨罷，獨速短蓑舞。", "不憂踏船翻，踏浪不踏土。", "吳姬霜雪白，赤脚浣白紵。", "嫁與踏浪兒，不識離別苦。", "歌君江湖曲，感我長羈旅。"]'),
('f6eef3d1-e820-4079-af79-c95e566532c6','章質夫寄惠崔徽真','蘇軾','宋','宋诗','song-poetry','','[]','玉釵半脫雲垂耳，亭亭芙蓉在秋水。',96,'全唐诗/poet.song.44000.json','["玉釵半脫雲垂耳，亭亭芙蓉在秋水。", "當時薄命一酸辛，千古華堂奉君子。", "水邊何處無麗人，近前試看丞相嗔。", "不如丹青不解語，世間言語原非真。", "知君被惱更愁絕，卷贈老夫驚老拙。", "爲君援筆賦梅花，未害廣平心似鐵。"]'),
('15683b64-5d39-4293-934b-97c27743fe94','訪張山人得山中字二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','魚龍隨水落，猿鶴喜君還。',48,'全唐诗/poet.song.44000.json','["魚龍隨水落，猿鶴喜君還。", "舊隠丘墟外，新堂紫翠間。", "野麋馴杖履，幽桂出榛菅。", "灑掃門前路，山公亦愛山。"]'),
('39b38451-910c-4dd8-9790-0bb353b72e21','訪張山人得山中字二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','萬木鎖雲龍，天留與戴公。',48,'全唐诗/poet.song.44000.json','["萬木鎖雲龍，天留與戴公。", "路迷山向背，人在瀼西東。", "薺麥餘春雪，櫻桃落晚風。", "入城都不記，歸路醉眠中。"]'),
('3fc60b12-bd00-44a5-9f56-679b9bfd2011','送孔郎中赴陝郊','蘇軾','宋','宋诗','song-poetry','','[]','驚風擊面黄沙走，西出崤函脫塵垢。',96,'全唐诗/poet.song.44000.json','["驚風擊面黄沙走，西出崤函脫塵垢。", "使君來自古徐州，聲震河潼殷關右。", "十里長亭聞鼓角，一川秀色明花柳。", "北臨飛檻卷黄流，南望青山如峴首。", "東風吹開錦繡谷，淥水翻動蒲萄酒。", "訟庭生草數開樽，過客如雲牢閉口。"]'),
('41c75429-2367-4e81-a603-35a36ca0821f','與梁左藏會飲傅國博家','蘇軾','宋','宋诗','song-poetry','','[]','將軍破賊自草檄，論詩說劍俱第一。',96,'全唐诗/poet.song.44000.json','["將軍破賊自草檄，論詩說劍俱第一。", "彭城老守本虛名，識字劣能欺項籍。", "風流別駕貴公子，欲把笙歌暖鋒鏑。", "紅旆朝開猛士噪，翠帷暮捲佳人出。", "東堂醉卧呼不起，啼鳥落花春寂寂。", "試教長笛傍耳根，一聲吹裂階前石。"]'),
('7aea76a2-adae-48f6-b7d3-eca302451066','寒食日答李公擇三絕次韵  其一','蘇軾','宋','宋诗','song-poetry','','[]','從來蘇李得名雙，只恐全齊笑陋邦。',32,'全唐诗/poet.song.44000.json','["從來蘇李得名雙，只恐全齊笑陋邦。", "詩似懸河供不辦，故欺張籍隴頭瀧。"]'),
('90c38626-e978-4470-9314-1d5eade2ae9f','寒食日答李公擇三絕次韵  其二','蘇軾','宋','宋诗','song-poetry','','[]','簿書鼛鼓不知春，佳句相呼頼故人。',32,'全唐诗/poet.song.44000.json','["簿書鼛鼓不知春，佳句相呼頼故人。", "寒食德公方上冢，歸來誰主復誰賓。"]'),
('d3dd0ade-44c5-4dc2-bf1a-f21c9d52d4a8','寒食日答李公擇三絕次韵  其三','蘇軾','宋','宋诗','song-poetry','','[]','巡城已困塵埃瞇，執扑仍遭蟣蝨緣。',32,'全唐诗/poet.song.44000.json','["巡城已困塵埃瞇，執扑仍遭蟣蝨緣。", "欲脫布衫携素手，試開病眼點黄連。"]'),
('0aa9d559-a916-4018-8f39-130a6d52aa07','約公擇飲是日大風','蘇軾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','先生生長匡廬山，山中讀書三十年。',208,'全唐诗/poet.song.44000.json','["先生生長匡廬山，山中讀書三十年。", "舊聞飲水師顔淵，不知治劇乃所便。", "偷兒夜探黑白丸，奮髯忽逢朱子元。", "半年羣盜誅七百，誰信家書藏九千。", "春風無事秋月閑，紅妝執樂豪且妍。", "紫衫玉带兩部全，琵琶一抹四十絃。", "客來留飲不計錢，齊人愛公如子産。", "兒啼卧路呼不還，我慚山郡空留連。", "牙兵部吏笑我寒，邀公飲酒公無難。", "約束官奴買花鈿，薰衣理髮夜不眠。", "曉來顛風塵暗天，我思其由豈坐慳。", "作詩愧謝公笑歡，歸來瑟縮愈不安。", "要當啖公八百里，豪氣一洗儒生酸。"]'),
('91fca2ea-dd81-4080-9e89-beb842f677d4','坐上賦戴花得天字','蘇軾','宋','宋诗','song-poetry','','[]','清明初過酒闌珊，折得奇葩晚更妍。',64,'全唐诗/poet.song.44000.json','["清明初過酒闌珊，折得奇葩晚更妍。", "春色豈關吾輩事，老狂聊作坐中先。", "醉吟不耐敧紗帽，起舞從教落酒船。", "結習漸消留不住，却須還與散花天。"]'),
('3daafd43-4b73-4778-9316-8f3fd4caea0a','夜飲次韵畢推官','蘇軾','宋','宋诗','song-poetry','','[]','簿書叢裏過春風，酒聖時時且復中。',64,'全唐诗/poet.song.44000.json','["簿書叢裏過春風，酒聖時時且復中。", "紅燭照庭嘶騕褭，黄雞催曉唱玲瓏。", "老來漸減金釵興，醉後空驚玉筯工。", "月未上時應早散，免教壑谷問吾公。"]'),
('293d3d12-cf2f-4189-a649-f483bbf5f34b','芙蓉城','蘇軾','宋','宋诗','song-poetry','','[]','芙蓉城中花冥冥，誰其主者石與丁。',296,'全唐诗/poet.song.44000.json','["芙蓉城中花冥冥，誰其主者石與丁。", "珠簾玉案翡翠屏，霞舒雲卷千娉婷。", "中有一人長眉青，炯如微雲淡疏星。", "往來三世空鍊形，竟坐誤讀黄庭經。", "天門夜開飛爽靈，無復白日乘雲軿。", "俗緣千劫磨不盡，翠被冷落淒餘馨。", "因過緱山朝帝廷，夜聞笙簫弭節聽。", "飄然而來誰使令，皎如明月入窗櫺。", "忽然而去不可執，寒衾虛幌風泠泠。", "仙宮洞房本不扃，夢中同躡鳳凰翎。", "徑度萬里如奔霆，玉樓浮空聳亭亭。", "天書雲篆誰所銘，遶樓飛步高竛竮。", "仙風鏘然韵流鈴，蘧蘧形開如酒醒。", "芳卿寄謝空丁寧，一朝覆水不返瓶。", "羅巾別淚空熒熒，春風花開秋葉零。", "世間羅綺紛羶腥，此身流浪隨滄溟。", "偶然相值兩浮萍，願君收視觀三庭。", "勿與嘉穀生蝗螟，從渠一念三千齡。", "下作人間尹與邢。"]'),
('af5ba04e-6011-47b9-bb94-95bf94e981c6','續麗人行','蘇軾','宋','宋诗','song-poetry','','[]','深宮無人春日長，沉香亭北百花香。',131,'全唐诗/poet.song.44000.json','["深宮無人春日長，沉香亭北百花香。", "美人睡起薄梳洗，燕舞鶑啼空斷腸。", "畫工欲畫無窮意，背立東風初破睡。", "若教回首却嫣然，陽城下蔡俱風靡。", "杜陵饑客眼長寒，蹇馿破帽隨金鞍。", "隔花臨水時一見，只許腰肢背後看。", "心醉歸來茅屋底，方信人間有西子。", "君不見孟光舉案與眉齊，何曾背面傷春啼。"]'),
('0cbb7e1f-642b-4ccd-92a5-b77c88d54f59','聞李公擇飲傅國博家大醉二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','兒童拍手鬧黄昏，應笑山公醉習園。',32,'全唐诗/poet.song.44000.json','["兒童拍手鬧黄昏，應笑山公醉習園。", "縱使先生能一石，主人未肯獨留髠。"]'),
('e54e577b-074b-475a-9eb7-721f2e5d7cca','聞李公擇飲傅國博家大醉二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','不肯惺惺騎馬迴，玉山知爲玉人頹。',32,'全唐诗/poet.song.44000.json','["不肯惺惺騎馬迴，玉山知爲玉人頹。", "紫雲有語君知否，莫喚分司御史來。"]'),
('9c8f519f-c106-4ad5-a216-c68b1c704ca2','傅子美召公擇飲偶以病不及往公擇有詩次韵','蘇軾','宋','宋诗','song-poetry','','[]','樊素阿蠻皆已出，使君應作玉箏歌。',32,'全唐诗/poet.song.44000.json','["樊素阿蠻皆已出，使君應作玉箏歌。", "可憐病士西窗下，一夜丹田手自摩。"]'),
('e0f8122a-d865-4996-a747-3af492eac019','觀子美病中作嗟歎不足因次韵','蘇軾','宋','宋诗','song-poetry','','[]','百尺長松澗下摧，知君此意爲誰來。',32,'全唐诗/poet.song.44000.json','["百尺長松澗下摧，知君此意爲誰來。", "霜枝半折孤根出，尚有狂風急雨催。"]'),
('2f0647e2-8afc-45aa-b281-cec659ee2e1d','起伏龍行','蘇軾','宋','宋诗','song-poetry','','[]','何年白竹千鈞弩，射殺南山雪毛虎。',160,'全唐诗/poet.song.44000.json','["何年白竹千鈞弩，射殺南山雪毛虎。", "至今顱骨带霜牙，尚作四海毛蟲祖。", "東方久旱千里赤，三月行人口生土。", "碧潭近在古城東，神物所蟠誰敢侮。", "上敧蒼石擁巌竇，下應清河通水府。", "眼光作電走金蛇，鼻息爲雲擢烟縷。", "當年負圖傳帝命，左右羲軒詔神禹。", "爾來懷寶但貪眠，滿腹雷霆瘖不吐。", "赤龍白虎戰明日，倒卷黄河作飛雨。", "嗟我豈樂鬬兩雄，有事徑須煩一怒。"]'),
('c0c66447-4199-4705-b7e6-aebfd61e251d','聞公擇過雲龍張山人輒往從之公擇有詩戲用其韵','蘇軾','宋','宋诗','song-poetry','','[]','我生固多憂，肉食嘗苦墨。',120,'全唐诗/poet.song.44000.json','["我生固多憂，肉食嘗苦墨。", "軒然就一笑，猶得好飲力。", "聞君過雲龍，對酒兩靜默。", "急携清歌女，出郭及未昃。", "一歡難力致，邂逅有勝特。", "喧蜂集晚花，亂雀啅叢棘。", "山人樂此耳，寂寞誰侍側。", "何當求好人，聊使治要襋。", "使君自孤僨，此理誰相值。", "不如學養生，一氣服千息。"]'),
('fe32f030-b966-4d6a-88a3-1ac0fa221b9a','送李公擇','蘇軾','宋','宋诗','song-poetry','','[]','嗟予寡兄弟，四海一子由。',168,'全唐诗/poet.song.44000.json','["嗟予寡兄弟，四海一子由。", "故人雖云多，出處不我謀。", "弓車無停招，逝去勢莫留。", "僅存今幾人，各在天一陬。", "有如長庚月，到曉爛不收。", "宜我與夫子，相好手足侔。", "比年兩見之，賓主更獻酬。", "樂哉十日飲，衎衎和不流。", "論事到深夜，僵仆鈴與騶。", "頗嘗見使君，有客如此不。", "欲別不忍言，慘慘集百憂。", "念我野夫兄，知名三十秋。", "已得其爲人，不待風馬牛。", "他年林下見，傾蓋如白頭。"]'),
('16b4f28f-5804-4d58-80f4-2185b29b10f1','送筍芍藥與公擇二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','久客厭虜饌，枵然思南烹。',74,'全唐诗/poet.song.44000.json','["久客厭虜饌，枵然思南烹。", "故人知我意，千里寄竹萌。", "駢頭玉嬰兒，一一脫錦䙀。", "庖人應未識，旅人眼先明。", "我家拙厨膳，彘肉芼蕪菁。", "送與江南客，燒煮配香秔。", "”。"]'),
('562abac4-d3ed-4662-9f87-9d805e90a0c2','送筍芍藥與公擇二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','今日忽不樂，折盡園中花。',72,'全唐诗/poet.song.44000.json','["今日忽不樂，折盡園中花。", "園中亦何有，芍藥裊殘葩。", "久旱復遭雨，紛披亂泥沙。", "不折亦安用，折去還可嗟。", "棄擲亮未能，送與謫仙家。", "還將一枝春，插向兩髻丫。"]'),
('fee58a5f-eb85-486c-b3a0-db6338c18dd9','和孫莘老次韵','蘇軾','宋','宋诗','song-poetry','','[]','去國光陰春雪消，還家蹤迹野雲飄。',64,'全唐诗/poet.song.44000.json','["去國光陰春雪消，還家蹤迹野雲飄。", "功名正自妨行樂，迎送纔堪博早朝。", "雖去友朋親吏卒，却辭讒謗得風謠。", "明年我亦江南去，不問雄繁與寂寥。"]'),
('023783ac-104d-4ef4-8d61-84b86e2710e3','遊張山人園','蘇軾','宋','宋诗','song-poetry','','[]','壁間一軸烟蘿子，盆裏千枝錦被堆。',64,'全唐诗/poet.song.44000.json','["壁間一軸烟蘿子，盆裏千枝錦被堆。", "慣與先生爲酒伴，不嫌刺史亦顔開。", "纖纖入麥黄花亂，颯颯催詩白雨來。", "聞道君家好井水，歸軒乞得滿瓶回。"]'),
('5e71d218-fa03-404d-b796-d1d4e070346f','杜介熙熙堂','蘇軾','宋','宋诗','song-poetry','','[]','崎嶇世路最先回，窈窕華堂手自開。',64,'全唐诗/poet.song.44000.json','["崎嶇世路最先回，窈窕華堂手自開。", "咄咄何曾書怪事，熙熙長覺似春臺。", "白砂碧玉味方永，黄紙紅旗心已灰。", "遥想閉門投轄飲，鵾絃鐵撥響如雷。"]'),
('12bae1ac-09f1-43fe-8c99-1520809c1a99','次韵答劉涇','蘇軾','宋','宋诗','song-poetry','','[]','吟詩莫作秋蟲聲，天公怪汝鉤物情，使汝未老華髮生。',216,'全唐诗/poet.song.44000.json','["吟詩莫作秋蟲聲，天公怪汝鉤物情，使汝未老華髮生。", "芝蘭得雨蔚青青，何用自燔以出馨。", "細書千紙雜真行，新音百變口如鶑。", "異義蜂起弟子爭，舌翻濤瀾卷齊城。", "萬卷堆胸兀相撐，以病爲樂子未驚。", "我有至味非煎烹，是中之樂吁難名。", "綠槐如山闇廣庭，飛蝱繞耳細而清。", "敗席展轉卧見經，亦自不嫌翠織成。", "意行信足無溝坑，不識五郎呼作卿。", "吏民哀我老不明，相戒無復煩鞭刑。", "時臨泗水照星星，微風不起鏡面平。", "安得一舟如葉輕，卧聞郵籤報水程。", "蓴羹羊酪不須評，一飽且救饑腸鳴。"]'),
('2e779458-b8e3-47d5-9014-7e26e7c60036','携妓樂游張山人園','蘇軾','宋','宋诗','song-poetry','','[]','大杏金黄小麥熟，墜巢乳鵲拳新竹。',64,'全唐诗/poet.song.44000.json','["大杏金黄小麥熟，墜巢乳鵲拳新竹。", "故將俗物惱幽人，細馬紅粧滿山谷。", "提壺勸酒意雖重，杜鵑催歸聲更速。", "酒闌人散却關門，寂歷斜陽挂疏木。"]'),
('d8ef1385-b2c0-4237-bdb7-ba6d9ec9abe3','種德亭','蘇軾','宋','宋诗','song-poetry','','[]','小圃傍城郭，閉門芝朮香。',96,'全唐诗/poet.song.44000.json','["小圃傍城郭，閉門芝朮香。", "名隨市人隠，德與佳木長。", "元化善養性，倉公多禁方。", "所活不可數，相逢旋相忘。", "但喜賓客來，置酒花滿堂。", "我欲東南去，再觀雙檜蒼。", "山茶想出屋，湖橘應過牆。", "木老德亦熟，吾言豈荒唐。"]'),
('20095a6a-37ec-4faa-934a-702efb631586','文與可有詩見寄云待將一段鵝溪絹掃取寒梢萬尺長次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','爲愛鵝溪白繭光，掃殘雞距紫毫芒。',32,'全唐诗/poet.song.44000.json','["爲愛鵝溪白繭光，掃殘雞距紫毫芒。", "世間那有千尋竹，月落庭空影許長。"]'),
('81388612-a69b-4e82-8d3b-f2cb95183572','聞辯才法師復歸上天竺以詩戲問','蘇軾','宋','宋诗','song-poetry','','[]','道人出山去，山色如死灰。',120,'全唐诗/poet.song.44000.json','["道人出山去，山色如死灰。", "白雲不解笑，青松有餘哀。", "忽聞道人歸，鳥語山容開。", "神光出寶髻，法雨洗浮埃。", "想見南北山，花發前後臺。", "寄聲問道人，借禪以爲詼。", "何所聞而去，何所見而回。", "道人笑不答，此意安在哉。", "昔年本不住，今者亦無來。", "此語竟非是，且食白楊梅。"]'),
('0cc35c28-928f-4800-a5ad-79e8de7cf874','和子由送將官梁左藏仲通','蘇軾','宋','宋诗','song-poetry','','[]','雨足誰言春麥短，城堅不怕秋濤卷。',128,'全唐诗/poet.song.44000.json','["雨足誰言春麥短，城堅不怕秋濤卷。", "日長惟有睡相宜，半脫紗巾落紈扇。", "芳草不鋤當戶長，珍禽獨下無人見。", "覺來身世都是夢，坐久枕痕猶著面。", "城西忽報故人來，急掃風軒炊麥飯。", "伏波論兵初矍鑠，中散談仙更清遠。", "南都從事亦學道，不惜腸空誇腦滿。", "問羊他日到金華，應許相將遊閬苑。"]'),
('e43b2e19-eee1-4c65-8429-4c20bd08300c','次韵秦觀秀才見贈秦與孫莘老李公擇甚熟將入京應舉','蘇軾','宋','宋诗','song-poetry','','[]','夜光明月非所投，逢年遇合百無憂。',192,'全唐诗/poet.song.44000.json','["夜光明月非所投，逢年遇合百無憂。", "將軍百戰竟不侯，伯郎一斗得凉州。", "翹關負重君無力，十年不入紛華域。", "故人坐上見君文，謂是古人吁莫測。", "新詩說盡萬物情，硬黄小字臨黄庭。", "故人已去君未到，空吟河畔草青青。", "誰謂他鄉各異縣，天遣君來破吾願。", "一聞君語識君心，短李髯孫眼中見。", "江湖放浪久全真，忽然一鳴驚倒人。", "縱橫所值無不可，知君不怕新書新。", "千金敝帚那堪換，我亦淹留豈長算。", "山中既未决同歸，我聊爾耳君其漫。"]'),
('e0465105-b2ae-49b2-9772-1de7c8cb889f','僕曩於長安陳漢卿家見吳道子畫佛碎爛可惜其後十餘年復見之於鮮于子駿家則已裝背完好子駿以見遺作詩謝之','蘇軾','宋','宋诗','song-poetry','','[]','貴人金多身復閑，爭買書畫不計錢。',208,'全唐诗/poet.song.44000.json','["貴人金多身復閑，爭買書畫不計錢。", "已將鐵石充逸少，更補朱繇爲道玄。", "烟薰屋漏裝玉軸，鹿皮蒼璧知誰賢。", "吳生畫佛本神授，夢中化作飛空仙。", "覺來落筆不經意，神妙獨到秋毫顛。", "昔我長安見此畫，歎息至寶空潸然。", "素絲斷續不忍看，已作蝴蝶飛聯翩。", "君能收拾爲補綴，體質散落嗟神全。", "誌公彷彿見刀尺，修羅天女猶雄妍。", "如觀老杜飛鳥句，脫字欲補知無緣。", "問君乞得良有意，欲將俗眼爲洗湔。", "貴人一見定羞怍，錦囊千紙何足捐。", "不須更用博麻縷，付與一炬隨飛烟。"]'),
('ad1a2ab4-b8d8-4ac8-ae49-385fff806e25','雨中過舒教授','蘇軾','宋','宋诗','song-poetry','','[]','疏疏簾外竹，瀏瀏竹間雨。',120,'全唐诗/poet.song.44000.json','["疏疏簾外竹，瀏瀏竹間雨。", "窗扉靜無塵，几硯寒生霧。", "美人樂幽獨，有得緣無慕。", "坐依蒲褐禪，起聽風甌語。", "客來淡無有，灑掃凉冠履。", "濃茗洗積昏，妙香浄浮慮。", "歸來北堂闇，一一微螢度。", "此生憂患中，一餉安閑處。", "飛鳶悔前笑，黄犬悲晚悟。", "自非陶靖節，誰識此閑趣。"]'),
('29708dfb-9c25-4592-916a-d8d69fc2551c','次韵舒教授寄李公擇','蘇軾','宋','宋诗','song-poetry','','[]','草書妙絕吾所兄，真書小低猶抗行。',128,'全唐诗/poet.song.44000.json','["草書妙絕吾所兄，真書小低猶抗行。", "論文作詩俱不敵，看君談笑收降旌。", "去年逾月方出晝，爲君劇飲幾濡首。", "今年過我雖少留，寂寞陶潛方止酒。", "別時流涕攬君鬚，懸知此歡墮空虛。", "松下縱橫餘屐齒，門前轣轆想君車。", "怪君一身都是德，近之清潤淪肌骨。", "細思還有可恨時，不許藍橋見傾國。"]'),
('42b3b58a-6df5-4c55-aee1-bf06dc05d445','送鄭戶曹','蘇軾','宋','宋诗','song-poetry','','[]','水繞彭城樓，山圍戲馬臺。',168,'全唐诗/poet.song.44000.json','["水繞彭城樓，山圍戲馬臺。", "古來豪傑地，千載有餘哀。", "隆準飛上天，重瞳亦成灰。", "白門下呂布，大星隕臨淮。", "尚想劉德輿，置酒此徘徊。", "爾來苦寂寞，廢圃多蒼苔。", "河從百步響，山到九里回。", "山水自相激，夜聲轉風雷。", "蕩蕩清河堧，黄樓我所開。", "秋月墮城角，春風摇酒杯。", "遲君爲座客，新詩出瓊瑰。", "樓成君已去，人事固多乖。", "他年君倦游，白首賦歸來。", "登樓一長嘯，使君安在哉。"]'),
('8dab14e8-259d-4376-8c28-ebe9415cbfaa','次韵黄魯直見贈古風二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','嘉穀卧風雨，稂莠登我場。',96,'全唐诗/poet.song.44000.json','["嘉穀卧風雨，稂莠登我場。", "陳前漫方丈，玉食慘無光。", "大哉天宇間，美惡更臭香。", "君看五六月，飛蚊殷回廊。", "茲時不少假，俯仰霜葉黄。", "期君蟠桃枝，千歲終一嘗。", "顧我如苦李，全生依路傍。", "紛紛不足道，悄悄徒自傷。"]'),
('2ba6d20f-9937-43ea-a12c-4b8094532e27','次韵黄魯直見贈古風二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','空山學仙子，妄意笙簫聲。',72,'全唐诗/poet.song.44000.json','["空山學仙子，妄意笙簫聲。", "千金得奇藥，開視皆豨苓。", "不知市人中，自有安期生。", "今君已度世，坐閱霜中蔕。", "摩挲古銅人，歲月不可計。", "閬風安在哉，要君相指似。"]'),
('8f72a7bc-b8c0-46b7-918f-77c5732c6747','次韵答舒教授觀余所藏墨','蘇軾','宋','宋诗','song-poetry','','[]','異時長笑王會稽，野鶩膻腥污刀几。',259,'全唐诗/poet.song.44000.json','["異時長笑王會稽，野鶩膻腥污刀几。", "暮年却得庾安西，自厭家雞題六紙。", "二子風流冠當代，顧與兒童爭慍喜。", "秦王十八已龍飛，嗜好晚將蛇蚓比。", "我生百事不掛眼，時人謬說云工此。", "世間有癖念誰無，傾身障簏尤堪鄙。", "人生當著幾緉屐，定心肯爲微物起。", "此墨足支三十年，但恐風霜侵髮齒。", "非人磨墨墨磨人，瓶應未罄罍先恥。", "逝將振衣歸故國，數畝荒園自鋤理。", "作書寄君君莫笑，但覓來禽與青李。", "一螺點漆便有餘，萬竈燒松何處使。", "君不見永寧第中擣龍麝，列屋閑居清且美。", "倒暈連眉秀嶺浮，雙鴉畫鬢香雲委。", "時聞五斛賜蛾綠，不惜千金求獺髓。", "聞君此詩當大笑，寒窗冷硯冰生水。"]'),
('00165ccd-ee87-43e4-ba3d-16078248ccd4','送鄭戶曹賦席上果得榧子','蘇軾','宋','宋诗','song-poetry','','[]','彼美玉山果，粲爲金盤實。',96,'全唐诗/poet.song.45000.json','["彼美玉山果，粲爲金盤實。", "瘴霧脫蠻溪，清樽奉佳客。", "客行何以贈，一語當加璧。", "祝君如此果，德膏以自澤。", "驅攘三彭仇，已我心腹疾。", "願君如此木，凜凜傲霜雪。", "斲爲君倚几，滑浄不容削。", "物微興不淺，此贈毋輕擲。"]'),
('66f2f7dd-fa03-4e9b-bae8-22bce3ca7912','送胡掾','蘇軾','宋','宋诗','song-poetry','','[]','亂葉和淒雨，投空如散絲。',48,'全唐诗/poet.song.45000.json','["亂葉和淒雨，投空如散絲。", "流年一如此，遊子去何之。", "節義古所重，艱危方自茲。", "他年著清德，仍復畏人知。"]'),
('a6ea7d4e-ac7a-4082-94e7-b265e598ea0c','密州宋國博以詩見紀在郡雜詠次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','吾觀二宋文，字字照縑素。',120,'全唐诗/poet.song.45000.json','["吾觀二宋文，字字照縑素。", "淵源皆有考，奇險或難句。", "後來邈無繼，嗣子其殆庶。", "胡爲尚流落，用舍真有數。", "當時苟悅可，慎勿笑杕杜。", "斲窗誰赴捄，袖手良優裕。", "山城辱吾繼，缺短煩遮護。", "昔年謬陳詩，無人聊瓦注。", "於今賡絕唱，外重中已懼。", "何當附家集，擊壤追咸濩。"]'),
('170a08a4-430b-45d5-b478-575bbc4de27d','答范淳甫','蘇軾','宋','宋诗','song-poetry','','[]','吾州下邑生劉季，誰數區區張與李。',64,'全唐诗/poet.song.45000.json','["吾州下邑生劉季，誰數區區張與李。", "重瞳遺跡已塵埃，惟有黄樓臨泗水。", "而今太守老且寒，俠氣不洗儒生酸。", "猶勝白門窮呂布，欲將鞍馬事曹瞞。"]'),
('ebef5268-aebf-4b1f-b1d4-320683c5e22a','次韵答王定國','蘇軾','宋','宋诗','song-poetry','','[]','每得君詩如得書，宣心寫妙書不如。',96,'全唐诗/poet.song.45000.json','["每得君詩如得書，宣心寫妙書不如。", "眼前百種無不有，知君一以詩驅除。", "傳聞都下十日雨，青泥沒馬街生魚。", "舊雨來人今不來，悠然獨酌卧清虛。", "我雖作郡古云樂，山川信美非吾廬。", "願君不廢重九約，念此衰冷勤呵噓。"]'),
('e43b23a2-3392-496b-9993-5d438aabb7ff','和鮮于子駿鄆州新堂月夜二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','去歲遊新堂，春風雪消後。',96,'全唐诗/poet.song.45000.json','["去歲遊新堂，春風雪消後。", "池中半篙水，池上千尺柳。", "佳人如桃李，胡蝶入衫袖。", "山川今何許，疆野已分宿。", "歲月不可思，駛若船放溜。", "繁華真一夢，寂寞兩榮朽。", "惟有當時月，依然照杯酒。", "應憐船上人，坐穩不知漏。"]'),
('5b54ab44-1f5b-436d-add9-7c880d67a2f9','和鮮于子駿鄆州新堂月夜二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','明月入華池，反照池上堂。',96,'全唐诗/poet.song.45000.json','["明月入華池，反照池上堂。", "堂中隠几人，心與水月凉。", "風螢已無迹，露草時有光。", "起觀河漢流，步屧響長廊。", "名都信繁會，千指調笙簧。", "先生病不飲，童子爲燒香。", "獨作五字詩，清卓如韋郎。", "詩成月漸側，皎皎兩相望。"]'),
('f12713dd-5099-4e6e-9e85-b7e1afd3d965','送將官梁左藏赴莫州','蘇軾','宋','宋诗','song-poetry','','[]','燕南垂，趙北際，其間不合大如礪。',128,'全唐诗/poet.song.45000.json','["燕南垂，趙北際，其間不合大如礪。", "至今父老哀公孫，蒸土爲城鐵作門。", "城中積穀三百萬，猛士如雲驕不戰。", "一旦鼓角鳴地中，帳下美人空掩面。", "豈如千騎平時來，笑談謦欬生風雷。", "葛巾羽扇紅塵靜，投壺雅歌清燕開。", "東方健兒虓虎樣，泣涕懷思廉恥將。", "彭城老守亦凄然，不見君家雪兒唱。"]'),
('1697127d-c61b-426f-b6f2-15ffe3118151','答仲屯田次韵','蘇軾','宋','宋诗','song-poetry','','[]','秋來不見渼陂岑，千里詩盟忽重尋。',64,'全唐诗/poet.song.45000.json','["秋來不見渼陂岑，千里詩盟忽重尋。", "大木百圍生遠籟，朱絃三歎有遺音。", "清風卷地收殘暑，素月流天掃積陰。", "欲遣何人賡絕唱，滿階桐葉候蟲吟。"]'),
('6f52dcbf-da50-4d05-b897-f6b08d041355','次韵子由送趙㞦歸覲錢塘遂赴永嘉','蘇軾','宋','宋诗','song-poetry','','[]','歸舟轉河曲，稍見楚山蒼。',120,'全唐诗/poet.song.45000.json','["歸舟轉河曲，稍見楚山蒼。", "候吏來迎客，吳音已带鄉。", "言從謝康樂，先獻魯靈光。", "已擊三千里，何須四十强。", "風流半刺史，清絕校書郎。", "到郡詩成集，尋溪水濺裳。", "芒鞋隨采藥，繭紙記流觴。", "海靜蛟鼉出，山空草木長。", "宦遊無遠近，民事要更嘗。", "願子傳家法，他年請尚方。"]'),
('e2ff38ce-a0ed-41a1-aa6e-5d20114d2d8a','中秋月寄子由三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','殷勤去年月，瀲灧古城東。',120,'全唐诗/poet.song.45000.json','["殷勤去年月，瀲灧古城東。", "憔悴去年人，卧病破窗中。", "徘徊巧相覓，窈窕穿房櫳。", "月豈知我病，但見歌樓空。", "撫枕三歎息，扶杖起相從。", "天風不相哀，吹我落瓊宮。", "白露入肺肝，夜吟如秋蟲。", "坐令太白豪，化爲東野窮。", "餘年知幾何，佳月豈屢逢。", "寒魚亦不睡，竟夕相噞喁。"]'),
('98f32f10-76fb-450d-8407-702cbc3a0cee','中秋月寄子由三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','六年逢此月，五年照離別。',120,'全唐诗/poet.song.45000.json','["六年逢此月，五年照離別。", "歌君別時曲，滿座爲淒咽。", "留都信繁麗，此會豈輕擲。", "鎔銀百頃湖，挂鏡千尋闕。", "三更歌吹罷，人影亂清樾。", "歸來北堂下，寒光翻露葉。", "喚酒與婦飲，念我向兒說。", "豈知衰病後，空盞對梨栗。", "但見古河東，荍麥花鋪雪。", "欲和去年曲，復恐心斷絕。"]'),
('50a2c0c9-0df4-44ac-b555-d869930954b1','中秋月寄子由三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','舒子在汶上，閉門相對清。',120,'全唐诗/poet.song.45000.json','["舒子在汶上，閉門相對清。", "鄭子向河朔，孤舟連夜行。", "頓子雖咫尺，兀如在牢扃。", "趙子寄書來，水調有餘聲。", "悠哉四子心，共此千里明。", "明月不解老，良辰難合并。", "回頭坐上人，聚散如流萍。", "嘗聞此宵月，萬里同陰晴。", "天公自著意，此會那可輕。", "明年各相望，俯仰今古情。"]'),
('3a25ec1c-44f0-4a7d-b484-ca45ee9273cc','中秋見月和子由','蘇軾','宋','宋诗','song-poetry','','["\u8282\u65e5", "\u4e2d\u79cb\u8282", "\u548f\u7269", "\u5199\u6708", "\u548f\u7269\u8bd7"]','明月未出羣山高，瑞光萬丈生白毫。',224,'全唐诗/poet.song.45000.json','["明月未出羣山高，瑞光萬丈生白毫。", "一杯未盡銀闕涌，亂雲脫壞如崩濤。", "誰爲天公洗眸子，應費明河千斛水。", "遂令冷看世間人，照我湛然心不起。", "西南火星如彈丸，角尾奕奕蒼龍蟠。", "今宵注眼看不見，更許螢火爭清寒。", "何人艤舟臨古汴，千燈夜作魚龍變。", "曲折無心逐浪花，低昂赴節隨歌板。", "青熒滅沒轉山前，浪颭風迴豈復堅。", "明月易低人易散，歸來呼酒更重看。", "堂前月色愈清好，咽咽寒螿鳴露草。", "卷簾推戶寂無人，窗下咿啞惟楚老。", "南都從事莫羞貧，對月題詩有幾人。", "明朝人事隨日出，怳然一夢瑶臺客。"]'),
('0a3deebf-0300-48ac-8178-225549a9eb39','答王鞏','蘇軾','宋','宋诗','song-poetry','','[]','汴泗遶吾城，城堅如削鐵。',182,'全唐诗/poet.song.45000.json','["汴泗遶吾城，城堅如削鐵。", "中有李臨淮，號令肝膽裂。", "古來彭城守，未省怕惡客。", "惡客云是誰，祥符相公孫。", "是家豪逸生有種，千金一擲頗黎盆。", "連車載酒來，不飲外酒嫌其村。", "子有千瓶酒，我有萬株菊。", "任子滿頭插，團團見花不見目。", "醉中插花歸，花重壓折軸。", "問客何所須，客言我愛山。", "青山自遶郭，不要買山錢。", "此外有黄樓，樓下一河水。", "美哉洋洋乎，可以療饑并洗耳。", "彭城之游樂復樂，客惡何如主人惡。"]'),
('f5c10517-9728-4a96-aabd-cc67c37fb53b','次韵王定國馬上見寄','蘇軾','宋','宋诗','song-poetry','','[]','昨夜霜風入裌衣，曉來病骨更支離。',64,'全唐诗/poet.song.45000.json','["昨夜霜風入裌衣，曉來病骨更支離。", "疏狂似我人誰顧，坎坷憐君志未移。", "但恨不携桃葉女，尚能來趁菊花時。", "南臺二謝人無繼，直恐君詩勝義熙。"]'),
('032046b8-e628-414c-aebe-36fafcc386fd','與頓起孫勉泛舟探韵得未字','蘇軾','宋','宋诗','song-poetry','','[]','窗前堆梧桐，牀下鳴絡緯。',192,'全唐诗/poet.song.45000.json','["窗前堆梧桐，牀下鳴絡緯。", "佳人尺書到，客子中夜喟。", "朝來一樽酒，晤語聊自慰。", "秋蠅已無聲，霜蟹初有味。", "當爲壯士飲，眥裂鬚磔蝟。", "勿作兒女懷，坐念蠨蛸畏。", "山城亦何有，一笑瀉肝胃。", "泛舟以娛君，魚鼈多可餼。", "縱爲十日飲，未遽主人費。", "吾儕俱老矣，耿耿知自貴。", "寧能傍門戶，啼笑雜猩狒。", "要將百篇詩，一吐千丈氣。", "蕭條歲行暮，迨此霜雪未。", "明朝出城南，遺跡觀楚魏。", "西風迫吹帽，金菊亂如沸。", "願君勿言歸，輕別吾所諱。"]'),
('e47abba1-0b5c-454d-b123-df1c34040189','次韵答頓起二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','挽袖推腰踏破紳，舊聞携手上天門。',64,'全唐诗/poet.song.45000.json','["挽袖推腰踏破紳，舊聞携手上天門。", "相逢應覺聲容似，欲話先驚歲月奔。", "新學已皆從許子，諸生猶自畏何蕃。", "殿廬直宿真如夢，猶記憂時策萬言。"]'),
('4820993f-8aa7-419d-a3d9-ca3aa9339ea0','次韵答頓起二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','十二東秦比漢京，去年古寺共題名。',64,'全唐诗/poet.song.45000.json','["十二東秦比漢京，去年古寺共題名。", "早衰怪我遽如許，苦學憐君太瘦生。", "茅屋擬歸田二頃，金丹終掃雪千莖。", "何人更似蘇司業，和遍新詩滿洛城。"]'),
('372b00a7-8041-4e16-9b8d-97b3d5368dc8','九日黄樓作','蘇軾','宋','宋诗','song-poetry','','["\u91cd\u9633\u8282"]','去年重陽不可說，南城夜半千漚發。',192,'全唐诗/poet.song.45000.json','["去年重陽不可說，南城夜半千漚發。", "水穿城下作雷鳴，泥滿城頭飛雨滑。", "黄花白酒無人問，日暮歸來洗靴韈。", "豈知還復有今年，把盞對花容一呷。", "莫嫌酒薄紅粉陋，終勝泥中千柄鍤。", "黄樓新成壁未乾，清河已落霜初殺。", "朝來白霧如細雨，南山不見千尋剎。", "樓前便作海茫茫，樓下空聞櫓鴉軋。", "薄寒中人老可畏，熱酒澆腸氣先壓。", "烟消日出見漁村，遠水鱗鱗山齾齾。", "詩人猛士雜龍虎，楚舞吳歌亂鵝鴨。", "一杯相屬君勿辭，此景何殊泛清霅。"]'),
('4a569fa5-20f4-4fae-b847-a3a8ed839387','太虛以黄樓賦見寄作詩爲謝','蘇軾','宋','宋诗','song-poetry','','[]','我在黄樓上，欲作黄樓詩。',120,'全唐诗/poet.song.45000.json','["我在黄樓上，欲作黄樓詩。", "忽得故人書，中有黄樓詞。", "黄樓高十丈，下建五丈旗。", "楚山以爲城，泗水以爲池。", "我詩無傑句，萬景驕莫隨。", "夫子獨何妙，雨雹散雷椎。", "雄辭雜今古，中有屈宋姿。", "南山多磬石，清滑如流脂。", "朱蠟爲摹刻，細妙分毫釐。", "佳處未易識，當有來者知。"]'),
('f37a85ed-423c-49a7-b018-7b6aa8ba8489','九日次韵王鞏','蘇軾','宋','宋诗','song-poetry','','[]','我醉欲眠君罷休，已教從事到青州。',64,'全唐诗/poet.song.45000.json','["我醉欲眠君罷休，已教從事到青州。", "鬢霜饒我三千丈，詩律輸君一百籌。", "聞道郎君閉東閣，且容老子上南樓。", "相逢不用忙歸去，明日黄花蝶也愁。"]'),
('4cefc101-e381-40d1-9e61-27e5d5279d39','送頓起','蘇軾','宋','宋诗','song-poetry','','["\u6cf0\u5c71", "\u79bb\u522b", "\u611f\u53f9", "\u4eba\u751f", "\u53cb\u60c5"]','客路相逢難，爲樂常不足。',120,'全唐诗/poet.song.45000.json','["客路相逢難，爲樂常不足。", "臨行挽衫袖，更賞折殘菊。", "佳人亦何念，悽斷陽關曲。", "酒闌不忍去，共接一寸燭。", "留君終無窮，歸駕不免促。", "岱宗已在眼，一往繼前躅。", "天門四十里，夜看扶桑浴。", "回頭望彭城，大海浮一粟。", "故人在其下，塵土相豗蹴。", "惟有黄樓詩，千古配淇澳。"]'),
('860f4857-b6e2-48c6-830d-8c270c296f49','送孫勉','蘇軾','宋','宋诗','song-poetry','','[]','昔年罷東武，曾過北海縣。',144,'全唐诗/poet.song.45000.json','["昔年罷東武，曾過北海縣。", "白河翻雪浪，黄土如蒸麪。", "桑麻冠東方，一熟天下賤。", "是時累饑饉，常苦盜賊變。", "每憐追胥官，野宿風裂面。", "君爲淮南秀，文采照金殿。", "胡爲事奔走，投筆腰羽箭。", "更被髯將軍，豪篇來督戰。", "親程三郡士，玉石不能衒。", "欲知君得人，失者亦稱善。", "君才無不可，要使經百鍊。", "吾詩堪咀嚼，聊送別酒嚥。"]'),
('2ae899b1-c407-4c83-bdb0-ee2d69677c51','李思訓畫長江絕島圖','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','山蒼蒼，水茫茫，大孤小孤江中央。',90,'全唐诗/poet.song.45000.json','["山蒼蒼，水茫茫，大孤小孤江中央。", "崖崩路絕猿鳥去，惟有喬木攙天長。", "客舟何處來，棹歌中流聲抑揚。", "沙平風軟望不到，孤山久與船低昂。", "峨峨兩烟鬟，曉鏡開新粧。", "舟中賈客莫漫狂，小姑前年嫁彭郎。"]'),
('8fcdd1f3-5f04-4d45-a663-e6ba5b82d02f','張安道見示近詩','蘇軾','宋','宋诗','song-poetry','','[]','人物一衰謝，微言難重尋。',120,'全唐诗/poet.song.45000.json','["人物一衰謝，微言難重尋。", "殷勤永嘉末，復聞正始音。", "清談未足多，感時意殊深。", "少年有奇志，欲和南風琴。", "荒林蜩蚻亂，廢沼蛙蟈淫。", "遂欲掩兩耳，臨文但噫瘖。", "蕭然王郎子，來自緱山陰。", "云見浮丘伯，吹簫明月岑。", "遺聲落淮泗，蛟鼉爲悲吟。", "願公正王度，祈招繼愔愔。"]'),
('9485902c-e0f7-4685-8530-bc6bdd313ee1','次韵王鞏顔復同泛舟','蘇軾','宋','宋诗','song-poetry','','[]','沈郎清瘦不勝衣，邊老便便带十圍。',64,'全唐诗/poet.song.45000.json','["沈郎清瘦不勝衣，邊老便便带十圍。", "躞蹀身輕山上走，歡呼船重醉中歸。", "舞腰似雪金釵落，談辯如雲玉麈揮。", "憶在錢塘正如此，回頭四十二年非。"]'),
('fcefa0e1-6af4-4569-b51e-1bbd31e7adf1','次韵張十七九日贈子由','蘇軾','宋','宋诗','song-poetry','','[]','千戈萬槊擁笓籬，九日清樽豈復持。',64,'全唐诗/poet.song.45000.json','["千戈萬槊擁笓籬，九日清樽豈復持。", "官事無窮何日了，菊花有信不吾欺。", "逍遥瓊館真堪羨，取次塵纓未可縻。", "迨此暇時須痛飲，他年長劍拄君頤。"]'),
('dad61155-2ea2-458b-9ace-bb1b33633616','次韵王鞏獨眠','蘇軾','宋','宋诗','song-poetry','','[]','居士身心如槁木，旅館孤眠體生粟。',64,'全唐诗/poet.song.45000.json','["居士身心如槁木，旅館孤眠體生粟。", "誰能相思琢白玉，服藥千朝償一宿。", "天寒日短銀燈續，欲往從之車脫軸。", "何人吹斷參差竹，泗水茫茫鴨頭綠。"]'),
('df3962e3-489a-4cc1-8b0e-349ef610c294','登雲龍山','蘇軾','宋','宋诗','song-poetry','','[]','醉中走上黄茅岡，滿岡亂石如羣羊。',56,'全唐诗/poet.song.45000.json','["醉中走上黄茅岡，滿岡亂石如羣羊。", "岡頭醉倒石作牀，仰看白雲天茫茫。", "歌聲落谷秋風長，路人舉首東南望，拍手大笑使君狂。"]'),
('c8fb5f45-3d82-4a5e-9b81-b495637f2b98','題雲龍山張山人草堂石磬','蘇軾','宋','宋诗','song-poetry','','[]','折爲督郵腰，懸作山人室。',24,'全唐诗/poet.song.45000.json','["折爲督郵腰，懸作山人室。", "殊非濮上音，信是泗濱石。"]'),
('052112d4-4a67-4cbe-a66b-87b479e3d20c','次韵王鞏留別','蘇軾','宋','宋诗','song-poetry','','[]','去國已八年，故人今有誰。',120,'全唐诗/poet.song.45000.json','["去國已八年，故人今有誰。", "當時交游內，未數蔡克兒。", "豈無知我者，好爵半已縻。", "爭爲東閣吏，不顧北山移。", "公子表獨立，與世頗異馳。", "不辭千里遠，成此一段奇。", "蛾眉亦可憐，無奈思餠師。", "無人伴客寢，惟有支牀龜。", "君歸與何人，文字相娛嬉。", "持此調張子，一笑當脫頤。"]'),
('6cae0b56-c15a-4a0d-b20a-e6b830788292','次韵僧潛見贈','蘇軾','宋','宋诗','song-poetry','','[]','道人胸中水鏡清，萬象起滅無逃形。',272,'全唐诗/poet.song.45000.json','["道人胸中水鏡清，萬象起滅無逃形。", "獨依古寺種秋菊，要伴騷人餐落英。", "人間底處有南北，紛紛鴻雁何曾冥。", "閉門坐穴一禪榻，頭上歲月空崢嶸。", "今年偶出爲求法，欲與慧劍加礱硎。", "雲衲新磨山水出，霜髭不剪兒童驚。", "公侯欲識不可得，故知倚市無傾城。", "秋風吹夢過淮水，想見橘柚垂空庭。", "故人各在天一角，相望落落如晨星。", "彭城老守何足顧，棗林桑野相邀迎。", "千山不憚荒店遠，兩脚欲趁飛猱輕。", "多生綺語磨不盡，尚有宛轉詩人情。", "猿吟鶴唳本無意，不知下有行人行。", "空階夜雨自清絕，誰使掩抑啼孤惸。", "我欲仙山掇瑶草，傾筐坐歎何時盈。", "簿書鞭扑晝填委，煮茗燒栗宜宵征。", "乞取摩尼照濁水，共看落月金盆傾。"]'),
('27ae46b4-e040-492c-81a3-c6f6b8562709','次韵潛師放魚','蘇軾','宋','宋诗','song-poetry','','[]','法師說法臨泗水，無數天花隨麈尾。',96,'全唐诗/poet.song.45000.json','["法師說法臨泗水，無數天花隨麈尾。", "勸將浄業種西方，莫待夢中呼起起。", "哀哉若魚竟坐口，遠愧知幾穆生醴。", "況逢孟簡對盧仝，不怕校人欺子美。", "疲民尚作魚尾赤，數罟未除吾顙泚。", "法師自有衣中珠，不用辛苦泥沙底。"]'),
('93233e7e-1070-4c03-9bf6-1ff4218890ab','滕縣時同年西園','蘇軾','宋','宋诗','song-poetry','','[]','人皆種榆柳，坐待十畝陰。',168,'全唐诗/poet.song.45000.json','["人皆種榆柳，坐待十畝陰。", "我獨種松柏，守此一片心。", "君看閭里間，盛衰日駸駸。", "種木不種德，聚散如飛禽。", "老時吾不識，用意一何深。", "知人得數士，重義忘千金。", "西園手所開，珍木來千岑。", "養此霜雪根，遲彼鸞鳳吟。", "池塘得流水，龜魚自浮沈。", "幽桂日夜長，白花亂青衿。", "豈獨蕃草木，子孫已成林。", "拱把不知數，會當出千尋。", "樊侯種梓漆，壽張富華簪。", "我作西園詩，以爲里人箴。"]'),
('19c9e6b2-c708-419d-b016-e88ffea0e3d9','次韵王廷老和張十七九日見寄二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','霜葉投空雀啅籬，上樓筋力强扶持。',64,'全唐诗/poet.song.45000.json','["霜葉投空雀啅籬，上樓筋力强扶持。", "對花把酒未甘老，膏面染鬚聊自欺。", "無事亦知君好飲，多才終恐世相縻。", "請看平日銜杯口，會有金椎爲控頤。"]'),
('677bf411-4472-4301-aa1a-96c2c33f8c50','次韵王廷老和張十七九日見寄二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','接果移花看補籬，腰鐮手斧不妨持。',64,'全唐诗/poet.song.45000.json','["接果移花看補籬，腰鐮手斧不妨持。", "上都新事長先到，老圃閑談未易欺。", "釀酒閉門開社甕，殺牛留客解耕縻。", "何時得見纖纖玉，右手持杯左捧頤。"]'),
('7ff2915b-9002-4f45-b33b-d1d6b632f063','鹿鳴宴','蘇軾','宋','宋诗','song-poetry','','[]','連騎匆匆畫鼓喧，喜君新奪錦標還。',64,'全唐诗/poet.song.45000.json','["連騎匆匆畫鼓喧，喜君新奪錦標還。", "金罍浮菊催開宴，紅蕊將春待入關。", "他日曾陪探禹穴，白頭重見賦南山。", "何時共樂昇平事，風月笙簫坐夜閑。"]'),
('6238a386-7325-4295-989f-9348520630a1','與舒教授張山人參寥師同遊戲馬臺書西軒壁兼簡顔長道二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','古寺長廊院院行，此軒偏慰旅人情。',64,'全唐诗/poet.song.45000.json','["古寺長廊院院行，此軒偏慰旅人情。", "楚山西斷如迎客，汴水南來故遶城。", "路失玉鈎芳草合，林亡白鶴古泉清。", "淡游何以娛庠老，坐聽郊原琢磬聲。"]'),
('a9891d1a-fa5f-43a1-bb0e-cf66106d39ba','與舒教授張山人參寥師同遊戲馬臺書西軒壁兼簡顔長道二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','竹杖芒鞋取次行，下臨官道見人情。',64,'全唐诗/poet.song.45000.json','["竹杖芒鞋取次行，下臨官道見人情。", "天寒菽粟猶棲畝，日暮牛羊自入城。", "沽酒獨教陶令醉，題詩誰似皎公清。", "更尋陋巷顔夫子，乞取微言繼此聲。"]'),
('c5a7c0b1-5aa2-4cae-8fac-29ed7f3452d2','夜過舒堯文戲作','蘇軾','宋','宋诗','song-poetry','','[]','先生堂上霜月苦，弟子讀書喧兩廡。',96,'全唐诗/poet.song.45000.json','["先生堂上霜月苦，弟子讀書喧兩廡。", "推門入室書縱橫，蠟紙燈籠晃雲母。", "先生骨清少眠卧，長夜默坐數更鼓。", "耐寒石硯欲生冰，得火銅瓶如過雨。", "郎君欲出先自贊，坐客歛衽誰敢侮。", "明朝阮籍過阿戎，應作羲之羨懷祖。"]'),
('6bac8bd7-d789-4e98-b3e4-8cde04f91e09','十月十五日觀月黄樓席上次韵','蘇軾','宋','宋诗','song-poetry','','[]','中秋天氣未應殊，不用紅紗照座隅。',64,'全唐诗/poet.song.45000.json','["中秋天氣未應殊，不用紅紗照座隅。", "山上白雲橫匹素，水中明月卧浮圖。", "未成短棹還三峽，已約輕舟泛五湖。", "爲問登臨好風景，明年還憶使君無。"]'),
('fdd07ac3-bb24-417a-b809-d64ebef2da0f','答王定民','蘇軾','宋','宋诗','song-poetry','','[]','開緘奕奕滿銀鉤，書尾題詩語更遒。',64,'全唐诗/poet.song.45000.json','["開緘奕奕滿銀鉤，書尾題詩語更遒。", "八法舊聞宗長史，五言今復擬蘇州。", "筆蹤好在留臺寺，旗隊遥知到石溝。", "欲寄鼠鬚并繭紙，請君章草賦黄樓。"]'),
('b9d766d8-2a68-41f9-a010-24765ca7e9f3','次韵王廷老退居見寄','蘇軾','宋','宋诗','song-poetry','','[]','浪蕊浮花不辨春，歸來方識歲寒人。',64,'全唐诗/poet.song.45000.json','["浪蕊浮花不辨春，歸來方識歲寒人。", "回頭自笑風波地，閉眼聊觀夢幻身。", "北牖已安陶令榻，西風還避庾公塵。", "更搔短髮東南望，試問今誰裹舊巾。"]'),
('412a44c9-aae8-476f-a763-7b5b4d892cef','百步洪二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','長洪斗落生跳波，輕舟南下如投梭。',192,'全唐诗/poet.song.45000.json','["長洪斗落生跳波，輕舟南下如投梭。", "水師絕叫鳬雁起，亂石一綫爭磋磨。", "有如兔走鷹隼落，駿馬下注千丈坡。", "斷弦離柱箭脫手，飛電過隙珠翻荷。", "四山眩轉風掠耳，但見流沫生千渦。", "嶮中得樂雖一快，何意水伯誇秋河。", "我生乘化日夜逝，坐覺一念逾新羅。", "紛紛爭奪醉夢裏，豈信荆棘埋銅駝。", "覺來俯仰失千劫，回視此水殊委蛇。", "君看岸邊蒼石上，古來篙眼如蜂窠。", "但應此心無所住，造物雖駛如吾何。", "回船上馬各歸去，多言譊譊師所呵。"]'),
('56e28b15-4279-4abb-bc3c-fe21ccc8b785','百步洪二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','佳人未肯回秋波，幼輿欲語防飛梭。',192,'全唐诗/poet.song.45000.json','["佳人未肯回秋波，幼輿欲語防飛梭。", "輕舟弄水買一笑，醉中蕩槳肩相摩。", "不學長安閭里俠，貂裘夜走臙脂坡。", "獨將詩句擬鮑謝，涉江共採秋江荷。", "不知詩中道何語，但覺兩頰生微渦。", "我時羽服黄樓上，坐見織女初斜河。", "歸來笛聲滿山谷，明月正照金叵羅。", "奈何捨我入塵土，擾擾毛羣欺卧駝。", "不念空齋老病叟，退食誰與同委蛇。", "時來洪上看遺跡，忍見屐齒青苔窠。", "詩成不覺雙淚下，悲吟相對惟羊何。", "欲遣佳人寄錦字，夜寒手冷無人呵。"]'),
('fb61a568-b689-4434-94c7-3aaff7f24bb6','次韵顔長道送傅倅','蘇軾','宋','宋诗','song-poetry','','[]','兩見黄花掃落英，南山山寺遍題名。',64,'全唐诗/poet.song.45000.json','["兩見黄花掃落英，南山山寺遍題名。", "宗成不獨依岑范，魯衛終當似弟兄。", "去歲雲濤浮汴泗，與君泥土滿衣纓。", "如今別酒休辭醉，試聽雙洪落後聲。"]'),
('f0fa13f6-ea15-4388-9686-10365deb329e','雲龍山觀燒得雲字','蘇軾','宋','宋诗','song-poetry','','[]','丁女真水妃，寒山便火耘。',240,'全唐诗/poet.song.45000.json','["丁女真水妃，寒山便火耘。", "隕霜知已殺，坯戶聽初焚。", "束縕方熠燿，敲石俄氤氳。", "落點甘泉烽，橫烟楚塞氛。", "窮蛇上喬木，潛蛟躡浮雲。", "驚飛墮傷雁，狂走迷癡麏。", "谷蟄起蜩燕，山妖竄夔羵。", "野竹爆哀聲，幽桂飄冤芬。", "悲同秋照蟹，快若夏燎蚊。", "火牛入燕壘，燧象奔吳軍。", "崩騰井陘口，萬馬皆朱幩。", "摇曳驪山陰，諸姨爛紅裙。", "方隨長風卷，忽值絕澗分。", "我本山中人，習見匪獨聞。", "偶從二三子，來訪張隠君。", "君家亦何有，物象移朝曛。", "把酒看飛燼，空庭落繽紛。", "行觀農事起，畦壠如纈紋。", "細雨發春穎，嚴霜倒秋蕡。", "始知一炬力，洗盡狐兔羣。"]'),
('b32e1c3d-f7b8-46b8-aece-45d27d67ce9a','祈雪霧豬泉出城馬上作贈舒堯文','蘇軾','宋','宋诗','song-poetry','','[]','三年走吳越，踏遍千重山。',120,'全唐诗/poet.song.45000.json','["三年走吳越，踏遍千重山。", "朝隨白雲去，暮與棲鴉還。", "翩如得木狖，飛步誰能攀。", "一爲符竹累，坐老敲榜間。", "此行亦何事，聊散腰脚頑。", "浩蕩城西南，亂山如玦環。", "山下野人家，桑柘雜榛菅。", "歲晏風日暖，人牛相對閑。", "薄雪不蓋土，麥苗稀可刪。", "願君發豪句，嘲詼破天慳。"]'),
('0c7a772f-792b-4292-9ff4-9017207bb4fd','次韵舒堯文祈雪霧豬泉','蘇軾','宋','宋诗','song-poetry','','["\u5fe7\u56fd\u5fe7\u6c11", "\u7948\u7977"]','長笑蛇醫一寸腹，銜冰吐雹何時足。',208,'全唐诗/poet.song.45000.json','["長笑蛇醫一寸腹，銜冰吐雹何時足。", "蒼鵝無罪亦可憐，斬頸橫盤不敢哭。", "豈知泉下有豬龍，卧枕雷車踏陰軸。", "前年太守爲旱請，雨點隨人如撒菽。", "太守歸國龍歸泉，至今人詠淇園綠。", "我今又復罹此旱，凜凜疲民在溝瀆。", "却尋舊跡叩神泉，坐客仍携王子淵。", "看草中和樂職頌，新聲妙語慰華顛。", "曉來泉上東風急，鬚上冰珠老蛟泣。", "怪詞欲逼龍飛起，險韵不量吾所及。", "行看積雪厚埋牛，誰與春工掀百蟄。", "此時還復借君詩，餘力汰輈仍貫笠。", "揮毫落紙勿言疲，驚龍再起震失匙。"]'),
('2d6b3607-8131-41b4-8f0b-c8841d8bdb22','和田國博喜雪','蘇軾','宋','宋诗','song-poetry','','[]','疇昔月如晝，晚來雲暗天。',48,'全唐诗/poet.song.45000.json','["疇昔月如晝，晚來雲暗天。", "玉花飛半夜，翠浪舞明年。", "螟螣無遺種，流亡稍占田。", "歲豐君不樂，鐘磬幾時編。"]'),
('b6d63c54-8e7c-4b97-a3d0-24f70676c3fe','宋復古畫瀟湘晚景圖三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','西征憶南國，堂上畫瀟湘。',48,'全唐诗/poet.song.45000.json','["西征憶南國，堂上畫瀟湘。", "照眼雲山出，浮空野水長。", "舊游心自省，信手筆都忘。", "會有衡陽客，來看意渺茫。"]'),
('1baaf3b0-0c6d-421f-b510-fad73079de31','宋復古畫瀟湘晚景圖三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','落落君懷抱，山川自屈蟠。',48,'全唐诗/poet.song.45000.json','["落落君懷抱，山川自屈蟠。", "經營初有適，揮灑不應難。", "江市人家少，烟村古木攢。", "知君有幽意，細細爲尋看。"]'),
('3bbfacca-6e27-427e-ba45-596fa75f9c55','宋復古畫瀟湘晚景圖三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','咫尺殊非少，陰晴自不齊。',48,'全唐诗/poet.song.45000.json','["咫尺殊非少，陰晴自不齊。", "徑蟠趨後崦，水會赴前溪。", "自說非人意，曾經入馬蹄。", "他年宦遊處，應指劍山西。"]'),
('415384ea-00ec-455d-be19-a0480a44673a','贈狄崇班季子','蘇軾','宋','宋诗','song-poetry','','[]','狄生臂鷹來，見客不會揖。',120,'全唐诗/poet.song.45000.json','["狄生臂鷹來，見客不會揖。", "踞牀咤得雋，借筯數禽入。", "短後椈豹裘，猶濺猩血濕。", "指呼索酒嘗，快作長鯨吸。", "半酣論刀槊，怒髮欲起立。", "北方老猘子，狂突尚不縶。", "要須此慓悍，氣壓邊烽急。", "夜走追鋒車，生斬活離級。", "持歸獻天王，封侯穩可拾。", "何爲走獵師，日使羣毛泣。"]'),
('3f02991c-eec7-4a1b-80c0-104995f64ef5','石炭','蘇軾','宋','宋诗','song-poetry','','[]','君不見前年雨雪行人斷，城中居民風裂骭。',131,'全唐诗/poet.song.45000.json','["君不見前年雨雪行人斷，城中居民風裂骭。", "濕薪半束抱衾裯，日暮敲門無處換。", "豈料山中有遺寶，磊落如䃜萬車炭。", "流膏迸液無人知，陣陣腥風自吹散。", "根苗一發浩無際，萬人鼓舞千人看。", "投泥潑水愈光明，爍玉流金見精悍。", "南山栗林漸可息，北山頑鑛何勞鍛。", "爲君鑄作百鍊刀，要斬長鯨爲萬段。"]'),
('dbebd085-9fc8-49b2-aec1-564c8fd4868f','與參寥師行園中得黄耳蕈','蘇軾','宋','宋诗','song-poetry','','[]','遣化何時取衆香，法筵齋缽久淒涼。',64,'全唐诗/poet.song.45000.json','["遣化何時取衆香，法筵齋缽久淒涼。", "寒蔬病甲誰能採，落葉空畦半已荒。", "老楮忽生黄耳菌，故人兼致白芽薑。", "蕭然放箸東南去，又入春山筍蕨鄉。"]'),
('3ab35581-db44-4a78-8676-ce973e7f8b5c','次韵參寥師寄秦太虛三絕句時秦君舉進士不得  其一','蘇軾','宋','宋诗','song-poetry','','[]','秦郎文字固超然，漢武憑虛意欲仙。',32,'全唐诗/poet.song.45000.json','["秦郎文字固超然，漢武憑虛意欲仙。", "底事秋來不得解，定中試與問諸天。"]'),
('4b39bb12-db6e-4dd9-8b73-b970c175ddaa','次韵參寥師寄秦太虛三絕句時秦君舉進士不得  其二','蘇軾','宋','宋诗','song-poetry','','[]','一尾追風抹萬蹄，崑崙玄圃謂朝隮。',32,'全唐诗/poet.song.45000.json','["一尾追風抹萬蹄，崑崙玄圃謂朝隮。", "回看世上無伯樂，却道鹽車勝月題。"]'),
('a7065d04-14f6-422c-b691-fc667e5123a8','次韵參寥師寄秦太虛三絕句時秦君舉進士不得  其三','蘇軾','宋','宋诗','song-poetry','','[]','得喪秋毫久已冥，不須聞此氣崢嶸。',32,'全唐诗/poet.song.45000.json','["得喪秋毫久已冥，不須聞此氣崢嶸。", "何妨却伴參寥子，無數新詩咳唾成。"]'),
('02523c54-e858-447f-a007-68c93c655324','送參寥師','蘇軾','宋','宋诗','song-poetry','','[]','上人學苦空，百念已灰冷。',168,'全唐诗/poet.song.45000.json','["上人學苦空，百念已灰冷。", "劍頭惟一鷄，焦穀無新穎。", "胡爲逐吾輩，文字爭蔚炳。", "新詩如玉屑，出語便清警。", "退之論草書，萬事未嘗屏。", "憂愁不平氣，一寓筆所騁。", "頗怪浮屠人，視身如丘井。", "頹然寄淡泊，誰與發豪猛。", "細思乃不然，真巧非幻影。", "欲令詩語妙，無厭空且靜。", "靜故了羣動，空故納萬境。", "閱世走人間，觀身卧雲嶺。", "鹹酸雜衆好，中有至味永。", "詩法不相妨，此語更當請。"]'),
('87a65680-40fc-44d7-9ecc-d6a93e12e169','人日獵城南會者十人以身輕一鳥過槍急萬人呼爲韵得鳥字','蘇軾','宋','宋诗','song-poetry','','[]','兒童笑使君，憂慍常悄悄。',168,'全唐诗/poet.song.45000.json','["兒童笑使君，憂慍常悄悄。", "誰拈白接䍦，令跨金騕褭。", "東風吹濕雪，手冷怯清曉。", "忽發兩鳴髇，相趁飛蝱小。", "放弓一長嘯，目送孤鴻矯。", "吟詩忘鞭轡，不語頭自掉。", "歸來仍脫粟，鹽豉煮芹蓼。", "何似雷將軍，兩眼霜鶻皎。", "黑頭已爲將，百戰意未了。", "馬上倒銀瓶，得兔不暇燎。", "少年負奇志，蹭蹬百憂繞。", "回首英雄人，老死已不少。", "青春還一夢，餘年真過鳥。", "莫上呼鷹臺，平生笑劉表。"]'),
('3c1502e2-a318-4dfa-8d05-86b9b405d636','將官雷勝得過字代作','蘇軾','宋','宋诗','song-poetry','','[]','胡騎入回中，急烽連夜過。',72,'全唐诗/poet.song.45000.json','["胡騎入回中，急烽連夜過。", "短刀穿虜陣，濺血貂裘涴。", "一來輦轂下，愁悶惟欲卧。", "今朝從公獵，稍覺天宇大。", "一雙鐵絲箭，未發手先唾。", "射殺雪毛狐，腰間餘一箇。"]'),
('73d48f22-212c-4d53-9e29-6d9abf6e3148','和參寥見寄','蘇軾','宋','宋诗','song-poetry','','["\u897f\u6e56"]','黄樓南畔馬臺東，雲月娟娟正點空。',64,'全唐诗/poet.song.45000.json','["黄樓南畔馬臺東，雲月娟娟正點空。", "欲共幽人洗筆硯，要傳流水入絲桐。", "且隨侍者尋西谷，莫學山僧老祝融。", "待我西湖借君去，一杯湯餠潑油葱。"]'),
('d2547a5a-d119-400e-9d0c-df146eaebd26','臺頭寺步月得人字','蘇軾','宋','宋诗','song-poetry','','[]','風吹河漢掃微雲，步屧中庭月趁人。',64,'全唐诗/poet.song.45000.json','["風吹河漢掃微雲，步屧中庭月趁人。", "浥浥爐香初泛夜，離離花影欲摇春。", "遥知金闕同清景，想見氈車輾暗塵。", "回首舊游真是夢，一簪華髮岸綸巾。"]'),
('cd9d0fd0-39ef-44d0-9397-826485bcfa1e','臺頭寺送宋希元','蘇軾','宋','宋诗','song-poetry','','[]','相從傾蓋只今年，送別南臺便黯然。',64,'全唐诗/poet.song.45000.json','["相從傾蓋只今年，送別南臺便黯然。", "入夜更歌金縷曲，他時莫忘角弓篇。", "三年不顧東鄰女，二頃方求負郭田。", "我欲歸休君未可，茂先方議劚龍泉。"]'),
('0f0cd0a0-f0d2-4561-bbea-5b8f7eeb3e0c','種松得徠字','蘇軾','宋','宋诗','song-poetry','','[]','春風吹榆林，亂莢飛作堆。',180,'全唐诗/poet.song.45000.json','["春風吹榆林，亂莢飛作堆。", "荒園一雨過，戢戢千萬栽。", "青松種不生，百株望一枚。", "一枚已有餘，氣壓千畝槐。", "野人易斗粟，云自魯徂徠。", "魯人不知貴，萬竈飛青煤。", "束縛同一車，胡爲乎來哉。", "泫然解其縛，清泉洗浮埃。", "枝傷葉尚困，生意未肯回。", "山僧老無子，養護如嬰孩。", "坐待走龍蛇，清陰滿南臺。", "孤根裂山石，直幹排風雷。", "我今百日客，養此千歲材。", "茯苓無消息，雙鬢日夜摧。", "古今一俯仰，作詩寄餘哀。"]'),
('062d20e1-6819-4204-a43c-037105198cfe','遊桓山會者十人以春水滿四澤夏雲多奇峰爲韵得澤字','蘇軾','宋','宋诗','song-poetry','','[]','東郊欲尋春，未見鶑花迹。',144,'全唐诗/poet.song.45000.json','["東郊欲尋春，未見鶑花迹。", "春風在流水，鳬雁先拍拍。", "孤帆信溶漾，弄此半篙碧。", "艤舟桓山下，長嘯理輕策。", "彈琴石室中，幽響清磔磔。", "弔彼泉下人，野火失枯腊。", "悟此人間世，何者爲真宅。", "暮回百步洪，散坐洪上石。", "愧我非王襄，子淵肯見客。", "臨流吹洞簫，水月照連璧。", "此歡真不朽，回首歲月隔。", "想像斜川遊，作詩寄彭澤。"]'),
('c32b501e-2f8b-4871-9534-03f527e498a1','戴道士得四字代作','蘇軾','宋','宋诗','song-poetry','','[]','少小家江南，寄跡方外士。',120,'全唐诗/poet.song.45000.json','["少小家江南，寄跡方外士。", "偶隨白雲出，賣藥彭城市。", "雪霜侵鬢髮，塵土污冠袂。", "頼此三尺桐，中有山水意。", "自從夷夏亂，七絲久已棄。", "心知鹿鳴三，不及胡琴四。", "使君獨慕古，嗜好與衆異。", "共弔桓魋宮，一灑孟嘗淚。", "歸來鎖塵匣，獨對斷絃喟。", "挂名石壁間，寂寞千歲事。"]'),
('6a3653a8-76c4-4ac7-9848-2c3b4552b10b','往在東武與人往反作粲字韵詩四首今黄魯直亦次韵見寄復和答之','蘇軾','宋','宋诗','song-poetry','','[]','苻堅破荆州，止獲一人半。',192,'全唐诗/poet.song.45000.json','["苻堅破荆州，止獲一人半。", "中郎老不遇，但喜識元歎。", "我今獨何幸，文字厭奇玩。", "又得天下才，相從百憂散。", "陰求我輩人，規作林泉伴。", "寧當待垂老，倉卒收一旦。", "不見梁伯鸞，空對孟光案。", "才難不其然，婦女厠周亂。", "世豈無作者，於我如既盥。", "獨喜誦君詩，咸韶音節緩。", "夜光一已多，矧獲纍纍貫。", "相思君欲瘦，不往我真懦。", "吾儕眷微祿，寒夜把寸炭。", "何時定相過，徑就我乎館。", "飄然東南去，江水清且暖。", "相與訪名山，微言師忍粲。"]'),
('ad1eefc2-4055-44c5-9aa1-8e3cb5648e79','月夜與客飲杏花下','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u6625\u5929", "\u6708\u591c", "\u611f\u6168"]','杏花飛簾散餘春，明月入戶尋幽人。',96,'全唐诗/poet.song.45000.json','["杏花飛簾散餘春，明月入戶尋幽人。", "褰衣步月踏花影，炯如流水涵青蘋。", "花間置酒清香發，爭挽長條落香雪。", "山城酒薄不堪飲，勸君且吸杯中月。", "洞簫聲斷月明中，惟憂月落酒杯空。", "明朝捲地春風惡，但見綠葉棲殘紅。"]'),
('fb4371d5-5810-40d6-b2ea-96a4c9ef1855','送蜀人張師厚赴殿試二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','忘歸不覺鬢毛斑，好事鄉人尚往還。',32,'全唐诗/poet.song.45000.json','["忘歸不覺鬢毛斑，好事鄉人尚往還。", "斷嶺不遮西望眼，送君直過楚王山。"]'),
('31cf15a4-b5d4-4d3d-b397-1551e3126fe6','送蜀人張師厚赴殿試二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','雲龍山下試春衣，放鶴亭前送落暉。',32,'全唐诗/poet.song.45000.json','["雲龍山下試春衣，放鶴亭前送落暉。", "一色杏花三十里，新郎君去馬如飛。"]'),
('bc257194-12f9-4d0c-acc1-13935c2d05f0','雪齋','蘇軾','宋','宋诗','song-poetry','','[]','君不見峨眉山西雪千里，北望成都如井底。',99,'全唐诗/poet.song.45000.json','["君不見峨眉山西雪千里，北望成都如井底。", "春風百日吹不消，五月行人如凍蟻。", "紛紛市人爭奪中，誰信言公似贊公。", "人間熱惱無處洗，故向西齋作雪峰。", "我夢扁舟入吳越，長廊靜院燈如月。", "開門不見人與牛，惟見空庭滿山雪。"]'),
('0af5c4ed-f900-4133-b93b-d6bab89d919b','以雙刀遺子由子由有詩次其韵','蘇軾','宋','宋诗','song-poetry','','[]','寶刀匣不見，但見龍雀環。',168,'全唐诗/poet.song.45000.json','["寶刀匣不見，但見龍雀環。", "何曾斬蛟蛇，亦未切琅玕。", "胡爲穿窬輩，見之要領寒。", "吾刀不汝問，有愧在其肝。", "念此力自藏，包之虎皮斑。", "湛然如古井，終歲不復瀾。", "不憂無所用，憂在用者難。", "佩之非其人，匣中自長歎。", "我老衆所易，屢遭非意干。", "惟有王玄通，階庭秀芝蘭。", "知子後必大，故擇刀所便。", "屠狗非不用，一歲六七刓。", "欲試百鍊剛，要須更泥蟠。", "作詩銘其背，以待知者看。"]'),
('58326154-80bb-4aff-b725-a322c60c703f','作書寄王晉卿忽憶前年寒食北城之遊走筆爲此詩','蘇軾','宋','宋诗','song-poetry','','[]','北城寒食烟火微，落花胡蝶作團飛。',112,'全唐诗/poet.song.45000.json','["北城寒食烟火微，落花胡蝶作團飛。", "王孫出游樂忘歸，門前驄馬紫金鞿。", "吹笙帳底烟霏霏，行人舉頭誰敢睎。", "扣門狂客君不麾，更遣傾城出翠帷。", "書生老眼省見稀，畫圖但覺周昉肥。", "別來春物已再菲，西望不見紅日圍。", "何時東山歌采薇，把盞一聽金縷衣。"]'),
('0e8b6d6b-a99b-4616-acfd-72a09c994c2f','次韵田國博部夫南京見寄二絕  其一','蘇軾','宋','宋诗','song-poetry','','[]','歲月翩翩下坂輪，歸來杏子已生人。',32,'全唐诗/poet.song.45000.json','["歲月翩翩下坂輪，歸來杏子已生人。", "深紅落盡東風惡，柳絮榆錢不當春。"]'),
('2ea0ad3d-f226-4521-8f84-c94b25b113ad','次韵田國博部夫南京見寄二絕  其二','蘇軾','宋','宋诗','song-poetry','','[]','火冷餳稀杏粥稠，青裙縞袂餉田頭。',32,'全唐诗/poet.song.45000.json','["火冷餳稀杏粥稠，青裙縞袂餉田頭。", "大夫行役家人怨，應羨居鄉馬少游。"]'),
('dc1d4caa-ad73-4c5d-abc5-9d99384a3758','再次韵答田國博部夫還二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','西郊黄土沒車輪，滿面風埃笑路人。',32,'全唐诗/poet.song.45000.json','["西郊黄土沒車輪，滿面風埃笑路人。", "已放役夫三萬指，從教積雨洗殘春。"]'),
('8d96ccfb-c373-4323-8f50-365003853a82','再次韵答田國博部夫還二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','枝上稀疏地上稠，忍看紅糝落牆頭。',32,'全唐诗/poet.song.45000.json','["枝上稀疏地上稠，忍看紅糝落牆頭。", "風流別乘多才思，歸趁西園秉燭遊。"]'),
('356171ae-4113-4e1b-8277-6b1b33162bc3','田國博見示石炭詩有鑄劍斬佞臣之句次韵答之','蘇軾','宋','宋诗','song-poetry','','[]','楚山鐵炭皆奇物，知君欲斫姦邪窟。',64,'全唐诗/poet.song.45000.json','["楚山鐵炭皆奇物，知君欲斫姦邪窟。", "屬鏤無眼不識人，楚國何曾斬無極。", "玉川狂直古遺民，救月裁詩語最真。", "千里妖蟆一寸鐵，地上空愁蟣蝨臣。"]'),
('d78953f7-f4b9-4e78-ac46-47360ea99d23','答郡中同僚賀雨','蘇軾','宋','宋诗','song-poetry','','[]','水旱行十年，饑疫遍九土。',168,'全唐诗/poet.song.45000.json','["水旱行十年，饑疫遍九土。", "奇窮所向惡，歲歲祈晴雨。", "雖非爲己求，重請終愧古。", "鬼神亦知我，老病入腰膂。", "何曾拜向人，此意難不許。", "重雲萋已合，微潤先流礎。", "蕭蕭止還作，坐聽及三鼓。", "天明將吏集，泥土滿靴屨。", "登城望麰麥，綠浪風掀舞。", "愧我賢友生，雄篇鬬新語。", "君看大熟歲，風雨占十五。", "天地本無功，祈禳何足數。", "渡河不入境，未若無蝗虎。", "而況刑白鵝，下策君勿取。"]'),
('5990029c-dfa3-46e9-9333-0d1d2c064c4f','留別叔通元弼坦夫','蘇軾','宋','宋诗','song-poetry','','[]','田三昔同僚，向我每傾倒。',120,'全唐诗/poet.song.45000.json','["田三昔同僚，向我每傾倒。", "當年或齟齬，反覆看愈好。", "寇三我部民，孝弟化鄰保。", "有如袁伯業，苦學到衰老。", "石生吾邑子，勁立風中草。", "宦遊甑生塵，菽水媚翁媼。", "我窮交舊絕，計拙集枯槁。", "三子尤見存，往復紛紵縞。", "迎我淮水北，送我睢陽道。", "願存金石契，凜凜貫華皓。"]'),
('7396e7ce-b908-43e7-95fd-ac7fe82a07b9','罷徐州往南京馬上走筆寄子由五首  其一','蘇軾','宋','宋诗','song-poetry','','[]','吏民莫扳援，歌管莫淒咽。',84,'全唐诗/poet.song.45000.json','["吏民莫扳援，歌管莫淒咽。", "吾生如寄耳，寧獨爲此別。", "別離隨處有，悲惱緣愛結。", "而我本無恩，此涕誰爲設。", "紛紛等兒戲，鞭𩍐遭割截。", "道邊雙石人，幾見太守發。", "有知當解笑，撫掌冠纓絕。"]'),
('ad3cd6b5-2f7d-48a9-8a90-f7124789367f','罷徐州往南京馬上走筆寄子由五首  其二','蘇軾','宋','宋诗','song-poetry','','[]','父老何自來，花枝裊長紅。',72,'全唐诗/poet.song.45000.json','["父老何自來，花枝裊長紅。", "洗盞拜馬前，請壽使君公。", "前年無使君，魚鼈化兒童。", "舉鞭謝父老，正坐使君窮。", "窮人命分惡，所向招災凶。", "水來非吾過，去亦非吾功。"]'),
('0a6fee2e-09b9-4113-b34b-bd68c1eb5012','罷徐州往南京馬上走筆寄子由五首  其三','蘇軾','宋','宋诗','song-poetry','','[]','古汴從西來，迎我向南京。',72,'全唐诗/poet.song.45000.json','["古汴從西來，迎我向南京。", "東流入淮泗，送我東南行。", "暫別復還見，依然有餘情。", "春雨漲微波，一夜到彭城。", "過我黄樓下，朱欄照飛甍。", "可憐洪上石，誰聽月中聲。"]'),
('4b6ab999-9ad4-4690-a3e5-7da071c5360d','罷徐州往南京馬上走筆寄子由五首  其四','蘇軾','宋','宋诗','song-poetry','','[]','前年過南京，麥老櫻桃熟。',72,'全唐诗/poet.song.45000.json','["前年過南京，麥老櫻桃熟。", "今來舊遊處，櫻麥半黄綠。", "歲月如宿昔，人事幾反覆。", "青衫老從事，坐穩生髀肉。", "聯翩閱三守，迎送如轉轂。", "歸耕何時决，田舍我已卜。"]'),
('6185e6bd-a7fb-4a78-be0f-ef11a06e44f0','罷徐州往南京馬上走筆寄子由五首  其五','蘇軾','宋','宋诗','song-poetry','','[]','卜田向何許，石佛山南路。',84,'全唐诗/poet.song.45000.json','["卜田向何許，石佛山南路。", "下有爾家川，千畦種秔稌。", "山泉宅龍蜃，平地走膏乳。", "異時畝一金，近欲爲逃戶。", "逝將解簪紱，賣劍買牛具。", "故山豈不懷，廢宅生蒿穭。", "便恐桐鄉人，長祠仲卿墓。"]'),
('1c3b088a-b6de-42e2-91f3-f714715dded4','書泗州孫景山西軒','蘇軾','宋','宋诗','song-poetry','','[]','落日明孤塔，青山繞病身。',24,'全唐诗/poet.song.45000.json','["落日明孤塔，青山繞病身。", "知君向西望，不愧塔中人。"]'),
('5c073bcc-18e3-4dae-944a-5c985e76707f','過泗上喜見張嘉父二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','眉間冰雪照淮明，筆下波瀾老欲平。',32,'全唐诗/poet.song.45000.json','["眉間冰雪照淮明，筆下波瀾老欲平。", "直得全生如許妙，不知形諜已多名。"]'),
('bace8d93-61f6-4b01-a4a3-df984fd859f2','過泗上喜見張嘉父二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','空翠娛人意自還，明窗一榻共秋閑。',32,'全唐诗/poet.song.45000.json','["空翠娛人意自還，明窗一榻共秋閑。", "會知名利不到處，定把清觴屬此山。"]'),
('31d53a3f-1611-47f7-9450-cce5d388beba','過淮三首贈景山兼寄子由  其一','蘇軾','宋','宋诗','song-poetry','','[]','好在長淮水，十年三往來。',48,'全唐诗/poet.song.45000.json','["好在長淮水，十年三往來。", "功名真已矣，歸計亦悠哉。", "今日風憐客，平時浪作堆。", "晚來洪澤口，捍索響如雷。"]'),
('bb19d8a5-d3de-4280-a490-ce7fbf31ee50','過淮三首贈景山兼寄子由  其二','蘇軾','宋','宋诗','song-poetry','','[]','過淮山漸好，松檜亦蒼然。',48,'全唐诗/poet.song.45000.json','["過淮山漸好，松檜亦蒼然。", "靄靄藏孤寺，泠泠出細泉。", "故人真吏隠，小檻带巌偏。", "却望臨淮市，東風語笑傳。"]'),
('179027ad-9bcf-4ef0-93bd-9d592b2717d4','過淮三首贈景山兼寄子由  其三','蘇軾','宋','宋诗','song-poetry','','[]','回首濉陽幕，簿書高沒人。',48,'全唐诗/poet.song.45000.json','["回首濉陽幕，簿書高沒人。", "何時桐柏水，一洗庾公塵。", "此去漸佳境，獨游長慘神。", "待君詩百首，來寫浙西春。"]'),
('65052c66-1432-4218-8326-9a2aac1476cc','舟中夜起','蘇軾','宋','宋诗','song-poetry','','[]','微風蕭蕭吹菰蒲，開門看雨月滿湖。',96,'全唐诗/poet.song.45000.json','["微風蕭蕭吹菰蒲，開門看雨月滿湖。", "舟人水鳥兩同夢，大魚驚竄如奔狐。", "夜深人物不相管，我獨形影相嬉娛。", "暗潮生渚弔寒蚓，落月挂柳看懸蛛。", "此生忽忽憂患裏，清境過眼能須臾。", "雞鳴鐘動百鳥散，船頭擊鼓還相呼。"]'),
('9bc69620-5aaf-449b-abd3-3c013b13c2d7','余去金山五年而復至次舊詩韵贈寶覺長老','蘇軾','宋','宋诗','song-poetry','','[]','誰能斗酒博西凉，但愛齋厨法豉香。',64,'全唐诗/poet.song.45000.json','["誰能斗酒博西凉，但愛齋厨法豉香。", "舊事真成一夢過，高譚爲洗五年忙。", "清風偶與山阿曲，明月聊隨屋角方。", "稽首願師憐久客，直將歸路指茫茫。"]'),
('21d202ea-5587-47c3-9d61-d3702da20475','大風留金山兩日','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u4eba\u751f", "\u5199\u666f"]','塔上一鈴獨自語，明日顛風當斷渡。',96,'全唐诗/poet.song.45000.json','["塔上一鈴獨自語，明日顛風當斷渡。", "朝來白浪打蒼崖，倒射軒窗作飛雨。", "龍驤萬斛不敢過，漁舟一葉從掀舞。", "細思城市有底忙，却笑蛟龍爲誰怒。", "無事久留童僕怪，此風聊得妻孥許。", "灊山道人獨何事，夜半不眠聽粥鼓。"]'),
('0299d2b2-83f3-405d-9210-3d0475473e46','遊惠山  其一','蘇軾','宋','宋诗','song-poetry','','[]','夢裏五年過，覺來雙鬢蒼。',72,'全唐诗/poet.song.45000.json','["夢裏五年過，覺來雙鬢蒼。", "還將塵土足，一步漪瀾堂。", "俯窺松桂影，仰見鴻鶴翔。", "炯然肝肺間，已作冰玉光。", "虛明中有色，清浄自生香。", "還從世俗去，永與世俗忘。"]'),
('b7166a4b-ca30-46e1-b8e0-5b3ec21a22ae','遊惠山  其二','蘇軾','宋','宋诗','song-poetry','','[]','薄雲不遮山，疏雨不濕人。',72,'全唐诗/poet.song.45000.json','["薄雲不遮山，疏雨不濕人。", "蕭蕭松徑滑，策策芒鞋新。", "嘉我二三子，皎然無緇磷。", "勝遊豈殊昔，清句仍絕塵。", "弔古泣舊史，疾讒歌小旻。", "哀哉扶風子，難與巢許鄰。"]'),
('045c464d-7429-48e9-9d8a-10cca10d9fe9','遊惠山  其三','蘇軾','宋','宋诗','song-poetry','','[]','敲火發山泉，烹茶避林樾。',72,'全唐诗/poet.song.45000.json','["敲火發山泉，烹茶避林樾。", "明窗傾紫盞，色味兩奇絕。", "吾生眠食耳，一飽萬想滅。", "頗笑玉川子，饑弄三百月。", "豈如山中人，睡起山花發。", "一甌誰與共，門外無來轍。"]'),
('b32a2e25-1750-4bf9-b635-881668486094','贈惠山僧惠表','蘇軾','宋','宋诗','song-poetry','','[]','行遍天涯意未闌，將心到處遣人安。',64,'全唐诗/poet.song.45000.json','["行遍天涯意未闌，將心到處遣人安。", "山中老宿依然在，案上楞巌已不看。", "敧枕落花餘幾片，閉門新竹自千竿。", "客來茶罷空無有，盧橘楊梅尚带酸。"]'),
('5bcbe70f-fdb0-4831-b2a4-7ad137d0c67b','贈錢道人','蘇軾','宋','宋诗','song-poetry','','[]','書生苦信書，世事仍臆度。',96,'全唐诗/poet.song.45000.json','["書生苦信書，世事仍臆度。", "不量力所負，輕出千鈞諾。", "當時一快意，事過有餘怍。", "不知幾州鐵，鑄此一大錯。", "我生涉憂患，常恐長罪惡。", "靜觀殊可喜，脚淺猶容却。", "而況錢夫子，萬事初不作。", "相逢更何言，無病亦無藥。"]'),
('f632ce13-55f8-416d-8831-a3e99f4f5b0c','與秦太虛參寥會於松江而關彥長徐安中適至分韵得風字二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','吳越溪山興未窮，又扶衰病過垂虹。',64,'全唐诗/poet.song.45000.json','["吳越溪山興未窮，又扶衰病過垂虹。", "浮天自古東南水，送客今朝西北風。", "絕境自忘千里遠，勝游難復五人同。", "舟師不會留連意，擬看斜陽萬頃紅。"]'),
('233c502c-1967-4054-946f-099abea0bc29','與秦太虛參寥會於松江而關彥長徐安中適至分韵得風字二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','二子緣詩老更窮，人間無處吐長虹。',64,'全唐诗/poet.song.45000.json','["二子緣詩老更窮，人間無處吐長虹。", "平生睡足連江雨，盡日舟橫擘岸風。", "人笑年來三黜慣，天教我輩一樽同。", "知君欲寫長相憶，更送銀盤尾鬣紅。"]'),
('f0fd30b3-5ee6-4bce-a8ff-6961bed69418','次韵答參寥','蘇軾','宋','宋诗','song-poetry','','[]','我有方外客，顔如瓊之英。',120,'全唐诗/poet.song.45000.json','["我有方外客，顔如瓊之英。", "十年塵土窟，一寸冰雪清。", "朅來從我遊，坦率見真情。", "顧我無足戀，戀此山水青。", "新詩如彈丸，脫手不暫停。", "昨日放魚回，衣巾滿浮萍。", "今日扁舟去，白酒載烏程。", "山頭見月出，江路聞鼉鳴。", "莫作孺子歌，滄浪濯吾纓。", "吾詩自堪唱，相子棹歌聲。"]'),
('b948e586-b9f8-418b-b7c7-481b11f2c499','次韵關令送魚','蘇軾','宋','宋诗','song-poetry','','[]','舉網驚呼得巨魚，饞涎不易忍流酥。',32,'全唐诗/poet.song.45000.json','["舉網驚呼得巨魚，饞涎不易忍流酥。", "更煩赤脚長鬚老，來趁西風十幅蒲。"]'),
('f9497d80-8705-490e-a8c6-f8468c0fe8a1','次韵秦太虛見戲耳聾','蘇軾','宋','宋诗','song-poetry','','["\u6292\u60c5", "\u653f\u6cbb"]','君不見詩人借車無可載，留得一錢何足頼。',163,'全唐诗/poet.song.45000.json','["君不見詩人借車無可載，留得一錢何足頼。", "晚年更似杜陵翁，右臂雖存耳先聵。", "人將蟻動作牛鬬，我覺風雷真一噫。", "聞塵掃盡根性空，不須更枕清流派。", "大朴初散失渾沌，六鑿相攘更勝敗。", "眼花亂墜酒生風，口業不停詩有債。", "君知五藴皆是賊，人生一病今先差。", "但恐此心終未了，不見不聞還是礙。", "今君疑我特佯聾，故作嘲詩窮嶮怪。", "須防額癢出三耳，莫放筆端風雨快。"]'),
('c4230e56-6e28-4e18-a99b-c3f40357cb1b','端午遍遊諸寺得禪字','蘇軾','宋','宋诗','song-poetry','','["\u7eaa\u6e38", "\u7aef\u5348\u8282", "\u5199\u666f"]','肩輿任所適，遇勝輒流連。',120,'全唐诗/poet.song.45000.json','["肩輿任所適，遇勝輒流連。", "焚香引幽步，酌茗開浄筵。", "微雨止還作，小窗幽更妍。", "盆山不見日，草木自蒼然。", "忽登最高塔，眼界窮大千。", "卞峰照城郭，震澤浮雲天。", "深沉既可喜，曠蕩亦所便。", "幽尋未云畢，墟落生晚煙。", "歸來記所歷，耿耿清不眠。", "道人亦未寢，孤燈同夜禪。"]'),
('111ca998-5381-4231-89ab-cf13c9db8eb1','送劉寺丞赴餘姚','蘇軾','宋','宋诗','song-poetry','','["\u94b1\u5858\u6c5f"]','中和堂後石楠樹，與君對牀聽夜雨。',160,'全唐诗/poet.song.45000.json','["中和堂後石楠樹，與君對牀聽夜雨。", "玉笙哀怨不逢人，但見香烟橫碧縷。", "謳吟思歸出無計，坐想蟋蟀空房語。", "明朝開鎖放觀潮，豪氣正與潮爭怒。", "銀山動地君不看，獨愛清香生雲霧。", "別來聚散如宿昔，城郭空存鶴飛去。", "我老人間萬事休，君亦洗心從佛祖。", "手香新寫法界觀，眼浄不覷登伽女。", "餘姚古縣亦何有，龍井白泉甘勝乳。", "千金買斷顧渚春，似與越人降日注。"]'),
('fab5b9fe-2f48-40b2-a208-4019a96c7c0e','霅上訪道人不遇','蘇軾','宋','宋诗','song-poetry','','[]','花光紅滿欄，草色綠無岸。',24,'全唐诗/poet.song.45000.json','["花光紅滿欄，草色綠無岸。", "不逢青眼人，長歌白石爛。"]'),
('46608aa2-b31d-4de9-a954-069d048de241','李公擇過高郵見施大夫與孫莘老賞花詩憶與僕去歲會於彭門折花饋筍故事作詩二十四韵見戲依韵奉答亦以戲公擇云','蘇軾','宋','宋诗','song-poetry','','[]','汝陽真天人，絹帽著紅槿。',288,'全唐诗/poet.song.45000.json','["汝陽真天人，絹帽著紅槿。", "纏頭三百萬，不買一微哂。", "共誇青山峰，曲盡花不隕。", "當時謫仙人，逸韵謝封畛。", "詩成天一笑，萬象解寒窘。", "驚開小桃杏，不待雷發軫。", "餘波尚涓滴，乞與居易稹。", "爾來誰復見，前輩風流盡。", "寂寞兩詩人，殘紅對櫻筍。", "饑腸得一醉，妙語傳不泯。", "君來恨不與，更復相牽引。", "我老心已灰，空煩扇餘燼。", "天游照六鑿，虛室掃充牣。", "懸知色竟空，那復嗜烏吻。", "蕭然一方丈，居士老龐藴。", "散花從滿裓，不答天女問。", "故人猶故目，怨句寫餘恨。", "疑我此心在，遮防費欄楯。", "應虞已斃蛇，折尾時一蠢。", "仄聞孟光賢，未學處仲忍。", "寄招應已足，左右侍雲鬒。", "何時花月夜，羊酒謝不敏。", "此生如幻耳，戲語君勿慍。", "應同亡是公，一對子虛听。"]'),
('1b248424-673c-4121-b447-22a41680075d','王鞏清虛堂','蘇軾','宋','宋诗','song-poetry','','[]','清虛堂裏王居士，閉眼觀心如止水。',96,'全唐诗/poet.song.45000.json','["清虛堂裏王居士，閉眼觀心如止水。", "水中照見萬象空，敢問堂中誰隠几。", "吳興太守老且病，堆案滿前長渴睡。", "願君勿笑反自觀，夢幻去來殊未已。", "長疑安石恐不免，未信犀首終無事。", "勿將一念住清虛，居士與我蓋同耳。"]'),
('5415e471-6060-413e-a227-766e9633fa95','和孫同年卞山龍洞禱晴','蘇軾','宋','宋诗','song-poetry','','[]','吳興連月雨，釜甑生魚蛙。',144,'全唐诗/poet.song.45000.json','["吳興連月雨，釜甑生魚蛙。", "往問卞山龍，曷不安厥家。", "梯空上巉絕，俯視驚谽谺。", "神井湧雲蓋，陰崖垂蘚花。", "交流百道泉，赴谷走羣蛇。", "不知落何處，隠隠如繅車。", "我來叩石戶，飛鼠翻白鴉。", "寄語洞中龍，睡味豈不嘉。", "雨師少弭節，雷師亦停撾。", "積水得反壑，稻苗出泥沙。", "農夫免菜色，龍亦飽豚豭。", "看君擁黄紬，高卧放晚衙。"]'),
('4a0ade6a-6b37-4291-8d35-a317278f2ba4','乘舟過賈收水閣收不在見其子三首  其一','蘇軾','宋','宋诗','song-poetry','','[]','愛酒陶元亮，能詩張志和。',48,'全唐诗/poet.song.45000.json','["愛酒陶元亮，能詩張志和。", "青山來水檻，白雨滿漁簑。", "淚垢添丁面，貧低舉案蛾。", "不知何所樂，竟夕獨酣歌。"]'),
('e22886c8-2afa-4fc9-a62b-4969fb2b0738','乘舟過賈收水閣收不在見其子三首  其二','蘇軾','宋','宋诗','song-poetry','','[]','嫋嫋風蒲亂，猗猗水荇長。',48,'全唐诗/poet.song.45000.json','["嫋嫋風蒲亂，猗猗水荇長。", "小舟浮鴨綠，大杓瀉鵝黄。", "得意詩酒社，終身魚稻鄉。", "樂哉無一事，何處不清凉。"]'),
('83358fbd-d3e8-49dd-8c8e-d6a94b31529c','乘舟過賈收水閣收不在見其子三首  其三','蘇軾','宋','宋诗','song-poetry','','[]','曳杖青苔岸，繫船枯柳根。',48,'全唐诗/poet.song.45000.json','["曳杖青苔岸，繫船枯柳根。", "德公方上冢，季路獨留言。", "已占蒲魚港，更開松菊園。", "從茲來往數，兒女自譍門。"]'),
('b9e2d492-ad05-4f0c-b767-9a0a1405da08','次韵孫秘丞見贈','蘇軾','宋','宋诗','song-poetry','','[]','感慨清哀似變風，老於詩句耳偏聰。',64,'全唐诗/poet.song.45000.json','["感慨清哀似變風，老於詩句耳偏聰。", "迂疏自笑成何事，冷淡誰能用許功。", "不怕飛蚊如立豹，肯隨白鳥過垂虹。", "吟哦相對忘三伏，擬泛冰溪入雪宮。"]'),
('0135515f-202f-450f-a96c-5d1b08bc6ac5','與客遊道場何山得鳥字','蘇軾','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','清溪到山盡，飛路盤空小。',240,'全唐诗/poet.song.45000.json','["清溪到山盡，飛路盤空小。", "紅亭與白塔，隠見喬木杪。", "中休得小庵，孤絕寄雲表。", "洞庭在北戶，雲水天渺渺。", "庵僧俗緣盡，浄業洗未了。", "十年畫鵲竹，益以詩自繞。", "高堂儼像設，禪室各深窈。", "奔泉何處來，華屋過溪沼。", "何山隔幽谷，去路清且悄。", "長松度翠蔓，絕壁挂啼鳥。", "我友自杭來，尚歎所歷少。", "歸途風雨作，一洗紅日燎。", "俄驚萬竅號，黑霧卷蓬蓼。", "舟人紛變色，坐羨輕鷗矯。", "我獨喚酒杯，醉死勝流殍。", "書生例强狠，造物空煩擾。", "更將掀舞勢，把燭畫風篠。", "美人爲破顔，正似腰支嫋。", "明朝更陳迹，清景墮空杳。", "作詩記餘歡，萬古一昏曉。"]'),
('c8336c6e-06db-47f4-945e-d11b4f166bce','僕去杭五年吳中仍歲大饑疫故人往往逝去聞湖上僧舍不復往日繁麗獨浄慈本長老學者益盛作詩寄之','蘇軾','宋','宋诗','song-poetry','','[]','來往三吳一夢間，故人半作冢纍然。',64,'全唐诗/poet.song.45000.json','["來往三吳一夢間，故人半作冢纍然。", "獨依舊社傳真法，要與遺民度厄年。", "趙叟近聞還印綬，竺翁先已反林泉。", "何時策杖相隨去，任性逍遥不學禪。"]'),
('c027278c-d40d-41bc-a422-f2bb4fa82147','送表忠觀錢道士歸杭','蘇軾','宋','宋诗','song-poetry','','[]','先王舊德在民心，著令稱忠上意深。',64,'全唐诗/poet.song.45000.json','["先王舊德在民心，著令稱忠上意深。", "墮淚行看會祠下，挂名爭欲刻碑陰。", "淒涼破屋塵凝坐，憔悴雲孫雪滿簪。", "未信諸豪容郭解，却從他縣施千金。"]'),
('81e1c6b6-36b7-41fa-be61-775ae50975c6','舶趠風','蘇軾','宋','宋诗','song-poetry','','[]','三旬已過黄梅雨，萬里初來舶趠風。',64,'全唐诗/poet.song.45000.json','["三旬已過黄梅雨，萬里初來舶趠風。", "幾處縈回度山曲，一時清駛滿江東。", "驚飄䔩䔩先秋葉，喚醒昏昏嗜睡翁。", "欲作蘭臺快哉賦，却嫌分別問雌雄。"]'),
('fd2d2be6-6456-4e91-b658-1bfa01352145','丁公默送蝤蛑','蘇軾','宋','宋诗','song-poetry','','[]','溪邊石蟹小於錢，喜見輪囷赤玉盤。',64,'全唐诗/poet.song.45000.json','["溪邊石蟹小於錢，喜見輪囷赤玉盤。", "半殻含黄宜點酒，兩螯斫雪勸加餐。", "蠻珍海錯聞名久，怪雨腥風入坐寒。", "堪笑吳興饞太守，一詩換得兩尖團。"]'),
('cf32658e-7617-4c9a-939f-156032ffb70f','送孫著作赴考城兼寄錢醇老李邦直二君於孫處有書見及','蘇軾','宋','宋诗','song-poetry','','[]','使君閑如雲，欲出誰肯伴。',144,'全唐诗/poet.song.45000.json','["使君閑如雲，欲出誰肯伴。", "清風獨無事，一嘯亦可喚。", "來從白蘋洲，吹我明月觀。", "門前遠行客，青衫流白汗。", "問子何匆匆，王事不可緩。", "故人錢與李，清廟兩圭瓚。", "蔚爲萬乘器，尚記溝中斷。", "子亦東南珍，價重不可算。", "別情何以慰，酒盡對空案。", "惟持一榻凉，勸子巾少岸。", "北風那復有，塵土飛灰炭。", "欲寄二大夫，發發不可絆。"]'),
('0d0ec84d-ca91-4e6a-94bb-6741e4550113','泛舟城南會者五人分韵賦詩得人皆苦炎字四首  其一','蘇軾','宋','宋诗','song-poetry','','[]','城中樓閣似魚鱗，不見清風起白蘋。',64,'全唐诗/poet.song.45000.json','["城中樓閣似魚鱗，不見清風起白蘋。", "試選苕溪最深處，仍呼我輩不羈人。", "窺船野鶴何曾下，見燭飛蟲空自馴。", "遶郭荷花一千頃，誰知六月下塘春。"]'),
('1c6c7879-ed78-4201-a858-7355030e8cd3','泛舟城南會者五人分韵賦詩得人皆苦炎字四首  其二','蘇軾','宋','宋诗','song-poetry','','[]','苦熱誠知處處皆，何當危坐學心齋。',64,'全唐诗/poet.song.45000.json','["苦熱誠知處處皆，何當危坐學心齋。", "海螯要共詩人把，溪月行遭霧雨霾。", "鄉國飄零斷書信，弟兄流落隔江淮。", "便應築室苕溪上，荷葉遮門水浸階。"]'),
('a81b3c90-4b93-4f3f-af0f-88770603d775','泛舟城南會者五人分韵賦詩得人皆苦炎字四首  其三','蘇軾','宋','宋诗','song-poetry','','[]','紫蟹鱸魚賤如土，得錢相付何曾數。',64,'全唐诗/poet.song.45000.json','["紫蟹鱸魚賤如土，得錢相付何曾數。", "碧筩時作象鼻彎，白酒微带荷心苦。", "運肘風生看斫鱠，隨刀雪落驚飛縷。", "不將醉語作新詩，飽食應慚腹如鼓。"]'),
('5b664730-fab2-40f1-98e5-92a8536542b1','泛舟城南會者五人分韵賦詩得人皆苦炎字四首  其四','蘇軾','宋','宋诗','song-poetry','','[]','橋上游人夜未厭，共依水檻立風簷。',64,'全唐诗/poet.song.45000.json','["橋上游人夜未厭，共依水檻立風簷。", "樓中煮酒初嘗芡，月夜新粧半出簾。", "南郭清游繼顔謝，北窗歸卧等羲炎。", "人間寒熱無窮事，自笑疏頑不受痁。"]'),
('bb384d4f-a40e-4ea7-aaec-f7589b9e1157','與王郎夜飲井水','蘇軾','宋','宋诗','song-poetry','','[]','吳興六月水泉溫，千頃菰蒲聚鬬蚊。',32,'全唐诗/poet.song.45000.json','["吳興六月水泉溫，千頃菰蒲聚鬬蚊。", "此井獨能深一丈，凜然如我亦如君。"]'),
('155fbc3a-0242-46b1-b86b-025775f84cfb','次韵李公擇梅花','蘇軾','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','詩人固長貧，日午饑未動。',240,'全唐诗/poet.song.45000.json','["詩人固長貧，日午饑未動。", "偶然得一飽，萬象困嘲弄。", "尋花不論命，愛雪長忍凍。", "天公非不憐，聽飽即喧鬨。", "君爲三郡守，所至滿賓從。", "江湖常在眼，詩酒事豪縱。", "奉使今折磨，清比於陵仲。", "永懷茶山下，携妓修春貢。", "更憶檻泉亭，插花雲髻重。", "蕭然卧灊麓，愁聽春禽哢。", "忽見早梅花，不飲但孤諷。", "詩成獨寄我，字字愈頭痛。", "嗟君本侍臣，筆橐從上雍。", "脫靴吟芍藥，給札賦雲夢。", "何人慰流落，嘉蘤天爲種。", "杯傾笛中吟，帽拂果下鞚。", "感時念羈旅，此意吾儕共。", "故山今何有，桐花集幺鳳。", "君亦憶匡廬，歸掃藏書洞。", "何當種此花，各抱漢陰甕。"]'),
('1d610b6e-084e-457e-a339-352578c8ab1d','送淵師歸徑山','蘇軾','宋','宋诗','song-poetry','','[]','我昔嘗爲徑山客，至今詩筆餘山色。',96,'全唐诗/poet.song.45000.json','["我昔嘗爲徑山客，至今詩筆餘山色。", "師住此山三十年，妙語應須得山骨。", "溪城六月水雲蒸，飛蚊猛捷如花鷹。", "羨師方丈冰雪冷，蘭膏不動長明燈。", "山中故人知我至，爭來問訊今何似。", "爲言百事不如人，兩眼猶能書細字。"]'),
('d8c2fadc-18c2-42ba-85af-a5116678b1ec','次韵周開祖長官見寄','蘇軾','宋','宋诗','song-poetry','','[]','俯仰東西閱數州，老於歧路豈伶優。',320,'全唐诗/poet.song.45000.json','["俯仰東西閱數州，老於歧路豈伶優。", "初聞父老推謝令，旋見兒童迎細侯。", "政拙年年祈水旱，民勞處處避嘲謳。", "河吞巨野那容塞，盜入蒙山不易搜。", "仕道固應慚孔孟，扶顛未可責由求。", "漸謀田舍猶懷祿，未脫風濤且傍洲。", "惘惘可憐真喪狗，時時相觸是虛舟。", "朅來震澤都如夢，只有苕溪可倚樓。", "齋釀酸甜如蜜水，樂工零落似風鷗。", "遠思顔柳并諸謝，近憶張陳與老劉。", "風定軒窗飛豹脚，雨餘欄檻上蝸牛。", "舊游到處皆蒼蘚，同甲惟君尚黑頭。", "憶昔湖山共尋勝，相逢杯酒兩忘憂。", "醉看梅雪清香過，夜棹風船駭汗流。", "百首共成山上集，三人同作月中遊。", "海南未起垂天翼，澗底仍依徑寸庥。", "已許春風歸過我，預憂詩筆老難酬。", "此生歲月行飄忽，晚節功名亦謬悠。", "犀首正緣無事飲，馮驩應爲有魚留。", "從今更踏青州麴，薄酒知君笑督郵。"]'),
('d6c49e3a-d39e-46e2-b563-8244470b36e4','林子中以詩寄文與可及余與可既歿追和其韵','蘇軾','宋','宋诗','song-poetry','','[]','斯人所甚厭，投畀每不受。',216,'全唐诗/poet.song.45000.json','["斯人所甚厭，投畀每不受。", "欲其少須臾，奪去惟恐後。", "云誰尸此職，無乃亦假守。", "賦才有巨細，無異斛與斗。", "胡不安其分，但聽物所誘。", "時來各飛動，意合無妍醜。", "坐令雞棲車，長載朱伯厚。", "平生無一旅，既死咤萬口。", "自聞與可亡，胸臆生堆阜。", "懸知臨絕意，要我一執手。", "相望五百里，安得自其牖。", "遺文付來哲，後事待諸友。", "伶俜嵇紹孤，老病孟光偶。", "世人賤目見，爭笑千金帚。", "君詩與楚詞，識者當有取。", "但知愛墨竹，此歎吾已久。", "故人多厚祿，能復哀君否。", "不見林與蘇，饑寒自奔走。"]'),
('e73290e8-c235-4f3a-8a52-4a3c2d9e9938','與王郎昆仲及兒子邁遶城觀荷花登峴山亭晚入飛英寺分韵得月明星稀四首  其一','蘇軾','宋','宋诗','song-poetry','','[]','昨夜雨鳴渠，曉來風襲月。',72,'全唐诗/poet.song.45000.json','["昨夜雨鳴渠，曉來風襲月。", "蕭然欲秋意，溪水清可啜。", "環城三十里，處處皆佳絕。", "蒲蓮浩如海，時見舟一葉。", "此間真避世，青蒻低白髮。", "相逢欲相問，已逐驚鷗沒。"]'),
('49869d3d-3ba2-438f-abee-29cfdf04a4cc','與王郎昆仲及兒子邁遶城觀荷花登峴山亭晚入飛英寺分韵得月明星稀四首  其二','蘇軾','宋','宋诗','song-poetry','','[]','清風定何物，可愛不可名。',72,'全唐诗/poet.song.45000.json','["清風定何物，可愛不可名。", "所至如君子，草木有嘉聲。", "我行本無事，孤舟任斜橫。", "中流自偃仰，適與風相迎。", "舉杯屬浩渺，樂此兩無情。", "歸來兩溪間，雲水夜自明。"]'),
('46e3c262-90af-46f0-a998-1331bc39e35e','與王郎昆仲及兒子邁遶城觀荷花登峴山亭晚入飛英寺分韵得月明星稀四首  其三','蘇軾','宋','宋诗','song-poetry','','[]','苕水如漢水，鱗鱗鴨頭青。',72,'全唐诗/poet.song.45000.json','["苕水如漢水，鱗鱗鴨頭青。", "吳興勝襄陽，萬瓦浮青冥。", "我非羊叔子，愧此峴山亭。", "悲傷意則同，歲月如流星。", "從我兩王子，高鴻插修翎。", "湛輩何足道，當以德自銘。"]'),
('35839c20-1438-4c70-a087-569d396482e8','與王郎昆仲及兒子邁遶城觀荷花登峴山亭晚入飛英寺分韵得月明星稀四首  其四','蘇軾','宋','宋诗','song-poetry','','[]','吏民憐我懶，鬬訟日已稀。',72,'全唐诗/poet.song.45000.json','["吏民憐我懶，鬬訟日已稀。", "能爲無事飲，可作不夜歸。", "復尋飛英游，盡此一寸暉。", "撞鐘履聲集，顛倒雲山衣。", "我來無時節，杖屨自推扉。", "莫作使君看，外似中已非。"]'),
('74e5d2e7-7f86-4127-a343-a2c51ead5dd1','次韵章子厚飛英留題','蘇軾','宋','宋诗','song-poetry','','[]','款段曾陪馬少游，而今人在鳳麟洲。',32,'全唐诗/poet.song.45000.json','["款段曾陪馬少游，而今人在鳳麟洲。", "黄公酒肆如重過，杳杳白蘋天盡頭。"]'),
('3fcfb88c-93b4-42ca-af30-66af7bfe4092','城南縣尉水亭得長字','蘇軾','宋','宋诗','song-poetry','','[]','兩慰鬰相望，東西百步場。',96,'全唐诗/poet.song.45000.json','["兩慰鬰相望，東西百步場。", "插旗蒲柳市，伐鼓水雲鄉。", "已作觀魚檻，仍開射鴨堂。", "全家依畫舫，極目亂紅妝。", "瀲瀲波頭細，疏疏雨脚長。", "我來閑濯足，溪漲欲浮牀。", "澤國山圍裏，孤城水影傍。", "欲知歸路處，葦外記風檣。"]'),
('953f000c-acb7-4352-87eb-3bcce93e18bf','與胡祠部游法華山','蘇軾','宋','宋诗','song-poetry','','[]','陂湖欲盡山爲界，始見寒泉落高派。',192,'全唐诗/poet.song.45000.json','["陂湖欲盡山爲界，始見寒泉落高派。", "道人未放泉出山，曲折虛堂瀉清快。", "使君年老尚兒戲，綠棹紅船舞澎湃。", "一笑翻杯水濺裙，餘歡濯足波生隘。", "長松攙天龍起立，蒼藤倒谷雲崩壞。", "仰穿蒙密得清曠，一覽震澤吁可怪。", "誰云四萬八千頃，渺渺東盡日所曬。", "歸途十里盡風荷，清唱一聲聞露薤。", "嗟予少小慕真隠，白髮青衫天所械。", "忽逢佳士與名山，何異枯楊便馬疥。", "君猶鸞鶴偶飄墮，六翮如雲豈長鎩。", "不將新句紀茲游，恐負山中清浄債。"]'),
('433eac44-16c7-41ab-93b6-cf92fc8ef3b9','又次前韵贈賈耘老','蘇軾','宋','宋诗','song-poetry','','[]','具區吞滅三州界，浩浩湯湯納千派。',192,'全唐诗/poet.song.45000.json','["具區吞滅三州界，浩浩湯湯納千派。", "從來不著萬斛船，一葉漁舟恣奔快。", "仙壇古洞不可到，空聽餘瀾鳴湃湃。", "今朝偶上法華嶺，縱觀始覺人寰隘。", "山頭卧碣弔孤冢，下有至人僵不壞。", "空餘白棘網秋蟲，無復青蓮出幽怪。", "我來徙倚長松下，欲掘茯苓親洗曬。", "聞道山中富奇藥，往往靈芝雜葵薤。", "詩人空腹待黄精，生事只看長柄械。", "今年大熟期一飽，食葉微蟲直癬疥。", "白花半落紫穟香，攘臂欲助磨鎌鎩。", "安得山泉變春酒，與子一洗尋常債。"]'),
('f84ebe03-3713-4c83-81f5-362e04a74c4b','趙閱道高齋','蘇軾','宋','宋诗','song-poetry','','[]','見公奔走謂公勞，聞公隠退云公高。',160,'全唐诗/poet.song.45000.json','["見公奔走謂公勞，聞公隠退云公高。", "公心底處有高下，夢幻去來隨所遭。", "不知高齋竟何義，此名之設緣吾曹。", "公年四十已得道，俗緣未盡餘伊臯。", "功名富貴皆逆旅，黄金知繫何人袍。", "超然已了一大事，挂冠而去真秋毫。", "坐看猿猱落罝罔，兩手未肯置所操。", "乃知賢達與愚陋，豈直相去九牛毛。", "長松百尺不自覺，企而羨者蓬與蒿。", "我欲贏糧往問道，未應舉臂辭盧敖。"]'),
('f6b1c0bd-be95-4e4a-bb57-93c958c3b948','送俞節推','蘇軾','宋','宋诗','song-poetry','','[]','吳興有君子，淡如朱絲琴。',72,'全唐诗/poet.song.45000.json','["吳興有君子，淡如朱絲琴。", "一唱三太息，至今有遺音。", "嗟余與夫子，相避如辰參。", "猶喜見諸郎，窈然清且深。", "異時多良士，末路喪初心。", "我生不有命，其肯枉尺尋。"]'),
('7071a868-be11-4619-b994-7a3221fa3230','次韵答孫侔','蘇軾','宋','宋诗','song-poetry','','[]','十年身不到朝廷，欲伴騷人賦落英。',64,'全唐诗/poet.song.45000.json','["十年身不到朝廷，欲伴騷人賦落英。", "但得低頭拜東野，不辭中路候淵明。", "艤舟苕霅人安在，卜築江淮計已成。", "千里論交一言足，與君蓋亦不須傾。"]'),
('a4649ec6-1d41-46f8-ad5e-64b319fc3112','重寄','蘇軾','宋','宋诗','song-poetry','','[]','凜然高節照時人，不信微官解浼君。',64,'全唐诗/poet.song.45000.json','["凜然高節照時人，不信微官解浼君。", "蔣濟謂能來阮籍，薛宣真欲吏朱雲。", "好詩衝口誰能擇，俗子疑人未遣聞。", "乞取千篇看俊逸，不將輕比鮑參軍。"]'),
('77202684-7394-4778-a05a-f226cca6265f','次韵和劉貢父登黄樓見寄並寄子由二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','青派連淮上，黄樓冠海隅。',120,'全唐诗/poet.song.45000.json','["青派連淮上，黄樓冠海隅。", "此詩尤偉麗，夫子計魁梧。", "世俗輕瑚璉，巾箱襲武夫。", "坐令乘傳遽，奔走爲儲須。", "邂逅我已失，登臨誰與俱。", "貧貪倉氏粟，身聽冶家橅。", "會合難前定，歸休試後圖。", "腴田未可買，窮鬼却須呼。", "二水何年到，雙洪不受艫。", "至今清夜夢，飛轡策天吳。"]'),
('55f8e6d4-6456-465e-b9c4-6040463b5835','次韵和劉貢父登黄樓見寄並寄子由二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','與子皆去國，十年天一隅。',108,'全唐诗/poet.song.45000.json','["與子皆去國，十年天一隅。", "數奇逢惡歲，計拙集枯梧。", "好士餘劉表，窮交憶灌夫。", "不矜持漢節，猶喜攬桓須。", "清句金絲合，高樓雪月俱。", "吟哦出新意，指畫想前橅。", "自寫千言賦，新裁六幅圖。", "傳看一座聳，勸著尺書呼。", "莫使騷人怨，東游不到吳。"]'),
('e24f4662-127c-4b08-b8dc-4513ffdadf3d','吳江岸','蘇軾','宋','宋诗','song-poetry','','[]','曉色兼秋色，蟬聲雜鳥聲。',24,'全唐诗/poet.song.45000.json','["曉色兼秋色，蟬聲雜鳥聲。", "壯懷銷鑠盡，回首尚心驚。"]'),
('dcf448a8-9488-4ea8-9a79-a7d16efa61b4','予以事繫御史臺獄獄吏稍見侵自度不能堪死獄中不得一別子由故作二詩授獄卒梁成以遺子由二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','聖主如天萬物春，小臣愚暗自亡身。',64,'全唐诗/poet.song.45000.json','["聖主如天萬物春，小臣愚暗自亡身。", "百年未滿先償債，十口無歸更累人。", "是處青山可埋骨，他時夜雨獨傷神。", "與君世世爲兄弟，又結來生未了因。"]'),
('e5636f9b-7828-4524-b58b-bd6979f3b6c5','予以事繫御史臺獄獄吏稍見侵自度不能堪死獄中不得一別子由故作二詩授獄卒梁成以遺子由二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','柏臺霜氣夜淒淒，風動琅璫月向低。',64,'全唐诗/poet.song.45000.json','["柏臺霜氣夜淒淒，風動琅璫月向低。", "夢繞雲山心似鹿，魂驚湯火命如雞。", "眼中犀角真吾子，身後牛衣愧老妻。", "百歲神游定何處，桐鄉知葬浙江西。"]'),
('c410e00d-50a3-4173-8a0d-fd35d48e2e40','己未十月十五日獄中恭聞太皇太后不豫有赦作詩','蘇軾','宋','宋诗','song-poetry','','[]','庭柏陰陰晝掩門，烏知有赦鬧黄昏。',64,'全唐诗/poet.song.45000.json','["庭柏陰陰晝掩門，烏知有赦鬧黄昏。", "漢宮自種三生福，楚客還招九死魂。", "縱有鋤犁及田畝，已無面目見丘園。", "只應聖主如堯舜，猶許先生作正言。"]'),
('17e9f7ef-a0c0-4992-a228-7fc31facc581','十月二十日恭聞太皇太后升遐以軾罪人不許成服欲哭則不敢欲泣則不可故作挽詞二章  其一','蘇軾','宋','宋诗','song-poetry','','[]','巍然開濟兩朝勳，信矣才難十亂臣。',64,'全唐诗/poet.song.45000.json','["巍然開濟兩朝勳，信矣才難十亂臣。", "原廟固應祠百世，先王何止活千人。", "和熹未聖猶貪位，明德雖賢不及民。", "月落風悲天雨泣，誰將椽筆寫光塵。"]'),
('152fdd78-fb4e-4927-9c16-753846916628','十月二十日恭聞太皇太后升遐以軾罪人不許成服欲哭則不敢欲泣則不可故作挽詞二章  其二','蘇軾','宋','宋诗','song-poetry','','[]','未報山陵國士知，遶林松柏已猗猗。',64,'全唐诗/poet.song.45000.json','["未報山陵國士知，遶林松柏已猗猗。", "一聲慟哭猶無所，萬死酬恩更有時。", "夢裏天衢隘雲仗，人間雨淚變彤帷。", "關雎卷耳平生事，白首纍臣正坐詩。"]'),
('10933c79-aef0-434e-99b7-0eda4509b0fd','御史臺榆槐竹柏四首 榆','蘇軾','宋','宋诗','song-poetry','','[]','我行汴堤上，厭見榆陰綠。',72,'全唐诗/poet.song.45000.json','["我行汴堤上，厭見榆陰綠。", "千株不盈畝，斬伐同一束。", "及居幽囚中，亦復見此木。", "蠹皮溜秋雨，病葉埋牆曲。", "誰言霜雪苦，生意殊未足。", "坐待春風至，飛英覆空屋。"]'),
('fe20ca4b-b076-4c07-b34b-60567e489b62','御史臺榆槐竹柏四首 槐','蘇軾','宋','宋诗','song-poetry','','[]','憶我初來時，草木向衰歇。',72,'全唐诗/poet.song.45000.json','["憶我初來時，草木向衰歇。", "高槐雖驚秋，晚蟬猶抱葉。", "淹留未云幾，離離見疏莢。", "棲鴉寒不去，哀叫饑啄雪。", "破巢带空枝，疏影挂殘月。", "豈無兩翅羽，伴我此愁絕。"]'),
('12376286-0b8b-404f-82d2-ae752a66d180','御史臺榆槐竹柏四首 竹','蘇軾','宋','宋诗','song-poetry','','[]','今日南風來，吹亂庭前竹。',72,'全唐诗/poet.song.45000.json','["今日南風來，吹亂庭前竹。", "低昂中音會，甲刃紛相觸。", "蕭然風雪意，可折不可辱。", "風霽竹已回，猗猗散青玉。", "故山今何有，秋雨荒籬菊。", "此君知健否，歸掃南軒綠。"]'),
('0ffcd722-4a46-4720-ae5e-4bf89a320df3','御史臺榆槐竹柏四首 柏','蘇軾','宋','宋诗','song-poetry','','[]','故園多珍木，翠柏如蒲葦。',72,'全唐诗/poet.song.45000.json','["故園多珍木，翠柏如蒲葦。", "幽囚無與樂，百日看不已。", "時來拾流膠，未忍踐落子。", "當年誰所種，少長與我齒。", "仰視蒼蒼幹，所閱固多矣。", "應見李將軍，膽落溫御史。"]'),
('b126ec27-0405-44ef-bd4b-6346b59935d9','十二月二十八日蒙恩責授檢校水部員外郎黄州團練副使復用前韵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','百日歸期恰及春，餘年樂事最關身。',64,'全唐诗/poet.song.45000.json','["百日歸期恰及春，餘年樂事最關身。", "出門便旋風吹面，走馬聯翩鵲啅人。", "却對酒杯渾是夢，試拈詩筆已如神。", "此災何必深追咎，竊祿從來豈有因。"]'),
('1d5b0fdd-5e26-48da-afd9-2a58022d01b5','十二月二十八日蒙恩責授檢校水部員外郎黄州團練副使復用前韵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','平生文字爲吾累，此去聲名不厭低。',64,'全唐诗/poet.song.45000.json','["平生文字爲吾累，此去聲名不厭低。", "塞上縱歸他日馬，城東不鬬少年雞。", "休官彭澤貧無酒，隠几維摩病有妻。", "堪笑睢陽老從事，爲余投檄向江西。"]'),
('436f83e4-e412-4c61-80d3-c83e2f70dc2d','陳州與文郎逸民飲別携手河堤上作此詩','蘇軾','宋','宋诗','song-poetry','','[]','白酒無聲滑瀉油，醉行堤上散吾愁。',64,'全唐诗/poet.song.45000.json','["白酒無聲滑瀉油，醉行堤上散吾愁。", "春風料峭羊角轉，河水渺綿瓜蔓流。", "君已思歸夢巴峽，我能未到說黄州。", "此身聚散何窮已，未忍悲歌學楚囚。"]'),
('10f55ff8-daf6-4458-b4cf-89c600ec635b','子由自南都來陳三日而別','蘇軾','宋','宋诗','song-poetry','','[]','夫子自逐客，尚能哀楚囚。',168,'全唐诗/poet.song.45000.json','["夫子自逐客，尚能哀楚囚。", "奔馳二百里，徑來寬我憂。", "相逢知有得，道眼清不流。", "別來未一年，落盡驕氣浮。", "嗟我晚聞道，款啟如孫休。", "至言難久服，放心不自收。", "悟彼善知識，妙藥應所投。", "納之憂患場，磨以百日愁。", "冥頑雖難化，鎸發亦已周。", "平時種種心，次第去莫留。", "但餘無所還，永與夫子遊。", "此別何足道，大江東西州。", "畏蛇不下榻，睡足吾無求。", "便爲齊安民，何必歸故丘。"]'),
('c92e4d1a-56ea-4730-b4db-01efb01050fe','正月十八日蔡州道上遇雪次子由韵二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','蘭菊有生意，微陽回寸根。',120,'全唐诗/poet.song.45000.json','["蘭菊有生意，微陽回寸根。", "方憂集暮雪，復喜迎朝暾。", "憶我故居室，浮光動南軒。", "松竹半傾瀉，未數葵與萱。", "三徑瑶草合，一瓶井花溫。", "至今行吟處，尚餘履舄痕。", "一朝出從仕，永愧李仲元。", "晚歲益可羞，犯雪方南奔。", "山城買廢圃，槁葉手自掀。", "長使齊安人，指說故侯園。"]'),
('1a85bdf6-d570-4494-a350-51dead70eaee','正月十八日蔡州道上遇雪次子由韵二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','鉛膏染髭鬚，旋露霜雪根。',120,'全唐诗/poet.song.45000.json','["鉛膏染髭鬚，旋露霜雪根。", "不如閉目坐，丹府夜自暾。", "誰知憂患中，方寸寓羲軒。", "大雪從壓屋，我非兒女萱。", "平生學踵息，坐覺兩𩍐溫。", "下馬作雪詩，滿地鞭箠痕。", "佇立望原野，悲歌爲黎元。", "道逢射獵子，遥指狐兔奔。", "蹤跡尚可原，窟穴何足掀。", "寄謝李丞相，吾將反丘園。"]'),
('7919921c-e959-4102-b038-17323fb927c0','過新息留示鄉人任師中','蘇軾','宋','宋诗','song-poetry','','[]','昔年嘗羨任夫子，卜居新息臨淮水。',128,'全唐诗/poet.song.45000.json','["昔年嘗羨任夫子，卜居新息臨淮水。", "怪君便爾忘故鄉，稻熟魚肥信清美。", "竹陂雁起天爲黑，桐柏烟橫山半紫。", "知君坐受兒女困，悔不先歸弄清泚。", "塵埃我亦失收身，此行蹭蹬尤可鄙。", "寄食方將依白足，附書未免煩黄耳。", "往雖不及來有年，詔恩倘許歸田里。", "却下關山入蔡州，爲買烏犍三百尾。"]'),
('a1d1711d-ec74-4fa6-975b-e8445edfc67e','過淮','蘇軾','宋','宋诗','song-poetry','','[]','朝離新息縣，初亂一水碧。',120,'全唐诗/poet.song.45000.json','["朝離新息縣，初亂一水碧。", "暮宿淮南村，已度千山赤。", "麏鼯號古戍，霧雨暗破驛。", "回頭梁楚郊，永與中原隔。", "黄州在何許，想像雲夢澤。", "吾生如寄耳，初不擇所適。", "但有魚與稻，生理已自畢。", "獨喜小兒子，少小事安佚。", "相從艱難中，肝肺如鐵石。", "便應與晤語，何止寄衰疾。"]'),
('ddacff39-fa0e-48af-b7bb-6ba1aaf0ef4a','書黁公詩後','蘇軾','宋','宋诗','song-poetry','','[]','黁公昔未化，來往淮山曲。',96,'全唐诗/poet.song.45000.json','["黁公昔未化，來往淮山曲。", "壽逾兩甲子，氣壓諸尊宿。", "但嗟濁惡世，不受龍象蹴。", "我來不及見，悵望空遺躅。", "霜顱隠白毫，鎖骨埋青玉。", "皆云似達摩，隻履還西竺。", "壁間餘清詩，字勢頗拔俗。", "爲吟五字偈，一洗凡眼肉。"]'),
('3b462396-247f-408d-8883-61dd8e5f13b2','游浄居寺','蘇軾','宋','宋诗','song-poetry','','[]','十載遊名山，自製山中衣。',144,'全唐诗/poet.song.45000.json','["十載遊名山，自製山中衣。", "願言畢婚嫁，携手老翠微。", "不悟俗緣在，失身蹈危機。", "刑名非夙學，陷穽損積威。", "遂恐生死隔，永與雲山違。", "今日復何日，芒鞋自輕飛。", "稽首兩足尊，舉頭雙涕揮。", "靈山會未散，八部猶光輝。", "願從二聖往，一洗千劫非。", "徘徊竹溪月，空翠摇烟霏。", "鐘聲自送客，出谷猶依依。", "回首吾家山，歲晚將焉歸。"]'),
('f1f49686-0c62-4b71-9efc-7b0f310f6bcf','梅花二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','春來幽谷水潺潺，的皪梅花草棘間。',32,'全唐诗/poet.song.45000.json','["春來幽谷水潺潺，的皪梅花草棘間。", "一夜東風吹石裂，半隨飛雪度關山。"]'),
('a33e4891-005e-4026-9475-4198313424dd','梅花二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','何人把酒慰深幽，開自無聊落更愁。',32,'全唐诗/poet.song.45000.json','["何人把酒慰深幽，開自無聊落更愁。", "幸有清溪三百曲，不辭相送到黄州。"]'),
('e2121093-8b21-4886-956a-23ff64914622','萬松亭','蘇軾','宋','宋诗','song-poetry','','[]','十年栽種百年規，好德無人助我儀。',64,'全唐诗/poet.song.45000.json','["十年栽種百年規，好德無人助我儀。", "縣令若同倉庾氏，亭松應長子孫枝。", "天公不救斧斤厄，野火解憐冰雪姿。", "爲問幾株能合抱，殷勤記取角弓詩。"]'),
('0a9051fc-70b5-4a9b-8158-0bcabcad41cc','戲作種松','蘇軾','宋','宋诗','song-poetry','','[]','我昔少年日，種松滿東岡。',192,'全唐诗/poet.song.45000.json','["我昔少年日，種松滿東岡。", "初移一寸根，瑣細如插秧。", "二年黄茅下，一一攢麥芒。", "三年出蓬艾，滿山散牛羊。", "不見十餘年，想作龍蛇長。", "夜風波浪碎，朝露珠璣香。", "我欲食其膏，已伐百本桑。", "人事多乖迕，神藥竟渺茫。", "朅來齊安野，夾路鬚髯蒼。", "會開龜蛇窟，不惜斤斧瘡。", "縱未得茯苓，且當拾流肪。", "釜盎百出入，皎然散飛霜。", "槁死三彭仇，澡換五穀腸。", "青骨凝綠髓，丹田發幽光。", "白髮何足道，要使雙瞳方。", "却後五百年，騎鶴還故鄉。"]'),
('2b1fe520-399c-4719-91c7-491e9cde40d8','張先生','蘇軾','宋','宋诗','song-poetry','','[]','熟視空堂竟不言，故應知我未天全。',64,'全唐诗/poet.song.45000.json','["熟視空堂竟不言，故應知我未天全。", "肯來傳舍人皆說，能致先生子亦賢。", "脫屣不妨眠糞屋，流澌爭看浴冰川。", "士廉豈識桃椎妙，妄意稱量未必然。"]'),
('0d8a8c3f-6737-4894-8031-c3f84ace0829','陳季常所蓄朱陳村嫁娶圖二首  其一','蘇軾','宋','宋诗','song-poetry','','[]','何年顧陸丹青手，畫作朱陳嫁娶圖。',32,'全唐诗/poet.song.45000.json','["何年顧陸丹青手，畫作朱陳嫁娶圖。", "聞道一村惟兩姓，不將門戶買崔盧。"]'),
('615382dd-af64-4195-9cd3-32bc1a5d3744','陳季常所蓄朱陳村嫁娶圖二首  其二','蘇軾','宋','宋诗','song-poetry','','[]','我是朱陳舊使君，勸農曾入杏花村。',32,'全唐诗/poet.song.45000.json','["我是朱陳舊使君，勸農曾入杏花村。", "而今風物那堪畫，縣吏催租夜打門。"]'),
('9e38983b-ccaa-46da-8225-c955aeb66a63','少年時嘗過一村院見壁上有詩云夜凉疑有雨院靜似無僧不知何人詩也宿黄州禪智寺寺僧皆不在夜半雨作偶記此詩故作一絕','蘇軾','宋','宋诗','song-poetry','','[]','佛燈漸暗饑鼠出，山雨忽來修竹鳴。',32,'全唐诗/poet.song.45000.json','["佛燈漸暗饑鼠出，山雨忽來修竹鳴。", "知是何人舊詩句，已應知我此時情。"]'),
('d66f8218-b0d1-4706-8537-6bb51d3462fc','初到黄州','蘇軾','宋','宋诗','song-poetry','','["\u957f\u6c5f", "\u4e50\u89c2", "\u6292\u60c5", "\u5730\u65b9", "\u5fc3\u60c5"]','自笑平生爲口忙，老來事業轉荒唐。',64,'全唐诗/poet.song.45000.json','["自笑平生爲口忙，老來事業轉荒唐。", "長江繞郭知魚美，好竹連山覺筍香。", "逐客不妨員外置，詩人例作水曹郎。", "只慚無補絲毫事，尚費官家壓酒囊。"]'),
('3cf3e8d4-c8c3-4dcf-9999-7cc1ed67d18f','定惠院寓居月夜偶出','蘇軾','宋','宋诗','song-poetry','','[]','幽人無事不出門，偶逐東風轉良夜。',160,'全唐诗/poet.song.45000.json','["幽人無事不出門，偶逐東風轉良夜。", "參差玉宇飛木末，繚繞香烟來月下。", "江雲有態清自媚，竹露無聲浩如瀉。", "已驚弱柳萬絲垂，尚有殘梅一枝亞。", "清詩獨吟還自和，白酒已盡誰能借。", "不惜青春忽忽過，但恐歡意年年謝。", "自知醉耳愛松風，會揀霜林結茅舍。", "浮浮大甑長炊玉，溜溜小槽如壓蔗。", "飲中真味老更濃，醉裏狂言醒可怕。", "閉門謝客對妻子，倒冠落佩從嘲駡。"]');
